window.HADITH_CACHE["ibnu-majah_4"] = {"2001":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا عَبْدُ اللَّهِ بْنُ نُمَيْرٍ عَنْ مُحَمَّدِ بْنِ إِسْحَقَ عَنْ ثَوْرٍ عَنْ عُبَيْدِ بْنِ أَبِي صَالِحٍ عَنْ صَفِيَّةَ بِنْتِ شَيْبَةَ قَالَتْ حَدَّثَتْنِي عَائِشَةُأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ لَا طَلَاقَ وَلَا عَتَاقَ فِي إِغْلَاقٍ","id":"Telah menceritakan kepada kami [Abu Bakr bin Abu Syaibah] berkata, telah menceritakan kepada kami [Abdullah bin Numair] dari [Muhammad bin Ishaq] dari [Tsaur] dari [Ubaid bin Abu Shalih] dari [Shafiah binti Syaibah] ia berkata, \" ['Aisyah] menceritakan kepadaku bahwa Rasulullah shallallahu 'alaihi wasallam bersabda: \"Tidak ada talak atau pembebasan (budak) disaat marah (yang memuncak).\""},"2002":{"ar":"حَدَّثَنَا أَبُو كُرَيْبٍ حَدَّثَنَا هُشَيْمٌ أَنْبَأَنَا عَامِرٌ الْأَحْوَلُ ح و حَدَّثَنَا أَبُو كُرَيْبٍ حَدَّثَنَا حَاتِمُ بْنُ إِسْمَعِيلَ عَنْ عَبْدِ الرَّحْمَنِ بْنِ الْحَارِثِ جَمِيعًا عَنْ عَمْرِو بْنِ شُعَيْبٍ عَنْ أَبِيهِ عَنْ جَدِّهِأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ لَا طَلَاقَ فِيمَا لَا تَمْلِكُ","id":"Telah menceritakan kepada kami [Abu Kuraib] berkata, telah menceritakan kepada kami [Husyaim] berkata, telah memberitakan kepada kami [Amir Al Ahwal]. (dalam jalur lain disebutkan) Telah menceritakan kepada kami [Abu Kuraib] berkata, telah menceritakan kepada kami [Hatim bin Isma'il] semuanya dari ['Abdurrahman bin Al Harits] dari ['Amr bin Syu'aib] dari [Bapaknya] dari [Kakeknya] bahwa Rasulullah shallallahu 'alaihi wasallam bersabda: \"Tidak ada perceraian pada apa yang tidak kamu miliki.\""},"2003":{"ar":"حَدَّثَنَا أَحْمَدُ بْنُ سَعِيدٍ الدَّارِمِيُّ حَدَّثَنَا عَلِيُّ بْنُ الْحُسَيْنِ بْنِ وَاقِدٍ حَدَّثَنَا هِشَامُ بْنُ سَعْدٍ عَنْ الزُّهْرِيِّ عَنْ عُرْوَةَ عَنْ الْمِسْوَرِ بْنِ مَخْرَمَةَعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ لَا طَلَاقَ قَبْلَ نِكَاحٍ وَلَا عِتْقَ قَبْلَ مِلْكٍ","id":"Telah menceritakan kepada kami [Ahmad bin Sa'id Ad Darimi] berkata, telah menceritakan kepada kami [Ali bin Al Husain bin Waqid] berkata, telah menceritakan kepada kami [Hisyam bin Sa'd] dari [Az Zuhri] dari [Urwah] dari [Miswar bin Makhramah] dari Nabi shallallahu 'alaihi wasallam, beliau bersabda: \"Tidak ada perceraian sebelum terjadi pernikahan dan tidak ada pembebasan sebelum memiliki.\""},"2004":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ يَحْيَى حَدَّثَنَا عَبْدُ الرَّزَّاقِ أَنْبَأَنَا مَعْمَرٌ عَنْ جُوَيْبِرٍ عَنْ الضَّحَّاكِ عَنْ النَّزَّالِ بْنِ سَبْرَةَ عَنْ عَلِيِّ بْنِ أَبِي طَالِبٍ رَضِيَ اللَّهُ عَنْهُعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ لَا طَلَاقَ قَبْلَ النِّكَاحِ","id":"Telah menceritakan kepada kami [Muhammad bin Yahya] berkata, telah menceritakan kepada kami ['Abdurrazaq] berkata, telah memberitakan kepada kami [Ma'mar] dari [Juwaibir] dari [Adl Dlahhak] dari [Nazzal bin Sabrah] dari [Ali bin Abu Thalib] radliallahu 'anhu, dari Nabi shallallahu 'alaihi wasallam, beliau bersabda: \"Tidak ada perceraian sebelum adanya pernikahan.\""},"2005":{"ar":"حَدَّثَنَا عَبْدُ الرَّحْمَنِ بْنُ إِبْرَاهِيمَ الدِّمَشْقِيُّ حَدَّثَنَا الْوَلِيدُ بْنُ مُسْلِمٍ حَدَّثَنَا الْأَوْزَاعِيُّ قَالَ سَأَلْتُ الزُّهْرِيَّ أَيُّ أَزْوَاجِ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ اسْتَعَاذَتْ مِنْهُ فَقَالَ أَخْبَرَنِي عُرْوَةُ عَنْ عَائِشَةَأَنَّ ابْنَةَ الْجَوْنِ لَمَّا دَخَلَتْ عَلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَدَنَا مِنْهَا قَالَتْ أَعُوذُ بِاللَّهِ مِنْكَ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عُذْتِ بِعَظِيمٍ الْحَقِي بِأَهْلِكِ","id":"Telah menceritakan kepada kami ['Abdurrahman bin Ibrahim Ad Dimasyqi] berkata, telah menceritakan kepada kami [Al Walid bin Muslim] berkata, telah menceritakan kepada kami [Al Auza'i] ia berkata; aku bertanya [Az Zuhri], \"Siapakah dari isteri-isteri Nabi shallallahu 'alaihi wasallam yang berlindung dari beliau?\" ia lalu berkata, \" [Urwah] telah mengabarkan kepadaku dari ['Aisyah], bahwa Puteri Al Jaun ketika bertemu dengan Rasulullah shallallahu 'alaihi wasallam dan beliau telah dekat dengannya, ia berkata, \"Aku berlindung kepada Allah darimu.\" Maka Rasulullah shallallahu 'alaihi wasallam pun bersabda: \"Engkau telah berlindung dengan sesuatu yang besar, kembalilah kepada keluargamu.\""},"2006":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ وَعَلِيُّ بْنُ مُحَمَّدٍ قَالَا حَدَّثَنَا وَكِيعٌ عَنْ جَرِيرِ بْنِ حَازِمٍ عَنْ الزُّبَيْرِ بْنِ سَعِيدٍ عَنْ عَبْدِ اللَّهِ بْنِ عَلِيِّ بْنِ يَزِيدَ بْنِ رُكَانَةَ عَنْ أَبِيهِ عَنْ جَدِّهِأَنَّهُ طَلَّقَ امْرَأَتَهُ الْبَتَّةَ فَأَتَى رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَسَأَلَهُ ف��قَالَ مَا أَرَدْتَ بِهَا قَالَ وَاحِدَةً قَالَ آللَّهِ مَا أَرَدْتَ بِهَا إِلَّا وَاحِدَةً قَالَ آللَّهِ مَا أَرَدْتُ بِهَا إِلَّا وَاحِدَةً قَالَ فَرَدَّهَا عَلَيْهِقَالَ مُحَمَّد بْن مَاجَةَ سَمِعْت أَبَا الْحَسَنِ عَلِيَّ بْنَ مُحَمَّدٍ الطَّنَافِسِيَّ يَقُولُ مَا أَشْرَفَ هَذَا الْحَدِيثَ قَالَ ابْن مَاجَةَ أَبُو عُبَيْدٍ تَرَكَهُ نَاجِيَةُ وَأَحْمَدُ جَبُنَ عَنْهُ","id":"Telah menceritakan kepada kami [Abu Bakr bin Abu Syaibah] dan [Ali bin Muhammad] keduanya berkata; telah menceritakan kepada kami [Waki'] dari [Jarir bin Hazim] dari [Az Zubair bin Sa'id] dari [Abdullah bin Ali bin Yazid bin Rukanah] dari [Bapaknya] dari [Kakeknya] bahwa ia telah mencerai isterinya dengan talak tiga. Lalu ia datang kepada Rasulullah shallallahu 'alaihi wasallam dan menanyakannya, lantas beliau balik bertanya: \"Apa yang kamu inginkan?\" ia menjawab: \"Talak satu.\" Beliau kembali menegaskan: \"Demi Allah, kamu tidak menginginkannya kecuali satu!? ia menjawab: \"Demi Allah, aku tidak menginginkannya kecuali satu.\" Ia berkata, \"Maka Beliau mengembalikan isterinya kepadanya.\" Muhammad bin Hajah berkata, \"Aku mendengar Abu Al Hasan Ali bin Muhammad Ath Thanafisi berkata, \"Betapa mulianya hadits ini.\" Ibnu Majah berkata, \"Nama Abu Ubaid telah ditinggalkan oleh Najiah, sementara Ahmad melemahkannya.\""},"2007":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا أَبُو مُعَاوِيَةَ عَنْ الْأَعْمَشِ عَنْ مُسْلِمٍ عَنْ مَسْرُوقٍ عَنْ عَائِشَةَ قَالَتْخَيَّرَنَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَاخْتَرْنَاهُ فَلَمْ نَرَهُ شَيْئًا","id":"Telah menceritakan kepada kami [Abu Bakr bin Abu Syaibah] berkata, telah menceritakan kepada kami [Abu Mu'awiyah] dari [Al A'masy] dari [Muslim] dari [Masruq] dari ['Aisyah] ia berkata, \"Rasulullah shallallahu 'alaihi wasallam membuat pilihan untuk kami hingga kami pun memilihnya, dan sama sekali kami tidak ada keinginan memilih thalaq sedikitpun.\""},"2008":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ يَحْيَى حَدَّثَنَا عَبْدُ الرَّزَّاقِ أَنْبَأَنَا مَعْمَرٌ عَنْ الزُّهْرِيِّ عَنْ عُرْوَةَ عَنْ عَائِشَةَ قَالَتْلَمَّا نَزَلَتْ{ وَإِنْ كُنْتُنَّ تُرِدْنَ اللَّهَ وَرَسُولَهُ }دَخَلَ عَلَيَّ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ يَا عَائِشَةُ إِنِّي ذَاكِرٌ لَكِ أَمْرًا فَلَا عَلَيْكِ أَنْ لَا تَعْجَلِي فِيهِ حَتَّى تَسْتَأْمِرِي أَبَوَيْكِ قَالَتْ قَدْ عَلِمَ وَاللَّهِ أَنَّ أَبَوَيَّ لَمْ يَكُونَا لِيَأْمُرَانِي بِفِرَاقِهِ قَالَتْ فَقَرَأَ عَلَيَّ{ يَا أَيُّهَا النَّبِيُّ قُلْ لِأَزْوَاجِكَ إِنْ كُنْتُنَّ تُرِدْنَ الْحَيَاةَ الدُّنْيَا وَزِينَتَهَا }الْآيَاتِ فَقُلْتُ فِي هَذَا أَسْتَأْمِرُ أَبَوَيَّ قَدْ اخْتَرْتُ اللَّهَ وَرَسُولَهُ","id":"Telah menceritakan kepada kami [Muhammad bin Yahya] berkata, telah menceritakan kepada kami [Abdurrazaq] berkata, telah memberitakan kepada kami [Ma'mar] dari [Az Zuhri] dari [Urwah] dari ['Aisyah] ia berkata, \"Katika turun ayat: \"(Dan jika kamu sekalian menghendaki (keredhaan) Allah dan Rasulnya-Nya) \", Rasulullah shallallahu 'alaihi wasallam masuk menemuiku seraya bersabda: \"Wahai 'Aisyah, aku akan mengingatkan suatu perkara kepadamu, maka janganlah kamu segera dalam memberi putusan hingga engkau minta pertimbangan terlebih dahulu kepada kedua orang tuamu, \" 'Aisyah melanjutkan penuturannya, \"Demi Allah, beliau sudah tahu bahwa kedua orang tuaku tidak akan mungkin memberiku saran untuk berpisah dengannya.\" 'Aisyah berkata, \"Lalu beliau membacakan kepadaku ayat: \"(Hai Nabi, katakanlah kepada isteri-isterimu: 'Jika kamu sekalian mengingini kehidupan dunia dan perhiasannya..).\" 'Aisyah berkata, \"Apakah dalam perkara semacam ini aku akan meminta pertimbangan orang tuaku! Sungguh, aku lebih memilih Allah dan Rasul-Nya.\""},"2009":{"ar":"حَدَّثَنَا بَكْرُ بْنُ خَلَفٍ أَبُو بِشْرٍ حَدَّثَنَا أَبُو عَاصِمٍ عَنْ جَعْفَرِ بْنِ يَحْيَى بْنِ ثَوْبَانَ عَنْ عَمِّهِ عُمَارَةَ بْنِ ثَوْبَانَ عَنْ عَطَاءٍ عَنْ ابْنِ عَبَّاسٍأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ لَا تَسْأَلُ الْمَرْأَةُ زَوْجَهَا الطَّلَاقَ فِي غَيْرِ كُنْهِهِ فَتَجِدَ رِيحَ الْجَنَّةِ وَإِنَّ رِيحَهَا لَيُوجَدُ مِنْ مَسِيرَةِ أَرْبَعِينَ عَامًا","id":"Telah menceritakan kepada kami [Bakr bin Khalaf Abu Bisyr] berkata, telah menceritakan kepada kami [Abu 'Ashim] dari [Ja'far bin Yahya bin Tsauban] dari pamannya [Umarah bin Tsauban] dari ['Atha] dari [Ibnu Abbas] bahwa Nabi shallallahu 'alaihi wasallam bersabda: \"Tidaklah seorang isteri yang minta cerai suaminya bukan karena alasan yang dibenarkan kemudian mendapatkan bau surga, sungguh bau surga dapat dicapai dengan perjalanan empat puluh tahun.\""},"2010":{"ar":"حَدَّثَنَا أَحْمَدُ بْنُ الْأَزْهَرِ حَدَّثَنَا مُحَمَّدُ بْنُ الْفَضْلِ عَنْ حَمَّادِ بْنِ زَيْدٍ عَنْ أَيُّوبَ عَنْ أَبِي قِلَابَةَ عَنْ أَبِي أَسْمَاءَ عَنْ ثَوْبَانَ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَيُّمَا امْرَأَةٍ سَأَلَتْ زَوْجَهَا الطَّلَاقَ فِي غَيْرِ مَا بَأْسٍ فَحَرَامٌ عَلَيْهَا رَائِحَةُ الْجَنَّةِ","id":"Telah menceritakan kepada kami [Ahmad Ibnul Azhar] berkata, telah menceritakan kepada kami [Muhammad Ibnul Fadll] dari [Hammad bin Zaid] dari [Ayyub] dari [Abu Qilabah] dari [Abu Asma] dari [Tsauban] ia berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Wanita mana saja yang minta cerai kepada suaminya bukan karena alasan yang dibenarkan, maka ia tidak akan mendapatkan bau surga.\""},"2011":{"ar":"حَدَّثَنَا أَزْهَرُ بْنُ مَرْوَانَ حَدَّثَنَا عَبْدُ الْأَعْلَى بْنُ عَبْدِ الْأَعْلَى حَدَّثَنَا سَعِيدُ بْنُ أَبِي عَرُوبَةَ عَنْ قَتَادَةَ عَنْ عِكْرِمَةَ عَنْ ابْنِ عَبَّاسٍأَنَّ جَمِيلَةَ بِنْتَ سَلُولَ أَتَتْ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَتْ وَاللَّهِ مَا أَعْتِبُ عَلَى ثَابِتٍ فِي دِينٍ وَلَا خُلُقٍ وَلَكِنِّي أَكْرَهُ الْكُفْرَ فِي الْإِسْلَامِ لَا أُطِيقُهُ بُغْضًا فَقَالَ لَهَا النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَتَرُدِّينَ عَلَيْهِ حَدِيقَتَهُ قَالَتْ نَعَمْ فَأَمَرَهُ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنْ يَأْخُذَ مِنْهَا حَدِيقَتَهُ وَلَا يَزْدَادَ","id":"Telah menceritakan kepada kami [Azhar bin Marwan] berkata, telah menceritakan kepada kami [Abdul A'la bin Abdul A'la] berkata, telah menceritakan kepada kami [Sa'id bin Abu Arubah] dari [Qatadah] dari [Ikrimah] dari [Ibnu Abbas] berkata, \"Jamilah binti Salul datang kepada Nabi shallallahu 'alaihi wasallam dan berkata, \"Aku tidak mencela Tsabit dalam masalah agama dan ahlaknya, akan tetapi aku benci kekafiran di dalam Islam, aku tidak mampu karena jengkel.\" Lalu Nabi shallallahu 'alaihi wasallam pun bersabda kepadanya: \"Apakah engkau bersedia mengembalikan kebun miliknya (mahar) kepadanya?\" ia menjawab, \"Ya.\" Maka beliau memerintahkan Tsabit mengambil kebun miliknya dan tidak memberi tambahan.\""},"2012":{"ar":"حَدَّثَنَا أَبُو كُرَيْبٍ حَدَّثَنَا أَبُو خَالِدٍ الْأَحْمَرُ عَنْ حَجَّاجٍ عَنْ عَمْرِو بْنِ شُعَيْبٍ عَنْ أَبِيهِ عَنْ جَدِّهِ قَالَكَانَتْ حَبِيبَةُ بِنْتُ سَهْلٍ تَحْتَ ثَابِتِ بْنِ قَيْسِ بْنِ شَمَّاسٍ وَكَانَ رَجُلًا دَمِيمًا فَقَالَتْ يَا رَسُولَ اللَّهِ وَاللَّهِ لَوْلَا مَخَافَةُ اللَّهِ إِذَا دَخَلَ عَلَيَّ لَبَصَقْتُ فِي وَجْهِهِ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَتَرُدِّينَ عَلَيْهِ حَدِيقَتَهُ قَالَتْ نَعَمْ فَرَدَّتْ عَلَيْهِ حَدِيقَتَهُ قَالَ فَفَرَّقَ بَيْنَهُمَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ","id":"Telah menceritakan kepada kami [Abu Kuraib] berkata, telah menceritakan kepada kami [Abu Khalid Al Ahmar] dari [Hajjaj] dari ['Amru bin Syu'aib] dari [Bapaknya] dari [Kakeknya] ia berkata, \"Habibah binti Sahl adalah isteri Tsabit bin Qais bin Syammas, sementara dia adalah seorang lelaki yang bermuka buruk. Habibah berkata, \"Wahai Rasulullah, demi Allah, sekiranya bukan karena takut kepada Allah, jika dia berani masuk kepadaku niscaya aku akan meludahi mukanya.\" Beliau lalu bersabda: \"Apakah kamu mau mengembalikan kebun miliknya (mahar) kepada dia?\" ia menjawab, \"Ya.\" Maka ia pun mengembalikan kebun tersebut kepada Tsabit bin Qais. Ia (perawi) berkata, \"Maka Rasulullah shallallahu 'alaihi wasallam pun menceraikan keduanya.\""},"2013":{"ar":"حَدَّثَنَا عَلِيُّ بْنُ سَلَمَةَ النَّيْسَابُورِيُّ حَدَّثَنَا يَعْقُوبُ بْنُ إِبْرَاهِيمَ بْنِ سَعْدٍ حَدَّثَنَا أَبِي عَنْ ابْنِ إِسْحَقَ أَخْبَرَنِي عُبَادَةُ بْنُ الْوَلِيدِ بْنِ عُبَادَةَ بْنِ الصَّامِتِ عَنْ الرُّبَيِّعِ بِنْتِ مُعَوِّذِ ابْنِ عَفْرَاءَ قَالَقُلْتُ لَهَا حَدِّثِينِي حَدِيثَكِ قَالَتْ اخْتَلَعْتُ مِنْ زَوْجِي ثُمَّ جِئْتُ عُثْمَانَ فَسَأَلْتُ مَاذَا عَلَيَّ مِنْ الْعِدَّةِ فَقَالَ لَا عِدَّةَ عَلَيْكِ إِلَّا أَنْ يَكُونَ حَدِيثَ عَهْدٍ بِكِ فَتَمْكُثِينَ عِنْدَهُ حَتَّى تَحِيضِينَ حَيْضَةً قَالَتْ وَإِنَّمَا تَبِعَ فِي ذَلِكَ قَضَاءَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي مَرْيَمَ الْمَغَالِيَّةِ وَكَانَتْ تَحْتَ ثَابِتِ بْنِ قَيْسٍ فَاخْتَلَعَتْ مِنْهُ","id":"Telah menceritakan kepada kami [Ali bin Salamah An Naisaburi] berkata, telah menceritakan kepada kami [Ya'qub bin Ibrahim bin Sa'd] berkata, telah menceritakan kepada kami [Bapakku] dari [Ibnu Ishaq] berkata, telah mengabarkan kepadaku [Ubadah bin Al Walid bin Ubadah bin Ash Shamit] dari [Ar Rubayyi' binti Mu'awwidz bin Afra] berkata, \"Aku berkata kepadanya, \"Ceritakanlah kepadaku tentang masalahmu.\" Ia menuturkan, \"Aku menggugat cerai suamiku, kemudian aku mendatangi Utsman dan bertanya, \"Apa kewajibanku dari Iddah?\" Maka dia menjawab, \"Tidak ada 'Iddah bagimu, karena kamu masih dalam keadaan baru, maka tinggallah di sisinya sehingga kamu mengalami haid satu kali.\" Rubayyi' berkata, \"Dalam perkara itu dia hanya mengikuti keputusan Rasulullah shallallahu 'alaihi wasallam sebagaimana dalam kasus Maryam Al Maghaliyyah, yang saat itu sedang berada di bawah naungan Tsabit bin Qais, kemudian dia meminta khulu' darinya.\""},"2014":{"ar":"حَدَّثَنَا هِشَامُ بْنُ عَمَّارٍ حَدَّثَنَا عَبْدُ الرَّحْمَنِ بْنُ أَبِي الرِّجَالِ عَنْ أَبِيهِ عَنْ عَمْرَةَ عَنْ عَائِشَةَ قَالَتْأَقْسَمَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنْ لَا يَدْخُلَ عَلَى نِسَائِهِ شَهْرًا فَمَكَثَ تِسْعَةً وَعِشْرِينَ يَوْمًا حَتَّى إِذَا كَانَ مِسَاءَ ثَلَاثِينَ دَخَلَ عَلَيَّ فَقُلْتُ إِنَّكَ أَقْسَمْتَ أَنْ لَا تَدْخُلَ عَلَيْنَا شَهْرًا فَقَالَ الشَّهْرُ هَكَذَا يُرْسِلُ أَصَابِعَهُ فِيهَا ثَلَاثَ مَرَّاتٍ وَالشَّهْرُ هَكَذَا وَأَرْسَلَ أَصَابِعَهُ كُلَّهَا وَأَمْسَكَ إِصْبَعًا وَاحِدًا فِي الثَّالِثَةِ","id":"Telah menceritakan kepada kami [Hisyam bin Ammar] berkata, telah menceritakan kepada kami ['Abdurrahman bin Abu Ar Rijal] dari [Bapaknya] dari [Amrah] dari ['Aisyah] ia berkata, \"Rasulullah shallallahu 'alaihi wasallam pernah bersumpah untuk tidak menggauli isteri-isterinya selama satu bulan, hal itu berlangsung hingga dua puluh sembilan hari. Maka ketika masuk malam ke tiga puluh beliau masuk menemuiku, aku bertanya, \"Engkau telah bersumpah untuk tidak menemui kami selama satu bulan?! \" beliau menjawab: \"Satu bulan itu seperti ini -beliau mengacungkan jari-jarinya tiga kali-, satu bulan itu seperti ini -lalu beliau mengacungkan semua jarinya dan menggenggam satu jari pada kali ketiganya.\""},"2015":{"ar":"حَدَّثَنَا سُوَيْدُ بْنُ سَعِيدٍ حَدَّثَنَا يَحْيَى بْنُ زَكَرِيَّا بْنِ أَبِي زَائِدَةَ عَنْ حَارِثَةَ بْنِ مُحَمَّدٍ عَنْ عَمْرَةَ عَنْ عَائِشَةَأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِنَّمَا آلَى لِأَنَّ زَيْنَبَ رَدَّتْ عَلَيْهِ هَدِيَّتَهُ فَقَالَتْ عَائِشَةُ لَقَدْ أَقْمَأَتْكَ فَغَضِبَ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَآلَى مِنْهُنَّ","id":"Telah menceritakan kepada kami [Suwaid bin Sa'id] berkata, telah menceritakan kepada kami [Yahya bin Zakariya bin Abu Za`idah] dari [Haritsah bin Muhammad] dari [Amrah] dari ['Aisyah] berkata, \"Rasulullah shallallahu 'alaihi wasallam melakukan Ila` (sumpah tidak akan meniduri isterinya) karena Zainab mengembalikan hadiah pemberian beliau. 'Aisyah berkata, \"Sesungguhnya ia telah merendahkanmu.\" Maka Nabi shallallahu 'alaihi wasallam marah dan meng-Ila` mereka.\""},"2016":{"ar":"حَدَّثَنَا أَحْمَدُ بْنُ يُوسُفَ السُّلَمِيُّ حَدَّثَنَا أَبُو عَاصِمٍ عَنْ ابْنِ جُرَيْجٍ عَنْ يَحْيَى بْنِ عَبْدِ اللَّهِ بْنِ مُحَمَّدِ بْنِ صَيْفِيٍّ عَنْ عِكْرِمَةَ بْنِ عَبْدِ الرَّحْمَنِ عَنْ أُمِّ سَلَمَةَأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ آلَى مِنْ بَعْضِ نِسَائِهِ شَهْرًا فَلَمَّا كَانَ تِسْعَةً وَعِشْرِينَ رَاحَ أَوْ غَدَا فَقِيلَ يَا رَسُولَ اللَّهِ إِنَّمَا مَضَى تِسْعٌ وَعِشْرُونَ فَقَالَ الشَّهْرُ تِسْعٌ وَعِشْرُونَ","id":"Telah menceritakan kepada kami [Ahmad bin Yusuf As Sulami] berkata, telah menceritakan kepada kami [Abu Ashim] dari [Ibnu Juraij] dari [Yahya bin Abdullah bin Muhammad bin Shaifi] dari [Ikrimah bin 'Abdurrahman] dari [Ummu Salamah] berkata, \"Rasulullah shallallahu 'alaihi wasallam meng-Ila` (sumpah untuk tidak menggaulinya) sebagian isteri-isterinya selama satu bulan. Maka, ketika telah masuk hari ke dua puluh sembilan beliau keluar di waktu sore atau pagi hari. Lalu dikatakan kepada beliau, \"Wahai Rasulullah, sekarang baru berlalu dua puluh sembilan hari! \" beliau lantas bersabda: \"Satu bulan itu dua puluh sembilan hari.\""},"2017":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا عَبْدُ اللَّهِ بْنُ نُمَيْرٍ حَدَّثَنَا مُحَمَّدُ بْنُ إِسْحَقَ عَنْ مُحَمَّدِ بْنِ عَمْرِو بْنِ عَطَاءٍ عَنْ سُلَيْمَانَ بْنِ يَسَارٍ عَنْ سَلَمَةَ بْنِ صَخْرٍ الْبَيَاضِيِّ قَالَكُنْتُ امْرَأً أَسْتَكْثِرُ مِنْ النِّسَاءِ لَا أَرَى رَجُلًا كَانَ يُصِيبُ مِنْ ذَلِكَ مَا أُصِيبُ فَلَمَّا دَخَلَ رَمَضَانُ ظَاهَرْتُ مِنْ امْرَأَتِي حَتَّى يَنْسَلِخَ رَمَضَانُ فَبَيْنَمَا هِيَ تُحَدِّثُنِي ذَاتَ لَيْلَةٍ انْكَشَفَ لِي مِنْهَا شَيْءٌ فَوَثَبْتُ عَلَيْهَا فَوَاقَعْتُهَا فَلَمَّا أَصْبَحْتُ غَدَوْتُ عَلَى قَوْمِي فَأَخْبَرْتُهُمْ خَبَرِي وَقُلْتُ لَهُمْ سَلُوا لِي رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالُوا مَا كُنَّا نَفْعَلُ إِذًا يُنْزِلَ اللَّهُ عَزَّ وَجَلَّ فِينَا كِتَابًا أَوْ يَكُونَ فِينَا مِنْ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَوْلٌ فَيَبْقَى عَلَيْنَا عَارُهُ وَلَكِنْ سَوْفَ نُسَلِّمُكَ لِجَرِيرَتِكَ اذْهَبْ أَنْتَ فَاذْكُرْ شَأْنَكَ لِرَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ فَخَرَجْتُ حَتَّى جِئْتُهُ فَأَخْبَرْتُهُ الْخَبَرَ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنْتَ بِذَاكَ فَقُلْتُ أَنَا بِذَاكَ وَهَا أَنَا يَا رَسُولَ اللَّهِ صَابِرٌ لِحُكْمِ اللَّهِ عَلَيَّ قَالَ فَأَعْتِقْ رَقَبَةً قَالَ قُلْتُ وَالَّذِي بَعَثَكَ بِالْحَقِّ مَا أَصْبَحْتُ أَمْلِكُ إِلَّا رَقَبَتِي هَذِهِ قَالَ فَصُمْ شَهْرَيْنِ مُتَتَابِعَيْنِ قَالَ قُلْتُ يَا رَسُولَ اللَّهِ وَهَلْ دَخَلَ عَلَيَّ مَا دَخَلَ مِنْ الْبَلَاءِ إِلَّا بِالصَّوْمِ قَالَ فَتَصَدَّقْ أَوْ أَطْعِمْ سِتِّينَ مِسْكِينًا قَالَ قُلْتُ وَالَّذِي بَعَثَكَ بِالْحَقِّ لَقَدْ بِتْنَا لَيْلَتَنَا هَذِهِ مَا لَنَا عَشَاءٌ قَالَ فَاذْهَبْ إِلَى صَاحِبِ صَدَقَةِ بَنِي زُرَيْقٍ فَقُلْ لَهُ فَلْيَدْفَعْهَا إِلَيْكَ وَأَطْعِمْ سِتِّينَ مِسْكِينًا وَانْتَفِعْ بِبَقِيَّتِهَا","id":"Telah menceritakan kepada kami [Abu Bakr bin Abu Syaibah] berkata, telah menceritakan kepada kami [Abdullah bin Numair] berkata, telah menceritakan kepada kami [Muhammad bin Ishaq] dari [Muhammad bin Amru bin 'Atha] dari [Sulaiman bin Yasar] dari [Salamah bin Shakhr Al Bayadli] ia berkata, \"Aku adalah orang yang paling besar ketertarikannya terhadap wanita, tidak seorang laki-laki pun yang seperti aku dalam hal itu. Ketika masuk bulan ramadlan aku menzhihar isteriku hingga bulan ramadlan berakhir. Ketika pada suatu malam ia berbicara kepadaku, sebagian auratnya tersingkaf hingga aku pun mendekapnya dan menggaulinya. Di pagi harinya aku pergi menemui kaumku dan mengabarkan apa yang telah aku lakukan. Aku katakan kepada mereka, \"Temanilah aku untuk menemui Rasulullah shallallahu 'alaihi wasallam, \" mereka berkata, \"Kami tidak akan melakukannya, kami takut akan ada ayat yang Allah 'azza wajalla turunkan atas kami. Atau, akan keluar perkataan Rasulullah shallallahu 'alaihi wasallam atas kami. Akan tetapi kami akan menyerahkan kamu beserta dosa-dosamu, maka pergi dan sebutkanlah perkaramu kepada Rasulullah shallallahu 'alaihi wasallam.\" Salamah bin Shakhr Al Bayadli berkata, \"Lalu aku keluar menemui beliau dan aku kabarkan hal itu kepadanya, Rasulullah shallallahu 'alaihi wasallam kemudian bersabda: \"Kamu berdosa karena hal itu, \" aku menjawab, \"Aku berdosa karena hal itu! Wahai Rasulullah, aku akan sabar dengan hukum Allah.\" Beliau bersabda: \"Bebaskanlah seorang budak.\" Salamah bin Shakhr Al Bayadli berkata, \"Aku berkata, \"Demi yang mengutusmu dengan keberanan, disaat pagi hari aku tidak mempunyai kecuali hanya budak ini.\" beliau bersabda: \"Berpuasalah dua bulan berturut-turut.\" Salamah bin Shakhr Al Bayadli berkata, \"Aku berkata, \"Wahai Rasulullah, apakah ada sesuatu yang menjadikan aku tertimpa musibah kecuali puasa?\" beliau bersabda: \"Bersedekahlah, atau beliau mengatakan, \"berilah makan enam puluh orang miskin.\" Salamah bin Shakhr Al Bayadli berkata, \"Aku berkata, \"Demi yang mengutusmu dengan kebenaran, malam ini kami telah bermalam dan kami tidak mendapati makan malam.\" Beliau bersabda: \"Temuilah pemegang harta sedekah dari bani Zurai', katakan kepadanya agar ia memberikan harta itu kepadamu. Lalu berilah makan kepada enam puluh orang miskin, dan manfaatkanlah sisanya.\""},"2018":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا مُحَمَّدُ بْنُ أَبِي عُبَيْدَةَ حَدَّثَنَا أَبِي عَنْ الْأَعْمَشِ عَنْ تَمِيمِ بْنِ سَلَمَةَ عَنْ عُرْوَةَ بْنِ الزُّبَيْرِ قَالَ قَالَتْ عَائِشَةُتَبَارَكَ الَّذِي وَسِعَ سَمْعُهُ كُلَّ شَيْءٍ إِنِّي لَأَسْمَعُ كَلَامَ خَوْلَةَ بِنْتِ ثَعْلَبَةَ وَيَخْفَى عَلَيَّ بَعْضُهُ وَهِيَ تَشْتَكِي زَوْجَهَا إِلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَهِيَ تَقُولُ يَا رَسُولَ اللَّهِ أَكَلَ شَبَابِي وَنَثَرْتُ لَهُ بَطْنِي حَتَّى إِذَا كَبِرَتْ سِنِّي وَانْقَطَعَ وَلَدِي ظَاهَرَ مِنِّي اللَّهُمَّ إِنِّي أَشْكُو إِلَيْكَ فَمَا بَرِحَتْ حَتَّى نَزَلَ جِبْرَائِيلُ بِهَؤُلَاءِ الْآيَاتِ{ قَدْ سَمِعَ اللَّهُ قَوْلَ الَّتِي تُجَادِلُكَ فِي زَوْجِهَا وَتَشْتَكِي إِلَى اللَّهِ }","id":"Telah menceritakan kepada kami [Abu Bakr bin Abu Syaibah] berkata, telah menceritakan kepada kami [Muhammad bin Abu Ubaidah] berkata, telah menceritakan kepada kami [Bapakku] dari [Al A'masy] dari [Tamim bin Salamah] dari [Urwah bin Az Zubair] ia berkata, \" ['Aisyah] berkata, \"Maha Suci Allah yang pendengaran-Nya mencakup segala sesuatu. Sungguh, aku pernah mendengar perkataan Khaulah binti Tsa'labah ketika ia mengadu kepada Rasulullah shallallahu 'alaihi wasallam tentang suaminya, namun aku tidak mendengar yang sebagiannya. Ia mengatakan, \"Wahai Rasulullah, ia telah memakan masa mudaku dan aku buka rahimku untuknya. Namun ketika umurku telah senja dan tidak bisa lagi memberi anak ia menzhiharku. Ya Allah, aku mengadu kepada-Mu, \" ia tetap saja begitu hingga Jibril turun dengan membaya ayat-ayat tersebut: \"(Sesungguhnya Allah telah mendengar perkataan wanita yang mengajukan gugatan kepada kamu tentang suaminya, dan mengadukan (halnya) kepada Allah..).\""},"2019":{"ar":"حَدَّثَنَا عَبْدُ اللَّهِ بْنُ سَعِيدٍ حَدَّثَنَا عَبْدُ اللَّهِ بْنُ إِدْرِيسَ عَنْ مُحَمَّدِ بْنِ إِسْحَقَ عَنْ مُحَمَّدِ بْنِ عَمْرِو بْنِ عَطَاءٍ عَنْ سُلَيْمَانَ بْنِ يَسَارٍ عَنْ سَلَمَةَ بْنِ صَخْرٍ الْبَيَاضِيِّعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي الْمُظَاهِرِ يُوَاقِعُ قَبْلَ أَنْ يُكَفِّرَ قَالَ كَفَّارَةٌ وَاحِدَةٌ","id":"Telah menceritakan kepada kami [Abdullah bin Sa'id] berkata, telah menceritakan kepada kami [Abdullah bin Idris] dari [Muhammad bin Ishaq] dari [Muhammad bin Amru bin 'Atha] dari [Sulaiman bin Yasar] dari [Salamah bin Shakhr Al Bayadli] dari Nabi shallallahu 'alaihi wasallam tentang seseorang yang menzhihar kemudian mensetubuhi (isteri yang ia zhihar) sebelum membayar kafarahnya, \"Cukup dengan satu kali kafarah.\""},"2020":{"ar":"حَدَّثَنَا الْعَبَّاسُ بْنُ يَزِيدَ حَدَّثَنَا غُنْدَرٌ حَدَّثَنَا مَعْمَرٌ عَنْ الْحَكَمِ بْنِ أَبَانَ عَنْ عِكْرِمَةَ عَنْ ابْنِ عَبَّاسٍأَنَّ رَجُلًا ظَاهَرَ مِنْ امْرَأَتِهِ فَغَشِيَهَا قَبْلَ أَنْ يُكَفِّرَ فَأَتَى النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَذَكَرَ ذَلِكَ لَهُ فَقَالَ مَا حَمَلَكَ عَلَى ذَلِكَ قَالَ يَا رَسُولَ اللَّهِ رَأَيْتُ بَيَاضَ حِجْلَيْهَا فِي الْقَمَرِ فَلَمْ أَمْلِكْ نَفْسِي أَنْ وَقَعْتُ عَلَيْهَا فَضَحِكَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَأَمَرَهُ أَلَّا يَقْرَبَهَا حَتَّى يُكَفِّرَ","id":"Telah menceritakan kepada kami [Al Abbas bin Yazid] berkata, telah menceritakan kepada kami [Ghundar] berkata, telah menceritakan kepada kami [Ma'mar] dari [Al Hakam bin Aban] dari [Ikrimah] dari [Ibnu Abbas] berkata, \"Seseorang menzhihzar isterinya kemudian ia menggaulinya sebelum membayar kafarah. Lalu ia datang kepada Nabi shallallahu 'alaihi wasallam dan menerangkan permasalahannya. Beliau bertanya: \"Apa yang membuatmu berbuat seperti itu?\" ia menjawab, \"Ya Rasulullah, aku melihat putih kedua kakinya saat terkena sinar rembulan, hingga aku tidak mampu menguasai jiwaku untuk menggaulinya.\" Rasulullah shallallahu 'alaihi wasallam tertawa dan memerintahkannya agar tidak mendekatinya hingga membayar kafarah.\""},"2021":{"ar":"حَدَّثَنَا أَبُو مَرْوَانَ الْعُثْمَانِيُّ مُحَمَّدُ بْنُ عُثْمَانَ حَدَّثَنَا إِبْرَاهِيمُ بْنُ سَعْدٍ عَنْ ابْنِ شِهَابٍ عَنْ سَهْلِ بْنِ سَعْدٍ السَّاعِدِيِّ قَالَجَاءَ عُوَيْمِرٌ إِلَى عَاصِمِ بْنِ عَدِيٍّ فَقَالَ سَلْ لِي رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَرَأَيْتَ رَجُلًا وَجَدَ مَعَ امْرَأَتِهِ رَجُلًا فَقَتَلَهُ أَيُقْتَلُ بِهِ أَمْ كَيْفَ يَصْنَعُ فَسَأَلَ عَاصِمٌ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَنْ ذَلِكَ فَعَابَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ الْمَسَائِلَ ثُمَّ لَقِيَهُ عُوَيْمِرٌ فَسَأَلَهُ فَقَالَ مَا صَنَعْتَ فَقَالَ صَنَعْتُ أَنَّكَ لَمْ تَأْتِنِي بِخَيْرٍ سَأَلْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَعَابَ الْمَسَائِلَ فَقَالَ عُوَيْمِرٌ وَاللَّهِ لَآتِيَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَلَأَسْأَلَنَّهُ فَأَتَى رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَوَجَدَهُ وَقَدْ أُنْزِلَ عَلَيْهِ فِيهِمَا فَلَاعَنَ بَيْنَهُمَا قَالَ عُوَيْمِرٌ وَاللَّهِ لَئِنْ انْطَلَقْتُ بِهَا يَا رَسُولَ اللَّهِ لَقَدْ كَذَبْتُ عَلَيْهَا قَالَ فَفَارَقَهَا قَبْلَ أَنْ يَأْمُرَهُ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَصَارَتْ سُنَّةً فِي الْمُتَلَاعِنَيْنِ ثُمَّ قَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ انْظُرُوهَا فَإِنْ جَاءَتْ بِهِ أَسْحَمَ أَدْعَجَ الْعَيْنَيْنِ عَظِيمَ الْأَلْيَتَيْنِ فَلَا أُرَاهُ إِلَّا قَدْ صَدَقَ عَلَيْهَا وَإِنْ جَاءَتْ بِهِ أُحَيْمِرَ كَأَنَّهُ وَحَرَةٌ فَلَا أُرَاهُ إِلَّا كَاذِبًا قَالَ فَجَاءَتْ بِهِ عَلَى النَّعْتِ الْمَكْرُوهِ","id":"Telah menceritakan kepada kami [Abu Marwan Al Utsmani Muhammad bin Utsman] berkata, telah menceritakan kepada kami [Ibrahim bin Sa'd] dari [Ibnu Syihab] dari [Sahl bin Sa'd As Sa'idi] ia berkata, \"Uwaimir datang menemui Ashim bin Adi dan berkata, \"Sampaikanlah pertanyaanku kepada Rasulullah shallallahu 'alaihi wasallam; apa pendapatmu jika seorang laki-laki marah ketika mendapati isterinya bersama laki-laki lain hingga ia membunuhnya. Apakah ia harus dibunuh (qishash) atau bagaimana?\" maka Ashim pun menanyakan hal itu kepada Rasulullah shallallahu 'alaihi wasallam, namun Rasulullah shallallahu 'alaihi wasallam mencela (benci) pertanyaan tersebut. Uwaimir lantas menemui Ashim dan bertanya kepadanya, \"Apa yang telah engkau lakukan?\" ia menjawab, \"Engkau datang kepadaku tidak membawa kebaikan, aku telah bertanya kepada Rasulullah shallallahu 'alaihi wasallam, namun beliau mencela pertanyaan tersebut. Maka Uwaimir pun berkata, \"Demi Allah, sungguh aku akan mendatangi Rasulullah shallallahu 'alaihi wasallam dan menanyakan hal itu kepadanya.\" Akhirnya ia datang menemui Rasulullah shallallahu 'alaihi wasallam, ia menemui beliau saat ayat yang berkenaan dengan permasalahannya telah diturunkan. Lalu Rasulullah menyuruhnya untuk saling mengambil sumpah antara keduanya. Uwaimir berkata, \"Demi Allah ya Rasulullah, jika aku membawanya pulang ke rumahku, berarti aku berdusta (tidak konsisten dengan ucapanku)?! \" Ia (perawi) berkata, \"Uwaimir pun berpisah dengan isterinya sebelum Rasulullah shallallahu 'alaihi wasallam memerintahkannya, hingga itu menjadi hal pertama kali yang terjadi dalam kasus li'an. Setelah itu Nabi shallallahu 'alaihi wasallam bersabda: \"Tolong awasi dan selidiki wanita itu, jika ia melahirkan bayinya yang berkulit hitam, warna mata yang sangat hitam dan pantat besar, berarti suaminya benar. Namun jika wanita itu melahirkan bayi dengan ciri-ciri warna kemerahan seperti wahrah (binatang semacam tokek), berarti suaminya yang bohong.\" Ia (perawi) berkata, \"Ternyata wanita itu melahirkan bayi yang ciri-cirinya tidak cocok dengan ayahnya ('Uwaimir).\""},"2022":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ بَشَّارٍ حَدَّثَنَا ابْنُ أَبِي عَدِيٍّ أَنْبَأَنَا هِشَامُ بْنُ حَسَّانَ حَدَّثَنَا عِكْرِمَةُ عَنْ ابْنِ عَبَّاسٍأَنَّ هِلَالَ بْنَ أُمَيَّةَ قَذَفَ امْرَأَتَهُ عِنْدَ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِشَرِيكِ ابْنِ سَحْمَاءَ فَقَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ الْبَيِّنَةَ أَوْ حَدٌّ فِي ظَهْرِكَ فَقَالَ هِلَالُ بْنُ أُمَيَّةَ وَالَّذِي بَعَثَكَ بِالْحَقِّ إِنِّي لَصَادِقٌ وَلَيُنْزِلَنَّ اللَّهُ فِي أَمْرِي مَا يُبَرِّئُ ظَهْرِي قَالَ فَنَزَلَتْ{ وَالَّذِينَ يَرْمُونَ أَزْوَاجَهُمْ وَلَمْ يَكُنْ لَهُمْ شُهَدَاءُ إِلَّا أَنْفُسُهُمْ حَتَّى بَلَغَ وَالْخَامِسَةَ أَنَّ غَضَبَ اللَّهِ عَلَيْهَا إِنْ كَانَ مِنْ الصَّادِقِينَ }فَانْصَرَفَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَأَرْسَلَ إِلَيْهِمَا فَجَاءَا فَقَامَ هِلَالُ بْنُ أُمَيَّةَ فَشَهِدَ وَالنَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ إِنَّ اللَّهَ يَعْلَمُ أَنَّ أَحَدَكُمَا كَاذِبٌ فَهَلْ مِنْ تَائِبٍ ثُمَّ قَامَتْ فَشَهِدَتْ فَلَمَّا كَانَ عِنْدَ الْخَامِسَةِ{ أَنَّ غَضَبَ اللَّهِ عَلَيْهَا إِنْ كَانَ مِنْ الصَّادِقِينَ }قَالُوا لَهَا إِنَّهَا لَمُوجِبَةٌ قَالَ ابْنُ عَبَّاسٍ فَتَلَكَّأَتْ وَنَكَصَتْ حَتَّى ظَنَنَّا أَنَّهَا سَتَرْجِعُ فَقَالَتْ وَاللَّهِ لَا أَفْضَحُ قَوْمِي سَائِرَ الْيَوْمِ فَقَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ انْظُرُوهَا فَإِنْ جَاءَتْ بِهِ أَكْحَلَ الْعَيْنَيْنِ سَابِغَ الْأَلْيَتَيْنِ خَدَلَّجَ السَّاقَيْنِ فَهُوَ لِشَرِيكِ ابْنِ سَحْمَاءَ فَجَاءَتْ بِهِ كَذَلِكَ فَقَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَوْلَا مَا مَضَى مِنْ كِتَابِ اللَّهِ عَزَّ وَجَلَّ لَكَانَ لِي وَلَهَا شَأْنٌ","id":"Telah menceritakan kepada kami [Muhammad bin Basysyar] berkata, telah menceritakan kepada kami [Ibnu Abu Adi] berkata, telah memberitakan kepada kami [Hisyam bin Hassan] berkata, telah menceritakan kepada kami [Ikrimah] dari [Ibnu Abbas] berkata, \"Hilal bin Umayyah menuduh isterinya selingkuh dengan Syarik bin Sahma di hadapan Nabi shallallahu 'alaihi wasallam. Maka, Nabi shallallahu 'alaihi wasallam pun bersabda: \"Engkau berikan bukti, atau engkau akan menerima hukuman had?! Hilal bin Umayyah lantas berkata, \"Demi yang mengutusmu dengan kebenaran, sungguh aku berkata benar. Dan pasti Allah akan menurunkan sebuah ayat yang akan membebaskan aku dari hukuman had.\" Ibnu Abbas berkata, \"Maka turunlah ayat: \"(Dan orang-orang yang menuduh isterinya (berzina), padahal mereka tidak ada mempunyai saksi-saksi selain diri mereka sendiri) \" hingga ayat \"(dan (sumpah) yang kelima: bahwa la'nat Allah atasnya jika suaminya itu termasuk orang-orang yang benar).\" Kemudian Nabi shallallahu 'alaihi wasallam berpaling dan mengutus utusan untuk memanggil keduanya (Hilal dan isterinya), dan mereka pun datang. Hilal bin Umayyah lantas berdiri dan bersaksi, lalu Rasulullah shallallahu 'alaihi wasallam bersabda: \"Sesungguhnya Allah mengetahui bahwa di antara kalian ada yang bohong, maka apakah ada yang mau bertaubat (sebelum terlambat)?\" setelah itu isterinya juga berdiri dan bersaksi. Maka ketika sampai pada (sumpah) yang kelima \"(bahwa la'nat Allah atasnya jika suaminya itu termasuk orang-orang yang benar).\" Para sahabat berkata, \"Ayat itu pasti akan mengenai wanita itu, ia wajib mendapatkan had.\" Ibnu Abbas berkata, \"Wanita itu ragu dan maju mundur hingga kami mengira seakan-akan ia akan kembali (taubat). Namun ia justru berkata, \"Sungguh kaumku tidak akan beruntung sepanjang hari.\" Setelah itu Nabi shallallahu 'alaihi wasallam bersabda: \"Lihatlah wanita itu, jika ia melahirkan anak yang bermata hitam, berpantat besar dan kedua betisnya juga besar, maka itu adalah anak Syarik bin Sahma.\" Dan wanita itu benar-benar melahirkan anak sebagaimana yang beliau sebutkan, maka Nabi shallallahu 'alaihi wasallam pun bersabda: \"Kalau bukan karena ketetapan yang telah tertera dalam Kitabullah, sungguh antara aku dengan dia pasti akan ada masalah.\""},"2023":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ خَلَّادٍ الْبَاهِلِيُّ وَإِسْحَقُ بْنُ إِبْرَاهِيمَ بْنِ حَبِيبٍ قَالَا حَدَّثَنَا عَبْدَةُ بْنُ سُلَيْمَانَ عَنْ الْأَعْمَشِ عَنْ إِبْرَاهِيمَ عَنْ عَلْقَمَةَ عَنْ عَبْدِ اللَّهِ قَالَكُنَّا فِي الْمَسْجِدِ لَيْلَةَ الْجُمُعَةِ فَقَالَ رَجُلٌ لَوْ أَنَّ رَجُلًا وَجَدَ مَعَ امْرَأَتِهِ رَجُلًا فَقَتَلَهُ قَتَلْتُمُوهُ وَإِنْ تَكَلَّمَ جَلَدْتُمُوهُ وَاللَّهِ لَأَذْكُرَنَّ ذَلِكَ لِلنَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَذَكَرَهُ لِلنَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَأَنْزَلَ اللَّهُ عَزَّ وَجَلَّ آيَاتِ اللِّعَانِ ثُمَّ جَاءَ الرَّجُلُ بَعْدَ ذَلِكَ يَقْذِفُ امْرَأَتَهُ فَلَاعَنَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بَيْنَهُمَا وَقَالَ عَسَى أَنْ تَجِيءَ بِهِ أَسْوَدَ فَجَاءَتْ بِهِ أَسْوَدَ جَعْدًا","id":"Telah menceritakan kepada kami [Abu Bakr bin Khallad Al Bahili] dan [Ishaq bin Ibrahim bin Habib] keduanya berkata; telah menceritakan kepada kami [Abdah bin Sulaiman] dari [Al A'masy] dari [Ibrahim] dari [Alqamah] dari [Abdullah] ia berkata, \"Ketika kami sedang berada di masjid pada malam jum'at, ada seseorang yang berkata, \"Kalau saja seorang suami mendapatkan seorang lelaki bersama isterinya, kemudian dia membunuhnya, kalian pasti akan balas membunuhnya. Dan jika ia berbicara, pasti kalian akan menderanya. Demi Allah, aku akan sampaikan hal itu kepada Nabi shallallahu 'alaihi wasallam.\" Maka ia pun menyampaikannya hal itu kepada Nabi shallallahu 'alaihi wasallam, hingga Allah 'azza wajalla menurunkan ayat-ayat li'an. Setelah kejadian itu, laki-laki tersebut kemudian menuduh isterinya, maka Nabi shallallahu 'alaihi wasallam memerintahkan agar keduanya saling bersumpah, beliau bersabda: \"Semoga dia melahirkan anak yang berkulit hitam.\" Dan benar saja, wanita tersebut melahirkan seorang anak yang berkulit hitam dan berambut keriting.\""},"2024":{"ar":"حَدَّثَنَا أَحْمَدُ بْنُ سِنَانٍ حَدَّثَنَا عَبْدُ الرَّحْمَنِ بْنُ مَهْدِيٍّ عَنْ مَالِكِ بْنِ أَنَسٍ عَنْ نَافِعٍ عَنْ ابْنِ عُمَرَأَنَّ رَجُلًا لَاعَنَ امْرَأَتَهُ وَانْتَفَى مِنْ وَلَدِهَا فَفَرَّقَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بَيْنَهُمَا وَأَلْحَقَ الْوَلَدَ بِالْمَرْأَةِ","id":"Telah menceritakan kepada kami [Ahmad bin Sinan] berkata, telah menceritakan kepada kami ['Abdurrahman bin Mahdi] dari [Malik bin Anas] dari [Nafi'] dari [Ibnu Umar] berkata, \"Seorang laki-laki menyumpahi isterinya dan tidak mengakui anak yang dilahirkannya. Rasulullah shallallahu 'alaihi wasallam kemudian memisahkan keduanya dan menasabkan anak tersebut kepada ibunya.\""},"2025":{"ar":"حَدَّثَنَا عَلِيُّ بْنُ سَلَمَةَ النَّيْسَابُورِيُّ حَدَّثَنَا يَعْقُوبُ بْنُ إِبْرَاهِيمَ بْنِ سَعْدٍ حَدَّثَنَا أَبِي عَنْ ابْنِ إِسْحَقَ قَالَ ذَكَرَ طَلْحَةُ بْنُ نَافِعٍ عَنْ سَعِيدِ بْنِ جُبَيْرٍ عَنْ ابْنِ عَبَّاسٍ قَالَتَزَوَّجَ رَجُلٌ مِنْ الْأَنْصَارِ امْرَأَةً مِنْ بَلْعِجْلَانَ فَدَخَلَ بِهَا فَبَاتَ عِنْدَهَا فَلَمَّا أَصْبَحَ قَالَ مَا وَجَدْتُهَا عَذْرَاءَ فَرُفِعَ شَأْنُهَا إِلَى النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَدَعَا الْجَارِيَةَ فَسَأَلَهَا فَقَالَتْ بَلَى قَدْ كُنْتُ عَذْرَاءَ فَأَمَرَ بِهِمَا فَتَلَاعَنَا وَأَعْطَاهَا الْمَهْرَ","id":"Telah menceritakan kepada kami [Ali bin Salamah An Naisaburi] berkata, telah menceritakan kepada kami [Ya'qub bin Ibrahim bin Sa'd] berkata, telah menceritakan kepada kami [Bapakku] dari [Ibnu Ishaq] ia berkata; [Thalhah bin Nafi'] menyebutkan dari [Sa'id bin Jubair] dari [Ibnu Abbas] ia berkata, \"Seorang laki-laki Anshar menikahi seorang wanita yang berasal dari Bal'ijlan, lalu ia masuk dan bermalam bersamanya. Ketika datang waktu pagi ia berkata, \"Aku tidak mendapatkan kegadisannya! \" hingga akhirnya, persoalan tersebut disampaikan kepada Nabi shallallahu 'alaihi wasallam. Beliau memanggil wanita tersebut dan menanyainya, wanita itu menjawab, \"Benar, aku masih dalam keadaan gadis.\" Maka beliau pun memerintahkan keduanya untuk saling bersumpah, dan beliau memberikan hak mahar kepadanya.\""},"2026":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ يَحْيَى حَدَّثَنَا حَيْوَةُ بْنُ شُرَيْحٍ الْحَضْرَمِيُّ عَنْ ضَمْرَةَ بْنِ رَبِيعَةَ عَنْ ابْنِ عَطَاءٍ عَنْ أَبِيهِ عَنْ عَمْرِو بْنِ شُعَيْبٍ عَنْ أَبِيهِ عَنْ جَدِّهِأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ أَرْبَعٌ مِنْ النِّسَاءِ لَا مُلَاعَنَةَ بَيْنَهُنَّ النَّصْرَانِيَّةُ تَحْتَ الْمُسْلِمِ وَالْيَهُودِيَّةُ تَحْتَ الْمُسْلِمِ وَالْحُرَّةُ تَحْتَ الْمَمْلُوكِ وَالْمَمْلُوكَةُ تَحْتَ الْحُرِّ","id":"Telah menceritakan kepada kami [Muhammad bin Yahya] berkata, telah menceritakan kepada kami [Haiwah bin Syuraih Al Hadlrami] dari [Dlamrah bin Rabi'ah] dari [Ibnu 'Atha] dari [Bapaknya] dari ['Amru bin Syu'aib] dari [Bapaknya] dari [Kakeknya] bahwa Nabi shallallahu 'alaihi wasallam bersabda: \"Ada empat orang dari kaum wanita yang li'an tidak berlaku bagi mereka; wanita Nasrani yang ada di bawah lelaki muslim, wanita Yahudi yang ada di bawah lelaki muslim, wanita merdeka yang ada di bawah seorang budak, dan budak wanita yang ada di bawah seorang lelaki merdeka.\""},"2027":{"ar":"حَدَّثَنَا الْحَسَنُ بْنُ قَزْعَةَ حَدَّثَنَا مَسْلَمَةُ بْنُ عَلْقَمَةَ حَدَّثَنَا دَاوُدُ بْنُ أَبِي هِنْدٍ عَنْ عَامِرٍ عَنْ مَسْرُوقٍ عَنْ عَائِشَةَ قَالَتْآلَى رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مِنْ نِسَائِهِ وَحَرَّمَ فَجَعَلَ الْحَلَالَ حَرَامًا وَجَعَلَ فِي الْيَمِينِ كَفَّارَةً","id":"Telah menceritakan kepada kami [Al Hasan bin Quz'ah] berkata, telah menceritakan kepada kami [Maslamah bin Alqamah] berkata, telah menceritakan kepada kami [Dawud bin Abu Hind] dari [Amir] dari [Masruq] dari ['Aisyah] ia berkata, \"Rasulullah shallallahu 'alaihi wasallam melakukan ilaa' terhada isteri-isterinya dan mengharamkan mereka. Beliau mengharamkan yang halal dan menjadikan kafarah di dalam yamin (sumpah).\""},"2028":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ يَحْيَى حَدَّثَنَا وَهْبُ بْنُ جَرِيرٍ حَدَّثَنَا هِشَامٌ الدَّسْتُوَائِيُّ عَنْ يَحْيَى بْنِ أَبِي كَثِيرٍ عَنْ يَعْلَى بْنِ حَكِيمٍ عَنْ سَعِيدِ بْنِ جُبَيْرٍ قَالَ قَالَ ابْنُ عَبَّاسٍفِي الْحَرَامِ يَمِينٌ وَكَانَ ابْنُ عَبَّاسٍ يَقُولُ{ لَقَدْ كَانَ لَكُمْ فِي رَسُولِ اللَّهِ أُسْوَةٌ حَسَنَةٌ }","id":"Telah menceritakan kepada kami [Muhammad bin Yahya] berkata, telah menceritakan kepada kami [Wahb bin Jarir] berkata, telah menceritakan kepada kami [Hisyam Ad Dastuwani] dari [Yahya bin Abu Katsir] dari [Ya'la bin Hakim] dari [Sa'id bin Jubair] ia berkata; [Ibnu Abbas] berkata, \"Di dalam perkara yang dilarang itu ada sumpah.\" Dan Ibnu Abbas berkata, \"Sungguh telah ada bagi kalian dalam diri Rasulullah suri tauladan yang baik.\""},"2029":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا حَفْصُ بْنُ غِيَاثٍ عَنْ الْأَعْمَشِ عَنْ إِبْرَاهِيمَ عَنْ الْأَسْوَدِ بْنِ يَزِيدَ عَنْ عَائِشَةَأَنَّهَا أَعْتَقَتْ بَرِيرَةَ فَخَيَّرَهَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَكَانَ لَهَا زَوْجٌ حُرٌّ","id":"Telah menceritakan kepada kami [Abu Bakr bin Abu Syaibah] berkata, telah menceritakan kepada kami [Hafsh bin Ghiyats] dari [Al A'masy] dari [Ibrahim] dari [Al Aswad bin Yazid] dari ['Aisyah] Bahwasanya ia telah memerdekakan Barirah, lalu Rasulullah shallallahu 'alaihi wasallam memberi pilihan kepadanya, dan ia memiliki seorang suami yang merdeka.\""},"2030":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ الْمُثَنَّى وَمُحَمَّدُ بْنُ خَلَّادٍ الْبَاهِلِيُّ قَالَا حَدَّثَنَا عَبْدُ الْوَهَّابِ الثَّقَفِيُّ حَدَّثَنَا خَالِدٌ الْحَذَّاءُ عَنْ عِكْرِمَةَ عَنْ ابْنِ عَبَّاسٍ قَالَكَانَ زَوْجُ بَرِيرَةَ عَبْدًا يُقَالُ لَهُ مُغِيثٌ كَأَنِّي أَنْظُرُ إِلَيْهِ يَطُوفُ خَلْفَهَا وَيَبْكِي وَدُمُوعُهُ تَسِيلُ عَلَى خَدِّهِ فَقَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لِلْعَبَّاسِ يَا عَبَّاسُ أَلَا تَعْجَبُ مِنْ حُبِّ مُغِيثٍ بَرِيرَةَ وَمِنْ بُغْضِ بَرِيرَةَ مُغِيثًا فَقَالَ لَهَا النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَوْ رَاجَعْتِيهِ فَإِنَّهُ أَبُو وَلَدِكِ قَالَتْ يَا رَسُولَ اللَّهِ تَأْمُرُنِي قَالَ إِنَّمَا أَشْفَعُ قَالَتْ لَا حَاجَةَ لِي فِيهِ","id":"Telah menceritakan kepada kami [Muhammad Ibnul Mutsanna] dan [Muhammad bin Khallad Al Bahili] keduanya berkata; telah menceritakan kepada kami [Abdul Wahhab Ats Tsaqafi] berkata, telah menceritakan kepada kami [Khalid Al Hadzdza] dari [Ikrimah] dari [Ibnu Abbas] ia berkata, \"Suami Barirah adalah seorang budak yang bernama Mughits, seakan-akan aku melihatnya berjalan di belakang Barirah sedang air matanya mengalir di pipinya. Nabi shallallahu 'alaihi wasallam lantas bersabda kepada Al Abbas: \"Wahai Abbas, tidakkah engkau taajub dengan cintanya Mughits kepada Barirah dan betapa bencinya Barirah kepada Mughits?\" Nabi shallallahu 'alaihi wasallam lalu bersabda kepada Barirah: \"Jika engkau mau kembali kepadanya, sungguh ia adalah bapak dari anakmu, \" Barirah menjawab, \"Wahai Rasulullah, apakah engkau memerintahkan kepadaku?\" beliau bersabda: \"Aku hanya menganjurkan.\" Barirah lalu berkata, \"Aku tidak butuh (dia).\""},"2031":{"ar":"حَدَّثَنَا عَلِيُّ بْنُ مُحَمَّدٍ حَدَّثَنَا وَكِيعٌ عَنْ أُسَامَةَ بْنِ زَيْدٍ عَنْ الْقَاسِمِ بْنِ مُحَمَّدٍ عَنْ عَائِشَةَ قَالَتْمَضَى فِي بَرِيرَةَ ثَلَاثُ سُنَنٍ خُيِّرَتْ حِينَ أُعْتِقَتْ وَكَانَ زَوْجُهَا مَمْلُوكًا وَكَانُوا يَتَصَدَّقُونَ عَلَيْهَا فَتُهْدِي إِلَى النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَيَقُولُ هُوَ عَلَيْهَا صَدَقَةٌ وَهُوَ لَنَا هَدِيَّةٌ وَقَالَ الْوَلَاءُ لِمَنْ أَعْتَقَ","id":"Telah menceritakan kepada kami [Ali bin Muhammad] berkata, telah menceritakan kepada kami [Waki'] dari [Usamah bin Yazid] dari [Al Qasim bin Muhammad] dari ['Aisyah] ia berkata, \"Telah berlalu bagi Barirah tiga kali haid, dan saat dimerdekakan ia diberi pilihan. Suaminya adalah seorang budak, orang-orang banyak memberi sedekah kepadanya, lalu ia hadiahkan sedekah tersebut kepada Nabi shallallahu 'alaihi wasallam. Beliau kemudian bersabda: \"Baginya adalah sedekah, dan bagi kita adalah hadiah.\" Beliau bersabda lagi: \"Loyalitas itu untuk yang memerdekakannya.\""},"2032":{"ar":"حَدَّثَنَا عَلِيُّ بْنُ مُحَمَّدٍ حَدَّثَنَا وَكِيعٌ عَنْ سُفْيَانَ عَنْ مَنْصُورٍ عَنْ إِبْرَاهِيمَ عَنْ الْأَسْوَدِ عَنْ عَائِشَةَ قَالَتْأُمِرَتْ بَرِيرَةُ أَنْ تَعْتَدَّ بِثَلَاثِ حِيَضٍ","id":"Telah menceritakan kepada kami [Ali bin Muhammad] berkata, telah menceritakan kepada kami [Waki'] dari [Sufyan] dari [Manshur] dari [Ibrahim] dari [Al Aswad] dari ['Aisyah] ia berkata, \"Barirah diperintah untuk menjalani masa iddah selama tiga kali haid.\""},"2033":{"ar":"حَدَّثَنَا إِسْمَعِيلُ بْنُ تَوْبَةَ حَدَّثَنَا عَبَّادُ بْنُ الْعَوَّامِ عَنْ يَحْيَى بْنِ أَبِي إِسْحَقَ عَنْ عَبْدِ الرَّحْمَنِ بْنِ أُذَيْنَةَ عَنْ أَبِي هُرَيْرَةَأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ خَيَّرَ بَرِيرَةَ","id":"Telah menceritakan kepada kami [Isma'il bin Taubah] berkata, telah menceritakan kepada kami ['Abbad bin Al 'Awwam] dari [Yahya bin Ishaq] dari ['Abdurrahman bin Udzainah] dari [Abu Hurairah] berkata, \"Rasulullah shallallahu 'alaihi wasallam memberi pilihan kepada Barirah.\""},"2034":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ طَرِيفٍ وَإِبْرَاهِيمُ بْنُ سَعِيدٍ الْجَوْهَرِيُّ قَالَا حَدَّثَنَا عُمَرُ بْنُ شَبِيبٍ الْمُسْلِيُّ عَنْ عَبْدِ اللَّهِ بْنِ عِيسَى عَنْ عَطِيَّةَ عَنْ ابْنِ عُمَرَ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ طَلَاقُ الْأَمَةِ اثْنَتَانِ وَعِدَّتُهَا حَيْضَتَانِ","id":"Telah menceritakan kepada kami [Muhammad bin Thuraif] dan [Ibrahim bin Sa'id Al Jauhari] keduanya berkata; telah menceritakan kepada kami [Umar bin Syabib Al Musli] dari [Abdullah bin Isa] dari ['Athiyyah] dari [Ibnu Umar] ia berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Talak bagi seorang budak wanita itu sebanyak dua kali, dan masa iddahnya adalah dua kali haid.\""},"2035":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ بَشَّارٍ حَدَّثَنَا أَبُو عَاصِمٍ حَدَّثَنَا ابْنُ جُرَيْجٍ عَنْ مُظَاهِرِ بْنِ أَسْلَمَ عَنْ الْقَاسِمِ عَنْ عَائِشَةَعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ طَلَاقُ الْأَمَةِ تَطْلِيقَتَانِ وَقُرْؤُهَا حَيْضَتَانِ","id":"Telah menceritakan kepada kami [Muhammad bin Basysyar] berkata, telah menceritakan kepada kami [Abu 'Ashim] berkata, telah menceritakan kepada kami [Ibnu Juraij] dari [Mudzahir bin Aslam] dari [Al Qasim] dari ['Aisyah] dari Nabi shallallahu 'alaihi wasallam, beliau bersabda: \"Talaknya seorang budak perempuan itu dua kali, dan masa tunggunya adalah dua kali haid.\""},"2036":{"ar":"قَالَ أَبُو عَاصِمٍ فَذَكَرْتُهُ لِمُظَاهِرٍ فَقُلْتُ حَدِّثْنِي كَمَا حَدَّثْتَ ابْنَ جُرَيْجٍ فَأَخْبَرَنِي عَنْ الْقَاسِمِ عَنْ عَائِشَةَعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ طَلَاقُ الْأَمَةِ تَطْلِيقَتَانِ وَقُرْؤُهَا حَيْضَتَانِ","id":"[Abu Ashim] berkata, \"Lalu aku sebutkan hal itu kepada [Muzhahir] -aku berkata; \"Ceritakanlah kepadaku sebagaimana engkau ceritakan kepada Ibnu Juraij-, lalu ia pun mengabarkan kepadaku, dari [Al Qasim] dari ['Aisyah] dari Nabi shallallahu 'alaihi wasallam, beliau bersabda: \"Talaknya seorang budak perempuan itu dua kali, dan masa tungguhnya adalah dua kali haid.\""},"2037":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ يَحْيَى حَدَّثَنَا يَحْيَى بْنُ عَبْدِ اللَّهِ بْنِ بُكَيْرٍ حَدَّثَنَا ابْنُ لَهِيعَةَ عَنْ مُوسَى بْنِ أَيُّوبَ الْغَافِقِيِّ عَنْ عِكْرِمَةَ عَنْ ابْنِ عَبَّاسٍ قَالَأَتَى النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ رَجُلٌ فَقَالَ يَا رَسُولَ اللَّهِ إِنَّ سَيِّدِي زَوَّجَنِي أَمَتَهُ وَهُوَ يُرِيدُ أَنْ يُفَرِّقَ بَيْنِي وَبَيْنَهَا قَالَ فَصَعِدَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ الْمِنْبَرَ فَقَالَ يَا أَيُّهَا النَّاسُ مَا بَالُ أَحَدِكُمْ يُزَوِّجُ عَبْدَهُ أَمَتَهُ ثُمَّ يُرِيدُ أَنْ يُفَرِّقَ بَيْنَهُمَا إِنَّمَا الطَّلَاقُ لِمَنْ أَخَذَ بِالسَّاقِ","id":"Telah menceritakan kepada kami [Muhammad bin Yahya] berkata, telah menceritakan kepada kami [Yahya bin Abdullah bin Bukair] berkata, telah menceritakan kepada kami [Ibnu Lahi'ah] dari [Musa bin Ayyub Al Ghafiqi] dari [Ikrimah] dari [Ibnu Abbas] ia berkata, \"Seorang lelaki datang menemui Nabi shallallahu 'alaihi wasallam dan berkata, \"Wahai Rasulullah, sesungguhnya tuanku mengawinkan aku dengan budak perempuannya, lalu ia ingin memisahkan aku dari dia.\" Ibnu Abbas berkata, \"Rasulullah shallallahu 'alaihi wasallam kemudian naik ke mimbar dan bersabda: \"Wahai manusia, kenapa salah seorang dari kalian menikahkan budaknya dengan budak perempuannya, kemudian dia ingin memisahkan keduanya?! Hanyasanya talak itu hak bagi orang yang memegang betis.\""},"2038":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ عَبْدِ الْمَلِكِ بْنِ زَنْجَوَيْهِ أَبُو بَكْرٍ حَدَّثَنَا عَبْدُ الرَّزَّاقِ حَدَّثَنَا مَعْمَرٌ عَنْ يَحْيَى بْنِ أَبِي كَثِيرٍ عَنْ عُمَرَ بْنِ مُعَتِّبٍ عَنْ أَبِي الْحَسَنِ مَوْلَى بَنِي نَوْفَلٍ قَالَسُئِلَ ابْنُ عَبَّاسٍ عَنْ عَبْدٍ طَلَّقَ امْرَأَتَهُ تَطْلِيقَتَيْنِ ثُمَّ أُعْتِقَا يَتَزَوَّجُهَا قَالَ نَعَمْ فَقِيلَ لَهُ عَمَّنْ قَالَ قَضَى بِذَلِكَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَقَالَ عَبْدُ الرَّزَّاقِ قَالَ عَبْدُ اللَّهِ بْنُ الْمُبَارَكِ لَقَدْ تَحَمَّلَ أَبُو الْحَسَنِ هَذَا صَخْرَةً عَظِيمَةً عَلَى عُنُقِهِ","id":"Telah menceritakan kepada kami [Muhammad bin Abdul Malik bin Zanjawaih Abu Bakr] berkata, telah menceritakan kepada kami ['Abdurrazaq] berkata, telah menceritakan kepada kami [Ma'mar] dari [Yahya bin Abu Katsir] dari [Umar bin Mu'attib] dari [Abul Hasan Maula Bani Naufal] ia berkata, \" [Ibnu Abbas] ditanya tentang seorang budak yang telah mentalak isterinya dengan dua talak kemudian keduanya dimerdekakan, maka apakah ia boleh menikahinya lagi?\" Ibnu Abbas menjawab, \"Ya, boleh.\" Ibnu Abbas ditanya lagi, \"Sumbernya dari siapa?\" ia menjawab, \"Demikianlah Rasulullah shallallahu 'alaihi wasallam memutuskan perkara seperti in.\" 'Abdurrazaq berkata; Abdullah bin Mubarak berkata, \"Sungguh Abul Hasan telah mampu memikul batu besar ini di atas pundaknya.\""},"2039":{"ar":"حَدَّثَنَا عَلِيُّ بْنُ مُحَمَّدٍ حَدَّثَنَا وَكِيعٌ عَنْ سَعِيدِ بْنِ أَبِي عَرُوبَةَ عَنْ مَطَرٍ الْوَرَّاقِ عَنْ رَجَاءِ بْنِ حَيْوَةَ عَنْ قَبِيصَةَ بْنِ ذُؤَيْبٍ عَنْ عَمْرِو بْنِ الْعَاصِ قَالَلَا تُفْسِدُوا عَلَيْنَا سُنَّةَ نَبِيِّنَا مُحَمَّدٍ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عِدَّةُ أُمِّ الْوَلَدِ أَرْبَعَةُ أَشْهُرٍ وَعَشْرًا","id":"Telah menceritakan kepada kami [Ali bin Muhammad] berkata, telah menceritakan kepada kami [Waki'] dari [Sa'id bin Abu 'Arubah] dari [Mathar Al Warraq] dari [Raja bin Haiwah] dari [Qabishah bin Dzu`aib] dari [Amru bin 'Ash] ia berkata, \"Janganlah kalian merusak sunnah Nabi kami, Muhammad shallallahu 'alaihi wasallam. Masa Iddah ummul walad adalah empat bulan sepuluh hari.\" "},"2040":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا يَزِيدُ بْنُ هَارُونَ أَنْبَأَنَا يَحْيَى بْنُ سَعِيدٍ عَنْ حُمَيْدِ بْنِ نَافِعٍ أَنَّهُ سَمِعَ زَيْنَبَ ابْنَةَ أُمِّ سَلَمَةَ تُحَدِّثُ أَنَّهَا سَمِعَتْ أُمَّ سَلَمَةَ وَأُمَّ حَبِيبَةَ تَذْكُرَانِأَنَّ امْرَأَةً أَتَتْ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَتْ إِنَّ ابْنَةً لَهَا تُوُفِّيَ عَنْهَا زَوْجُهَا فَاشْتَكَتْ عَيْنُهَا فَهِيَ تُرِيدُ أَنْ تَكْحَلَهَا فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَدْ كَانَتْ إِحْدَاكُنَّ تَرْمِي بِالْبَعْرَةِ عِنْدَ رَأْسِ الْحَوْلِ وَإِنَّمَا هِيَ أَرْبَعَةَ أَشْهُرٍ وَعَشْرًا","id":"Telah menceritakan kepada kami [Abu Bakr bin Abu Syaibah] berkata, telah menceritakan kepada kami [Yazid bin harun] berkata, telah memberitakan kepada kami [Yahya bin Sa'id] dari [Humaid bin Nafi'] Bahwasanya ia mendengar [Zainab bintu Ummu Salamah] menceritakan bahwa ia mendengar [Ummu Salamah] dan [Ummu Habibah] menyebutkan, bahwa ada seorang wanita mendatangi Nabi shallallahu 'alaihi wasallam dan mengatakan bahwa suami anak perempuannya telah meninggal, lalu anaknya merasakan sakit pada matanya, hingga ia (ibu) ingin memberikan celak. Maka Rasulullah shallallahu 'alaihi wasallam pun bersabda: \"Sungguh, tradisi kalian dahulu menyudahi masa iddahnya dengan cara melempar kotoran unta (setelah masa iddah genap satu tahun), padahal masa iddahnya hanyalah empat bulan sepuluh hari.\""},"2041":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا سُفْيَانُ بْنُ عُيَيْنَةَ عَنْ الزُّهْرِيِّ عَنْ عُرْوَةَ عَنْ عَائِشَةَعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ لَا يَحِلُّ لِامْرَأَةٍ أَنْ تُحِدَّ عَلَى مَيِّتٍ فَوْقَ ثَلَاثٍ إِلَّا عَلَى زَوْجٍ","id":"Telah menceritakan kepada kami [Abu Bakr bin Abu Syaibah] berkata, telah menceritakan kepada kami [Sufyan bin Uyainah] dari [Az Zuhri] dari [Urwah] dari ['Aisyah] dari Nabi shallallahu 'alaihi wasallam, beliau bersabda: \"Tidak halal bagi seorang wanita melakukan ihdad (tidak berhias dan memakai wewangian) atas mayat lebih dari tiga hari, kecuali untuk suaminya.\""},"2042":{"ar":"حَدَّثَنَا هَنَّادُ بْنُ السَّرِيِّ حَدَّثَنَا أَبُو الْأَحْوَصِ عَنْ يَحْيَى بْنِ سَعِيدٍ عَنْ نَافِعٍ عَنْ صَفِيَّةَ بِنْتِ أَبِي عُبَيْدٍ عَنْ حَفْصَةَ زَوْجِ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَتْقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَا يَحِلُّ لِامْرَأَةٍ تُؤْمِنُ بِاللَّهِ وَالْيَوْمِ الْآخِرِ أَنْ تُحِدَّ عَلَى مَيِّتٍ فَوْقَ ثَلَاثٍ إِلَّا عَلَى زَوْجٍ","id":"Telah menceritakan kepada kami [Hannad bin As Sari] berkata, telah menceritakan kepada kami [Abu Al Ahwash] dari [Yahya bin Sa'id] dari [Nafi'] dari [Shafiah binti Abu Ubaid] dari [Hafshah] -isteri Nabi shallallahu 'alaihi wasallam- ia berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Tidak halal bagi seorang wanita yang beriman kepada Allah dan hari akhir melakukan ihdad (tidak berhias dan memakai wewangian) atas mayat lebih dari tiga hari, kecuali untuk suaminya.\""},"2043":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا عَبْدُ اللَّهِ بْنُ نُمَيْرٍ عَنْ هِشَامِ بْنِ حَسَّانَ عَنْ حَفْصَةَ عَنْ أُمِّ عَطِيَّةَ قَالَتْقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَا تُحِدُّ عَلَى مَيِّتٍ فَوْقَ ثَلَاثٍ إِلَّا امْرَأَةٌ تُحِدُّ عَلَى زَوْجِهَا أَرْبَعَةَ أَشْهُرٍ وَعَشْرًا وَلَا تَلْبَسُ ثَوْبًا مَصْبُوغًا إِلَّا ثَوْبَ عَصْبٍ وَلَا تَكْتَحِلُ وَلَا تَطَيَّبُ إِلَّا عِنْدَ أَدْنَى طُهْرِهَا بِنُبْذَةٍ مِنْ قُسْطٍ أَوْ أَظْفَارٍ","id":"Telah menceritakan kepada kami [Abu Bakr bin Abu Syaibah] berkata, telah menceritakan kepada kami [Abdullah bin Numair] dari [Hisyam bin Hassan] dari [Hafshah] dari [Ummu Athiah] ia berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"(Seorang wanita) tidak boleh melakukan ihdad (tidak berhias dan memakai wewangian) atas mayit lebih dari tiga hari, kecuali seorang wanita untuk suaminya, empat bulan sepuluh hari. Tidak boleh memakai kain yang dicelup selain kain kecuali kain Ashb (kain yang telah dicelup sebelum ditenun). Tidak boleh bercelak dan memakai wewangian kecuali setelah sucinya sedikit qusth (kayu wangi), atau azhfar (wewangian dari Yaman).\""},"2044":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ بَشَّارٍ حَدَّثَنَا يَحْيَى بْنُ سَعِيدٍ الْقَطَّانُ وَعُثْمَانُ بْنُ عُمَرَ قَالَا حَدَّثَنَا ابْنُ أَبِي ذِئْبٍ عَنْ خَالِهِ الْحَارِثِ بْنِ عَبْدِ الرَّحْمَنِ عَنْ حَمْزَةَ بْنِ عَبْدِ اللَّهِ بْنِ عُمَرَ عَنْ عَبْدِ اللَّهِ بْنِ عُمَرَ قَالَكَانَتْ تَحْتِي امْرَأَةٌ وَكُنْتُ أُحِبُّهَا وَكَانَ أَبِي يُبْغِضُهَا فَذَكَرَ ذَلِكَ عُمَرُ لِلنَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَأَمَرَنِي أَنْ أُطَلِّقَهَا فَطَلَّقْتُهَا","id":"Telah menceritakan kepada kami [Muhammad bin Basysyar] berkata, telah menceritakan kepada kami [Yahya bin Sa'id Al Qaththan] dan [Utsman bin Umar] keduanya berkata; telah menceritakan kepada kami [Ibnu Abu Dzi`b] dari pamannya [Al Harits bin 'Abdurrahman] dari [Hamzah bin Abdullah bin Umar] dari [Abdullah bin Umar] ia berkata, \"Aku memiliki seorang isteri yang aku sukai, namun ayahku tidak menyukainya.\" Lalu Umar menyampaikan hal itu kepada Nabi shallallahu 'alaihi wasallam hingga beliau memerintahkanku untuk menceraikannya, maka aku pun menceraikannya.\""},"2045":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ بَشَّارٍ حَدَّثَنَا مُحَمَّدُ بْنُ جَعْفَرٍ حَدَّثَنَا شُعْبَةُ عَنْ عَطَاءِ بْنِ السَّائِبِ عَنْ أَبِي عَبْدِ الرَّحْمَنِأَنَّ رَجُلًا أَمَرَهُ أَبُوهُ أَوْ أُمُّهُ شَكَّ شُعْبَةُ أَنْ يُطَلِّقَ امْرَأَتَهُ فَجَعَلَ عَلَيْهِ مِائَةَ مُحَرَّرٍ فَأَتَى أَبَا الدَّرْدَاءِ فَإِذَا هُوَ يُصَلِّي الضُّحَى وَيُطِيلُهَا وَصَلَّى مَا بَيْنَ الظُّهْرِ وَالْعَصْرِ فَسَأَلَهُ فَقَالَ أَبُو الدَّرْدَاءِ أَوْفِ بِنَذْرِكَ وَبِرَّ وَالِدَيْكَ وَقَالَ أَبُو الدَّرْدَاءِ سَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ الْوَالِدُ أَوْسَطُ أَبْوَابِ الْجَنَّةِ فَحَافِظْ عَلَى وَالِدَيْكَ أَوْ اتْرُكْ","id":"Telah menceritakan kepada kami [Muhammad bin Basysyar] berkata, telah menceritakan kepada kami [Muhammad bin Ja'far] berkata, telah menceritakan kepada kami [Syu'bah] dari ['Atha bin As Sa`ib] dari [Abu 'Abdurrahman] berkata, \"Seorang laki-laki disuruh ayah atau ibunya -Syu'bah merasa ragu- untuk menceraikan isterinya dan ia akan diganti dengan seratus budak. Maka ia mendatangi Abu Darda yang waktu itu sedang melaksanakan shalat dluha, dan ia memperpanjang ahalatnya. Ketika Abu Darda shalat antara zhuhur dan asar, barulah ia menanyakan hal tersebut. [Abu Darda] menjawab: \"Tepati nadzarmu dan berbuat baiklah kepada kedua orang tuamu. Karena aku mendengar Rasulullah shallallahu 'alaihi wasallam bersabda: \"Orang tua akan berada di tengah-tengah pintu surga, maka jagalah kedua orang tuamu atau justru kamu meninggalkannya.\""},"2046":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا مُحَمَّدُ بْنُ مُصْعَبٍ عَنْ الْأَوْزَاعِيِّ عَنْ يَحْيَى بْنِ أَبِي كَثِيرٍ عَنْ هِلَالِ بْنِ أَبِي مَيْمُونَةَ عَنْ عَطَاءِ بْنِ يَسَارٍ عَنْ رِفَاعَةَ الْجُهَنِيِّ قَالَكَانَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِذَا حَلَفَ قَالَ وَالَّذِي نَفْسُ مُحَمَّدٍ بِيَدِهِ","id":"Telah menceritakan kepada kami [Abu Bakr bin Abu Syaibah] berkata, telah menceritakan kepada kami [Muhammad bin Mush'ab] dari [Al Auza'i] dari [Yahya bin Abu Katsir] dari [Hilal bin Abu Maimunah] dari [Atha bin Yasar] dari [Rifa'ah Al Juhani] ia berkata, \"Jika Nabi shallallahu 'alaihi wasallam bersumpah beliau mengatakan: \"Demi Dzat yang jiwa Muhammad ada dalam tangan-Nya.\""},"2047":{"ar":"حَدَّثَنَا هِشَامُ بْنُ عَمَّارٍ حَدَّثَنَا عَبْدُ الْمَلِكِ بْنُ مُحَمَّدٍ الصَّنْعَانِيُّ حَدَّثَنَا الْأَوْزَاعِيُّ عَنْ يَحْيَى بْنِ أَبِي كَثِيرٍ عَنْ هِلَالِ بْنِ أَبِي مَيْمُونَةَ عَنْ عَطَاءِ بْنِ يَسَارٍ عَنْ رِفَاعَةَ بْنِ عَرَابَةَ الْجُهَنِيِّ قَالَكَانَتْ يَمِينُ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ الَّتِي يَحْلِفُ بِهَا أَشْهَدُ عِنْدَ اللَّهِ وَالَّذِي نَفْسِي بِيَدِهِ","id":"Telah menceritakan kepada kami [Hisyam bin Ammar] berkata, telah menceritakan kepada kami [Abdul Malik bin Muhammad bin Ash Shan'ani] berkata, telah menceritakan kepada kami [Al Auza'i] dari [Yahya bin Abu Katsir] dari [Hilal bin Abu Maimunah] dari ['Atha bin Yasar] dari [Rifa'ah bin Arabah Al Juhani] ia berkata, \"Sumpah yang biasa dipakai oleh Rasulullah shallallahu 'alaihi wasallam dan berarti di sisi Allah adalah: \"Demi Dzat yang jiwaku ada dalam tangan-Nya.\""},"2048":{"ar":"حَدَّثَنَا أَبُو إِسْحَقَ الشَّافِعِيُّ إِبْرَاهِيمُ بْنُ مُحَمَّدِ بْنِ الْعَبَّاسِ حَدَّثَنَا عَبْدُ اللَّهِ بْنُ رَجَاءٍ الْمَكِّيُّ عَنْ عَبَّادِ بْنِ إِسْحَقَ عَنْ ابْنِ شِهَابٍ عَنْ سَالِمٍ عَنْ أَبِيهِ قَالَ كَانَتْأَكْثَرُ أَيْمَانِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَا وَمُصَرِّفِ الْقُلُوبِ","id":"Telah menceritakan kepada kami [Abu Ishaq Asy Syafi'I Ibrahim bin Muhammad Ibnul Abbas] berkata, telah menceritakan kepada kami [Abdullah bin Raja Al Makki] dari [Abbad bin Ishaq] dari [Ibnu Syihab] dari [Salim] dari [Bapaknya] ia berkata, \"Kebanyakan sumpah yang dipakai oleh Rasulullah shallallahu 'alaihi wasallam adalah: \"Tidak, dan demi Dzat yang membolak-balikkan hati.\""},"2049":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا حَمَّادُ بْنُ خَالِدٍ ح و حَدَّثَنَا يَعْقُوبُ بْنُ حُمَيْدِ بْنِ كَاسِبٍ حَدَّثَنَا مَعْنُ بْنُ عِيسَى جَمِيعًا عَنْ مُحَمَّدِ بْنِ هِلَالٍ عَنْ أَبِيهِ عَنْ أَبِي هُرَيْرَةَقَالَ كَانَتْ يَمِينُ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَا وَأَسْتَغْفِرُ اللَّهَ","id":"Telah menceritakan kepada kami [Abu Bakr bin Abu Syaibah] berkata, telah menceritakan kepada kami [Hammad bin Khalid]. (dalam jalur lain disebutkan) Telah menceritakan kepada kami [Ya'qub bin Humaid bin Kasib] berkata, telah menceritakan kepada kami [Ma'an bin Isa] semuanya dari [Muhammad bin Hilal] dari [Bapaknya] dari [Abu Hurairah] ia berkata, \"Kebanyakan sumpah yang dipakai oleh Rasulullah shallallahu 'alaihi wasallam adalah: \"Tidak, dan aku meminta ampunan Allah.\""},"2050":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ أَبِي عُمَرَ الْعَدَنِيُّ حَدَّثَنَا سُفْيَانُ بْنُ عُيَيْنَةَ عَنْ الزُّهْرِيِّ عَنْ سَالِمِ بْنِ عَبْدِ اللَّهِ بْنِ عُمَرَ عَنْ أَبِيهِ عَنْ عُمَرَأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ سَمِعَهُ يَحْلِفُ بِأَبِيهِ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِنَّ اللَّهَ يَنْهَاكُمْ أَنْ تَحْلِفُوا بِآبَائِكُمْقَالَ عُمَرُ فَمَا حَلَفْتُ بِهَا ذَاكِرًا وَلَا آثِرًا","id":"Telah menceritakan kepada kami [Muhammad bin Abu Umar Al Adani] berkata, telah menceritakan kepada kami [Sufyan bin Uyainah] dari [Az Zuhri] dari [Salim bin Abdullah bin Umar] dari [Bapaknya] dari [Umar] bahwa Rasulullah shallallahu 'alaihi wasallam mendengarnya bersumpah dengan nama bapaknya, maka Rasulullah shallallahu 'alaihi wasallam pun bersabda: \"Sesungguhnya Allah melarang kalian untuk bersumpah dengan bapak-bapak kalian.\" Umar berkata, \"Maka aku tidak lagi bersumpah baik sumpah itu dariku atau dari orang lain (yang aku tirukan).\""},"2051":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا عَبْدُ الْأَعْلَى عَنْ هِشَامٍ عَنْ الْحَسَنِ عَنْ عَبْدِ الرَّحْمَنِ بْنِ سَمُرَةَ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَا تَحْلِفُوا بِالطَّوَاغِي وَلَا بِآبَائِكُمْ","id":"Telah menceritakan kepada kami [Abu Bakr bin Abu Syaibah] berkata, telah menceritakan kepada kami [Abdul A'la] dari [Hisyam] dari [Al Hasan] dari ['Abdurrahman bin Samurah] ia berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Janganlah kalian bersumpah dengan para thaghut atau dengan dan bapak-bapak kalian.\""},"2052":{"ar":"حَدَّثَنَا عَبْدُ الرَّحْمَنِ بْنُ إِبْرَاهِيمَ الدِّمَشْقِيُّ حَدَّثَنَا عُمَرُ بْنُ عَبْدِ الْوَاحِدِ عَنْ الْأَوْزَاعِيِّ عَنْ الزُّهْرِيِّ عَنْ حُمَيْدٍ عَنْ أَبِي هُرَيْرَةَأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ مَنْ حَلَفَ فَقَالَ فِي يَمِينِهِ بِاللَّاتِ وَالْعُزَّى فَلْيَقُلْ لَا إِلَهَ إِلَّا اللَّهُ","id":"Telah menceritakan kepada kami ['Abdurrahman bin Ibrahim Ad Dimasyqi] berkata, telah menceritakan kepada kami [Umar bin Abdul Wahid] dari [Al Auza'i] dari [Az Zuhri] dari [Humaid] dari [Abu Hurairah] bahwa Rasulullah shallallahu 'alaihi wasallam bersabda: \"Barangsiapa bersumpah, lalu dalam sumpahnya ia mengatakan dengan Lata dan Uzza, maka hendaklah ia mengatakan dengan LAA ILAAHA ILLA ALLAHU (Tidak ada Tuhan yang berhak untuk disembah selain Allah).\""},"2053":{"ar":"حَدَّثَنَا عَلِيُّ بْنُ مُحَمَّدٍ وَالْحَسَنُ بْنُ عَلِيٍّ الْخَلَّالُ قَالَا حَدَّثَنَا يَحْيَى بْنُ آدَمَ عَنْ إِسْرَائِيلَ عَنْ أَبِي إِسْحَقَ عَنْ مُصْعَبِ بْنِ سَعْدٍ عَنْ سَعْدٍ قَالَحَلَفْتُ بِاللَّاتِ وَالْعُزَّى فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قُلْ لَا إِلَهَ إِلَّا اللَّهُ وَحْدَهُ لَا شَرِيكَ لَهُ ثُمَّ انْفُثْ عَنْ يَسَارِكَ ثَلَاثًا وَتَعَوَّذْ وَلَا تَعُدْ","id":"Telah menceritakan kepada kami [Ali bin Muhammad] dan [Al Hasan bin Ali Al Khallal] keduanya berkata; telah menceritakan kepada kami [Yahya bin Adam] dari [Isra`il] dari [Abu Ishaq] dari [Mush'ab bin Sa'd] dari [Sa'd] ia berkata, \"Aku telah bersumpah dengan nama lata dan uzza! \" Maka Rasulullah shallallahu 'alaihi wasallam bersabda: \"Ucapkanlah, 'Tidak ada Tuhan yang berhak di sembah selain Allah, yang tidak ada sekutu bagi-Nya'. Kemudian tiupkan ke sebelah kirimu tiga kali, dan berlindunglah serta jangan kamu ulangi.\""},"2054":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ الْمُثَنَّى حَدَّثَنَا ابْنُ أَبِي عَدِيٍّ عَنْ خَالِدٍ الْحَذَّاءِ عَنْ أَبِي قِلَابَةَ عَنْ ثَابِتِ بْنِ الضَّحَّاكِ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَنْ حَلَفَ بِمِلَّةٍ سِوَى الْإِسْلَامِ كَاذِبًا مُتَعَمِّدًا فَهُوَ كَمَا قَالَ","id":"Telah menceritakan kepada kami [Muhammad bin Al Mutsanna] telah menceritakan kepada kami [Ibnu Abu Adi] dari [Khalid Al Khaddza`] dari [Abu Qilabah] dari [Tsabit Adl Dlahhak] dia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Barangsiapa bersumpah dengan selain agama Islam dengan sengaja berdusta, maka ia seperti yang telah dikatakannya.\""},"2055":{"ar":"حَدَّثَنَا هِشَامُ بْنُ عَمَّارٍ حَدَّثَنَا بَقِيَّةُ عَنْ عَبْدِ اللَّهِ بْنِ مُحَرَّرٍ عَنْ قَتَادَةَ عَنْ أَنَسٍ قَالَسَمِعَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ رَجُلًا يَقُولُ أَنَا إِذًا لَيَهُودِيٌّ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَجَبَتْ","id":"Telah menceritakan kepada kami [Hisyam bin Ammar] berkata, telah menceritakan kepada kami [Baqiyyah] dari [Abdullah bin Muharrar] dari [Qatadah] dari [Anas] berkata, \"Nabi shallallahu 'alaihi wasallam mendengar seorang laki-laki berkata, \"Kalau begitu aku menjadi orang Yahudi saja.\" Maka Nabi shallallahu 'alaihi wasallam pun bersabda: \"Ia telah menjadi Yahudi.\""},"2056":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ إِسْمَعِيلَ بْنِ سَمُرَةَ حَدَّثَنَا عَمْرُو بْنُ رَافِعٍ الْبَجَلِيُّ حَدَّثَنَا الْفَضْلُ بْنُ مُوسَى عَنْ الْحُسَيْنِ بْنِ وَاقِدٍ عَنْ عَبْدِ اللَّهِ بْنِ بُرَيْدَةَ عَنْ أَبِيهِ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَنْ قَالَ إِنِّي بَرِيءٌ مِنْ الْإِسْلَامِ فَإِنْ كَانَ كَاذِبًا فَهُوَ كَمَا قَالَ وَإِنْ كَانَ صَادِقًا لَمْ يَعُدْ إِلَى الْإِسْلَامِ سَالِمًا","id":"Telah menceritakan kepada kami [Muhammad bin Isma'il bin Samurah] berkata, telah menceritakan kepada kami [Amru bin Rafi' Al Bajali] berkata, telah menceritakan kepada kami [Al Fadll bin Musa] dari [Al Husain bin Waqid] dari [Abdullah bin Buraidah] dari [Bapaknya] ia berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Barangsiapa mengatakan 'aku berlepas diri dari Islam', jika ia mengucapkan hal dengan berbohong, maka hukumnya sebagaimana yang ia ucapkan, namun jika benar maka ia tidak akan kembali ke dalam Islam dengan selamat.\""},"2057":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ إِسْمَعِيلَ بْنِ سَمُرَةَ حَدَّثَنَا أَسْبَاطُ بْنُ مُحَمَّدٍ عَنْ مُحَمَّدِ بْنِ عَجْلَانَ عَنْ نَافِعٍ عَنْ ابْنِ عُمَرَ قَالَسَمِعَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ رَجُلًا يَحْلِفُ بِأَبِيهِ فَقَالَ لَا تَحْلِفُوا بِآبَائِكُمْ مَنْ حَلَفَ بِاللَّهِ فَلْيَصْدُقْ وَمَنْ حُلِفَ لَهُ بِاللَّهِ فَلْيَرْضَ وَمَنْ لَمْ يَرْضَ بِاللَّهِ فَلَيْسَ مِنْ اللَّهِ","id":"Telah menceritakan kepada kami [Muhammad bin Isma'il bin Samurah] berkata, telah menceritakan kepada kami [Asbath bin Muhammad] dari [Muhammad bin 'Ajlan] dari [Nafi'] dari [Ibnu Umar] ia berkata, \"Nabi shallallahu 'alaihi wasallam mendengar seorang laki-laki bersumpah dengan bapaknya, maka beliau bersabda: \"Janganlah kalian bersumpah dengan bapak-bapak kalian. Barangsiapa bersumpah dengan Allah maka percayailah, dan barangsiapa disumpai dengan nama Allah hendaklah ia ridla, maka barangsiapa tidak ridla dengan Allah dia bukan dari golongan kami.\""},"2058":{"ar":"حَدَّثَنَا يَعْقُوبُ بْنُ حُمَيْدِ بْنِ كَاسِبٍ حَدَّثَنَا حَاتِمُ بْنُ إِسْمَعِيلَ عَنْ أَبِي بَكْرِ بْنِ يَحْيَى بْنِ النَّضْرِ عَنْ أَبِيهِ عَنْ أَبِي هُرَيْرَةَأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ رَأَى عِيسَى ابْنُ مَرْيَمَ رَجُلًا يَسْرِقُ فَقَالَ أَسَرَقْتَ فَقَالَ لَا وَالَّذِي لَا إِلَهَ إِلَّا هُوَ فَقَالَ عِيسَى آمَنْتُ بِاللَّهِ وَكَذَّبْتُ بَصَرِي","id":"Telah menceritakan kepada kami [Ya'qub bin Humaid bin Kasib] berkata, telah menceritakan kepada kami [Hatim bin Isma'il] dari [Abu Bakr bin Yahya bin An Nadlr] dari [Bapaknya] dari [Abu Hurairah] berkata, \"Nabi shallallahu 'alaihi wasallam bersabda: \"Isa bin Maryam melihat seorang laki-laki mencuri, ia pun berkata, \"Apakah engkau mencuri?\" laki-laki itu berkata, \"Tidak, Dzat yang tidak ada Tuhan selain Dia! \" Isa lalu berkata, \"Aku beriman dengan Allah dan mendustai penglihatanku.\""},"2059":{"ar":"حَدَّثَنَا عَلِيُّ بْنُ مُحَمَّدٍ حَدَّثَنَا أَبُو مُعَاوِيَةَ عَنْ بَشَّارِ بْنِ كِدَامٍ عَنْ مُحَمَّدِ بْنِ زَيْدٍ عَنْ ابْنِ عُمَرَ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِنَّمَا الْحَلِفُ حِنْثٌ أَوْ نَدَمٌ","id":"Telah menceritakan kepada kami [Ali bin Muhammad] berkata, telah menceritakan kepada kami [Abu Mu'awiyah] dari [Basysyar bin Kidam] dari [Muhammad bin Zaid] dari [Ibnu Umar] ia berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Hanyasanaya sumpah itu adalah dosa atau penyesalan.\""},"2060":{"ar":"حَدَّثَنَا الْعَبَّاسُ بْنُ عَبْدِ الْعَظِيمِ الْعَنْبَرِيُّ حَدَّثَنَا عَبْدُ الرَّزَّاقِ أَنْبَأَنَا مَعْمَرٌ عَنْ ابْنِ طَاوُسٍ عَنْ أَبِيهِ عَنْ أَبِي هُرَيْرَةَ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَنْ حَلَفَ فَقَالَ إِنْ شَاءَ اللَّهُ فَلَهُ ثُنْيَاهُ","id":"Telah menceritakan kepada kami [Al Abbas bin Abdul Azhim Al Anbari] berkata, telah menceritakan kepada kami ['Abdurrazaq] berkata, telah memberitakan kepada kami [Ma'mar] dari [Thawus] dari [Bapaknya] dari [Abu Hurairah] ia berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Barangsiapa bersumpah lantas mengucapkan 'Jika Allah menghendaki', maka baginya adalah sesuatu yang dikecualikan.\""},"2061":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ زِيَادٍ حَدَّثَنَا عَبْدُ الْوَارِثِ بْنُ سَعِيدٍ عَنْ أَيُّوبَ عَنْ نَافِعٍ عَنْ ابْنِ عُمَرَ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَنْ حَلَفَ وَاسْتَثْنَى إِنْ شَاءَ رَجَعَ وَإِنْ شَاءَ تَرَكَ غَيْرُ حَانِثٍ","id":"Telah menceritakan kepada kami [Muhammad bin Ziyad] berkata, telah menceritakan kepada kami [Abdul Warits bin Sa'id] dari [Ayyub] dari [Nafi'] dari [Ibnu Umar] ia berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Siapa yang bersumpah dan mengucapkan 'Insya-Allah', jika berkehendak ia boleh melakukan sumpahnya dan jika berkehendak ia boleh meninggalkannya tanpa berdosa.\""},"2062":{"ar":"حَدَّثَنَا عَبْدُ اللَّهِ بْنُ مُحَمَّدٍ الزُّهْرِيُّ حَدَّثَنَا سُفْيَانُ بْنُ عُيَيْنَةَ عَنْ أَيُّوبَ عَنْ نَافِعٍ عَنْ ابْنِ عُمَرَرِوَايَةً قَالَ مَنْ حَلَفَ وَاسْتَثْنَى فَلَنْ يَحْنَثْ","id":"Telah menceritakan kepada kami [Abdullah bin Muhammad Az Zuhri] berkata, telah menceritakan kepada kami [Sufyan bin Uyainah] dari [Ayyub] dari [Nafi'] dari [Ibnu Umar] secara riwayat, beliau bersabda: \"Barangsiapa bersumpah dengan memberi pengecualian (insyaallah), maka ia tidak berdosa.\""},"2063":{"ar":"حَدَّثَنَا أَحْمَدُ بْنُ عَبْدَةَ أَنْبَأَنَا حَمَّادُ بْنُ زَيْدٍ حَدَّثَنَا غَيْلَانُ بْنُ جَرِيرٍ عَنْ أَبِي بُرْدَةَ عَنْ أَبِيهِ أَبِي مُوسَى قَالَأَتَيْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي رَهْطٍ مِنْ الْأَشْعَرِيِّينَ نَسْتَحْمِلُهُ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَاللَّهِ مَا أَحْمِلُكُمْ وَمَا عِنْدِي مَا أَحْمِلُكُمْ عَلَيْهِ قَالَ فَلَبِثْنَا مَا شَاءَ اللَّهُ ثُمَّ أُتِيَ بِإِبِلٍ فَأَمَرَ لَنَا بِثَلَاثَةِ ذَوْدٍ غُرِّ الذُّرَى فَلَمَّا انْطَلَقْنَا قَالَ بَعْضُنَا لِبَعْضٍ أَتَيْنَا رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ نَسْتَحْمِلُهُ فَحَلَفَ أَلَّا يَحْمِلَنَا ثُمَّ حَمَلَنَا ارْجِعُوا بِنَا فَأَتَيْنَاهُ فَقُلْنَا يَا رَسُولَ اللَّهِ إِنَّا أَتَيْنَاكَ نَسْتَحْمِلُكَ فَحَلَفْتَ أَنْ لَا تَحْمِلَنَا ثُمَّ حَمَلْتَنَا فَقَالَ وَاللَّهِ مَا أَنَا حَمَلْتُكُمْ بَلْ اللَّهُ حَمَلَكُمْ إِنِّي وَاللَّهِ إِنْ شَاءَ اللَّهُ لَا أَحْلِفُ عَلَى يَمِينٍ فَأَرَى خَيْرًا مِنْهَا إِلَّا كَفَّرْتُ عَنْ يَمِينِي وَأَتَيْتُ الَّذِي هُوَ خَيْرٌ أَوْ قَالَ أَتَيْتُ الَّذِي هُوَ خَيْرٌ وَكَفَّرْتُ عَنْ يَمِينِي","id":"Telah menceritakan kepada kami [Ahmad bin Abdah] berkata, telah memberitakan kepada kami [Hammad bin Zaid] berkata, telah menceritakan kepada kami [Ghailan bin Jarir] dari [Abu Burdah] dari bapaknya [Abu Musa] ia berkata, \"Aku mendatangi Rasulullah shallallahu 'alaihi wasallam dalam sebuah rombongan orang-orang Asy'ari, mengharap agar beliau membawa kami. Rasulullah shallallahu 'alaihi wasallam lalu bersabda: \"Demi Allah, aku tidak akan membawa kalian, dan aku tidak mempunyai sesuatu yang bisa aku gunakan untuk membawa kalian.\" Abu Musa berkata, \"Namun kami tetap tinggal beberapa saat, hingga kemudian didatangkan seekor unta di hadapan beliau. Lalu beliau memerintahkan kepada kami untuk menunggangi tiga ekor unta yang gemuk. Ketika kami telah berangkat, sebagian kami berkata kepada sebagian yang lain, \"Kami mendatangi Rasulullah shallallahu 'alaihi wasallam mengharap agar beliau bersedia membawa kami, namun justru beliau bersumpah dan tidak mau membawa kami. Setelah itu beliau membawa kami dan bersabda: \"Kembalilah bersama kami, \" maka kami mendatangi beliau. Lantas kami berkata, \"Wahai Rasulullah, kami mendatangimu mengharap agar engkau mau membawa kami, namun engkau malah bersumpah untuk tidak membawa kami, dan setelah itu engkau membawa kami! \" beliau menjawab: \"Demi Allah, aku tidak membawa kalian, tetapi Allah lah yang telah membawa kalian. Sesungguhnya aku, demi Allah, insyaallah jika aku bersumpah atas sesuatu, kemudian melihat yang lebih baik darinya, aku akan menebus sumpahku dan kembali kepada yang lebih baik darinya, atau beliau bersabda: \"aku mengambil yang lebih baik darinya dan menebus sumpahku.\""},"2064":{"ar":"حَدَّثَنَا عَلِيُّ بْنُ مُحَمَّدٍ وَعَبْدُ اللَّهِ بْنُ عَامِرِ بْنِ زُرَارَةَ قَالَا حَدَّثَنَا أَبُو بَكْرِ بْنُ عَيَّاشٍ عَنْ عَبْدِ الْعَزِيزِ بْنِ رُفَيْعٍ عَنْ تَمِيمِ بْنِ طَرَفَةَ عَنْ عَدِيِّ ابْنِ حَاتِمٍ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَنْ حَلَفَ عَلَى يَمِينٍ فَرَأَى خَيْرًا مِنْهَا فَلْيَأْتِ الَّذِي هُوَ خَيْرٌ وَلْيُكَفِّرْ عَنْ يَمِينِهِ","id":"Telah menceritakan kepada kami [Ali bin Muhammad] dan [Abdullah bin Amir bin Zurarah] keduanya berkata; telah menceritakan kepada kami [Abu Bakr bin Ayyasy] dari [Abdul Aziz bin Rufai'] dari [Tamim bin Tharafah] dari [Adi bin Hatim] ia berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Barangsiapa bersumpah atas sesuatu kemudian melihat yang lebih baik darinya, maka hendaklah ia mengambil yang lebih baik dan menebus sumpahnya.\""},"2065":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ أَبِي عُمَرَ الْعَدَنِيُّ حَدَّثَنَا سُفْيَانُ بْنُ عُيَيْنَةَ حَدَّثَنَا أَبُو الزَّعْرَاءِ عَمْرُو بْنُ عَمْرٍو عَنْ عَمِّهِ أَبِي الْأَحْوَصِ عَوْفِ بْنِ مَالِكٍ الْجُشَمِيِّ عَنْ أَبِيهِ قَالَقُلْتُ يَا رَسُولَ اللَّهِ يَأْتِينِي ابْنُ عَمِّي فَأَحْلِفُ أَنْ لَا أُعْطِيَهُ وَلَا أَصِلَهُ قَالَ كَفِّرْ عَنْ يَمِينِكَ","id":"Telah menceritakan kepada kami [Muhammad bin Abu Umar Al 'Adani] berkata, telah menceritakan kepada kami [Sufyan bin 'Uyainah] berkata, telah menceritakan kepada kami [Abu Az Za'ra Amru bin Amru] dari pamannya [Abul Ahwash Auf bin Malik Al Jusyami] dari [Bapaknya] ia berkata, \"Wahai Rasulullah, keponakanku datang kepadaku. Lalu aku bersumpah untuk tidak memberinya dan tidak menyambung tali silaturrahim.\" Beliau bersabda: \"Hendaknya kamu membayar kafarat atas sumpahmu itu.\""},"2066":{"ar":"حَدَّثَنَا عَلِيُّ بْنُ مُحَمَّدٍ حَدَّثَنَا عَبْدُ اللَّهِ بْنُ نُمَيْرٍ عَنْ حَارِثَةَ بْنِ أَبِي الرِّجَالِ عَنْ عَمْرَةَ عَنْ عَائِشَةَ قَالَتْقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَنْ حَلَفَ فِي قَطِيعَةِ رَحِمٍ أَوْ فِيمَا لَا يَصْلُحُ فَبِرُّهُ أَنْ لَا يُتِمَّ عَلَى ذَلِكَ","id":"Telah menceritakan kepada kami [Ali bin Muhammad] berkata, telah menceritakan kepada kami [Abdullah bin Numair] dari [Haritsah bin Abu Rajal] dari [Amrah] dari ['Aisyah] ia berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Barangsiapa bersumpah untuk memutus tali silaturrahim atau pada sesuatu yang tidak ada maslahatnya, maka tindakan yang baik adalah tidak melaksanakannya.\""},"2067":{"ar":"حَدَّثَنَا عَبْدُ اللَّهِ بْنُ عَبْدِ الْمُؤْمِنِ الْوَاسِطِيُّ حَدَّثَنَا عَوْنُ بْنُ عُمَارَةَ حَدَّثَنَا رَوْحُ بْنُ الْقَاسِمِ عَنْ عُبَيْدِ اللَّهِ بْنِ عُمَرَ عَنْ عَمْرِو بْنِ شُعَيْبٍ عَنْ أَبِيهِ عَنْ جَدِّهِأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ مَنْ حَلَفَ عَلَى يَمِينٍ فَرَأَى غَيْرَهَا خَيْرًا مِنْهَا فَلْيَتْرُكْهَا فَإِنَّ تَرْكَهَا كَفَّارَتُهَا","id":"Telah menceritakan kepada kami [Abdullah bin Abdul Mu'min Al Wasithi] berkata, telah menceritakan kepada kami ['Aun bin Umarah] berkata, telah menceritakan kepada kami [Rauh bin Al Qasim] dari [Ubaidullah bin Umar] dari [Amru bin Syu'aib] dari [Bapaknya] dari [Kakeknya] bahwa Nabi shallallahu 'alaihi wasallam bersabda: \"Barangsiapa bersumpah atas suatu sumpah, kemudian ia melihat sesuatu yang lebih baik darinya, maka hendaklah ia meninggalkannya (sumpah), sebab meninggalkannya adalah sebagai bentuk kafarah.\""},"2068":{"ar":"حَدَّثَنَا الْعَبَّاسُ بْنُ يَزِيدَ حَدَّثَنَا زِيَادُ بْنُ عَبْدِ اللَّهِ الْبَكَّائِيُّ حَدَّثَنَا عُمَرُ بْنُ عَبْدِ اللَّهِ بْنِ يَعْلَى الثَّقَفِيُّ عَنْ الْمِنْهَالِ بْنِ عَمْرٍو عَنْ سَعِيدِ بْنِ جُبَيْرٍ عَنْ ابْنِ عَبَّاسٍ قَالَكَفَّرَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِصَاعٍ مِنْ تَمْرٍ وَأَمَرَ النَّاسَ بِذَلِكَ فَمَنْ لَمْ يَجِدْ فَنِصْفُ صَاعٍ مِنْ بُرٍّ","id":"Telah menceritakan kepada kami [Al Abbas bin Yazid] berkata, telah menceritakan kepada kami [Ziyad bin Abdullah Al Bakka`i] berkata, telah menceritakan kepada kami [Umar bin Abdullah bin Ya'la Ats Tsaqafi] dari [Minhal bin 'Amru] dari [Sa'id bin Jubair] dari [Ibnu Abbas] ia berkata, \"Rasulullah shallallahu 'alaihi wasallam membayar kafarat dengan satu gantang kurma, beliau juga memerintahkan orang-orang untuk melakukan seperti itu. Barangsiapa tidak mendapatinya maka setengah gantang dari gandum.\""},"2069":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ يَحْيَى حَدَّثَنَا عَبْدُ الرَّحْمَنِ بْنُ مَهْدِيٍّ حَدَّثَنَا سُفْيَانُ بْنُ عُيَيْنَةَ عَنْ سُلَيْمَانَ بْنِ أَبِي الْمُغِيرَةِ عَنْ سَعِيدِ بْنِ جُبَيْرٍ عَنْ ابْنِ عَبَّاسٍ قَالَكَانَ الرَّجُلُ يَقُوتُ أَهْلَهُ قُوتًا فِيهِ سَعَةٌ وَكَانَ الرَّجُلُ يَقُوتُ أَهْلَهُ قُوتًا فِيهِ شِدَّةٌ فَنَزَلَتْ{ مِنْ أَوْسَطِ مَا تُطْعِمُونَ أَهْلِيكُمْ }","id":"Telah menceritakan kepada kami [Muhammad bin Yahya] berkata, telah menceritakan kepada kami ['Abdurrahman bin Mahdi] berkata, telah menceritakan kepada kami [Sufyan bin Uyainah] dari [Sulaiman bin Abul Mughirah] dari [Sa'id bin Jubair] dari [Ibnu Abbas] ia berkata, \"Seorang lelaki memberi makanan pokok pada keluarganya dengan berlebihan, dan ada juga yang memberi makanan pokok pada keluarganya dengan kekurangan, lalu turunlah ayat: ' Yaitu dari makanan yang biasa kamu berikan kepada keluargamu'.\" (QS. Al Maidah; 89)."},"2070":{"ar":"حَدَّثَنَا سُفْيَانُ بْنُ وَكِيعٍ حَدَّثَنَا مُحَمَّدُ بْنُ حُمَيْدٍ الْمَعْمَرِيُّ عَنْ مَعْمَرٍ عَنْ هَمَّامٍ قَالَ سَمِعْتُ أَبَا هُرَيْرَةَ يَقُولُقَالَ أَبُو الْقَاسِمِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِذَا اسْتَلَجَّ أَحَدُكُمْ فِي الْيَمِينِ فَإِنَّهُ آثَمُ لَهُ عِنْدَ اللَّهِ مِنْ الْكَفَّارَةِ الَّتِي أُمِرَ بِهَاو حَدَّثَنَا مُحَمَّدُ بْنُ يَحْيَى حَدَّثَنَا يَحْيَى بْنُ صَالِحٍ الْوَحَاظِىُّ حَدَّثَنَا مُعَاوِيَةُ بْنُ سَلَّامٍ عَنْ يَحْيَى بْنِ أَبِي كَثِيرٍ عَنْ عِكْرِمَةَ عَنْ أَبِي هُرَيْرَةَ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ نَحْوَهُ","id":"Telah menceritakan kepada kami [Sufyan bin Waki'] berkata, telah menceritakan kepada kami [Muhammad bin Humaid Al Ma'mari] dari [Ma'mar] dari [Hammam] ia berkata, \"Aku mendengar [Abu Hurairah] berkata, \"Abu Qasim shallallahu 'alaihi wasallam bersabda: \"Jika salah seorang dari kalian meneruskan sumpahnya maka ia akan berdosa. Dan di sisi Allah ia mempunyai kafarah sebagaimana yang telah diperintahkan.\" Telah menceritakan kepada kami [Muhammad bin Yahya] Telah menceritakan kepada kami [Yahya bin Shalih Al Wahazhi] Telah menceritakan kepada kami [Mu'awiyah bin Salam] dari [Yahya bin Abu Katsir] dari [Ikrimah] dari [Abu Hurairah] dari Nabi shallallahu 'alaihi wasallam dengan Hadits yang serupa."},"2071":{"ar":"حَدَّثَنَا عَلِيُّ بْنُ مُحَمَّدٍ حَدَّثَنَا وَكِيعٌ عَنْ عَلِيِّ بْنِ صَالِحٍ عَنْ أَشْعَثَ بْنِ أَبِي الشَّعْثَاءِ عَنْ مُعَاوِيَةَ بْنِ سُوَيْدِ بْنِ مُقَرِّنٍ عَنْ الْبَرَاءِ بْنِ عَازِبٍ قَالَأَمَرَنَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِإِبْرَارِ الْمُقْسِمِ","id":"Telah menceritakan kepada kami [Ali bin Muhammad] berkata, telah menceritakan kepada kami [Waki'] dari [Ali bin Shalih] dari [Asy'ats bin Abu Asy Sya'tsa] dari [Mu'awiah bin Suwaid bin Muqarrin] dari [Al Bara bin Azib] ia berkata, \"Rasulullah shallallahu 'alaihi wasallam memerintahkan kami untuk menunaikan sumpah.\""},"2072":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا مُحَمَّدُ بْنُ فُضَيْلٍ عَنْ يَزِيدَ بْنِ أَبِي زِيَادٍ عَنْ مُجَاهِدٍ عَنْ عَبْدِ الرَّحْمَنِ بْنِ صَفْوَانَ أَوْ صَفْوَانَ بْنِ عَبْدِ الرَّحْمَنِ الْقُرَشِيِّ قَالَلَمَّا كَانَ يَوْمُ فَتْحِ مَكَّةَ جَاءَ بِأَبِيهِ فَقَالَ يَا رَسُولَ اللَّهِ اجْعَلْ لِأَبِي نَصِيبًا فِي الْهِجْرَةِ فَقَالَ إِنَّهُ لَا هِجْرَةَ فَانْطَلَقَ فَدَخَلَ عَلَى الْعَبَّاسِ فَقَالَ قَدْ عَرَفْتَنِي قَالَ أَجَلْ فَخَرَجَ الْعَبَّاسُ فِي قَمِيصٍ لَيْسَ عَلَيْهِ رِدَاءٌ فَقَالَ يَا رَسُولَ اللَّهِ قَدْ عَرَفْتَ فُلَانًا وَالَّذِي بَيْنَنَا وَبَيْنَهُ وَجَاءَ بِأَبِيهِ لِتُبَايِعَهُ عَلَى الْهِجْرَةِ فَقَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِنَّهُ لَا هِجْرَةَ فَقَالَ الْعَبَّاسُ أَقْسَمْتُ عَلَيْكَ فَمَدَّ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَدَهُ فَمَسَّ يَدَهُ فَقَالَ أَبْرَرْتُ عَمِّي وَلَا هِجْرَةَحَدَّثَنَا مُحَمَّدُ بْنُ يَحْيَى حَدَّثَنَا الْحَسَنُ بْنُ الرَّبِيعِ عَنْ عَبْدِ اللَّهِ بْنِ إِدْرِيسَ عَنْ يَزِيدَ بْنِ أَبِي زِيَادٍ بِإِسْنَادِهِ نَحْوَهُ قَالَ يَزِيدُ بْنُ أَبِي زِيَادٍ يَعْنِي لَا هِجْرَةَ مِنْ دَارٍ قَدْ أَسْلَمَ أَهْلُهَا","id":"Telah menceritakan kepada kami [Abu Bakr bin Abu Syaibah] berkata, telah menceritakan kepada kami [Muhammad bin Fudlail] dari [Yazid bin Abu Ziyad] dari [Mujahid] dari ['Abdurrahman bin Shafwan] atau Shafwan bin 'Abdurrahman Al Qurasyi ia berkata, \"Ketika penaklukan kota Makkah ia datang bersama bapaknya, lalu ia berkata, \"Wahai Rasulullah, berilah bapakku pahala hijrah, \" beliau bersabda: \"Sesungguhnya sudah tidak ada hijrah lagi.\" Ia pun pergi dan menemui Al Abbas, ia berkata, \"Engkau kenal dengan aku?\" Al Abbas menjawab, \"Tentu, \" Al Abbas kemudian keluar dengan mengenakan kemeja tanpa selendang, ia lantas berkata, \"Wahai Rasulullah, engkau telah mengenal si fulan dan apa yang terjadi antara kami dengan dia. Ia datang dengan bapaknya agar engkau membai'atnya untuk hijrah.\" Nabi shallallahu 'alaihi wasallam bersabda: \"Sesungguhnya sudah tidak ada hijrah lagi.\" Al Abbas berkata, \"Aku bersumpah atas engkau.\" Lalu Nabi shallallahu 'alaihi wasallam mengulurkan tangan dan memegang tangan Al Abbas seraya bersabda: \"Aku telah menetapi pamanku, namun tidak ada hijrah lagi.\" Telah menceritakan kepada kami [Muhammad bin Yahya] berkata, telah menceritakan kepada kami [Al Hasan bin Ar Rabi'] dari [Abdullah bin Idris] dari [Yazid bin Abu Ziyad] dengan sanadnya sebagaimana dalam hadits.\" Yazid bin Abu Ziyad berkata, \"Tidak ada hijrah dari suatu negri yang penghuninya telah masuk Islam.\""},"2073":{"ar":"حَدَّثَنَا هِشَامُ بْنُ عَمَّارٍ حَدَّثَنَا عِيسَى بْنُ يُونُسَ حَدَّثَنَا الْأَجْلَحُ الْكِنْدِيُّ عَنْ يَزِيدَ بْنِ الْأَصَمِّ عَنْ ابْنِ عَبَّاسٍ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِذَا حَلَفَ أَحَدُكُمْ فَلَا يَقُلْ مَا شَاءَ اللَّهُ وَشِئْتَ وَلَكِنْ لِيَقُلْ مَا شَاءَ اللَّهُ ثُمَّ شِئْتَ","id":"Telah menceritakan kepada kami [Hisyam bin Ammar] berkata, telah menceritakan kepada kami [Isa bin Yunus] berkata, telah menceritakan kepada kami [Al Ajlah Al Kindi] dari [Yazid bin Al Asham] dari [Ibnu Abbas] ia berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Jika salah seorang dari kalian bersumpah, maka jangan mengucapkan 'Jika Allah dan kamu menghendaki'. Akan tetapi ucapkanlah 'Jika Allah menghendaki kemudian kamu'.\""},"2074":{"ar":"حَدَّثَنَا هِشَامُ بْنُ عَمَّارٍ حَدَّثَنَا سُفْيَانُ بْنُ عُيَيْنَةَ عَنْ عَبْدِ الْمَلِكِ بْنِ عُمَيْرٍ عَنْ رِبْعِيِّ بْنِ حِرَاشٍ عَنْ حُذَيْفَةَ بْنِ الْيَمَانِأَنَّ رَجُلًا مِنْ الْمُسْلِمِينَ رَأَى فِي النَّوْمِ أَنَّهُ لَقِيَ رَجُلًا مِنْ أَهْلِ الْكِتَابِ فَقَالَ نِعْمَ الْقَوْمُ أَنْتُمْ لَوْلَا أَنَّكُمْ تُشْرِكُونَ تَقُولُونَ مَا شَاءَ اللَّهُ وَشَاءَ مُحَمَّدٌ وَذَكَرَ ذَلِكَ لِلنَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ أَمَا وَاللَّهِ إِنْ كُنْتُ لَأَعْرِفُهَا لَكُمْ قُولُوا مَا شَاءَ اللَّهُ ثُمَّ شَاءَ مُحَمَّدٌحَدَّثَنَا مُحَمَّدُ بْنُ عَبْدِ الْمَلِكِ بْنِ أَبِي الشَّوَارِبِ حَدَّثَنَا أَبُو عَوَانَةَ عَنْ عَبْدِ الْمَلِكِ عَنْ رِبْعِيِّ بْنِ حِرَاشٍ عَنْ الطُّفَيْلِ بْنِ سَخْبَرَةَ أَخِي عَائِشَةَ لِأُمِّهَا عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِنَحْوِهِ","id":"Telah menceritakan kepada kami [Hisyam bin Ammar] berkata, telah menceritakan kepada kami [Sufyan bin Uyainah] dari [Abdul Malik bin Umair] dari [Rib'i bin Hirasy] dari [Hudzaifah Ibnul Yaman] berkata; \"Seorang laki-laki muslim bermimpi dalam tidurnya bertemu dengan seorang yahudi, yahudi tersebut berkata, \"Sebaik-baik kaum adalah kalian, jika kalian tidak berbuat syirik. Kalian mengatakan 'Apa yang dikehendaki Allah dan yang dikehendaki Muhammad'.\" Lalu hal itu disebutkan kepada Nabi shallallahu 'alaihi wasallam, beliau pun bersabda: \"Demi Allah, aku lebih tahu dari kalian, maka ucapkanlah 'Apa yang dikehendaki Allah kemudian Muhammad'.\" Telah menceritakan kepada kami [Muhammad bin Abdul Malik bin Abu Asy Syawarib] berkata, telah menceritakan kepada kami [Abu Awanah] dari [Abdul Malik] dari [Rib'i bin Hirasy] dari [Ath Thufail bin Sakhbarah] -saudara 'Aisyah dari ibu-, dari Nabi shallallahu 'alaihi wasallam sebagaimana dalam hadits.\""},"2075":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا عُبَيْدُ اللَّهِ بْنُ مُوسَى عَنْ إِسْرَائِيلَ ح و حَدَّثَنَا يَحْيَى بْنُ حَكِيمٍ عَنْ عَبْدِ الرَّحْمَنِ بْنِ مَهْدِيٍّ عَنْ إِسْرَائِيلَ عَنْ إِبْرَاهِيمَ بْنِ عَبْدِ الْأَعْلَى عَنْ جَدَّتِهِ عَنْ أَبِيهَا سُوَيْدِ بْنِ حَنْظَلَةَ قَالَخَرَجْنَا نُرِيدُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَمَعَنَا وَائِلُ بْنُ حُجْرٍ فَأَخَذَهُ عَدُوٌّ لَهُ فَتَحَرَّجَ النَّاسُ أَنْ يَحْلِفُوا فَحَلَفْتُ أَنَا أَنَّهُ أَخِي فَخَلَّى سَبِيلَهُ فَأَتَيْنَا رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَأَخْبَرْتُهُ أَنَّ الْقَوْمَ تَحَرَّجُوا أَنْ يَحْلِفُوا وَحَلَفْتُ أَنَا أَنَّهُ أَخِي فَقَالَ صَدَقْتَ الْمُسْلِمُ أَخُو الْمُسْلِمِ","id":"Telah menceritakan kepada kami [Abu Bakr bin Abu Syaibah] berkata, telah menceritakan kepada kami [Ubaidullah bin Musa] dari [Israil]. Telah menceritakan kepada kami [Yahya bin Hakim] dari ['Abdurrahman bin Mahdi] dari [Isra`il] dari [Ibrahim bin Abdul A'la] dari [Neneknya] dari bapaknya [Suwaid bin Hanzhalah] ia berkata; \"Kami berangkat ingin menemui Rasulullah shallallahu 'alaihi wasallam, sementara kami bersama Wail bin Hujr. Kemudian ia diculik musuhnya. Kami (para sahabat) terpaksa harus bersumpah, dan saya bersumpah bahwa Wail bin Hujr saudaraku. Karena sumpahku, musuh pun membebaskan Wail untuk meneruskan perjalanan. Setiba kami di Rasulullah, kami utarakan kasus kami, yaitu para sahabat terpaksa harus bersumpah, dan aku bersumpah bahwa Wail saudaraku. Nabi membenarkan tindakan kami dan berujar 'Engkau benar, sebab seorang muslim saudara muslim lainnya.'"},"2076":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا يَزِيدُ بْنُ هَارُونَ أَنْبَأَنَا هُشَيْمٌ عَنْ عَبَّادِ بْنِ أَبِي صَالِحٍ عَنْ أَبِيهِ عَنْ أَبِي هُرَيْرَةَ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِنَّمَا الْيَمِينُ عَلَى نِيَّةِ الْمُسْتَحْلِفِ","id":"Telah menceritakan kepada kami [Abu Bakr bin Abu Syaibah] berkata, telah menceritakan kepada kami [Yazid bin Harun] berkata, telah memberitakan kepada kami [Husyaim] dari [Abbad bin Abu Shalih] dari [Bapaknya] dari [Abu Hurairah] ia berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Sesungguhnya sumpah itu bergantung dengan niat orang yang bersumpah.\""},"2077":{"ar":"حَدَّثَنَا عَمْرُو بْنُ رَافِعٍ حَدَّثَنَا هُشَيْمٌ أَنْبَأَنَا عَبْدُ اللَّهِ بْنُ أَبِي صَالِحٍ عَنْ أَبِيهِ عَنْ أَبِي هُرَيْرَةَ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَمِينُكَ عَلَى مَا يُصَدِّقُكَ بِهِ صَاحِبُكَ","id":"Telah menceritakan kepada kami [Amru bin Rafi'] berkata, telah menceritakan kepada kami [Husyaim] berkata, telah memberitakan kepada kami [Abdullah bin Abu Shalih] dari [Bapaknya] dari [Abu Hurairah] ia berkata; \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Sumpahmu itu adalah apa yang dibenarkan oleh temanmu.\""},"2078":{"ar":"حَدَّثَنَا عَلِيُّ بْنُ مُحَمَّدٍ حَدَّثَنَا وَكِيعٌ عَنْ سُفْيَانَ عَنْ مَنْصُورٍ عَنْ عَبْدِ اللَّهِ بْنِ مُرَّةَ عَنْ عَبْدِ اللَّهِ بْنِ عُمَرَ قَالَنَهَى رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَنْ النَّذْرِ وَقَالَ إِنَّمَا يُسْتَخْرَجُ بِهِ مِنْ اللَّئِيمِ","id":"Telah menceritakan kepada kami [Ali bin Muhammad] berkata, telah menceritakan kepada kami [Waki'] dari [Sufyan] dari [Manshur] dari [Abdullah bin Murrah] dari [Abdullah bin Umar] ia berkata, \"Rasulullah shallallahu 'alaihi wasallam melarang nadzar. Dan beliau juga bersabda: \"Hanyasanya ia dikeluarkan dari orang yang bahil.\""},"2079":{"ar":"حَدَّثَنَا أَحْمَدُ بْنُ يُوسُفَ حَدَّثَنَا عُبَيْدُ اللَّهِ عَنْ سُفْيَانَ عَنْ أَبِي الزِّنَادِ عَنْ الْأَعْرَجِ عَنْ أَبِي هُرَيْرَةَ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْ��ِ وَسَلَّمَ إِنَّ النَّذْرَ لَا يَأْتِي ابْنَ آدَمَ بِشَيْءٍ إِلَّا مَا قُدِّرَ لَهُ وَلَكِنْ يَغْلِبُهُ الْقَدَرُ مَا قُدِّرَ لَهُ فَيُسْتَخْرَجُ بِهِ مِنْ الْبَخِيلِ فَيُيَسَّرُ عَلَيْهِ مَا لَمْ يَكُنْ يُيَسَّرُ عَلَيْهِ مِنْ قَبْلِ ذَلِكَ وَقَدْ قَالَ اللَّهُ أَنْفِقْ أُنْفِقْ عَلَيْكَ","id":"Telah menceritakan kepada kami [Ahmad bin Yusuf] berkata, telah menceritakan kepada kami [Ubaidullah] dari [Sufyan] dari [Abu Az Zinad] dari [Al A'raj] dari [Abu Hurairah] ia berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Sesungguhnya nadzar itu tidaklah datang kepada anak Adam kecuali sesuatu yang telah ditakdirkan atasnya. Akan tetapi sesuatu yang telah ditakdirkan itu terkalahkan oleh ketetapan takdir (yang lain), hingga ia (yang dinadzarkan) dikeluarkan dari seorang yang bakhil. Lalu dimudahkan baginya sesuatu yang sebelumnya sulit. Dan Allah berfirman: \"Berinfaklah, maka Aku akan berifak kepadamu.\""},"2080":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي سَهْلٍ حَدَّثَنَا سُفْيَانُ بْنُ عُيَيْنَةَ حَدَّثَنَا أَيُّوبُ عَنْ أَبِي قِلَابَةَ عَنْ عَمِّهِ عَنْ عِمْرَانَ بْنِ الْحُصَيْنِ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَا نَذْرَ فِي مَعْصِيَةٍ وَلَا نَذْرَ فِيمَا لَا يَمْلِكُ ابْنُ آدَمَ","id":"Telah menceritakan kepada kami [Abu Bakr bin Abu Sahl] berkata, telah menceritakan kepada kami [Sufyan bin Uyainah] berkata, telah menceritakan kepada kami [Ayyub] dari [Abu Qilabah] dari [Pamannya] dari [Imran bin Al Hushain] ia berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Tidak ada nadzar dalam bermaksiat, dan tidak ada nadzar dalam perkara yang anak Adam tidak mampu melaksanakannya.\""},"2081":{"ar":"حَدَّثَنَا أَحْمَدُ بْنُ عَمْرِو بْنِ السَّرْحِ الْمِصْرِيُّ أَبُو طَاهِرٍ حَدَّثَنَا ابْنُ وَهْبٍ أَنْبَأَنَا يُونُسُ عَنْ ابْنِ شِهَابٍ عَنْ أَبِي سَلَمَةَ عَنْ عَائِشَةَأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ لَا نَذْرَ فِي مَعْصِيَةٍ وَكَفَّارَتُهُ كَفَّارَةُ يَمِينٍ","id":"Telah menceritakan kepada kami [Ahmad bin Amru bin As Sarh Al Mishri Abu Thahir] berkata, telah menceritakan kepada kami [Ibnu Wahb] berkata, telah memberitakan kepada kami [Yunus] dari [Ibnu Syihab] dari [Abu Salamah] dari ['Aisyah] bahwa Rasulullah shallallahu 'alaihi wasallam bersabda: \"Tidak ada nadzar dalam bermaksiat, dan kafarahnya adalah kafarah sumpah.\""},"2082":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا أَبُو أُسَامَةَ عَنْ عُبَيْدِ اللَّهِ عَنْ طَلْحَةَ بْنِ عَبْدِ الْمَلِكِ عَنْ الْقَاسِمِ بْنِ مُحَمَّدٍ عَنْ عَائِشَةَ قَالَتْقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَنْ نَذَرَ أَنْ يُطِيعَ اللَّهَ فَلْيُطِعْهُ وَمَنْ نَذَرَ أَنْ يَعْصِيَ اللَّهَ فَلَا يَعْصِهِ","id":"Telah menceritakan kepada kami [Abu Bakr bin Abu Syaibah] berkata, telah menceritakan kepada kami [Abu Usamah] dari [Ubaidullah] dari [Thalhah bin Abdul Malik] dari [Al Qasim bin Muhammad] dari ['Aisyah] ia berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Barangsiapa bernadzar untuk taat kepada Allah hendaklah ia mentaati-Nya. Dan barangsiapa bernadzar untuk bermaksiat kepada-Nya, maka janganlah ia lakukan.\""},"2083":{"ar":"حَدَّثَنَا عَلِيُّ بْنُ مُحَمَّدٍ حَدَّثَنَا وَكِيعٌ حَدَّثَنَا إِسْمَعِيلُ بْنُ رَافِعٍ عَنْ خَالِدِ بْنِ يَزِيدَ عَنْ عُقْبَةَ بْنِ عَامِرٍ الْجُهَنِيِّ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَنْ نَذَرَ نَذْرًا وَلَمْ يُسَمِّهِ فَكَفَّارَتُهُ كَفَّارَةُ يَمِينٍ","id":"Telah menceritakan kepada kami [Ali bin Muhammad] berkata, telah menceritakan kepada kami [Waki'] berkata, telah menceritakan kepada kami [Isma'il bin Rafi'] dari [Khalid bin Yazid] dari [Uqbah bin Amir Al Juhani] ia berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Barangsiapa bernadzar dengan suatu nadzar dan belum menentukan bentuk kafarahnya, maka kafarahnya adalah kafarat sumpah.\""},"2084":{"ar":"حَدَّثَنَا هِشَامُ بْنُ عَمَّارٍ حَدَّثَنَا عَبْدُ الْمَلِكِ بْنُ مُحَمَّدٍ الصَّنْعَانِيُّ حَدَّثَنَا خَارِجَةُ بْنُ مُصْعَبٍ عَنْ بُكَيْرِ بْنِ عَبْدِ اللَّهِ بْنِ الْأَشَجِّ عَنْ كُرَيْبٍ عَنْ ابْنِ عَبَّاسٍعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ مَنْ نَذَرَ نَذْرًا وَلَمْ يُسَمِّهِ فَكَفَّارَتُهُ كَفَّارَةُ يَمِينٍ وَمَنْ نَذَرَ نَذْرًا لَمْ يُطِقْهُ فَكَفَّارَتُهُ كَفَّارَةُ يَمِينٍ وَمَنْ نَذَرَ نَذْرًا أَطَاقَهُ فَلْيَفِ بِهِ","id":"Telah menceritakan kepada kami [Hisyam bin Ammar] berkata, telah menceritakan kepada kami [Abdul Malik bin Muhammad Ash Shan'ani] berkata, telah menceritakan kepada kami [Kharijah bin Mush'ab] dari [Bukair bin Abdullah bin Al Asyaj] dari [Kuraib] dari [Ibnu Abbas] dari Nabi shallallahu 'alaihi wasallam, beliau bersabda: \"Barangsiapa bernadzar dengan suatu nadzar dan belum menyebutkan bentuknya (kafarahnya), maka kafaratnya adalah kafarat sumpah. Barangsiapa bernadzar dengan sesuatu yang tidak mampu ia lakukan, maka kafaratnya adalah sama dengan kafarat sumpah. Dan barangsiapa bernadzar dengan suatu nadzar yang dia mampu, maka hendaklah ia tunaikan.\""},"2085":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا حَفْصُ بْنُ غِيَاثٍ عَنْ عُبَيْدِ اللَّهِ بْنِ عُمَرَ عَنْ نَافِعٍ عَنْ ابْنِ عُمَرَ عَنْ عُمَرَ بْنِ الْخَطَّابِ قَالَنَذَرْتُ نَذْرًا فِي الْجَاهِلِيَّةِ فَسَأَلْتُ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بَعْدَمَا أَسْلَمْتُ فَأَمَرَنِي أَنْ أُوفِيَ بِنَذْرِي","id":"Telah menceritakan kepada kami [Abu Bakr bin Abu Syaibah] berkata, telah menceritakan kepada kami [Hafsh bin Ghiyats] dari [Ubaidullah bin Umar] dari [Nafi'] dari [Ibnu Umar] dari [Umar Ibnul Khtahthab] ia berkata, \"Di masa Jahiliyah aku pernah bernadzar, setelah aku masuk Islam, aku bertanya kepada Nabi shallallahu 'alaihi wasallam. Beliau memerintahkan aku untuk menunaikan nadzarku tersebut.\""},"2086":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ يَحْيَى وَعَبْدُ اللَّهِ بْنُ إِسْحَقَ الْجَوْهَرِيُّ قَالَا حَدَّثَنَا عَبْدُ اللَّهِ بْنُ رَجَاءٍ أَنْبَأَنَا الْمَسْعُودِيُّ عَنْ حَبِيبِ بْنِ أَبِي ثَابِتٍ عَنْ سَعِيدِ بْنِ جُبَيْرٍ عَنْ ابْنِ عَبَّاسٍأَنَّ رَجُلًا جَاءَ إِلَى النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ يَا رَسُولَ اللَّهِ إِنِّي نَذَرْتُ أَنْ أَنْحَرَ بِبُوَانَةَ فَقَالَ فِي نَفْسِكَ شَيْءٌ مِنْ أَمْرِ الْجَاهِلِيَّةِ قَالَ لَا قَالَ أَوْفِ بِنَذْرِكَ","id":"Telah menceritakan kepada kami [Muhammad bin Yahya] dan [Abdullah bin Ishaq Al Jauhari] keduanya berkata; telah menceritakan kepada kami [Abdullah bin Raja] berkata, telah memberitakan kepada kami [Al Mas'udi] dari [Habib bin Abu Tsabit] dari [Sa'id bin Jubair] dari [Ibnu Abbas], \"Bahwa seorang laki-laki datang kepada Nabi shallallahu 'alaihi wasallam dan bertanya; \"Wahai Rasulullah, sesungguhnya aku pernah bernadzar untuk berkurban di Buwanah!? Beliau bertanya: \"Apakah dalam dirimu masih melekat sesuatu dari perkara jahiliyah?\" ia menjawab, \"Tidak.\" Beliau bersabda: \"Tunaikanlah.\""},"2087":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا مَرْوَانُ بْنُ مُعَاوِيَةَ عَنْ عَبْدِ اللَّهِ بْنِ عَبْدِ الرَّحْمَنِ الطَّائِفِيِّ عَنْ مَيْمُونَةَ بِنْتِ كَرْدَمٍ الْيَسَارِيَّةِأَنَّ أَبَاهَا لَقِيَ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَهِيَ رَدِيفَةٌ لَهُ فَقَالَ إِنِّي نَذَرْتُ أَنْ أَنْحَرَ بِبُوَانَةَ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ هَلْ بِهَا وَثَنٌ قَالَ لَا قَالَ أَوْفِ بِنَذْرِكَحَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا ابْنُ دُكَيْنٍ عَنْ عَبْدِ اللَّهِ بْنِ عَبْدِ الرَّحْمَنِ عَنْ يَزِيدَ بْنِ مِقْسَمٍ عَنْ مَيْمُونَةَ بِنْتِ كَرْدَمٍ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِنَحْوِهِ","id":"Telah menceritakan kepada kami [Abu Bakr bin Abu Syaibah] berkata, telah menceritakan kepada kami [Marwan bin Mu'awiyah] dari [Abdullah bin 'Abdurrahman Ath Tha`ifi] dari [Maimunah binti Kardam Al Yasariah] bahwa bapaknya pernah bertemu dengan Nabi shallallahu 'alaihi wasallam, sementara ia ada dibelakang bapaknya. Bapaknya berkata, \"Aku bernadzar untuk berkurban di Buwanah?\" lalu Rasulullah shallallahu 'alaihi wasallam bersabda: \"Apakah di sana ada patung?\" ia menjawab, \"Tidak.\" Beliau lalu bersabda: \"Laksanakanlah nadzarmu.\" Telah menceritakan kepada kami [Abu Bakr bin Abu Syaibah] berkata, telah menceritakan kepada kami [Ibnu Dukain] dari [Abdullah bin 'Abdurrahman] dari [Yazid bin Miqsam] dari [Maimunah binti Kardam] dari Nabi shallallahu 'alaihi wasallam sebagaimana dalam hadits.\""},"2088":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ رُمْحٍ أَنْبَأَنَا اللَّيْثُ بْنُ سَعْدٍ عَنْ ابْنِ شِهَابٍ عَنْ عُبَيْدِ اللَّهِ بْنِ عَبْدِ اللَّهِ عَنْ ابْنِ عَبَّاسٍأَنَّ سَعْدَ بْنَ عُبَادَةَ اسْتَفْتَى رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي نَذْرٍ كَانَ عَلَى أُمِّهِ تُوُفِّيَتْ وَلَمْ تَقْضِهِ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ اقْضِهِ عَنْهَا","id":"Telah menceritakan kepada kami [Muhammad bin Rumh] berkata, telah memberitakan kepada kami [Al Laits bin Sa'd] dari [Ibnu Syihab] dari [Ubaidullah bin Abdullah] dari [Ibnu Abbas] berkata, \"Sa'd bin Ubadah meminta fatwa Rasulullah shallallahu 'alaihi wasallam tentang nadzar ibunya yang telah meninggal dan belum dilaksanakan, maka Rasulullah shallallahu 'alaihi wasallam pun bersabda: \"Lakukanlah untuknya.\""},"2089":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ يَحْيَى حَدَّثَنَا يَحْيَى بْنُ بُكَيْرٍ حَدَّثَنَا ابْنُ لَهِيعَةَ عَنْ عَمْرِو بْنِ دِينَارٍ عَنْ جَابِرِ بْنِ عَبْدِ اللَّهِأَنَّ امْرَأَةً أَتَتْ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَتْ إِنَّ أُمِّي تُوُفِّيَتْ وَعَلَيْهَا نَذْرُ صِيَامٍ فَتُوُفِّيَتْ قَبْلَ أَنْ تَقْضِيَهُ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لِيَصُمْ عَنْهَا الْوَلِيُّ","id":"Telah menceritakan kepada kami [Muhammad bin Yahya] berkata, telah menceritakan kepada kami [Yahya bin Bukair] berkata, telah menceritakan kepada kami [Ibnu Lahi'ah] dari ['Amru bin Dinar] dari [Jabir bin Abdullah] berkata, \"Seorang perempuan datang kepada Rasulullah shallallahu 'alaihi wasallam dan berkata, \"Ibuku meninggal, sementara ia pernah bernadzar untuk melaksanakan puasa namun ia meninggal sebelum melaksanakan nadzarnya?\" Maka Rasulullah shallallahu 'alaihi wasallam menjawab: \"Hendaklah walinya yang melakukannya.\""},"2090":{"ar":"حَدَّثَنَا عَلِيُّ بْنُ مُحَمَّدٍ حَدَّثَنَا عَبْدُ اللَّهِ بْنُ نُمَيْرٍ عَنْ يَحْيَى بْنِ سَعِيدٍ عَنْ عُبَيْدِ اللَّهِ بْنِ زَحْرٍ عَنْ أَبِي سَعِيدٍ الرُّعَيْنِيِّ أَنَّ عَبْدَ اللَّهِ بْنَ مَالِكٍ أَخْبَرَهُ أَنَّ عُقْبَةَ بْنَ عَامِرٍ أَخْبَرَهُأَنَّ أُخْتَهُ نَذَرَتْ أَنْ تَمْشِيَ حَافِيَةً غَيْرَ مُخْتَمِرَةٍ وَأَنَّهُ ذَكَرَ ذَلِكَ لِرَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ مُرْهَا فَلْتَرْكَبْ وَلْتَخْتَمِرْ وَلْتَصُمْ ثَلَاثَةَ أَيَّامٍ","id":"Telah menceritakan kepada kami [Ali bin Muhammad] berkata, telah menceritakan kepada kami [Abdullah bin Numair] dari [Yahya bin Sa'id] dari [Ubaidullah bin Zahr] dari [Abu Sa'id Ar Ru'aini] bahwa [Abdullah bin Malik] mengabarkan kepadanya, [Uqbah bin Amir] mengabarkan kepadanya, bahwa saudara perempuannya pernah bernadzar untuk berjalan dengan telanjang kaki dan tidak mengenakan kerudung. lalu ia ceritakan hal itu kepada Rasulullah shallallahu 'alaihi wasallam hingga beliau bersabda: \"Perintahkanlah ia untuk berkendaraan, berkerudung dan berpuasa selama tiga hari.\""},"2091":{"ar":"حَدَّثَنَا يَعْقُوبُ بْنُ حُمَيْدِ بْنِ كَاسِبٍ حَدَّثَنَا عَبْدُ الْعَزِيزِ بْنُ مُحَمَّدٍ عَنْ عَمْرِو بْنِ أَبِي عَمْرٍو عَنْ الْأَعْرَجِ عَنْ أَبِي هُرَيْرَةَ قَالَرَأَى النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ شَيْخًا يَمْشِي بَيْنَ ابْنَيْهِ فَقَالَ مَا شَأْنُ هَذَا فَقَالَ ابْنَاهُ نَذْرٌ يَا رَسُولَ اللَّهِ قَالَ ارْكَبْ أَيُّهَا الشَّيْخُ فَإِنَّ اللَّهَ غَنِيٌّ عَنْكَ وَعَنْ نَذْرِكَ","id":"Telah menceritakan kepada kami [Ya'qub bin Humaid bin Kasib] berkata, telah menceritakan kepada kami [Abdul Aziz bin Muhammad] dari [Amru bin Abu Amru] dari [Al A'raj] dari [Abu Hurairah] ia berkata, \"Nabi shallallahu 'alaihi wasallam melihat orang tua berjalan di antara kedua anaknya, beliau lantas bertanya: \"Ada apa dengan orang ini?\" kedua anaknya menjawab, \"Wahai Rasulullah, ia bernadzar.\" Beliau lalu bersabda: \"Naiklah kendaraan wahai orang tua, sesungguhnya Allah tidak butuh pengorbanan dan nadzarmu.\""},"2092":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ يَحْيَى حَدَّثَنَا إِسْحَقُ بْنُ مُحَمَّدٍ الْفَرْوِيُّ حَدَّثَنَا عَبْدُ اللَّهِ بْنُ عُمَرَ عَنْ عُبَيْدِ اللَّهِ بْنِ عُمَرَ عَنْ عَطَاءٍ عَنْ ابْنِ عَبَّاسٍأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَرَّ بِرَجُلٍ بِمَكَّةَ وَهُوَ قَائِمٌ فِي الشَّمْسِ فَقَالَ مَا هَذَا قَالُوا نَذَرَ أَنْ يَصُومَ وَلَا يَسْتَظِلَّ إِلَى اللَّيْلِ وَلَا يَتَكَلَّمَ وَلَا يَزَالُ قَائِمًا قَالَ لِيَتَكَلَّمْ وَلْيَسْتَظِلَّ وَلْيَجْلِسْ وَلْيُتِمَّ صَوْمَهُحَدَّثَنَا الْحُسَيْنُ ابْنُ مُحَمَّدِ بْنِ شَنْبَةَ الْوَاسِطِيُّ حَدَّثَنَا الْعَلَاءُ بْنُ عَبْدِ الْجَبَّارِ عَنْ وُهَيْبٍ عَنْ أَيُّوبَ عَنْ عِكْرِمَةَ عَنْ ابْنِ عَبَّاسٍ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ نَحْوَهُ وَاللَّهُ أَعْلَمُ","id":"Telah menceritakan kepada kami [Muhammad bin Yahya] berkata, telah menceritakan kepada kami [Ishaq bin Muhammad Al Farwi] berkata, telah menceritakan kepada kami [Abdullah bin Umar] dari [Ubaidullah bin Umar] dari ['Atha] dari [Ibnu Abbas] berkata, \"Rasulullah shallallahu 'alaihi wasallam melewati seorang lelaki di Mekkah yang sedang berdiri di bawah terik matahari. Beliau lalu bertanya: \"Apa yang sedang dilakukan lelaki ini?\" Para sahabat menjawab, \"Dia bernadzar untuk berpuasa, tidak berteduh hingga datang malam, tidak berbicara dan akan terus berdiri.\" Beliau bersabda: \"Suruhlah ia agar berbicara, berteduh, duduk dan menyempurnakan puasanya.\" Telah menceritakan kepada kami [Al Husain bin Muhammad bin Syanbah Al Wasithi] berkata, telah menceritakan kepada kami [Al 'Ala bin Abdul Jabbar] dari [Wuhaib] dari [Ayyub] dari [Ikrimah] dari [Ibnu Abbas] dari Nabi shallallahu 'alaihi wasallam sebagaimana dalam hadits. Waallahu A'lam."},"2093":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ وَعَلِيُّ بْنُ مُحَمَّدٍ وَإِسْحَقُ بْنُ إِبْرَاهِيمَ بْنِ حَبِيبٍ قَالُوا حَدَّثَنَا أَبُو مُعَاوِيَةَ حَدَّثَنَا الْأَعْمَشُ عَنْ إِبْرَاهِيمَ عَنْ الْأَسْوَدِ عَنْ عَائِشَةَ قَالَتْقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِنَّ أَطْيَبَ مَا أَكَلَ الرَّجُلُ مِنْ كَسْبِهِ وَإِنَّ وَلَدَهُ مِنْ كَسْبِهِ","id":"Telah menceritakan kepada kami [Abu Bakr bin Abu Syaibah] dan [Ali bin Muhammad] dan [Ishaq bin Ibrahim bin Habib] mereka berkata; telah menceritakan kepada kami [Abu Mu'awiyah] berkata, telah menceritakan kepada kami [Al A'masy] dari [Ibrahim] dari [Al Aswad] dari ['Aisyah] ia berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Sesuatu yang paling baik untuk dimakan oleh seseorang adalah dari jeri payahnya. Dan anak adalah termasuk dari jeri payahnya.\""},"2094":{"ar":"حَدَّثَنَا هِشَامُ بْنُ عَمَّارٍ حَدَّثَنَا إِسْمَعِيلُ بْنُ عَيَّاشٍ عَنْ بَحِيرِ بْنِ سَعْدٍ عَنْ خَالِدِ بْنِ مَعْدَانَ عَنْ الْمِقْدَامِ بْنِ مَعْدِيكَرِبَ الزُّبَيْدِيِّعَنْ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ مَا كَسَبَ الرَّجُلُ كَسْبًا أَطْيَبَ مِنْ عَمَلِ يَدِهِ وَمَا أَنْفَقَ الرَّجُلُ عَلَى نَفْسِهِ وَأَهْلِهِ وَوَلَدِهِ وَخَادِمِهِ فَهُوَ صَدَقَةٌ","id":"Telah menceritakan kepada kami [Hisyam bin Ammar] berkata, telah menceritakan kepada kami [Isma'il bin 'Ayyasy] dari [Bahir bin Sa'd] dari [Khalid bin Ma'dan] dari [Al Miqdam bin Ma'dikarib Az Zubaidi] dari Rasulullah shallallahu 'alaihi wasallam, beliau bersabda: \"Tidak ada yang lebih baik dari usaha seorang laki-laki kecuali dari hasil tangannya sendiri. Dan apa-apa yang diinfakkan oleh seorang laki-laki kepada diri, isteri, anak dan pembantunya adalah sedekah.\""},"2095":{"ar":"حَدَّثَنَا أَحْمَدُ بْنُ سِنَانٍ حَدَّثَنَا كَثِيرُ بْنُ هِشَامٍ حَدَّثَنَا كُلْثُومُ بْنُ جَوْشَنٍ الْقُشَيْرِيُّ عَنْ أَيُّوبَ عَنْ نَافِعٍ عَنْ ابْنِ عُمَرَ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ التَّاجِرُ الْأَمِينُ الصَّدُوقُ الْمُسْلِمُ مَعَ الشُّهَدَاءِ يَوْمَ الْقِيَامَةِ","id":"Telah menceritakan kepada kami [Ahmad bin Sinan] berkata, telah menceritakan kepada kami [Katsir bin Hisyam] berkata, telah menceritakan kepada kami [Kultsum bin Jausyan Al Qusyairi] dari [Ayyub] dari [Nafi'] dari [Ibnu Umar] ia berkata; \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Seorang pedagang yang dapat dipercaya, jujur dan muslim, maka kelak pada hari kiamat ia akan bersama para syuhada.\""},"2096":{"ar":"حَدَّثَنَا يَعْقُوبُ بْنُ حُمَيْدِ بْنِ كَاسِبٍ حَدَّثَنَا عَبْدُ الْعَزِيزِ الدَّرَاوَرْدِيُّ عَنْ ثَوْرِ بْنِ زَيْدٍ الدِّيْلِيِّ عَنْ أَبِي الْغَيْثِ مَوْلَى ابْنِ مُطِيعٍ عَنْ أَبِي هُرَيْرَةَأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ السَّاعِي عَلَى الْأَرْمَلَةِ وَالْمِسْكِينِ كَالْمُجَاهِدِ فِي سَبِيلِ اللَّهِ وَكَالَّذِي يَقُومُ اللَّيْلَ وَيَصُومُ النَّهَارَ","id":"Telah menceritakan kepada kami [Ya'qub bin Humaid bin Kasib] berkata, telah menceritakan kepada kami [Abdul Aziz Ad Darawardi] dari [Tsaur bin Zaid Ad Daili] dari [Abu Al Ghaits] mantan budak Ibnu Muthi', dari [Abu Hurairah] bahwa Nabi shallallahu 'alaihi wasallam bersabda: \"Orang yang membantu orang janda dan orang miskin seperti mujahid di jalan Allah, atau seperti orang yang shalat malam dan puasa di siang hari.\""},"2097":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا خَالِدُ بْنُ مَخْلَدٍ حَدَّثَنَا عَبْدُ اللَّهِ بْنُ سُلَيْمَانَ عَنْ مُعَاذِ بْنِ عَبْدِ اللَّهِ بْنِ خُبَيْبٍ عَنْ أَبِيهِ عَنْ عَمِّهِ قَالَكُنَّا فِي مَجْلِسٍ فَجَاءَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَعَلَى رَأْسِهِ أَثَرُ مَاءٍ فَقَالَ لَهُ بَعْضُنَا نَرَاكَ الْيَوْمَ طَيِّبَ النَّفْسِ فَقَالَ أَجَلْ وَالْحَمْدُ لِلَّهِ ثُمَّ أَفَاضَ الْقَوْمُ فِي ذِكْرِ الْغِنَى فَقَالَ لَا بَأْسَ بِالْغِنَى لِمَنْ اتَّقَى وَالصِّحَّةُ لِمَنْ اتَّقَى خَيْرٌ مِنْ الْغِنَى وَطِيبُ النَّفْسِ مِنْ النَّعِيمِ","id":"Telah menceritakan kepada kami [Abu Bakr bin Abu Syaibah] berkata, telah menceritakan kepada kami [Khalid bin Makhlad] berkata, telah menceritakan kepada kami [Abdullah bin Sulaiman] dari [Mu'adz bin Abdullah bin Khubaib] dari [Bapaknya] dari [Pamannya] ia berkata, \"Kami sedang duduk-duduk dalam sebuah majelis, lalu Nabi shallallahu 'alaihi wasallam datang, sementara di kepalanya masih ada sisa air mandi. Sebagian kami berkata kepada beliau, \"Hari ini kami melihatmu tampak bahagia, \" beliau lantas menjawab: \"Benar, segala puji bagi Allah.\" Setelah itu orang-orang hanyut dalam perbincangan masalah kekayaan hingga beliau pun bersabda: \"Tidak apa-apa dengan kaya bagi orang yang bertakwa. Dan sehat bagi orang yang bertakwa itu lebih baik dari kaya. Dan bahagia itu bagian dari kenikmatan.\""},"2098":{"ar":"حَدَّثَنَا هِشَامُ بْنُ عَمَّارٍ حَدَّثَنَا إِسْمَعِيلُ بْنُ عَيَّاشٍ عَنْ عُمَارَةَ بْنِ غَزِيَّةَ عَنْ رَبِيعَةَ بْنِ أَبِي عَبْدِ الرَّحْمَنِ عَنْ عَبْدِ الْمَلِكِ بْنِ سَعِيدٍ الْأَنْصَارِيِّ عَنْ أَبِي حُمَيْدٍ السَّاعِدِيِّ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَجْمِلُوا فِي طَلَبِ الدُّنْيَا فَإِنَّ كُلًّا مُيَسَّرٌ لِمَا خُلِقَ لَهُ","id":"Telah menceritakan kepada kami [Hisyam bin Ammar] berkata, telah menceritakan kepada kami [Isma'il bin 'Ayyasy] dari [Umarah bin Ghaziyyah] dari [Rabi'ah bin Abu 'Abdurrahman] dari [Abdul Malik bin Sa'id Al Anshari] dari [Abu Humaid As Sa'idi] ia berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Carilah yang baik dalam mencari dunia, karena setiap orang telah dipermudah dalam melaksanakan bagiannya.\""},"2099":{"ar":"حَدَّثَنَا إِسْمَعِيلُ بْنُ بِهْرَامٍ حَدَّثَنَا الْحَسَنُ بْنُ مُحَمَّدِ بْنِ عُثْمَانَ زَوْجُ بِنْتِ الشَّعْبِيِّ حَدَّثَنَا سُفْيَانُ عَنْ الْأَعْمَشِ عَنْ يَزِيدَ الرَّقَاشِيِّ عَنْ أَنَسِ بْنِ مَالِكٍ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَعْظَمُ النَّاسِ هَمًّا الْمُؤْمِنُ الَّذِي يَهُمُّ بِأَمْرِ دُنْيَاهُ وَآخِرَتِهِقَالَ أَبُو عَبْد اللَّهِ هَذَا حَدِيثٌ غَرِيبٌ تَفَرَّدَ بِهِ إِسْمَعِيلُ","id":"Telah menceritakan kepada kami [Isma'il bin Bihram] berkata, telah menceritakan kepada kami [Al Hasan bin Muhammad bin Utsman] -suami putri Asy Sya'bi- berkata, telah menceritakan kepada kami [Sufyan] dari [Al A'masy] dari [Yazid Ar Raqqasyi] dari [Anas bin Malik] ia berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Manusia yang paling besar semangatnya adalah orang mukmin yang punya perhatian terhadap urusan dunia dan akhiratnya.\" Abu Abdullah berkata, \"Ini adalah hadits gharib dan hanya diriwayatkan oleh Isma'il.\""},"2100":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ الْمُصَفَّى الْحِمْصِيُّ حَدَّثَنَا الْوَلِيدُ بْنُ مُسْلِمٍ عَنْ ابْنِ جُرَيْجٍ عَنْ أَبِي الزُّبَيْرِ عَنْ جَابِرِ بْنِ عَبْدِ اللَّهِ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَيُّهَا النَّاسُ اتَّقُوا اللَّهَ وَأَجْمِلُوا فِي الطَّلَبِ فَإِنَّ نَفْسًا لَنْ تَمُوتَ حَتَّى تَسْتَوْفِيَ رِزْقَهَا وَإِنْ أَبْطَأَ عَنْهَا فَاتَّقُوا اللَّهَ وَأَجْمِلُوا فِي الطَّلَبِ خُذُوا مَا حَلَّ وَدَعُوا مَا حَرُمَ","id":"Telah menceritakan kepada kami [Muhammad bin Al Mushaffa Al Himshi] berkata, telah menceritakan kepada kami [Al Walid bin Muslim] dari [Ibnu Juraij] dari [Abu Zubair] dari [Jabir bin Abdullah] ia berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Wahai manusia, bertakwalah kepada Allah dan carilah yang baik dalam mencari dunia. Sesungguhnya sebuah jiwa tidak akan mati hingga terpenuhi rizkinya meski tersendat-sendat. Bertakwalah kepada Allah, carilah yang baik dalam mencari dunia, ambilah yang halal dan tinggalkan yang haram.\""},"2101":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ عَبْدِ اللَّهِ بْنِ نُمَيْرٍ حَدَّثَنَا أَبُو مُعَاوِيَةَ عَنْ الْأَعْمَشِ عَنْ شَقِيقٍ عَنْ قَيْسِ بْنِ أَبِي غَرَزَةَ قَالَكُنَّا نُسَمَّى فِي عَهْدِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ السَّمَاسِرَةَ فَمَرَّ بِنَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَسَمَّانَا بِاسْمٍ هُوَ أَحْسَنُ مِنْهُ فَقَالَ يَا مَعْشَرَ التُّجَّارِ إِنَّ الْبَيْعَ يَحْضُرُهُ الْحَلِفُ وَاللَّغْوُ فَشُوبُوهُ بِالصَّدَقَةِ","id":"Telah menceritakan kepada kami [Muhammad bin Abdullah bin Numair] berkata, telah menceritakan kepada kami [Abu Mu'awiyah] dari [Al A'masy] dari [Syaqiq] dari [Qais bin Abu Gharazah] ia berkata, \"Pada masa Rasulullah shallallahu 'alaihi wasallam kami diberi julukan dengan nama Samasirah (calo), lalu Rasulullah shallallahu 'alaihi wasallam melewati kami dan memberi nama kami dengan nama yang lebih baik. Beliau bersabda: \"Wahai para pedagang, sesungguhnya perdagangan itu selalu disusupi oleh sumpah palsu, maka susupilah dengan sedekah (seakan-akan itu sebagai kafarahnya).\""},"2102":{"ar":"حَدَّثَنَا يَعْقُوبُ بْنُ حُمَيْدِ بْنِ كَاسِبٍ حَدَّثَنَا يَحْيَى بْنُ سُلَيْمٍ الطَّائِفِيُّ عَنْ عَبْدِ اللَّهِ بْنِ عُثْمَانَ بْنِ خُثَيْمٍ عَنْ إِسْمَعِيلَ بْنِ عُبَيْدِ بْنِ رِفَاعَةَ عَنْ أَبِيهِ عَنْ جَدِّهِ رِفَاعَةَ قَالَخَرَجْنَا مَعَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَإِذَا النَّاسُ يَتَبَايَعُونَ بُكْرَةً فَنَادَاهُمْ يَا مَعْشَرَ التُّجَّارِ فَلَمَّا رَفَعُوا أَبْصَارَهُمْ وَمَدُّوا أَعْنَاقَهُمْ قَالَ إِنَّ التُّجَّارَ يُبْعَثُونَ يَوْمَ الْقِيَامَةِ فُجَّارًا إِلَّا مَنْ اتَّقَى اللَّهَ وَبَرَّ وَصَدَقَ","id":"Telah menceritakan kepada kami [Ya'qub bin Humaid bin Kasib] berkata, telah menceritakan kepada kami [Yahya bin Sulaim Ath Tha`ifi] dari [Abdullah bin Utsman bin Khutsaim] dari [Isma'il bin Ubaid bin Rifa'ah] dari [Bapaknya] dari Kakeknya [Rifa'ah] ia berkata, \"Saat kami keluar bersama Rasulullah shallallahu 'alaihi wasallam, ternyata ada orang-orang sedang berjual beli di pagi yang masih buta. Beliau lantas menyeru mereka: \"Wahai para pedagang.\" Tatkala mereka mengangkat pandangannya dan memanjangkan leher-leher mereka, beliau bersabda: \"Sesungguhnya para pedagang akan dibangkitkan pada hari kiamat dalam keadaan berdosa, kecuali orang yang bertakwa kepada Allah, berbuat baik dan jujur.\""},"2103":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ بَشَّارٍ حَدَّثَنَا مُحَمَّدُ بْنُ عَبْدِ اللَّهِ حَدَّثَنَا فَرْوَةُ أَبُو يُونُسَ عَنْ هِلَالِ بْنِ جُبَيْرٍ عَنْ أَنَسِ بْنِ مَالِكٍ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَنْ أَصَابَ مِنْ شَيْءٍ فَلْيَلْزَمْهُ","id":"Telah menceritakan kepada kami [Muhammad bin Basysyar] berkata, telah menceritakan kepada kami [Muhammad bin Abdullah] berkata, telah menceritakan kepada kami [Farwah Abu Yunus] dari [Hilal bin Jubair] dari [Anas bin Malik] ia berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Barangsiapa diberi sesuatu maka tekunilah ia.\""},"2104":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ يَحْيَى حَدَّثَنَا أَبُو عَاصِمٍ أَخْبَرَنِي أَبِي عَنْ الزُّبَيْرِ بْنِ عُبَيْدٍ عَنْ نَافِعٍ قَالَكُنْتُ أُجَهِّزُ إِلَى الشَّامِ وَإِلَى مِصْرَ فَجَهَّزْتُ إِلَى الْعِرَاقِ فَأَتَيْتُ عَائِشَةَ أُمَّ الْمُؤْمِنِينَ فَقُلْتُ لَهَا يَا أُمَّ الْمُؤْمِنِينَ كُنْتُ أُجَهِّزُ إِلَى الشَّامِ فَجَهَّزْتُ إِلَى الْعِرَاقِ فَقَالَتْ لَا تَفْعَلْ مَا لَكَ وَلِمَتْجَرِكَ فَإِنِّي سَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ إِذَا سَبَّبَ اللَّهُ لِأَحَدِكُمْ رِزْقًا مِنْ وَجْهٍ فَلَا يَدَعْهُ حَتَّى يَتَغَيَّرَ لَهُ أَوْ يَتَنَكَّرَ لَهُ","id":"Telah menceritakan kepada kami [Muhammad bin Yahya] berkata, telah menceritakan kepada kami [Abu 'Ashim] berkata, telah mengabarkan kepadaku [Bapakku] dari [Az Zubair bin Ubaid] dari [Nafi'] ia berkata, \"Aku pernah mempersiapkan perbekalan untuk pergi ke Syam dan Mesir, namun aku mempersiapkan diri untuk pergi ke Iraq. Lalu aku mendatangi ['Aisyah Ummul Mukminin] dan berkata kepadanya, \"Wahai ummul mukminin, aku pernah mempersiapkan diri untuk pergi ke Syam, dan sekarang aku akan berangkat ke Iraq.\" Maka dia berkata, \"Jangan kamu lakukan, apa manfaatnya bagimu dan bagi perniagaanmu, sesungguhnya aku mendengar Rasulullah shallallahu 'alaihi wasallam bersabda: \"Jika Allah membuat sebab bagi seseorang tentang rizkinya dari satu arah, maka janganlah ia meninggalkannya hingga dia berubah atau hilang darinya.\""},"2105":{"ar":"حَدَّثَنَا سُوَيْدُ بْنُ سَعِيدٍ حَدَّثَنَا عَمْرُو بْنُ يَحْيَى بْنِ سَعِيدٍ الْقُرَشِيُّ عَنْ جَدِّهِ سَعِيدِ بْنِ أَبِي أُحَيْحَةَ عَنْ أَبِي هُرَيْرَةَ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَا بَعَثَ اللَّهُ نَبِيًّا إِلَّا رَاعِيَ غَنَمٍ قَالَ لَهُ أَصْحَابُهُ وَأَنْتَ يَا رَسُولَ اللَّهِ قَالَ وَأَنَا كُنْتُ أَرْعَاهَا لِأَهْلِ مَكَّةَ بِالْقَرَارِيطِقَالَ سُوَيْدٌ يَعْنِي كُلَّ شَاةٍ بِقِيرَاطٍ","id":"Telah menceritakan kepada kami [Suwaid bin Sa'id] berkata, telah menceritakan kepada kami ['Amru bin Yahya bin Sa'id Al Qurasyi] dari kakeknya [Sa'id bin Abu Uhaihah] dari [Abu Hurairah] ia berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Tidaklah Allah mengutus seorang Nabi kecuali sebagai pengembala kambing.\" Para sahabatnya bertanya, \"Engkau sendiri bagaimana?\" Beliau menjawab: \"Aku adalah seorang penggembala kambing bagi penduduk Mekkah dengan upah beberapa qirath.\" Suwaid berkata, \"Yang dimaksudnya adalah setiap satu kambing dengan satu qirath.\""},"2106":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ يَحْيَى حَدَّثَنَا مُحَمَّدُ بْنُ عَبْدِ اللَّهِ الْخُزَاعِيُّ وَالْحَجَّاجُ وَالْهَيْثَمُ بْنُ جَمِيلٍ قَالُوا حَدَّثَنَا حَمَّادٌ عَنْ ثَابِتٍ عَنْ أَبِي رَافِعٍ عَنْ أَبِي هُرَيْرَةَأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ كَانَ زَكَرِيَّا نَجَّارًا","id":"Telah menceritakan kepada kami [Muhammad bin Yahya] berkata, telah menceritakan kepada kami [Muhammad bin Abdullah Al Khuza'i] dan [Al Hajjaj] dan [Al Haitsam bin Jamil] mereka berkata; telah menceritakan kepada kami [Hammad] dari [Tsabit] dari [Abu Rabi'] dari [Abu Hurairah] bahwa Rasulullah shallallahu 'alaihi wasallam bersabda: \"Zakaria adalah seorang tukang.\""},"2107":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ رُمْحٍ حَدَّثَنَا اللَّيْثُ بْنُ سَعْدٍ عَنْ نَافِعٍ عَنْ الْقَاسِمِ بْنِ مُحَمَّدٍ عَنْ عَائِشَةَأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ إِنَّ أَصْحَابَ الصُّوَرِ يُعَذَّبُونَ يَوْمَ الْقِيَامَةِ يُقَالُ لَهُمْ أَحْيُوا مَا خَلَقْتُمْ","id":"Telah menceritakan kepada kami [Muhammad bin Rumh] berkata, telah menceritakan kepada kami [Al Laits bin Sa'd] dari [Nafi'] dari [Al Qasim bin Muhammad] dari ['Aisyah] bahwa Rasulullah shallallahu 'alaihi wasallam bersabda: \"Sesungguhnya para pelukis pada hari kiamat akan disiksa. Dikatakan kepada mereka, \"Hidupkanlah apa yang telah engkau ciptakan.\""},"2108":{"ar":"حَدَّثَنَا عَمْرُو بْنُ رَافِعٍ حَدَّثَنَا عُمَرُ بْنُ هَارُونَ عَنْ هَمَّامٍ عَنْ فَرْقَدٍ السَّبَخِيِّ عَنْ يَزِيدَ بْنِ عَبْدِ اللَّهِ بْنِ الشِّخِّيرِ عَنْ أَبِي هُرَيْرَةَ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَكْذَبُ النَّاسِ الصَّبَّاغُونَ وَالصَّوَّاغُونَ","id":"Telah menceritakan kepada kami [Amru bin Rafi'] berkata, telah menceritakan kepada kami [Umar bin Harun] dari [Hammam] dari [Farqad As Sabakhi] dari [Yazid bin Abdullah bin Asy Syikhir] dari [Abu Hurairah] ia berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Sedusta-dusta manusia adalah para pencelup (pewarna kain) dan orang-orang yang padai berselit lidah.\""},"2109":{"ar":"حَدَّثَنَا نَصْرُ بْنُ عَلِيٍّ الْجَهْضَمِيُّ حَدَّثَنَا أَبُو أَحْمَدَ حَدَّثَنَا إِسْرَائِيلُ عَنْ عَلِيِّ بْنِ سَالِمِ بْنِ ثَوْبَانَ عَنْ عَلِيِّ بْنِ زَيْدِ بْنِ جُدْعَانَ عَنْ سَعِيدِ بْنِ الْمُسَيَّبِ عَنْ عُمَرَ بْنِ الْخَطَّابِ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ الْجَالِبُ مَرْزُوقٌ وَالْمُحْتَكِرُ مَلْعُونٌ","id":"Telah menceritakan kepada kami [Nashr bin Ali Al Jahdlami] telah menceritakan kepada kami [Abu Ahmad] Telah menceritakan kepada kami [Isra`il] dari [Ali bin Salim bin Tsauban] dari [Ali bin Zaid bin Jud'an] dari [Sa'id bin Al Musayyab] dari [Umar bin Khaththab] ia berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Orang yang mencari nafkah itu diberi rizki dan orang yang menimbun itu dilaknat.\""},"2110":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا يَزِيدُ بْنُ هَارُونَ عَنْ مُحَمَّدِ بْنِ إِسْحَقَ عَنْ مُحَمَّدِ بْنِ إِبْرَاهِيمَ عَنْ سَعِيدِ بْنِ الْمُسَيَّبِ عَنْ مَعْمَرِ بْنِ عَبْدِ اللَّهِ بْنِ نَضْلَةَ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَا يَحْتَكِرُ إِلَّا خَاطِئٌ","id":"Telah menceritakan kepada kami [Abu Bakr bin Abu Syaibah] berkata, telah menceritakan kepada kami [Yazid bin Harun] dari [Muhammad bin Ishaq] dari [Muhammad bin Ibrahim] dari [Sa'id Ibnul Musayyab] dari [Ma'mar bin Abdullah bin Nadllah] ia berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Tidak ada yang menimbun kecuali orang yang salah.\""},"2111":{"ar":"حَدَّثَنَا يَحْيَى بْنُ حَكِيمٍ حَدَّثَنَا أَبُو بَكْرٍ الْحَنَفِيُّ حَدَّثَنَا الْهَيْثَمُ بْنُ رَافِعٍ حَدَّثَنِي أَبُو يَحْيَى الْمَكِّيُّ عَنْ فَرُّوخَ مَوْلَى عُثْمَانَ بْنِ عَفَّانَ عَنْ عُمَرَ بْنِ الْخَطَّابِ قَالَسَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ مَنْ احْتَكَرَ عَلَى الْمُسْلِمِينَ طَعَامًا ضَرَبَهُ اللَّهُ بِالْجُذَامِ وَالْإِفْلَاسِ","id":"Telah menceritakan kepada kami [Yahya bin Hakim] berkata, telah menceritakan kepada kami [Abu Bakr Al Hanafi] berkata, telah menceritakan kepada kami [Al Haitsam bin Rafi'] berkata, telah menceritakan kepadaku [Abu Yahya Al Makki] dari [Farukh] -mantan budak Utsman bin Affan- dari [Umar Ibnul Khaththab] ia berkata, \"Aku mendengar Rasulullah shallallahu 'alaihi wasallam bersabda: \"Barangsiapa menimbun makanan atas kaum muslimin, maka Allah akan menghukumnya dengan penyakit dan kerugian.\""},"2112":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ عَبْدِ اللَّهِ بْنِ نُمَيْرٍ حَدَّثَنَا أَبُو مُعَاوِيَةَ حَدَّثَنَا الْأَعْمَشُ عَنْ جَعْفَرِ بْنِ إِيَاسٍ عَنْ أَبِي نَضْرَةَ عَنْ أَبِي سَعِيدٍ الْخُدْرِيِّ قَالَبَعَثَنَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ ثَلَاثِينَ رَاكِبًا فِي سَرِيَّةٍ فَنَزَلْنَا بِقَوْمٍ فَسَأَلْنَاهُمْ أَنْ يَقْرُونَا فَأَبَوْا فَلُدِغَ سَيِّدُهُمْ فَأَتَوْنَا فَقَالُوا أَفِيكُمْ أَحَدٌ يَرْقِي مِنْ الْعَقْرَبِ فَقُلْتُ نَعَمْ أَنَا وَلَكِنْ لَا أَرْقِيهِ حَتَّى تُعْطُونَا غَنَمًا قَالُوا فَإِنَّا نُعْطِيكُمْ ثَلَاثِينَ شَاةً فَقَبِلْنَاهَا فَقَرَأْتُ عَلَيْهِ الْحَمْدُ سَبْعَ مَرَّاتٍ فَبَرِئَ وَقَبَضْنَا الْغَنَمَ فَعَرَضَ فِي أَنْفُسِنَا مِنْهَا شَيْءٌ فَقُلْنَا لَا تَعْجَلُوا حَتَّى نَأْتِيَ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَلَمَّا قَدِمْنَا ذَكَرْتُ لَهُ الَّذِي صَنَعْتُ فَقَالَ أَوَ مَا عَلِمْتَ أَنَّهَا رُقْيَةٌ اقْتَسِمُوهَا وَاضْرِبُوا لِي مَعَكُمْ سَهْمًاحَدَّثَنَا أَبُو كُرَيْبٍ حَدَّثَنَا هُشَيْمٌ حَدَّثَنَا أَبُو بِشْرٍ عَنْ ابْنِ أَبِي الْمُتَوَكِّلِ عَنْ أَبِي الْمُتَوَكِّلِ عَنْ أَبِي سَعِيدٍ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِنَحْوِهِ و حَدَّثَنَا مُحَمَّدُ بْنُ بَشَّارٍ حَدَّثَنَا مُحَمَّدُ بْنُ جَعْفَرٍ حَدَّثَنَا شُعْبَةُ عَنْ أَبِي بِشْرٍ عَنْ أَبِي الْمُتَوَكِّلِ عَنْ أَبِي سَعِيدٍ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِنَحْوِهِ قَالَ أَبُو عَبْد اللَّهِ وَالصَّوَابُ هُوَ أَبُو الْمُتَوَكِّلِ","id":"Telah menceritakan kepada kami [Muhammad bin Abdullah bin Numair] berkata, telah menceritakan kepada kami [Abu Mu'awiyah] berkata, telah menceritakan kepada kami [Al A'masy] dari [Ja'far bin Iyas] dari [Abu Nadlrah] dari [Abu Sa'id Al Khudri] ia berkata, \"Rasulullah shallallahu 'alaihi wasallam mengutus kami dalam sebuah ekspedisi dengan tiga puluh penunggang kuda. Lalu kami singgah pada suatu kaum, kami meminta agar mereka mau menerima kami sebagai tamu, namun mereka menolak. Kemudian pemimpin mereka disengat oleh binatang hingga mereka mendatangi kami. Mereka berkata, \"Apakah di antara kalian ada seseorang yang bisa meruqyah dari sengatan kalajengking?\" aku menjawab, \"Ya, aku bisa. Namun aku tidak akan meruqyahnya hingga kalian memberi kami kambing.\" Mereka berkata, \"Kami akan memberikan tiga puluh kambing kepada kalian.\" Kami pun sepakat dengan mereka. Kemudian aku bacakan AL HAMDULILLAH sebanyak tujuh kali, dan ia pun sembuh. Lantas kami mengambil kambing tersebut, namun ada sesuatu yang mengganjal dalam hati kami, hingga kami berkata, \"Janganlah kalian terburu-buru sehingga kita mendatangi Nabi shallallahu 'alaihi wasallam.\" Ketika kami tiba (di Madinah), aku ceritakan apa yang telah aku lakukan itu kepada beliau, beliau pun bersabda: \"Tidak tahukan kalian bahwa itu adalah ruqyah? Bagikanlah kambing itu dan berikan bagianku.\" Telah menceritakan kepada kami [Abu Kuraib] berkata, telah menceritakan kepada kami [Husyaim] berkata, telah menceritakan kepada kami [Abu Bisyr] dari Ibnu Abu Al Mutawakkil dari [Abu Al Mutawakkil] dari [Abu Sa'id] dari Nabi shallallahu 'alaihi wasallam sebagaimana dalam hadits.\" (dalam jalur lain disebutkan) Telah menceritakan kepada kami [Muhammad bin Basysyar] berkata, telah menceritakan kepada kami [Muhammad bin Ja'far] berkata, telah menceritakan kepada kami [Syu'bah] dari [Abu Bisyr] dari [Abu Al Mutawakkil] dari [Abu Sa'id] dari Nabi shallallahu 'alaihi wasallam sebagaimana dalam hadits.\" Abdullah berkata, \"Yang benar, dia adalah Abu Al Mutawakkil.\""},"2113":{"ar":"حَدَّثَنَا عَلِيُّ بْنُ مُحَمَّدٍ وَمُحَمَّدُ بْنُ إِسْمَعِيلَ قَالَا حَدَّثَنَا وَكِيعٌ حَدَّثَنَا مُغِيرَةُ بْنُ زِيَادٍ الْمَوْصِلِيُّ عَنْ عُبَادَةَ بْنِ نُسَيٍّ عَنْ الْأَسْوَدِ بْنِ ثَعْلَبَةَ عَنْ عُبَادَةَ بْنِ الصَّامِتِ قَالَعَلَّمْتُ نَاسًا مِنْ أَهْلِ الصُّفَّةِ الْقُرْآنَ وَالْكِتَابَةَ فَأَهْدَى إِلَيَّ رَجُلٌ مِنْهُمْ قَوْسًا فَقُلْتُ لَيْسَتْ بِمَالٍ وَأَرْمِي عَنْهَا فِي سَبِيلِ اللَّهِ فَسَأَلْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَنْهَا فَقَالَ إِنْ سَرَّكَ أَنْ تُطَوَّقَ بِهَا طَوْقًا مِنْ نَارٍ فَاقْبَلْهَا","id":"Telah menceritakan kepada kami [Ali bin Muhammad] dan [Muhammad bin Isma'il] keduanya berkata; telah menceritakan kepada kami [Waki'] berkata, telah menceritakan kepada kami [Mughirah bin Ziyad Al Maushili] dari [Ubadah bin Nusai] dari [Al Aswad bin Tsa'labah] dari [Ubadah bin Ash Shamit] ia berkata, \"Aku mengajari Al Quran dan menulis kepada beberapa orang dari penghuni Ash Shuffah, lalu seorang dari mereka memberiku hadiah sebuah tombak. Maka aku pun berkata, \"Ini bukanlah termasuk harta, dan aku gunakan di jalan Allah. Lalu aku tanyakan hal itu kepada Rasulullah shallallahu 'alaihi wasallam, beliau menjawab: \"Jika engkau suka untuk dihimpit api neraka, maka terimalah.\""},"2114":{"ar":"حَدَّثَنَا سَهْلُ بْنُ أَبِي سَهْلٍ حَدَّثَنَا يَحْيَى بْنُ سَعِيدٍ عَنْ ثَوْرِ بْنِ يَزِيدَ حَدَّثَنَا خَالِدُ بْنُ مَعْدَانَ حَدَّثَنِي عَبْدُ الرَّحْمَنِ بْنُ سَلْمٍ عَنْ عَطِيَّةَ الْكَلَاعِيِّ عَنْ أُبَيِّ بْنِ كَعْبٍ قَالَعَلَّمْتُ رَجُلًا الْقُرْآنَ فَأَهْدَى إِلَيَّ قَوْسًا فَذَكَرْتُ ذَلِكَ لِرَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ إِنْ أَخَذْتَهَا أَخَذْتَ قَوْسًا مِنْ نَارٍ فَرَدَدْتُهَا","id":"Telah menceritakan kepada kami [Sahl bin Abu Sahl] berkata, telah menceritakan kepada kami [Yahya bin Sa'id] dari [Tsaur bin Yazid] berkata, telah menceritakan kepada kami [Khalid bin Ma'dan] berkata, telah menceritakan kepadaku ['Abdurrahman bin Salm] dari ['Athiyyah Al Kala'i] dari [Ubay bin Ka'b] ia berkata, \"Aku menganjarkan Al Qur'an kepada seseorang, kemudian dia memberi hadiah kepadaku satu busur panah. Lalu aku menyampaikan hal itu kepada Rasulullah shallallahu 'alaihi wasallam, beliau bersabda: \"Jika kamu mengambilnya berarti kamu telah mengambil busur panah dari neraka.\" Maka aku pun mengembalikannya.\""},"2115":{"ar":"حَدَّثَنَا هِشَامُ بْنُ عَمَّارٍ وَمُحَمَّدُ بْنُ الصَّبَّاحِ قَالَا حَدَّثَنَا سُفْيَانُ بْنُ عُيَيْنَةَ عَنْ الزُّهْرِيِّ عَنْ أَبِي بَكْرِ بْنِ عَبْدِ الرَّحْمَنِ عَنْ أَبِي مَسْعُودٍأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ نَهَى عَنْ ثَمَنِ الْكَلْبِ وَمَهْرِ الْبَغِيِّ وَحُلْوَانِ الْكَاهِنِ","id":"Telah menceritakan kepada kami [Hisyam bin Ammar] dan [Muhammad bin Ash Shabbah] keduanya berkata; telah menceritakan kepada kami [Sufyan bin Uyainah] dari [Az Zuhri] dari [Abu Bakr bin 'Abdurrahman] dari [Abu Mas'ud] berkata, \"Nabi shallallahu 'alaihi wasallam melarang kami makan hasil penjualan anjing, upah pelacur dan upah dukun.\""},"2116":{"ar":"حَدَّثَنَا عَلِيُّ بْنُ مُحَمَّدٍ وَمُحَمَّدُ بْنُ طَرِيفٍ قَالَا حَدَّثَنَا مُحَمَّدُ بْنُ فُضَيْلٍ حَدَّثَنَا الْأَعْمَشُ عَنْ أَبِي حَازِمٍ عَنْ أَبِي هُرَيْرَةَ قَالَنَهَى رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَنْ ثَمَنِ الْكَلْبِ وَعَسْبِ الْفَحْلِ","id":"Telah menceritakan kepada kami [Ali bin Muhammad] dan [Muhammad bin Tharif] keduanya berkata; telah menceritakan kepada kami [Muhammad bin Fudlail] berkata, telah menceritakan kepada kami [Al A'masy] dari [Abu Hazim] dari [Abu Hurairah] ia berkata, \"Rasulullah shallallahu 'alaihi wasallam melarang makan dari hasil penjualan anjing dan hasi zina.\""},"2117":{"ar":"حَدَّثَنَا هِشَامُ بْنُ عَمَّارٍ حَدَّثَنَا الْوَلِيدُ بْنُ مُسْلِمٍ أَنْبَأَنَا ابْنُ لَهِيعَةَ عَنْ أَبِي الزُّبَيْرِ عَنْ جَابِرٍ قَالَنَهَى رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَنْ ثَمَنِ السِّنَّوْرِ","id":"Telah menceritakan kepada kami [Hisyam bin Ammar] berkata, telah menceritakan kepada kami [Al Walid bin Muslim] berkata, telah memberitakan kepada kami [Ibnu Lahi'ah] dari [Abu Az Zubair] dari [Jabir] ia berkata; \"Rasulullah shallallahu 'alaihi wasallam melarang harta penjualan kucing.\""},"2118":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ أَبِي عُمَرَ الْعَدَنِيُّ حَدَّثَنَا سُفْيَانُ بْنُ عُيَيْنَةَ عَنْ ابْنِ طَاوُسٍ عَنْ أَبِيهِ عَنْ ابْنِ عَبَّاسٍأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ احْتَجَمَ وَأَعْطَاهُ أَجْرَهُتَفَرَّدَ بِهِ ابْنُ أَبِي عُمَرَ وَحْدَهُ قَالَهُ ابْن مَاجَةَ","id":"Telah menceritakan kepada kami [Muhammad bin Abu Umar Al Adani] berkata, telah menceritakan kepada kami [Sufyan bin Uyainah] dari [Ibnu Thawus] dari [Bapaknya] dari [Ibnu Abbas] berkata, \"Nabi shallallahu 'alaihi wasallam pernah melakukan bekam dan memberikan upahnya.\" Ibnu Majah berkata, \"Hadits ini hanya diriwayatkan oleh Ibnu Abu Umar.\""},"2119":{"ar":"حَدَّثَنَا عَمْرُو بْنُ عَلِيٍّ أَبُو حَفْصٍ الصَّيْرَفِيُّ حَدَّثَنَا أَبُو دَاوُدَ ح و حَدَّثَنَا مُحَمَّدُ بْنُ عُبَادَةَ الْوَاسِطِيُّ حَدَّثَنَا يَزِيدُ بْنُ هَارُونَ قَالَا حَدَّثَنَا وَرْقَاءُ عَنْ عَبْدِ الْأَعْلَى عَنْ أَبِي جَمِيلَةَ عَنْ عَلِيٍّ قَالَاحْتَجَمَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَأَمَرَنِي فَأَعْطَيْتُ الْحَجَّامَ أَجْرَهُ","id":"Telah menceritakan kepada kami [Amru bin Ali Abu Hafsh Ash Shairafi] berkata, telah menceritakan kepada kami [Abu Dawud]. (dalam jalur lain disebutkan) Telah menceritakan kepada kami [Muhammad bin Ubadah Al Wasithi] berkata, telah menceritakan kepada kami [Yazid bin Harun] keduanya berkata; telah menceritakan kepada kami [Warqa] dari [Abdul A'la] dari [Abu Jamilah] dari [Ali] ia berkata, \"Rasulullah shallallahu 'alaihi wasallam melakukan bekam, dan beliau memerintahkan aku untuk memberi upah kepada tukang bekamnya.\""},"2120":{"ar":"حَدَّثَنَا عَبْدُ الْحَمِيدِ بْنُ بَيَانٍ الْوَاسِطِيُّ حَدَّثَنَا خَالِدُ بْنُ عَبْدِ اللَّهِ عَنْ يُونُسَ عَنْ ابْنِ سِيرِينَ عَنْ أَنَسِ بْنِ مَالِكٍأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ احْتَجَمَ وَأَعْطَى الْحَجَّامَ أَجْرَهُ","id":"Telah menceritakan kepada kami [Abdul Hamid bin Bayan Al Wasithi] berkata, telah menceritakan kepada kami [Khalid bin Abdullah] dari [Yunus] dari [Ibnu Sirin] dari [Anas bin Malik] berkata, \"Nabi shallallahu 'alaihi wasallam melakukan bekam dan memberikan upah kepada tukang bekamnya.\""},"2121":{"ar":"حَدَّثَنَا هِشَامُ بْنُ عَمَّارٍ حَدَّثَنَا يَحْيَى بْنُ حَمْزَةَ حَدَّثَنِي الْأَوْزَاعِيُّ عَنْ الزُّهْرِيِّ عَنْ أَبِي بَكْرِ بْنِ عَبْدِ الرَّحْمَنِ بْنِ الْحَارِثِ بْنِ هِشَامٍ عَنْ أَبِي مَسْعُودٍ عُقْبَةَ بْنِ عَمْرٍو قَالَنَهَى رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَنْ كَسْبِ الْحَجَّامِ","id":"Telah menceritakan kepada kami [Hisyam bin Ammar] berkata, telah menceritakan kepada kami [Yahya bin Hamzah] berkata, telah menceritakan kepadaku [Al Auza'I] dari [Az Zuhri] dari [Abu Bakr bin 'Abdurrahman bin Al Harits bin Hisyam] dari [Abu Mas'ud Uqbah bin Amru] ia berkata, \"Rasulullah shallallahu 'alaihi wasallam melarang mengambil upah bekam.\""},"2122":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا شَبَابَةُ بْنُ سَوَّارٍ عَنْ ابْنِ أَبِي ذِئْبٍ عَنْ الزُّهْرِيِّ عَنْ حَرَامِ بْنِ مُحَيِّصَةَ عَنْ أَبِيهِأَنَّهُ سَأَلَ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَنْ كَسْبِ الْحَجَّامِ فَنَهَاهُ عَنْهُ فَذَكَرَ لَهُ الْحَاجَةَ فَقَالَ اعْلِفْهُ نَوَاضِحَكَ","id":"Telah menceritakan kepada kami [Abu Bakr bin Abu Syaibah] berkata, telah menceritakan kepada kami [Syababah bin Sawwar] dari [Ibnu Abu Dzi`b] dari [Az Zuhri] dari [Haram bin Muhayyishah] dari [Bapaknya] bahwa ia pernah bertanya Nabi shallallahu 'alaihi wasallam tentang upah bekam, namun beliau melarangnya. Lalu disebutkan kepada beliau suatu kebutuhan, beliau pun bersabda: \"Berilah untuk makan untamu.\""},"2123":{"ar":"حَدَّثَنَا عِيسَى بْنُ حَمَّادٍ الْمِصْرِيُّ أَنْبَأَنَا اللَّيْثُ بْنُ سَعْدٍ عَنْ يَزِيدَ بْنِ أَبِي حَبِيبٍ أَنَّهُ قَالَ قَالَ عَطَاءُ بْنُ أَبِي رَبَاحٍ سَمِعْتُ جَابِرَ بْنَ عَبْدِ اللَّهِ يَقُولُقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَامَ الْفَتْحِ وَهُوَ بِمَكَّةَ إِنَّ اللَّهَ وَرَسُولَهُ حَرَّمَ بَيْعَ الْخَمْرِ وَالْمَيْتَةِ وَالْخِنْزِيرِ وَالْأَصْنَامِ فَقِيلَ لَهُ عِنْدَ ذَلِكَ يَا رَسُولَ اللَّهِ أَرَأَيْتَ شُحُومَ الْمَيْتَةِ فَإِنَّهُ يُدْهَنُ بِهَا السُّفُنُ وَيُدْهَنُ بِهَا الْجُلُودُ وَيَسْتَصْبِحُ بِهَا النَّاسُ قَالَ لَا هُنَّ حَرَامٌ ثُمَّ قَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَاتَلَ اللَّهُ الْيَهُودَ إِنَّ اللَّهَ حَرَّمَ عَلَيْهِمْ الشُّحُومَ فَأَجْمَلُوهُ ثُمَّ بَاعُوهُ فَأَكَلُوا ثَمَنَهُ","id":"Telah menceritakan kepada kami [Isa bin Hammad Al Mishri] berkata, telah memberitakan kepada kami [Al Laits bin Sa'd] dari [Yazid bin Abu Habib] Bahwasanya ia berkata; ['Atha bin Abu Rabah] berkata, \"Aku mendengar [Jabir bin Abdullah] berkata, \"Ketika Rasulullah shallallahu 'alaihi wasallam berada di Makkah saat pembukaan kota Makkah, beliau bersabda: \"Sesungguhnya Allah dan Rasul-Nya telah mengharamkan penjualan khamer, bangkai, babi dan patung.\" Lalu dikatakan kepada beliau, \"Wahai Rasulullah, bagaimana dengan lemak bangkai? Ia bisa digunakan sebagai pelumas kapal, pelumas kulit dan minyak untuk lampu mereka.\" beliau menjawab: \"Itu tidak haram.\" Kemudian beliau melanjutkan: \"Semoga Allah memerangi orang-orang yahudi, sesungguhnya Allah telah mengharamkan lemak atas mereka. Maka cairkanlah (lemak tersebut hingga keluar minyaknya), kemudian jual dan makanlah dari hasilnya.\""},"2124":{"ar":"حَدَّثَنَا أَحْمَدُ بْنُ مُحَمَّدِ بْنِ يَحْيَى بْنِ سَعِيدٍ الْقَطَّانِ حَدَّثَنَا هَاشِمُ بْنُ الْقَاسِمِ حَدَّثَنَا أَبُو جَعْفَرٍ الرَّازِيُّ عَنْ عَاصِمٍ عَنْ أَبِي الْمُهَلَّبِ عَنْ عُبَيْدِ اللَّهِ الْإِفْرِيقِيِّ عَنْ أَبِي أُمَامَةَ قَالَنَهَى رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَنْ بَيْعِ الْمُغَنِّيَاتِ وَعَنْ شِرَائِهِنَّ وَعَنْ كَسْبِهِنَّ وَعَنْ أَكْلِ أَثْمَانِهِنَّ","id":"Telah menceritakan kepada kami [Ahmad bin Muhammad bin Yahya bin Sa'id Al Qaththan] berkata, telah menceritakan kepada kami [Hasyim bin Al Qasim] berkata, telah menceritakan kepada kami [Abu Ja'far Ar Razi] dari ['Ashim] dari [Abul Muhallab] dari [Ubaidullah Al Ifriqi] dari [Abu Umamah] ia berkata, \"Rasulullah shallallahu 'alaihi wasallam melarang menjual para wanita penyanyi, membelinya, mengambil keuntungannya dan memakan harganya.\""},"2125":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا عَبْدُ اللَّهِ بْنُ نُمَيْرٍ وَأَبُو أُسَامَةَ عَنْ عُبَيْدِ اللَّهِ بْنِ عُمَرَ عَنْ خُبَيْبِ بْنِ عَبْدِ الرَّحْمَنِ عَنْ حَفْصِ بْنِ عَاصِمٍ عَنْ أَبِي هُرَيْرَةَ قَالَنَهَى رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَنْ بَيْعَتَيْنِ عَنْ الْمُلَامَسَةِ وَالْمُنَابَذَةِ","id":"Telah menceritakan kepada kami [Abu Bakr bin Abu Syaibah] berkata, telah menceritakan kepada kami [Abdullah bin Numair] dan [Abu Usamah] dari [Ubaidullah bin Umar] dari [Khubaib bin 'Abdurrahman] dari [Hafsh bin Ashim] dari [Abu Hurairah] ia berkata, \"Rasulullah shallallahu 'alaihi wasallam melarang dari dua model jual beli; Mulamasah dan Munabadzah.\" "},"2126":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ وَسَهْلُ بْنُ أَبِي سَهْلٍ قَالَا حَدَّثَنَا سُفْيَانُ بْنُ عُيَيْنَةَ عَنْ الزُّهْرِيِّ عَنْ عَطَاءِ بْنِ يَزِيدَ اللَّيْثِيِّ عَنْ أَبِي سَعِيدٍ الْخُدْرِيِّأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ نَهَى عَنْ الْمُلَامَسَةِ وَالْمُنَابَذَةِزَادَ سَهْلٌ قَالَ سُفْيَانُ الْمُلَامَسَةُ أَنْ يَلْمِسَ الرَّجُلُ بِيَدِهِ الشَّيْءَ وَلَا يَرَاهُ وَالْمُنَابَذَةُ أَنْ يَقُولَ أَلْقِ إِلَيَّ مَا مَعَكَ وَأُلْقِي إِلَيْكَ مَا مَعِي","id":"Telah menceritakan kepada kami [Abu Bakr bin Abu Syaibah] dan [Sahl bin Abu Sahl] keduanya berkata; telah menceritakan kepada kami [Sufyan bin Uyainah] dari [Az Zuhri] dari ['Atha bin Yazid Al laitsi] dari [Abu Sa'id Al Khudri] berkata; \"Rasulullah shallallahu 'alaihi wasallam melarang jual beli dengan sistem mulamasah dan menabadzah.\" Sahl menambahkan, \"Sufyan berkata, \"Mulamasah adalah seseorang memegang barang (dagangan) tanpa memperhatikannya. Sedangkan munabadzah, seseorang mengatakan, 'lemparkanlah barang milikmu kepadaku, maka aku akan melempar barang milikku'.\""},"2127":{"ar":"حَدَّثَنَا سُوَيْدُ بْنُ سَعِيدٍ حَدَّثَنَا مَالِكُ بْنُ أَنَسٍ عَنْ نَافِعٍ عَنْ ابْنِ عُمَرَأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ لَا يَبِيعُ بَعْضُكُمْ عَلَى بَيْعِ بَعْضٍ","id":"Telah menceritakan kepada kami [Suwaid bin Sa'id] berkata, telah menceritakan kepada kami [Malik bin Anas] dari [Nafi'] dari [Ibnu Umar] bahwa Rasulullah shallallahu 'alaihi wasallam bersabda: \"Janganlah salah seorang dari kalian bertrasasaksi atas transaksi saudaranya.\""},"2128":{"ar":"حَدَّثَنَا هِشَامُ بْنُ عَمَّارٍ حَدَّثَنَا سُفْيَانُ عَنْ الزُّهْرِيِّ عَنْ سَعِيدِ بْنِ الْمُسَيَّبِ عَنْ أَبِي هُرَيْرَةَعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ لَا يَبِيعُ الرَّجُلُ عَلَى بَيْعِ أَخِيهِ وَلَا يَسُومُ عَلَى سَوْمِ أَخِيهِ","id":"Telah menceritakan kepada kami [Hisyam bin Ammar] berkata, telah menceritakan kepada kami [Sufyan] dari [Az Zuhri] dari [Sa'id Ibnul Musayyab] dari [Abu Hurairah] dari Nabi shallallahu 'alaihi wasallam, beliau bersabda: \"Janganlah seorang laki-laki melakukan transaksi atas transaksi saudaranya, atau menawar atas tawaran saudaranya.\""},"2129":{"ar":"قَرَأْتُ عَلَى مُصْعَبِ بْنِ عَبْدِ اللَّهِ الزُّبَيْرِيِّ عَنْ مَالِكٍ ح و حَدَّثَنَا أَبُو حُذَافَةَ حَدَّثَنَا مَالِكُ بْنُ أَنَسٍ عَنْ نَافِعٍ عَنْ ابْنِ عُمَرَأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ نَهَى عَنْ النَّجْشِ","id":"Aku membaca di hadapan [Mush'ab bin Abdullah Az Zubairi] dari [Malik]. (dan diriwayatkan dari jalur lain) Telah menceritakan kepada kami [Abu Hudzafah] berkata, telah menceritakan kepada kami [Malik bin Anas] dari [Nafi'] dari [Ibnu Umar] berkata, \"Nabi shallallahu 'alaihi wasallam melarang jual beli dengan cara Najasy (menambah harga untuk menipu pembeli).\""},"2130":{"ar":"حَدَّثَنَا هِشَامُ بْنُ عَمَّارٍ وَسَهْلُ بْنُ أَبِي سَهْلٍ قَالَا حَدَّثَنَا سُفْيَانُ عَنْ الزُّهْرِيِّ عَنْ سَعِيدٍ عَنْ أَبِي هُرَيْرَةَعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ لَا تَنَاجَشُوا","id":"Telah menceritakan kepada kami [Hisyam bin Ammar] dan [Sahl bin Abu Sahl] keduanya berkata; telah menceritakan kepada kami [Sufyan] dari [Az Zuhri] dari [Sa'id] dari [Abu Hurairah] dari Nabi shallallahu 'alaihi wasallam, beliau bersabda: \"Janganlah kalian jual beli dengan cara Najasy (menambah harga untuk menipu pembeli).\""},"2131":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا سُفْيَانُ بْنُ عُيَيْنَةَ عَنْ الزُّهْرِيِّ عَنْ سَعِيدِ بْنِ الْمُسَيَّبِ عَنْ أَبِي هُرَيْرَةَأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ لَا يَبِيعُ حَاضِرٌ لِبَادٍ","id":"Telah menceritakan kepada kami [Abu Bakr bin Abu Syaibah] berkata, telah menceritakan kepada kami [Sufyan bin Uyainah] dari [Az Zuhri] dari [Sa'id Ibnul Musayyab] dari [Abu Hurairah] bahwa Rasulullah shallallahu 'alaihi wasallam bersabda: \"Janganlah orang kota menjual kepada orang kampung.\""},"2132":{"ar":"حَدَّثَنَا هِشَامُ بْنُ عَمَّارٍ حَدَّثَنَا سُفْيَانُ بْنُ عُيَيْنَةَ عَنْ أَبِي الزُّبَيْرِ عَنْ جَابِرِ بْنِ عَبْدِ اللَّهِأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ لَا يَبِيعُ حَاضِرٌ لِبَادٍ دَعُوا النَّاسَ يَرْزُقُ اللَّهُ بَعْضَهُمْ مِنْ بَعْضٍ","id":"Telah menceritakan kepada kami [Hisyam bin Ammar] berkata, telah menceritakan kepada kami [Sufyan bin Uyainah] dari [Abu Az Zubair] dari [Jabir bin Abdullah] bahwa Nabi shallallahu 'alaihi wasallam bersabda: \"Janganlah orang kota menjual kepada orang kampung. Biarkanlah mereka, Allah akan memberi rizki mereka dengan perantara sesama mereka.\""},"2133":{"ar":"حَدَّثَنَا الْعَبَّاسُ بْنُ عَبْدِ الْعَظِيمِ الْعَنْبَرِيُّ حَدَّثَنَا عَبْدُ الرَّزَّاقِ أَنْبَأَنَا مَعْمَرٌ عَنْ ابْنِ طَاوُسٍ عَنْ أَبِيهِ عَنْ ابْنِ عَبَّاسٍ قَالَنَهَى رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنْ يَبِيعَ حَاضِرٌ لِبَادٍقُلْتُ لِابْنِ عَبَّاسٍ مَا قَوْلُهُ حَاضِرٌ لِبَادٍ قَالَ لَا يَكُونُ سِمْسَارًا","id":"Telah menceritakan kepada kami [Al Abbas bin Abdul Azhim Al 'Anbari] berkata, telah menceritakan kepada kami [Abdurrazaq] berkata, telah memberitakan kepada kami [Ma'mar] dari [Ibnu Thawus] dari [Bapaknya] dari [Ibnu Abbas] ia berkata, \"Rasulullah shallallahu 'alaihi wasallam melarang orang kota menjual kepada orang kampung.\" Aku bertanya Ibnu Abbas, \"Apa maksud sabda beliau 'orang kota menjual kepada orang kampung'?\" ia menjawab, \"Jangan sampai ia menjadi calo.\""},"2134":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ وَعَلِيُّ بْنُ مُحَمَّدٍ قَالَا حَدَّثَنَا أَبُو أُسَامَةَ عَنْ هِشَامِ بْنِ حَسَّانَ عَنْ مُحَمَّدِ بْنِ سِيرِينَ عَنْ أَبِي هُرَيْرَةَعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ لَا تَلَقَّوْا الْأَجْلَابَ فَمَنْ تَلَقَّى مِنْهُ شَيْئًا فَاشْتَرَى فَصَاحِبُهُ بِالْخِيَارِ إِذَا أَتَى السُّوقَ","id":"Telah menceritakan kepada kami [Abu Bakr bin Abu Syaibah] dan [Ali bin Muhammad] keduanya berkata; telah menceritakan kepada kami [Abu Usamah] dari [Hisyam bin Hassan] dari [Muhammad bin Sirin] dari [Abu Hurairah] dari Nabi shallallahu 'alaihi wasallam, beliau bersabda: \"Janganlah kalian menghadang kafilah dagang, barangsiapa menghadang dan membeli sesuatu darinya, maka jika tiba di pasar pemiliknya boleh memilih.\""},"2135":{"ar":"حَدَّثَنَا عُثْمَانُ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا عَبْدَةُ بْنُ سُلَيْمَانَ عَنْ عُبَيْدِ اللَّهِ بْنِ عُمَرَ عَنْ نَافِعٍ عَنْ ابْنِ عُمَرَ قَالَنَهَى رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَنْ تَلَقِّي الْجَلَبِ","id":"Telah menceritakan kepada kami [Utsman bin Abu Syaibah] berkata, telah menceritakan kepada kami ['Abdah bin Sulaiman] dari [Ubaidullah bin Umar] dari [Nafi'] dari [Ibnu Umar] ia berkata, \"Rasulullah shallallahu 'alaihi wasallam melarang untuk menghadang kafilah dagang (sebelum sampai pasar).\""},"2136":{"ar":"حَدَّثَنَا يَحْيَى بْنُ حَكِيمٍ حَدَّثَنَا يَحْيَى بْنُ سَعِيدٍ وَحَمَّادُ بْنُ مَسْعَدَةَ عَنْ سُلَيْمَانَ التَّيْمِيِّ ح و حَدَّثَنَا إِسْحَقُ بْنُ إِبْرَاهِيمَ بْنِ حَبِيبِ بْنِ الشَّهِيدِ حَدَّثَنَا مُعْتَمِرُ بْنُ سُلَيْمَانَ قَالَ سَمِعْتُ أَبِي قَالَ حَدَّثَنَا أَبُو عُثْمَانَ النَّهْدِيُّ عَنْ عَبْدِ اللَّهِ بْنِ مَسْعُودٍ قَالَنَهَى رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَنْ تَلَقِّي الْبُيُوعِ","id":"Telah menceritakan kepada kami [Yahya bin Hakim] berkata, telah menceritakan kepada kami [Yahya bin Sa'id] dan [Hammad bin Mas'adah] dari [Sulaiman At Taimi]. (dalam jalur lain disebutkan) Telah menceritakan kepada kami [Ishaq bin Ibrahim bin Habib bin Asy Syahid] berkata, telah menceritakan kepada kami [Mu'tamir bin Sulaiman] ia berkata, \"Aku mendengar [Bapakku] berkata; telah menceritakan kepada kami [Abu Utsman An Nahdi] dari [Abdullah bin Mas'ud] ia berkata, \"Rasulullah shallallahu 'alaihi wasallam melarang menghadang kafilah dagang.\""},"2137":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ رُمْحٍ الْمِصْرِيُّ أَنْبَأَنَا اللَّيْثُ بْنُ سَعْدٍ عَنْ نَافِعٍ عَنْ عَبْدِ اللَّهِ بْنِ عُمَرَعَنْ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ إِذَا تَبَايَعَ الرَّجُلَانِ فَكُلُّ وَاحِدٍ مِنْهُمَا بِالْخِيَارِ مَا لَمْ يَفْتَرِقَا وَكَانَا جَمِيعًا أَوْ يُخَيِّرَ أَحَدُهُمَا الْآخَرَ فَإِنْ خَيَّرَ أَحَدُهُمَا الْآخَرَ فَتَبَايَعَا عَلَى ذَلِكَ فَقَدْ وَجَبَ الْبَيْعُ وَإِنْ تَفَرَّقَا بَعْدَ أَنْ تَبَايَعَا وَلَمْ يَتْرُكْ وَاحِدٌ مِنْهُمَا الْبَيْعَ فَقَدْ وَجَبَ الْبَيْعُ","id":"Telah menceritakan kepada kami [Muhammad bin Rumh Al Mishri] berkata, telah memberitakan kepada kami [Al Laits bin Sa'd] dari [Nafi'] dari [Abdullah bin Umar] dari Rasulullah shallallahu 'alaihi wasallam, beliau bersabda: \"Jika dua orang saling bertransaksi, maka setiap dari keduanya mempunyai hak pilih selama belum berpisah. Keduanya, atau masing-masing di antara keduanya sama-sama mempunyai hak pilih (untuk meneruskan atau membatalkan jual beli). Jika salah satunya memberi tawaran lantas keduanya terjadi kesepakatan, maka jual beli telah berlaku. Jika keduanya berpisah setelah terjadi kesepakatan, dan salah satunya tidak menggagalkan transaksi, jual beli telah berlaku.\""},"2138":{"ar":"حَدَّثَنَا أَحْمَدُ بْنُ عَبْدَةَ وَأَحْمَدُ بْنُ الْمِقْدَامِ قَالَا حَدَّثَنَا حَمَّادُ بْنُ زَيْدٍ عَنْ جَمِيلِ بْنِ مُرَّةَ عَنْ أَبِي الْوَضِيءِ عَنْ أَبِي بَرْزَةَ الْأَسْلَمِيِّ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ الْبَيِّعَانِ بِالْخِيَارِ مَا لَمْ يَتَفَرَّقَا","id":"Telah menceritakan kepada kami [Ahmad bin Abdah] dan [Ahmad Ibnul Miqdam] keduanya berkata; telah menceritakan kepada kami [Hammad bin Zaid] dari [Jamil bin Murrah] dari [Abu Al Wadli'i] dari [Abu Barzah Al Aslami] ia berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Dua orang yang melakukan jual beli mempunyai pilihan selama keduanya belum berpisah.\""},"2139":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ يَحْيَى وَإِسْحَقُ بْنُ مَنْصُورٍ قَالَا حَدَّثَنَا عَبْدُ الصَّمَدِ حَدَّثَنَا شُعْبَةُ عَنْ قَتَادَةَ عَنْ الْحَسَنِ عَنْ سَمُرَةَ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ الْبَيِّعَانِ بِالْخِيَارِ مَا لَمْ يَتَفَرَّقَا","id":"Telah menceritakan kepada kami [Muhammad bin Yahya] dan [Ishaq bin Manshur] keduanya berkata; telah menceritakan kepada kami [Abdu Ash Shamad] berkata, telah menceritakan kepada kami [Syu'bah] dari [Qatadah] dari [Al Hasan] dari [Samurah] ia berkata, \"Rasululullah shallallahu 'alaihi wasallam bersabda: \"Dua orang yang melakukan jual beli mempunyai pilihan selama keduanya belum berpisah.\""},"2140":{"ar":"حَدَّثَنَا حَرْمَلَةُ بْنُ يَحْيَى وَأَحْمَدُ بْنُ عِيسَى الْمِصْرِيَّانِ قَالَا حَدَّثَنَا عَبْدُ اللَّهِ بْنُ وَهْبٍ أَخْبَرَنِي ابْنُ جُرَيْجٍ عَنْ أَبِي الزُّبَيْرِ عَنْ جَابِرِ بْنِ عَبْدِ اللَّهِ قَالَاشْتَرَى رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مِنْ رَجُلٍ مِنْ الْأَعْرَابِ حِمْلَ خَبَطٍ فَلَمَّا وَجَبَ الْبَيْعُ قَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ اخْتَرْ فَقَالَ الْأَعْرَابِيُّ عَمْرَكَ اللَّهَ بَيِّعًا","id":"Telah menceritakan kepada kami [Harmalah bin Yahya] dan [Ahmad bin Isa] keduanya dari Mesir, mereka berkata; telah menceritakan kepada kami [Abdullah bin Wahb] berkata, telah mengabarkan kepadaku [Ibnu Juraij] dari [Abu Zubair] dari [Jabir bin Abdullah] ia berkata, \"Rasulullah shallallahu 'alaihi wasallam membeli tempat wadah air susu dari seorang arab dusun. Ketika jual beli telah berlaku, Rasulullah shallallahu 'alaihi wasallam bersabda: \"Pilihlah.\" Arab dusun itu berkata, \"Semoga Allah memberimu umur panjang dalam berjual beli.\""},"2141":{"ar":"حَدَّثَنَا الْعَبَّاسُ بْنُ الْوَلِيدِ الدِّمَشْقِيُّ حَدَّثَنَا مَرْوَانُ بْنُ مُحَمَّدٍ حَدَّثَنَا عَبْدُ الْعَزِيزِ بْنُ مُحَمَّدٍ عَنْ دَاوُدَ بْنِ صَالِحٍ الْمَدِينِيِّ عَنْ أَبِيهِ قَالَ سَمِعْتُ أَبَا سَعِيدٍ الْخُدْرِيَّ يَقُولُقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِنَّمَا الْبَيْعُ عَنْ تَرَاضٍ","id":"Telah menceritakan kepada kami [Al Abbas bin Al Walid Ad Dimasyqi] berkata, telah menceritakan kepada kami [Marwan bin Muhammad] berkata, telah menceritakan kepada kami [Abdul Aziz bin Muhammad] dari [Dawud bin Shalih Al Madini] dari [Bapaknya] berkata; aku mendengar [Abu Sa'id] ia berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Hanyasanya jual beli berlaku dengan saling ridla.\""},"2142":{"ar":"حَدَّثَنَا عُثْمَانُ بْنُ أَبِي شَيْبَةَ وَمُحَمَّدُ بْنُ الصَّبَّاحِ قَالَا حَدَّثَنَا هُشَيْمٌ أَنْبَأَنَا ابْنُ أَبِي لَيْلَى عَنْ الْقَاسِمِ بْنِ عَبْدِ الرَّحْمَنِ عَنْ أَبِيهِأَنَّ عَبْدَ اللَّهِ بْنَ مَسْعُودٍ بَاعَ مِنْ الْأَشْعَثِ بْنِ قَيْسٍ رَقِيقًا مِنْ رَقِيقِ الْإِمَارَةِ فَاخْتَلَفَا فِي الثَّمَنِ فَقَالَ ابْنُ مَسْعُودٍ بِعْتُكَ بِعِشْرِينَ أَلْفًا وَقَالَ الْأَشْعَثُ بْنُ قَيْسٍ إِنَّمَا اشْتَرَيْتُ مِنْكَ بِعَشْرَةِ آلَافٍ فَقَالَ عَبْدُ اللَّهِ إِنْ شِئْتَ حَدَّثْتُكَ بِحَدِيثٍ سَمِعْتُهُ مِنْ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ هَاتِهِ قَالَ فَإِنِّي سَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ إِذَا اخْتَلَفَ الْبَيِّعَانِ وَلَيْسَ بَيْنَهُمَا بَيِّنَةٌ وَالْبَيْعُ قَائِمٌ بِعَيْنِهِ فَالْقَوْلُ مَا قَالَ الْبَائِعُ أَوْ يَتَرَادَّانِ الْبَيْعَ قَالَ فَإِنِّي أَرَى أَنْ أَرُدَّ الْبَيْعَ فَرَدَّهُ","id":"Telah menceritakan kepada kami [Utsman bin Abu Syaibah] dan [Muhammad bin Ash Shabbah] keduanya berkata; telah menceritakan kepada kami [Husyaim] berkata, telah memberitakan kepada kami [Ibnu Abu Laila] dari [Al Qasim bin 'Abdurrahman] dari [Bapaknya] bahwa Abdullah bin Mas'ud menjual seorang budak kepada Al Asy'ats bin Qais, namun keduanya berselisih dalam menentukan harga. Ibnu Mas'ud berkata, \"Aku menjual ini kepadamu dengan harga dua puluh ribu, \" sementara Al Asy'ats bin Qais berkata, \"Aku membelinya darimu dengan harga sepuluh ribu.\" [Abdullah bin Mas'ud] kemudian berkata, \"Jika engkau mau maka akan aku bacakan sebuah hadits yang aku dengar dari Rasulullah shallallahu 'alaihi wasallam, \" Al Asy'ats berkata, \"Silahkan.\" Abdullah bin Mas'ud berkata, \"Sesungguhnya aku mendengar Rasulullah shallallahu 'alaihi wasallam bersabda: \"Jika dalam jual beli terjadi perselisihan antara kedua belah dan tidak ada bukti di antara keduanya padahal transaksi telah terjadi, ucapan yang dijadikan pedoman adalah ucapan penjual, atau pembeli dan penjual sama-sama menarik pembayaran dan barangnya.\" Asy'ats menjawab, \"Aku sependapat untuk mengembalikan barang, \" lalu ia pun melakukannya.\""},"2143":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ بَشَّارٍ حَدَّثَنَا مُحَمَّدُ بْنُ جَعْفَرٍ حَدَّثَنَا شُعْبَةُ عَنْ أَبِي بِشْرٍ قَالَ سَمِعْتُ يُوسُفَ بْنَ مَاهَكَ يُحَدِّثُ عَنْ حَكِيمِ بْنِ حِزَامٍ قَالَقُلْتُ يَا رَسُولَ اللَّهِ الرَّجُلُ يَسْأَلُنِي الْبَيْعَ وَلَيْسَ عِنْدِي أَفَأَبِيعُهُ قَالَ لَا تَبِعْ مَا لَيْسَ عِنْدَكَ","id":"Telah menceritakan kepada kami [Muhammad bin Basysyar] berkata, telah menceritakan kepada kami [Muhammad bin Ja'far] berkata, telah menceritakan kepada kami [Syu'bah] dari [Abu Bisyr] ia berkata; aku mendengar [Yusuf bin Mahak] menceritakan dari [Hakim bin Hizam] ia berkata, \"Aku berkata, \"Wahai Rasulullah, seorang laki-laki memintaku untuk menjual, sementara aku tidak mempunyai sesuatu, maka apakah boleh aku menjualnya?\" beliau menjawab: \"Janganlah engkau menjual sesuatu yang bukan milikmu.\""},"2144":{"ar":"حَدَّثَنَا أَزْهَرُ بْنُ مَرْوَانَ قَالَ حَدَّثَنَا حَمَّادُ بْنُ زَيْدٍ ح و حَدَّثَنَا أَبُو كُرَيْبٍ حَدَّثَنَا إِسْمَعِيلُ ابْنُ عُلَيَّةَ قَالَا حَدَّثَنَا أَيُّوبُ عَنْ عَمْرِو بْنِ شُعَيْبٍ عَنْ أَبِيهِ عَنْ جَدِّهِ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَا يَحِلُّ بَيْعُ مَا لَيْسَ عِنْدَكَ وَلَا رِبْحُ مَا لَمْ يُضْمَنْ","id":"Telah menceritakan kepada kami [Azhar bin Marwan] ia berkata; telah menceritakan kepada kami [Hammad bin Zaid]. (dalam jalur lain disebutkan) Telah menceritakan kepada kami [Abu Kuraib] berkata, telah menceritakan kepada kami [Isma'il bin Ulayyah] keduanya berkata; telah menceritakan kepada kami [Ayyub] dari [Amru bin Syu'aib] dari [Bapaknya] dari [Kakeknya] ia berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Tidak halal menjual sesuatu yang tidak engkau miliki, dan tidak ada keuntungan pada sesuatu yang belum ada jaminan.\""},"2145":{"ar":"حَدَّثَنَا عُثْمَانُ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا مُحَمَّدُ بْنُ الْفُضَيْلِ عَنْ لَيْثٍ عَنْ عَطَاءٍ عَنْ عَتَّابِ بْنِ أَسِيدٍ قَالَلَمَّا بَعَثَهُ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِلَى مَكَّةَ نَهَاهُ عَنْ شِفِّ مَا لَمْ يُضْمَنْ","id":"Telah menceritakan kepada kami [Utsman bin Abu Syaibah] berkata, telah menceritakan kepada kami [Muhammad bin Al Fudlail] dari [Al Laits] dari ['Atha] dari ['Attab bin Asid] ia berkata, \"Tatkala Rasulullah shallallahu 'alaihi wasallam mengutusnya ke Makah, beliau melarangnya (membeli) kain apabila belum ada jaminan.\""},"2146":{"ar":"حَدَّثَنَا حُمَيْدُ بْنُ مَسْعَدَةَ حَدَّثَنَا خَالِدُ بْنُ الْحَارِثِ حَدَّثَنَا سَعِيدٌ عَنْ قَتَادَةَ عَنْ الْحَسَنِ عَنْ عُقْبَةَ بْنِ عَامِرٍ أَوْ سَمُرَةَ بْنِ جُنْدَبٍعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ أَيُّمَا رَجُلٍ بَاعَ بَيْعًا مِنْ رَجُلَيْنِ فَهُوَ لِلْأَوَّلِ مِنْهُمَا","id":"Telah menceritakan kepada kami [Humaid bin Mas'adah] berkata, telah menceritakan kepada kami [Khalid Ibnul Harits] berkata, telah menceritakan kepada kami [Sa'id] dari [Qatadah] dari [Al Hasan] dari [Uqbah bin Amir] atau [Samurah bin Jundab] dari Nabi shallallahu 'alaihi wasallam, beliau bersabda: \"Laki-laki mana saja yang menjual barang kepada dua orang, maka yang berhak adalah yang pertama.\""},"2147":{"ar":"حَدَّثَنَا الْحُسَيْنُ بْنُ أَبِي السَّرِيِّ الْعَسْقَلَانِيُّ وَمُحَمَّدُ بْنُ إِسْمَعِيلَ قَالَا حَدَّثَنَا وَكِيعٌ حَدَّثَنَا سَعِيدُ بْنُ بَشِيرٍ عَنْ قَتَادَةَ عَنْ الْحَسَنِ عَنْ سَمُرَةَ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِذَا بَاعَ الْمُجِيزَانِ فَهُوَ لِلْأَوَّلِ","id":"Telah menceritakan kepada kami [Al Husain bin Abu Sarri Al 'Asqlani] dan [Muhammad bin Isma'il] keduanya berkata; telah menceritakan kepada kami [Waki'] berkata, telah menceritakan kepada kami [Sa'id bin Basyir] dari [Qatadah] dari [Al Hasan] dari [Samurah] ia berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Apabila ada dua orang penawar dalam jual beli, maka yang berhak adalah yang pertama.\""},"2148":{"ar":"حَدَّثَنَا هِشَامُ بْنُ عَمَّارٍ حَدَّثَنَا مَالِكُ بْنُ أَنَسٍ قَالَ بَلَغَنِي عَنْ عَمْرِو بْنِ شُعَيْبٍ عَنْ أَبِيهِ عَنْ جَدِّهِأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ نَهَى عَنْ بَيْعِ الْعُرْبَانِ","id":"Telah menceritakan kepada kami [Hisyam bin Ammar] berkata, telah menceritakan kepada kami [Malik bin Anas] berkata, telah sampai kepadaku dari ['Amru bin Syu'aib] dari [Bapaknya] dari [Kakeknya] berkata, \"Nabi shallallahu 'alaihi wasallam melarang jual beli dengan sistem 'Urban (membeli dengan cara panjer, jika gagal uang tidak kembali).\""},"2149":{"ar":"حَدَّثَنَا الْفَضْلُ بْنُ يَعْقُوبَ الرُّخَامِيُّ حَدَّثَنَا حَبِيبُ بْنُ أَبِي حَبِيبٍ أَبُو مُحَمَّدٍ كَاتِبُ مَالِكِ بْنِ أَنَسٍ حَدَّثَنَا عَبْدُ اللَّهِ بْنُ عَامِرٍ الْأَسْلَمِيُّ عَنْ عَمْرِو بْنِ شُعَيْبٍ عَنْ أَبِيهِ عَنْ جَدِّهِ أَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ نَهَى عَنْ بَيْعِ الْعُرْبَانِقَالَ أَبُو عَبْد اللَّهِ الْعُرْبَانُ أَنْ يَشْتَرِيَ الرَّجُلُ دَابَّةً بِمِائَةِ دِينَارٍ فَيُعْطِيَهُ دِينَارَيْنِ عُرْبُونًا فَيَقُولُ إِنْ لَمْ أَشْتَرِ الدَّابَّةَ فَالدِّينَارَانِ لَكَ وَقِيلَ يَعْنِي وَاللَّهُ أَعْلَمُ أَنْ يَشْتَرِيَ الرَّجُلُ الشَّيْءَ فَيَدْفَعَ إِلَى الْبَائِعِ دِرْهَمًا أَوْ أَقَلَّ أَوْ أَكْثَرَ وَيَقُولَ إِنْ أَخَذْتُهُ وَإِلَّا فَالدِّرْهَمُ لَكَ","id":"Telah menceritakan kepada kami [Al Fadll bin Ya'qub Ar Rukhami] berkata, telah menceritakan kepada kami [Habib bin Abu Habib Abu Muhammad] -juru tulis Malik bin Anas- berkata, telah menceritakan kepada kami [Abdullah bin Amir Al Aslami] dari [Amru bin Syu'aib] dari [Bapaknya] dari [Kakeknya] berkata, \"Nabi shallallahu 'alaihi wasallam telah melarang jual beli dengan sistem 'Urban.\" Abu Abdullah berkata, \"'Urban adalah seperti jika seorang laki-laki membeli seekor binatang dengan seratus dinar, lalu ia memberikan dua dinar sebagai panjer. Lalu ia berkata, \"Jika aku tidak jadi beli, maka uang dua dinar tersebut menjadi milikmu.\" Dan dikatakan, \"(Yakni) Allah lebih tahu dengan seorang laki-laki yang membeli sesuatu, lalu kepada sang penjual ia menyerahkan uang satu dirham, atau kurang dari itu, atau lebih banyak dari itu, lalu ia mengatakan, \"Jika aku mengambil barang tersebut maka transaksi jadi, jika tidak maka uang satu dirham itu menjadi milikmu.\""},"2150":{"ar":"حَدَّثَنَا مُحْرِزُ بْنُ سَلَمَةَ الْعَدَنِيُّ حَدَّثَنَا عَبْدُ الْعَزِيزِ بْنُ مُحَمَّدٍ عَنْ عُبَيْدِ اللَّهِ عَنْ أَبِي الزِّنَادِ عَنْ الْأَعْرَجِ عَنْ أَبِي هُرَيْرَةَ قَالَنَهَى رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَنْ بَيْعِ الْغَرَرِ وَعَنْ بَيْعِ الْحَصَاةِ","id":"Telah menceritakan kepada kami [Muhriz bin Salamah Al 'Adani] berkata, telah menceritakan kepada kami [Abdul Aziz bin Muhammad] dari [Ubaidullah] dari [Abu Az Zinad] dari [Al A'raj] dari [Abu Hurairah] ia berkata, \"Rasulullah shallallahu 'alaihi wasallam melarang jual beli gharar (menimbulkan kerugian bagi orang lain) dan jual beli hashah.\" "},"2151":{"ar":"حَدَّثَنَا أَبُو كُرَيْبٍ وَالْعَبَّاسُ بْنُ عَبْدِ الْعَظِيمِ الْعَنْبَرِيُّ قَالَا حَدَّثَنَا أَسْوَدُ بْنُ عَامِرٍ حَدَّثَنَا أَيُّوبُ بْنُ عُتْبَةَ عَنْ يَحْيَى بْنِ أَبِي كَثِيرٍ عَنْ عَطَاءٍ عَنْ ابْنِ عَبَّاسٍ قَالَنَهَى رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَنْ بَيْعِ الْغَرَرِ","id":"Telah menceritakan kepada kami [Abu Kuraib] dan [Al Abbas bin Abdul Azhim Al Anbari] keduanya berkata; telah menceritakan kepada kami [Aswad bin Amir] berkata, telah menceritakan kepada kami [Ayyub bin Utbah] dari [Yahya bin Abu Katsir] dari ['Atha] dari [Ibnu Abbas] ia berkata, \"Rasulullah shallallahu 'alaihi wasallam melarang jual beli gharar (menimbulkan kerugian bagi orang lain).\""},"2152":{"ar":"حَدَّثَنَا هِشَامُ بْنُ عَمَّارٍ حَدَّثَنَا حَاتِمُ بْنُ إِسْمَعِيلَ حَدَّثَنَا جَهْضَمُ بْنُ عَبْدِ اللَّهِ الْيَمَانِيُّ عَنْ مُحَمَّدِ بْنِ إِبْرَاهِيمَ الْبَاهِلِيِّ عَنْ مُحَمَّدِ بْنِ زَيْدٍ الْعَبْدِيِّ عَنْ شَهْرِ بْنِ حَوْشَبٍ عَنْ أَبِي سَعِيدٍ الْخُدْرِيِّ قَالَنَهَى رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَنْ شِرَاءِ مَا فِي بُطُونِ الْأَنْعَامِ حَتَّى تَضَعَ وَعَمَّا فِي ضُرُوعِهَا إِلَّا بِكَيْلٍ وَعَنْ شِرَاءِ الْعَبْدِ وَهُوَ آبِقٌ وَعَنْ شِرَاءِ الْمَغَانِمِ حَتَّى تُقْسَمَ وَعَنْ شِرَاءِ الصَّدَقَاتِ حَتَّى تُقْبَضَ وَعَنْ ضَرْبَةِ الْغَائِصِ","id":"Telah menceritakan kepada kami [Hisyam bin Ammar] berkata, telah menceritakan kepada kami [Hatim bin Isma'il] berkata, telah menceritakan kepada kami [Jahdlam bin Abdullah Al Yamani] dari [Muhammad bin Ibrahim Al Bahili] dari [Muhammad bin Zaid Al Abdi] dari [Syahr bin Hausyab] dari [Abu Sa'id Al Khudri] ia berkata; \"Rasulullah shallallahu 'alaihi wasallam melarang membeli sesuatu yang masih di dalam perut binatang hingga ia melahirkan, dan apa yang ada dalam kantung susunya kecuali dengan takaran. Dan dari membeli budak yang melarikan diri, membeli harta rampasan perang hingga dibagikan, membeli harta sedekah hingga dibagikan dan dari membeli hasil seorang penyelam (karena belum jelas hasilnya).\""},"2153":{"ar":"حَدَّثَنَا هِشَامُ بْنُ عَمَّارٍ حَدَّثَنَا سُفْيَانُ بْنُ عُيَيْنَةَ عَنْ أَيُّوبَ عَنْ سَعِيدِ بْنِ جُبَيْرٍ عَنْ ابْنِ عُمَرَأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ نَهَى عَنْ بَيْعِ حَبَلِ الْحَبَلَةِ","id":"Telah menceritakan kepada kami [Hisyam bin Ammar] berkata, Telah menceritakan kepada kami [Sufyan bin Uyainah] dari [Ayyub] dari [Sa'id bin Jubair] dari [Ibnu Umar] berkata, \"Rasulullah shallallahu 'alaihi wasallam melarang menjual anak (binatang) yang masih dalam kandungan.\""},"2154":{"ar":"حَدَّثَنَا هِشَامُ بْنُ عَمَّارٍ حَدَّثَنَا عِيسَى بْنُ يُونُسَ حَدَّثَنَا الْأَخْضَرُ بْنُ عَجْلَانَ حَدَّثَنَا أَبُو بَكْرٍ الْحَنَفِيُّ عَنْ أَنَسِ بْنِ مَالِكٍأَنَّ رَجُلًا مِنْ الْأَنْصَارِ جَاءَ إِلَى النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَسْأَلُهُ فَقَالَ لَكَ فِي بَيْتِكَ شَيْءٌ قَالَ بَلَى حِلْسٌ نَلْبَسُ بَعْضَهُ وَنَبْسُطُ بَعْضَهُ وَقَدَحٌ نَشْرَبُ فِيهِ الْمَاءَ قَالَ ائْتِنِي بِهِمَا قَالَ فَأَتَاهُ بِهِمَا فَأَخَذَهُمَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِيَدِهِ ثُمَّ قَالَ مَنْ يَشْتَرِي هَذَيْنِ فَقَالَ رَجُلٌ أَنَا آخُذُهُمَا بِدِرْهَمٍ قَالَ مَنْ يَزِيدُ عَلَى دِرْهَمٍ مَرَّتَيْنِ أَوْ ثَلَاثًا قَالَ رَجُلٌ أَنَا آخُذُهُمَا بِدِرْهَمَيْنِ فَأَعْطَاهُمَا إِيَّاهُ وَأَخَذَ الدِّرْهَمَيْنِ فَأَعْطَاهُمَا الْأَنْصَارِيَّ وَقَالَ اشْتَرِ بِأَحَدِهِمَا طَعَامًا فَانْبِذْهُ إِلَى أَهْلِكَ وَاشْتَرِ بِالْآخَرِ قَدُومًا فَأْتِنِي بِهِ فَفَعَلَ فَأَخَذَهُ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَشَدَّ فِيهِ عُودًا بِيَدِهِ وَقَالَ اذْهَبْ فَاحْتَطِبْ وَلَا أَرَاكَ خَمْسَةَ عَشَرَ يَوْمًا فَجَعَلَ يَحْتَطِبُ وَيَبِيعُ فَجَاءَ وَقَدْ أَصَابَ عَشْرَةَ دَرَاهِمَ فَقَالَ اشْتَرِ بِبَعْضِهَا طَعَامًا وَبِبَعْضِهَا ثَوْبًا ثُمَّ قَالَ هَذَا خَيْرٌ لَكَ مِنْ أَنْ تَجِيءَ وَالْمَسْأَلَةُ نُكْتَةٌ فِي وَجْهِكَ يَوْمَ الْقِيَامَةِ إِنَّ الْمَسْأَلَةَ لَا تَصْلُحُ إِلَّا لِذِي فَقْرٍ مُدْقِعٍ أَوْ لِذِي غُرْمٍ مُفْظِعٍ أَوْ دَمٍ مُوجِعٍ","id":"Telah menceritakan kepada kami [Hisyam bin Ammar] berkata, telah menceritakan kepada kami [Isa bin Yunus] berkata, telah menceritakan kepada kami [Al Akhdlar bin Ajlan] berkata, telah menceritakan kepada kami [Abu Bakr Al Hanafi] dari [Anas bin Malik] berkata, \"Seorang lelaki Anshar datang kepada Nabi shallallahu 'alaihi wasallam dan meminta kepada Beliau. Maka beliau pun bertanya kepadanya: \"Apakah di rumahmu ada sesuatu?\" Ia menjawab, \"Ya. Sebuah alas pelana yang sebagian kami pakai dan sebagian lagi kami bentangkan, serta sebuah gelas yang kami gunakan untuk minum air.\" Beliau bersabda: \"Berikanlah keduanya itu untukku.\" Anas berkata, \"Orang itu lantas membawa keduanya hingga Rasulullah shallallahu 'alaihi wasallam mengambilnya dengan tangannya, kemudian bersabda: \"Siapa yang mau membeli dua barang ini?\" Seorang laki-laki berkata, \"Saya mau membelinya dengan satu dirham! \" Beliau bertanya lagi: \"Siapa yang mau menambahnya?\" Beliau ulangi pertanyaan itu dua atau tiga kali. Lalu seorang laki-laki berkata, \"Saya akan membelinya dengan dua dirham.\" Lalu Beliau memberikan barang tersebut kepadanya, kemudian meminta uang pembayarannya seraya memberikannya kepada sahabat Anshar tadi. Beliau kemudian bersabda: \"Belilah makanan dengan satu dirham untuk keluargamu, dan sisanya belikanlah sebuah kapak. Setelah itu bawalah kapak itu kepadaku.\" Laki-laki itu pun melakukannya, Rasulullah shallallahu 'alaihi wasallam kemudian mengambil kapak dan memasang kayu sebagai gagangnya. Beliau lalu bersabda: \"Pergi dan carilah kayu bakar, dan selama lima belas hari ini aku tidak ingin melihatmu.\" Setelah itu, laki-laki tersebut pergi mencari kayu bakar dan menjualnya. Kemudian ia datang menemui Nabi setelah menghasilkan sepuluh dirham, beliau lalu bersabda: \"Belilah makanan dengan separuh uangmu dan belilah pakaian dengan separuh yang lain.\" Kemudian beliau bersabda: \"Ini lebih baik bagimu daripada kamu datang dan meminta-minta. Pada hari kiamat kelak meminta-minta akan menjadi titik hitam di wajahmu, maka tidak boleh meminta-minta kecuali bagi orang yang sangat fakir, atau orang yang terlilit hutang, atau darah yang menyakitkan (untuk membayar denda karena membunuh orang).\""},"2155":{"ar":"حَدَّثَنَا زِيَادُ بْنُ يَحْيَى أَبُو الْخَطَّابِ حَدَّثَنَا مَالِكُ بْنُ سُعَيْرٍ حَدَّثَنَا الْأَعْمَشُ عَنْ أَبِي صَالِحٍ عَنْ أَبِي هُرَيْرَةَ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَنْ أَقَالَ مُسْلِمًا أَقَالَهُ اللَّهُ عَثْرَتَهُ يَوْمَ الْقِيَامَةِ","id":"Telah menceritakan kepada kami [Ziyad bin Yahya Abu Al Khaththab] berkata, telah menceritakan kepada kami [Malik bin Su'air] berkata, telah menceritakan kepada kami [Al A'masy] dari [Abu Shalih] dari [Abu Hurairah] ia berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Barangsiapa menerima pembatalan seorang muslim dalam jual beli, maka pada hari kiamat Allah akan mengampuni dosa-dosanya.\""},"2156":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ الْمُثَنَّى حَدَّثَنَا حَجَّاجٌ حَدَّثَنَا حَمَّادُ بْنُ سَلَمَةَ عَنْ قَتَادَةَ وَحُمَيْدٌ وَثَابِتٌ عَنْ أَنَسِ بْنِ مَالِكٍ قَالَغَلَا السِّعْرُ عَلَى عَهْدِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالُوا يَا رَسُولَ اللَّهِ قَدْ غَلَا السِّعْرُ فَسَعِّرْ لَنَا فَقَالَ إِنَّ اللَّهَ هُوَ الْمُسَعِّرُ الْقَابِضُ الْبَاسِطُ الرَّازِقُ إِنِّي لَأَرْجُو أَنْ أَلْقَى رَبِّي وَلَيْسَ أَحَدٌ يَطْلُبُنِي بِمَظْلَمَةٍ فِي دَمٍ وَلَا مَالٍ","id":"Telah menceritakan kepada kami [Muhammad Ibnul Mutsanna] berkata, telah menceritakan kepada kami [Hajjaj] berkata, telah menceritakan kepada kami [Hammad bin Salamah] dari [Qatadah] dan [Humaid] dan [Tsabit] dari [Anas bin Malik] ia berkata, \"Pernah terjadi kenaikan harga pada masa Rasulullah shallallahu 'alaihi wasallam, maka orang-orang pun berkata, \"Wahai Rasulullah, harga-harga telah melambung tinggi, maka tetapkanlah setandar harga untuk kami.\" Beliau lalu bersabda: \"Sesungguhnya Allah lah yang menentukan harga, yang menyempitkan dan melapangkan, dan Dia yang memberi rizki. Sungguh, aku berharap ketika berjumpa dengan Allah tidak ada seseorang yang meminta pertanggungjawaban dariku dalam hal darah dan harta.\""},"2157":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ زِيَادٍ حَدَّثَنَا عَبْدُ الْأَعْلَى حَدَّثَنَا سَعِيدٌ عَنْ قَتَادَةَ عَنْ أَبِي نَضْرَةَ عَنْ أَبِي سَعِيدٍ قَالَغَلَا السِّعْرُ عَلَى عَهْدِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالُوا لَوْ قَوَّمْتَ يَا رَسُولَ اللَّهِ قَالَ إِنِّي لَأَرْجُو أَنْ أُفَارِقَكُمْ وَلَا يَطْلُبَنِي أَحَدٌ مِنْكُمْ بِمَظْلَمَةٍ ظَلَمْتُهُ","id":"Telah menceritakan kepada kami [Muhammad bin Ziyad] berkata, telah menceritakan kepada kami [Abdul A'la] berkata, telah menceritakan kepada kami [Sa'id] dari [Qatadah] dari [Abu Nadlrah] dari [Abu Sa'id] ia berkata, \"Pernah terjadi kenaikan harga pada masa Rasulullah shallallahu 'alaihi wasallam, orang-orang pun berkata, \"Wahai Rasulullah, andai saja engkau standarkan saja (harganya).\" Beliau bersabda: \"Aku sangat berharap ketika berpisah dengan kalian tidak ada seorang pun dari kalian yang menuntutku karena kezhaliman yang aku lakukan.\""},"2158":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ أَبَانَ الْبَلْخِيُّ أَبُو بَكْرٍ حَدَّثَنَا إِسْمَعِيلُ بْنُ عُلَيَّةَ عَنْ يُونُسَ بْنِ عُبَيْدٍ عَنْ عَطَاءِ بْنِ فَرُّوخَ قَالَ قَالَ عُثْمَانُ بْنُ عَفَّانَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَدْخَلَ اللَّهُ الْجَنَّةَ رَجُلًا كَانَ سَهْلًا بَائِعًا وَمُشْتَرِيًا","id":"Telah menceritakan kepada kami [Muhammad bin Aban Al Balkhi Abu Bakr] berkata, telah menceritakan kepada kami [Isma'il bin Ulayyah] dari [Yunus bin Ubaid] dari ['Atha bin Farukh] ia berkata; [Utsman bin Affan] berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Allah akan memasukkan ke dalam surga seorang laki-laki yang mempermudah saat menjual atau membeli barang.\""},"2159":{"ar":"حَدَّثَنَا عَمْرُو بْنُ عُثْمَانَ بْنِ سَعِيدِ بْنِ كَثِيرِ بْنِ دِينَارٍ الْحِمْصِيُّ حَدَّثَنَا أَبِي حَدَّثَنَا أَبُو غَسَّانَ مُحَمَّدُ بْنُ مُطَرِّفٍ عَنْ مُحَمَّدِ بْنِ الْمُنْكَدِرِ عَنْ جَابِرِ بْنِ عَبْدِ اللَّهِ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ رَحِمَ اللَّهُ عَبْدًا سَمْحًا إِذَا بَاعَ سَمْحًا إِذَا اشْتَرَى سَمْحًا إِذَا اقْتَضَى","id":"Telah menceritakan kepada kami ['Amru bin Utsman bin Sa'id bin Katsir bin Dinar Al Himshi] berkata, telah menceritakan kepada kami [Bapakku] berkata, telah menceritakan kepada kami [Abu Ghassan Muhammad bin Mutharrif] dari [Muhammad bin Al Munkadir] dari [Jabir bin Abdullah] ia berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Allah menyayangi seorang hamba yang murah hati jika berjualan, bermurah hati jika membeli dan bermurah hati jika memutuskan.\""},"2160":{"ar":"حَدَّثَنَا يَعْقُوبُ بْنُ حُمَيْدِ بْنِ كَاسِبٍ حَدَّثَنَا يَعْلَى بْنُ شَبِيبٍ عَنْ عَبْدِ اللَّهِ بْنِ عُثْمَانَ بْنِ خُثَيْمٍ عَنْ قَيْلَةَ أُمِّ بَنِي أَنْمَارٍ قَالَتْأَتَيْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي بَعْضِ عُمَرِهِ عِنْدَ الْمَرْوَةِ فَقُلْتُ يَا رَسُولَ اللَّهِ إِنِّي امْرَأَةٌ أَبِيعُ وَأَشْتَرِي فَإِذَا أَرَدْتُ أَنْ أَبْتَاعَ الشَّيْءَ سُمْتُ بِهِ أَقَلَّ مِمَّا أُرِيدُ ثُمَّ زِدْتُ ثُمَّ زِدْتُ حَتَّى أَبْلُغَ الَّذِي أُرِيدُ وَإِذَا أَرَدْتُ أَنْ أَبِيعَ الشَّيْءَ سُمْتُ بِهِ أَكْثَرَ مِنْ الَّذِي أُرِيدُ ثُمَّ وَضَعْتُ حَتَّى أَبْلُغَ الَّذِي أُرِيدُ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَا تَفْعَلِي يَا قَيْلَةُ إِذَا أَرَدْتِ أَنْ تَبْتَاعِي شَيْئًا فَاسْتَامِي بِهِ الَّذِي تُرِيدِينَ أُعْطِيتِ أَوْ مُنِعْتِ وَإِذَا أَرَدْتِ أَنْ تَبِيعِي شَيْئًا فَاسْتَامِي بِهِ الَّذِي تُرِيدِينَ أَعْطَيْتِ أَوْ مَنَعْتِ","id":"Telah menceritakan kepada kami [Ya'qub bin Humaid bin Kasib] berkata, telah menceritakan kepada kami [Ya'la bin Syabib] dari [Abdullah bin Utsman bin Khutsaim] dari [Qailah Ummu Bani Anmar] ia berkata, \"Aku pernah mendatangi Rasulullah shallallahu 'alaihi wasallam di Marwa di salah satu umrahnya. Lalu aku berkata kepadanya, \"Ya Rasulullah, aku seorang wanita yang biasa melakukan transaksi jual beli, apabila aku ingin membeli sesuatu aku menawarnya lebih kecil dari yang aku inginkan. Kemudian aku menaikkan tawaran, lalu menaikkannya lagi hingga mencapai harga yang aku inginkan. Apabila aku ingin menjual sesuatu, maka aku tawarkan lebih banyak dari yang aku inginkan, kemudian aku menurunkannya hingga mencapai harga yang aku inginkan?! Maka Rasulullah shallallahu 'alaihi wasallam pun bersabda: \"Jangan kamu lakukan wahai Qailah, apabila kamu ingin membeli sesuatu maka tawarlah dengan harga yang kamu inginkan, baik kamu diberi atau tidak, dan jika kamu menjual sesuatu maka tawarkanlah dengan harga yang kamu inginkan, sehingga kamu memberikan atau menahannya.\""},"2161":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ يَحْيَى حَدَّثَنَا يَزِيدُ بْنُ هَارُونَ عَنْ الْجُرَيْرِيِّ عَنْ أَبِي نَضْرَةَ عَنْ جَابِرِ بْنِ عَبْدِ اللَّهِ قَالَكُنْتُ مَعَ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي غَزْوَةٍ فَقَالَ لِي أَتَبِيعُ نَاضِحَكَ هَذَا بِدِينَارٍ وَاللَّهُ يَغْفِرُ لَكَ قُلْتُ يَا رَسُولَ اللَّهِ هُوَ نَاضِحُكُمْ إِذَا أَتَيْتُ الْمَدِينَةَ قَالَ فَتَبِيعُهُ بِدِينَارَيْنِ وَاللَّهُ يَغْفِرُ لَكَ قَالَ فَمَا زَالَ يَزِيدُنِي دِينَارًا دِينَارًا وَيَقُولُ مَكَانَ كُلِّ دِينَارٍ وَاللَّهُ يَغْفِرُ لَكَ حَتَّى بَلَغَ عِشْرِينَ دِينَارًا فَلَمَّا أَتَيْتُ الْمَدِينَةَ أَخَذْتُ بِرَأْسِ النَّاضِحِ فَأَتَيْتُ بِهِ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ يَا بِلَالُ أَعْطِهِ مِنْ الْغَنِيمَةِ عِشْرِينَ دِينَارًا وَقَالَ انْطَلِقْ بِنَاضِحِكَ فَاذْهَبْ بِهِ إِلَى أَهْلِكَ","id":"Telah menceritakan kepada kami [Muhammad bin Yahya] berkata, telah menceritakan kepada kami [Yazid bin Harun] dari [Al Jurairi] dari [Abu Nadlrah] dari [Jabir bin Abdullah] ia berkata, \"Ketika aku bersama Nabi shallallahu 'alaihi wasallam dalam satu peperangan, beliau bertanya kepadaku: \"Apakah kamu bersedia menjual alat penyiram ini dengan satu dinar, dan Allah akan mengampunimu?\" Aku menjawab, \"Wahai Rasulullah, alat itu akan menjadi milikmu jika aku telah sampai Madinah.\" Beliau bersabda: \"Apakah kamu bersedia menjualnya dengan dua dinar, dan Allah akan mengampunimu?\" Jabir berkata, \"Beliau terus saja menambah harga satu dinar demi satu dinar, dan di setiap penambahan satu dinar beliau mengatakan: 'Dan Allah akan mengampunimu', hingga mencapai dua puluh dinar. Ketika aku sampai Madinah, aku mengambil kepala alat penyiram dan membawanya menemui Nabi shallallahu 'alaihi wasallam, beliau lalu bersabda: \"Wahai Bilal, beri dia dua puluh dinar dari harta rampasan perang.\" Kemudian beliau bersabda lagi: \"Ambillah alat penyiram itu, dan bawalah kepada keluargamu.\""},"2162":{"ar":"حَدَّثَنَا عَلِيُّ بْنُ مُحَمَّدٍ وَسَهْلُ بْنُ أَبِي سَهْلٍ قَالَا حَدَّثَنَا عُبَيْدُ اللَّهِ بْنُ مُوسَى أَنْبَأَنَا الرَّبِيعُ بْنُ حَبِيبٍ عَنْ نَوْفَلِ بْنِ عَبْدِ الْمَلِكِ عَنْ أَبِيهِ عَنْ عَلِيٍّ قَالَنَهَى رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَنْ السَّوْمِ قَبْلَ طُلُوعِ الشَّمْسِ وَعَنْ ذَبْحِ ذَوَاتِ الدَّرِّ","id":"Telah menceritakan kepada kami [Ali bin Muhammad] dan [Sahl bin Abu Sahl] keduanya berkata; telah menceritakan kepada kami [Ubaidullah bin Musa] berkata, telah memberitakan kepada kami [Rabi' bin Habib] dari [Naufal bin Abdul Malik] dari [Bapaknya] dari [Ali] ia berkata, \"Rasulullah shallallahu 'alaihi wasallam telah melarang menaikan harga yang telah berlaku sebelum terbitnya matahari, dan menyembelih hewan yang sedang banyak susunya.\""},"2163":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ وَعَلِيُّ بْنُ مُحَمَّدٍ وَأَحْمَدُ بْنُ سِنَانٍ قَالُوا حَدَّثَنَا أَبُو مُعَاوِيَةَ عَنْ الْأَعْمَشِ عَنْ أَبِي صَالِحٍ عَنْ أَبِي هُرَيْرَةَ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ ثَلَاثَةٌ لَا يُكَلِّمُهُمْ اللَّهُ عَزَّ وَجَلَّ يَوْمَ الْقِيَامَةِ وَلَا يَنْظُرُ إِلَيْهِمْ وَلَا يُزَكِّيهِمْ وَلَهُمْ عَذَابٌ أَلِيمٌ رَجُلٌ عَلَى فَضْلِ مَاءٍ بِالْفَلَاةِ يَمْنَعُهُ ابْنَ السَّبِيلِ وَرَجُلٌ بَايَعَ رَجُلًا سِلْعَةً بَعْدَ الْعَصْرِ فَحَلَفَ بِاللَّهِ لَأَخَذَهَا بِكَذَا وَكَذَا فَصَدَّقَهُ وَهُوَ عَلَى غَيْرِ ذَلِكَ وَرَجُلٌ بَايَعَ إِمَامًا لَا يُبَايِعُهُ إِلَّا لِدُنْيَا فَإِنْ أَعْطَاهُ مِنْهَا وَفَى لَهُ وَإِنْ لَمْ يُعْطِهِ مِنْهَا لَمْ يَفِ لَهُ","id":"Telah menceritakan kepada kami [Abu Bakr bin Abu Syaibah] dan [Ali bin Muhammad] dan [Ahmad bin Sinan] mereka berkata; telah menceritakan kepada kami [Abu Mu'awiyah] dari [Al A'masy] dari [Abu Shalih] dari [Abu Hurairah] ia berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Ada tiga manusia yang tidak akan diajak bicara oleh Allah pada hari kiamat, tidak akan disucikan dosanya dan bagi mereka siksa yang pedih; orang yang mempunyai kelebihan air pada suatu belahan bumi lalu ia menahannya dari Ibnu sabil. Seorang laki-laki yang menjual dagangannya setelah ashar lalu ia bersumpah bahwa ia membelinya dengan harga sekian dan sekian, hingga sang pembeli percaya padahal ia bohong. Dan seorang laki-laki yang membaiat seorang pemimpin, ia tidak membaiatnya kecuali untuk mendapatkan dunia. Jika sang pemimpin memberi ia penuhi dan jika tidak memberi ia tidak menepati bai'atnya.\""},"2164":{"ar":"حَدَّثَنَا عَلِيُّ بْنُ مُحَمَّدٍ وَمُحَمَّدُ بْنُ إِسْمَعِيلَ قَالَا حَدَّثَنَا وَكِيعٌ عَنْ الْمَسْعُودِيِّ عَنْ عَلِيِّ بْنِ مُدْرِكٍ عَنْ خَرَشَةَ بْنِ الْحُرِّ عَنْ أَبِي ذَرٍّ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ ح و حَدَّثَنَا مُحَمَّدُ بْنُ بَشَّارٍ حَدَّثَنَا مُحَمَّدُ بْنُ جَعْفَرٍ حَدَّثَنَا شُعْبَةُ عَنْ عَلِيِّ بْنِ مُدْرِكٍ عَنْ أَبِي زُرْعَةَ بْنِ عَمْرِو بْنِ جَرِيرٍ عَنْ خَرَشَةَ بْنِ الْحُرِّ عَنْ أَبِي ذَرٍّعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ ثَلَاثَةٌ لَا يُكَلِّمُهُمْ اللَّهُ يَوْمَ الْقِيَامَةِ وَلَا يَنْظُرُ إِلَيْهِمْ وَلَا يُزَكِّيهِمْ وَلَهُمْ عَذَابٌ أَلِيمٌ فَقُلْتُ مَنْ هُمْ يَا رَسُولَ اللَّهِ فَقَدْ خَابُوا وَخَسِرُوا قَالَ الْمُسْبِلُ إِزَارَهُ وَالْمَنَّانُ عَطَاءَهُ وَالْمُنَفِّقُ سِلْعَتَهُ بِالْحَلِفِ الْكَاذِبِ","id":"Telah menceritakan kepada kami [Ali bin Muhammad] dan [Muhammad bin Isma'il] keduanya berkata; telah menceritakan kepada kami [Waki'] dari [Al Mas'udi] dari [Ali bin Mudrik] dari [Kharasyah Ibnul Hur] dari [Abu Dzar] dari Nabi shallallahu 'alaihi wasallam. (dalam jalur lain disebutkan) Telah menceritakan kepada kami [Muhammad bin Basysyar] berkata, telah menceritakan kepada kami [Muhammad bin Ja'far] berkata, telah menceritakan kepada kami [Syu'bah] dari [Ali bin Mudrik] dari [Abu Zur'ah bin Amru bin Jarir] dari [Khasyarah Ibnul Hur] dari [Abu Dzar] dari Nabi shallallahu 'alaihi wasallam, beliau bersabda: \"Ada tiga manusia yang tidak akan diajak bicara oleh Allah pada hari kiamat, tidak akan disucikan dosanya dan bagi mereka siksa yang pedih, \" aku bertanya, \"Wahai Rasulullah, siapakah mereka? sungguh sia-sia dan merugilah mereka?\" beliau bersabda: \"Orang yang kain sarungnya melebihi mata kaki, orang yang mengungkit-ungkit dalam pemberian, dan orang yang melariskan dagangan dengan sumpah palsu.\""},"2165":{"ar":"حَدَّثَنَا يَحْيَى بْنُ خَلَفٍ حَدَّثَنَا عَبْدُ الْأَعْلَى ح و حَدَّثَنَا هِشَامُ بْنُ عَمَّارٍ حَدَّثَنَا إِسْمَعِيلُ بْنُ عَيَّاشٍ قَالَا حَدَّثَنَا مُحَمَّدُ بْنُ إِسْحَقَ عَنْ مَعْبَدِ بْنِ كَعْبِ بْنِ مَالِكٍ عَنْ أَبِي قَتَادَةَ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِيَّاكُمْ وَالْحَلِفَ فِي الْبَيْعِ فَإِنَّهُ يُنَفِّقُ ثُمَّ يَمْحَقُ","id":"Telah menceritakan kepada kami [Yahya bin Khalaf] berkata, telah menceritakan kepada kami [Abdul A'la]. (dalam jalur lain disebutkan) Telah menceritakan kepada kami [Hisyam bin Ammar] berkata, telah menceritakan kepada kami [Isma'il bin Ayyasy] keduanya berkata; telah menceritakan kepada kami [Muhammad bin Ishaq] dari [Ma'bad bin Ka'b bin Malik] dari [Abu Qatadah] ia berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Jauhilah oleh kalian bersumpah dalam jual beli, sesungguhnya ia mendatangkan keuntungan namun menghilangkan keberkahan.\""},"2166":{"ar":"حَدَّثَنَا هِشَامُ بْنُ عَمَّارٍ حَدَّثَنَا مَالِكُ بْنُ أَنَسٍ قَالَ حَدَّثَنِي نَافِعٌ عَنْ ابْنِ عُمَرَأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ مَنْ اشْتَرَى نَخْلًا قَدْ أُبِّرَتْ فَثَمَرَتُهَا لِلْبَائِعِ إِلَّا أَنْ يَشْتَرِطَ الْمُبْتَاعُحَدَّثَنَا مُحَمَّدُ بْنُ رُمْحٍ أَنْبَأَنَا اللَّيْثُ بْنُ سَعْدٍ عَنْ نَافِعٍ عَنْ ابْنِ عُمَرَ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِنَحْوِهِ","id":"Telah menceritakan kepada kami [Hisyam bin Ammar] berkata, telah menceritakan kepada kami [Malik bin Anas] ia berkata; telah menceritakan kepadaku [Nafi'] dari [Ibnu Umar] bahwa Nabi shallallahu 'alaihi wasallam bersabda: \"Barangsiapa membeli pohon kurma sementara buahnya telah matang maka buahnya untuk sang penjual, kecuali jika sang pembeli memberi syarat.\" Telah menceritakan kepada kami [Muhammad bin Rumh] berkata, telah memberitakan kepada kami [Al Laits bin Sa'd] dari [Nafi'] dari [Ibnu Umar] dari Nabi shallallahu 'alaihi wasallam dengan Hadits yang serupa.\""},"2167":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ رُمْحٍ أَنْبَأَنَا اللَّيْثُ بْنُ سَعْدٍ ح و حَدَّثَنَا هِشَامُ بْنُ عَمَّارٍ حَدَّثَنَا سُفْيَانُ بْنُ عُيَيْنَةَ جَمِيعًا عَنْ ابْنِ شِهَابٍ الزُّهْرِيِّ عَنْ سَالِمِ بْنِ عَبْدِ اللَّهِ بْنِ عُمَرَ عَنْ ابْنِ عُمَرَأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ مَنْ بَاعَ نَخْلًا قَدْ أُبِّرَتْ فَثَمَرَتُهَا لِلَّذِي بَاعَهَا إِلَّا أَنْ يَشْتَرِطَ الْمُبْتَاعُ وَمَنْ ابْتَاعَ عَبْدًا وَلَهُ مَالٌ فَمَالُهُ لِلَّذِي بَاعَهُ إِلَّا أَنْ يَشْتَرِطَ الْمُبْتَاعُ","id":"Telah menceritakan kepada kami [Muhammad bin Rumh] berkata, telah memberitakan kepada kami [Al Laits bin Sa'd]. (dalam jalur lain disebutkan) Telah menceritakan kepada kami [Hisyam bin Ammar] berkata, telah menceritakan kepada kami [Sufyan bin Uyainah] dari [Ibnu Syihab Az Zuhri] dari [Salim bin Abdullah bin Umar] dari [Ibnu Umar] bahwa Rasulullah shallallahu 'alaihi wasallam bersabda: \"Barangsiapa menjual pohon kurma sementara buahnya sudah matang maka buahnya bagi yang menjual, kecuali jika sang pembeli membuat persyaratan. Dan barangsiapa menjual seorang budak yang mempunyai harta, maka hartanya untuk yang menjualnya, kecuali jika sang pembeli membuat persyaratan.\""},"2168":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ الْوَلِيدِ حَدَّثَنَا مُحَمَّدُ بْنُ جَعْفَرٍ حَدَّثَنَا شُعْبَةُ عَنْ عَبْدِ رَبِّهِ بْنِ سَعِيدٍ عَنْ نَافِعٍ عَنْ ابْنِ عُمَرَعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنَّهُ قَالَ مَنْ بَاعَ نَخْلًا وَبَاعَ عَبْدًا جَمَعَهُمَا جَمِيعًا","id":"Telah menceritakan kepada kami [Muhammad bin Al Walid] berkata, telah menceritakan kepada kami [Muhammad bin Ja'far] berkata, telah menceritakan kepada kami [Syu'bah] dari [Abdu Rabbih bin Sa'id] dari [Nafi'] dari [Ibnu Umar] dari Nabi shallallahu 'alaihi wasallam, beliau bersabda: \"Barangsiapa menjual pohon kurma dan menjual budak, maka Allah akan mengumpulkan keduanya.\""},"2169":{"ar":"حَدَّثَنَا عَبْدُ رَبِّهِ بْنُ خَالِدٍ النُّمَيْرِيُّ أَبُو الْمُغَلِّسِ حَدَّثَنَا الْفُضَيْلُ بْنُ سُلَيْمَانَ عَنْ مُوسَى بْنِ عُقْبَةَ حَدَّثَنِي إِسْحَقُ بْنُ يَحْيَى ابْنِ الْوَلِيدِ عَنْ عُبَادَةَ بْنِ الصَّامِتِ قَالَقَضَى رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِثَمَرِ النَّخْلِ لِمَنْ أَبَّرَهَا إِلَّا أَنْ يَشْتَرِطَ الْمُبْتَاعُ وَأَنَّ مَالَ الْمَمْلُوكِ لِمَنْ بَاعَهُ إِلَّا أَنْ يَشْتَرِطَ الْمُبْتَاعُ","id":"Telah menceritakan kepada kami [Abdu Rabbih bin Khalid An Numairi Abul Mughallis] berkata, telah menceritakan kepada kami [Al Fudlail bin Sulaiman] dari [Musa bin Uqbah] berkata, telah menceritakan kepadaku [Ishaq bin Yahya bin Al Walid] dari [Ubadah bin Shamit] ia berkata, \"Rasulullah shallallahu 'alaihi wasallam telah menetapkan buah kurma bagi orang yang mengelolanya kecuali jika pembeli membuat persyaratan. Dan sesungguhnya harta seorang budak itu bagi orang yang menjualnya kecuali pembeli membuat persyaratan.\""},"2170":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ رُمْحٍ أَنْبَأَنَا اللَّيْثُ بْنُ سَعْدٍ عَنْ نَافِعٍ عَنْ ابْنِ عُمَرَعَنْ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ لَا تَبِيعُوا الثَّمَرَةَ حَتَّى يَبْدُوَ صَلَاحُهَا نَهَى الْبَائِعَ وَالْمُشْتَرِيَ","id":"Telah menceritakan kepada kami [Muhammad bin Rumh] berkata, telah memberitakan kepada kami [Al Laits bin Sa'd] dari [Nafi'] dari [Ibnu Umar] dari Rasulullah shallallahu 'alaihi wasallam, beliau bersabda: 'Janganlah kalian menjual buah-buahan hingga matang', beliau melarang penjual dan pembeli.\""},"2171":{"ar":"حَدَّثَنَا أَحْمَدُ بْنُ عِيسَى الْمِصْرِيُّ حَدَّثَنَا عَبْدُ اللَّهِ بْنُ وَهْبٍ عَنْ يُونُسَ بْنِ يَزِيدَ عَنْ ابْنِ شِهَابٍ حَدَّثَنِي سَعِيدُ بْنُ الْمُسَيَّبِ وَأَبُو سَلَمَةَ بْنُ عَبْدِ الرَّحْمَنِ عَنْ أَبِي هُرَيْرَةَ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَا تَبِيعُوا الثَّمَرَ حَتَّى يَبْدُوَ صَلَاحُهُ","id":"Telah menceritakan kepada kami [Ahmad bin Isa Al Mishri] berkata, telah menceritakan kepada kami [Abdullah bin Wahb] dari [Yunus bin Yazid] dari [Ibnu Syihab] berkata, telah menceritakan kepadaku [Sa'id bin Al Musayyab] dan [Abu Salamah bin 'Abdurrahman] dari [Abu Hurairah] ia berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Janganlah menjual buah-buahan sehingga nampak matangnya.\""},"2172":{"ar":"حَدَّثَنَا هِشَامُ بْنُ عَمَّارٍ حَدَّثَنَا سُفْيَانُ عَنْ ابْنِ جُرَيْجٍ عَنْ عَطَاءٍ عَنْ جَابِرٍأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ نَهَى عَنْ بَيْعِ الثَّمَرِ حَتَّى يَبْدُوَ صَلَاحُهُ","id":"Telah menceritakan kepada kami [Hisyam bin Ammar] berkata, telah menceritakan kepada kami [Sufyan] dari [Ibnu Juraij] dari ['Atha] dari [Jabir] berkata, \"Nabi shallallahu 'alaihi wasallam melarang menjual buah hingga tampak matangnya.\""},"2173":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ الْمُثَنَّى حَدَّثَنَا حَجَّاجٌ حَدَّثَنَا حَمَّادٌ عَنْ حُمَيْدٍ عَنْ أَنَسِ بْنِ مَالِكٍأَن��َ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ نَهَى عَنْ بَيْعِ الثَّمَرَةِ حَتَّى تَزْهُوَ وَعَنْ بَيْعِ الْعِنَبِ حَتَّى يَسْوَدَّ وَعَنْ بَيْعِ الْحَبِّ حَتَّى يَشْتَدَّ","id":"Telah menceritakan kepada kami [Muhammad Ibnul Mutsanna] berkata, telah menceritakan kepada kami [Hajjaj] berkata, telah menceritakan kepada kami [Hammad] dari [Humaid] dari [Anas bin Malik] berkata, \"Rasulullah shallallahu 'alaihi wasallam melarang dari menjual buah-buahan hingga tampak matangnya, menjual anggur hingga berwarna hitam dan dari menjual biji hingga menjadi keras.\""},"2174":{"ar":"حَدَّثَنَا هِشَامُ بْنُ عَمَّارٍ وَمُحَمَّدُ بْنُ الصَّبَّاحِ قَالَا حَدَّثَنَا سُفْيَانُ عَنْ حُمَيْدٍ الْأَعْرَجِ عَنْ سُلَيْمَانَ بْنِ عَتِيقٍ عَنْ جَابِرِ بْنِ عَبْدِ اللَّهِأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ نَهَى عَنْ بَيْعِ السِّنِينَ","id":"Telah menceritakan kepada kami [Hisyam bin Ammar] dan [Muhammad bin Ash Shabbah] keduanya berkata; telah menceritakan kepada kami [Sufyan] dari [Humaid Al A'raj] dari [Sulaiman bin 'Atiq] dari [Jabir bin Abdullah] ia berkata, \"Rasulullah shallallahu 'alaihi wasallam melarang jual beli sinin.\" "},"2175":{"ar":"حَدَّثَنَا هِشَامُ بْنُ عَمَّارٍ حَدَّثَنَا يَحْيَى بْنُ حَمْزَةَ حَدَّثَنَا ثَوْرُ بْنُ يَزِيدَ عَنْ ابْنِ جُرَيْجٍ عَنْ أَبِي الزُّبَيْرِ عَنْ جَابِرِ بْنِ عَبْدِ اللَّهِأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ مَنْ بَاعَ ثَمَرًا فَأَصَابَتْهُ جَائِحَةٌ فَلَا يَأْخُذْ مِنْ مَالِ أَخِيهِ شَيْئًا عَلَامَ يَأْخُذُ أَحَدُكُمْ مَالَ أَخِيهِ الْمُسْلِمِ","id":"Telah menceritakan kepada kami [Hisyam bin Ammar] berkata, telah menceritakan kepada kami [Yahya bin Hamzah] berkata, telah menceritakan kepada kami [Tsaur bin Yazid] dari [Ibnu Juraij] dari [Abu Az Zubair] dari [Jabir bin Abdillah] bahwa Rasulullah shallallahu 'alaihi wasallam bersabda: \"Barangsiapa menjual buah-buahan lalu terkena wabah (rusak), maka janganlah mengambil dari harta saudaranya sedikitpun. Atas dasar apa salah seorang dari kalian mengambil harta saudaranya sesama muslim! \""},"2176":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ وَعَلِيُّ بْنُ مُحَمَّدٍ وَمُحَمَّدُ بْنُ إِسْمَعِيلَ قَالُوا حَدَّثَنَا وَكِيعٌ حَدَّثَنَا سُفْيَانُ عَنْ سِمَاكِ بْنِ حَرْبٍ عَنْ سُوَيْدِ بْنِ قَيْسٍ قَالَجَلَبْتُ أَنَا وَمَخْرَفَةُ الْعَبْدِيُّ بَزًّا مِنْ هَجَرَ فَجَاءَنَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَسَاوَمَنَا سَرَاوِيلَ وَعِنْدَنَا وَزَّانٌ يَزِنُ بِالْأَجْرِ فَقَالَ لَهُ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَا وَزَّانُ زِنْ وَأَرْجِحْ","id":"Telah menceritakan kepada kami [Abu Bakr bin Abu Syaibah] dan [Ali bin Muhammad] serta [Muhammad bin Isma'il] mereka berkata; telah menceritakan kepada kami [Waki'] berkata, telah menceritakan kepada kami [Sufyan] dari [Simak bin Harb] dari [Suwaid bin Qais] ia berkata, \"Aku dan Makhrafah 'Abdi membawa pakaian dari Hajar, lalu Rasulullah shallallahu 'alaihi wasallam datang menemui kami dan menawar celana panjang, sementara di sisi kami ada seorang tukang timbang yang biasa menimbang untuk mendapat upah. Lalu Nabi shallallahu 'alaihi wasallam bersabda kepadanya: \"Wahai tukang timbang, timbang dan tentukanlah berapa beratnya.\""},"2177":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ بَشَّارٍ وَمُحَمَّدُ بْنُ الْوَلِيدِ قَالَا حَدَّثَنَا مُحَمَّدُ بْنُ جَعْفَرٍ حَدَّثَنَا شُعْبَةُ عَنْ سِمَاكِ بْنِ حَرْبٍ قَالَ سَمِعْتُ مَالِكًا أَبَا صَفْوَانَ بْنَ عُمَيْرَةَ قَالَبِعْتُ مِنْ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ رِجْلَ سَرَاوِيلَ قَبْلَ الْهِجْرَةِ فَوَزَنَ لِي فَأَرْجَحَ لِي","id":"Telah menceritakan kepada kami [Muhammad bin Basysyar] dan [Muhammad bin Al Walid] keduanya berkata; telah menceritakan kepada kami [Muhammad bin Ja'far] berkata, telah menceritakan kepada kami [Syu'bah] dari [Simak bin Harb] ia berkata, \"Aku mendengar [Malik Abu Shafwan bin Umairah] berkata, \"Aku membeli celana dari Rasulullah shallallahu 'alaihi wasallam sebelum hijrah, maka beliau menimbang dan menentukan beratnya untukku.\""},"2178":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ يَحْيَى حَدَّثَنَا عَبْدُ الصَّمَدِ حَدَّثَنَا شُعْبَةُ عَنْ مُحَارِبِ بْنِ دِثَارٍ عَنْ جَابِرِ بْنِ عَبْدِ اللَّهِ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِذَا وَزَنْتُمْ فَأَرْجِحُوا","id":"Telah menceritakan kepada kami [Muhammad bin Yahya] berkata, telah menceritakan kepada kami [Abdush Shamad] berkata, telah menceritakan kepada kami [Syu'bah] dari [Muharib bin Ditsar] dari [Jabir bin Abdullah] ia berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Apabila kalian menimbang maka tentukanlah beratnya (yang sesuai).\""},"2179":{"ar":"حَدَّثَنَا عَبْدُ الرَّحْمَنِ بْنُ بِشْرِ بْنِ الْحَكَمِ وَمُحَمَّدُ بْنُ عَقِيلِ بْنِ خُوَيْلِدٍ قَالَا حَدَّثَنَا عَلِيُّ بْنُ الْحُسَيْنِ بْنِ وَاقِدٍ حَدَّثَنِي أَبِي حَدَّثَنِي يَزِيدُ النَّحْوِيُّ أَنَّ عِكْرِمَةَ حَدَّثَهُ عَنْ ابْنِ عَبَّاسٍ قَالَلَمَّا قَدِمَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ الْمَدِينَةَ كَانُوا مِنْ أَخْبَثِ النَّاسِ كَيْلًا فَأَنْزَلَ اللَّهُ سُبْحَانَهُ{ وَيْلٌ لِلْمُطَفِّفِينَ }فَأَحْسَنُوا الْكَيْلَ بَعْدَ ذَلِكَ","id":"Telah menceritakan kepada kami ['Abdurrahman bin Bisyr bin Al Hakam] dan [Muhammad bin Aqil bin Khuwailid] keduanya berkata; telah menceritakan kepada kami [Ali bin Al Husain bin Waqid] berkata, telah menceritakan kepadaku [Bapakku] berkata, telah menceritakan kepadaku [Yazid An Nahwi] bahwa [Ikrimah] menceritakan kepadanya dari [Ibnu Abbas] ia berkata, \"Tatkala Nabi shallallahu 'alaihi wasallam tiba di Madinah, mereka adalah orang-orang yang paling buruk dalam menimbang. Maka Allah menurunkan ayat: '(Celakalah bagi orang-orang yang curang dalam timbangan) ', Setelah itu mereka berlaku jujur dalam timbangannya.\""},"2180":{"ar":"حَدَّثَنَا هِشَامُ بْنُ عَمَّارٍ حَدَّثَنَا سُفْيَانُ عَنْ الْعَلَاءِ بْنِ عَبْدِ الرَّحْمَنِ عَنْ أَبِيهِ عَنْ أَبِي هُرَيْرَةَ قَالَمَرَّ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِرَجُلٍ يَبِيعُ طَعَامًا فَأَدْخَلَ يَدَهُ فِيهِ فَإِذَا هُوَ مَغْشُوشٌ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَيْسَ مِنَّا مَنْ غَشَّ","id":"Telah menceritakan kepada kami [Hisyam bin Ammar] berkata, telah menceritakan kepada kami [Sufyan] dari [Al 'Ala bin 'Abdurrahman] dari [Bapaknya] dari [Abu Hurairah] ia berkata, \"Rasulullah shallallahu 'alaihi wasallam melewati seorang laki-laki yang sedang menjual makanan, lalu beliau memasukkan tangan ke dalamnya, dan ternyata beliau tertipu (dalam keranjang bagian bawah kosong), maka Rasulullah shallallahu 'alaihi wasallam pun bersabda: \"Bukan dari golongan kami orang yang menipu.\""},"2181":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا أَبُو نُعَيْمٍ حَدَّثَنَا يُونُسُ بْنُ أَبِي إِسْحَقَ عَنْ أَبِي دَاوُدَ عَنْ أَبِي الْحَمْرَاءِ قَالَرَأَيْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَرَّ بِجَنَبَاتِ رَجُلٍ عِنْدَهُ طَعَامٌ فِي وِعَاءٍ فَأَدْخَلَ يَدَهُ فِيهِ فَقَالَ لَعَلَّكَ غَشَشْتَ مَنْ غَشَّنَا فَلَيْسَ مِنَّا","id":"Telah menceritakan kepada kami [Abu Bakr bin Abu Syaibah] berkata, telah menceritakan kepada kami [Abu Nu'aim] berkata, telah menceritakan kepada kami [Yunus bin Abu Ishaq] dari [Abu Dawud] dari [Abul Hamra] ia berkata, \"Aku melihat Rasululllah shallallahu 'alaihi wasallam melewati warung seseorang yang mempunyai makanan dalam bejana. Beliau memasukkan tangannya ke dalam bejana itu, lalu beliau bersabda: \"Kenapa kamu menipu? barangsiapa menipu kami, maka dia bukan dari golongan kami.\""},"2182":{"ar":"حَدَّثَنَا سُوَيْدُ بْنُ سَعِيدٍ حَدَّثَنَا مَالِكُ بْنُ أَنَسٍ عَنْ نَافِعٍ عَنْ ابْنِ عُمَرَأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ مَنْ ابْتَاعَ طَعَامًا فَلَا يَبِعْهُ حَتَّى يَسْتَوْفِيَهُ","id":"Telah menceritakan kepada kami [Suwaid bin Sa'id] berkata, telah menceritakan kepada kami [Malik bin Anas] dari [Nafi'] dari [Ibnu Umar] bahwa Rasulullah shallallahu 'alaihi wasallam bersabda: \"Barangsiapa membeli makanan, maka janganlah ia menjualnya kembali hingga ia memegangnya.\""},"2183":{"ar":"حَدَّثَنَا عِمْرَانُ بْنُ مُوسَى اللَّيْثِيُّ حَدَّثَنَا حَمَّادُ بْنُ زَيْدٍ ح و حَدَّثَنَا بِشْرُ بْنُ مُعَاذٍ الضَّرِيرُ حَدَّثَنَا أَبُو عَوَانَةَ وَحَمَّادُ بْنُ زَيْدٍ قَالَا حَدَّثَنَا عَمْرُو بْنُ دِينَارٍ عَنْ طَاوُسٍ عَنْ ابْنِ عَبَّاسٍ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَنْ ابْتَاعَ طَعَامًا فَلَا يَبِعْهُ حَتَّى يَسْتَوْفِيَهُ قَالَ أَبُو عَوَانَةَ فِي حَدِيثِهِ قَالَ ابْنُ عَبَّاسٍ وَأَحْسِبُ كُلَّ شَيْءٍ مِثْلَ الطَّعَامِ","id":"Telah menceritakan kepada kami [Imran bin Musa Al Laitsi] berkata, telah menceritakan kepada kami [Hammad bin Zaid]. (dalam jalur lain disebutkan) Telah menceritakan kepada kami [Bisyr bin Mu'adz Adl Dlarir] berkata, telah menceritakan kepada kami [Abu 'Awanah] dan [Hammad bin Zaid] keduanya berkata; telah menceritakan kepada kami [Amru bin Dinar] dari [Thawus] dari [Ibnu Abbas] ia berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Barangsiapa membeli makanan, maka janganlah ia menjualnya kembali hingga ia memegangnya.\" Abu Awanah menyebutkan dalam haditsnya, \"Ibnu Abbas berkata, \"Aku menganggap bahwa hal itu mencakup segala sesuatu yang seperti makanan.\""},"2184":{"ar":"حَدَّثَنَا عَلِيُّ بْنُ مُحَمَّدٍ حَدَّثَنَا وَكِيعٌ عَنْ ابْنِ أَبِي لَيْلَى عَنْ أَبِي الزُّبَيْرِ عَنْ جَابِرٍ قَالَنَهَى رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَنْ بَيْعِ الطَّعَامِ حَتَّى يَجْرِيَ فِيهِ الصَّاعَانِ صَاعُ الْبَائِعِ وَصَاعُ الْمُشْتَرِي","id":"Telah menceritakan kepada kami [Ali bin Muhammad] berkata, telah menceritakan kepada kami [Waki'] dari [Ibnu Abu Laila] dari [Abu Zubair] dari [Jabir] ia berkata, \"Rasulullah shallallahu 'alaihi wasallam melarang menjual makanan hingga dilakukan dua penimbangan, penimbangan pertama oleh penjual, penimbangan kedua oleh pembeli.\" "},"2185":{"ar":"حَدَّثَنَا سَهْلُ بْنُ أَبِي سَهْلٍ حَدَّثَنَا عَبْدُ اللَّهِ بْنُ نُمَيْرٍ عَنْ عُبَيْدِ اللَّهِ عَنْ نَافِعٍ عَنْ ابْنِ عُمَرَ قَالَكُنَّا نَشْتَرِي الطَّعَامَ مِنْ الرُّكْبَانِ جِزَافًا فَنَهَانَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنْ نَبِيعَهُ حَتَّى نَنْقُلَهُ مِنْ مَكَانِهِ","id":"Telah menceritakan kepada kami [Sahl bin Abu Sahl] berkata, telah menceritakan kepada kami [Abdullah bin Numair] dari [Ubaidullah] dari [Nafi'] dari [Ibnu Umar] ia berkata, \"Kami membeli makanan dari para pedagang dengan cara Jizaf (tanpa ukuran dan takaran), lalu Rasulullah shallallahu 'alaihi wasallam melarang kami untuk menjualnya kembali hingga kami memindahkannya dari tempat semula (dengan ukuran).\""},"2186":{"ar":"حَدَّثَنَا عَلِيُّ بْنُ مَيْمُونٍ الرَّقِّيُّ حَدَّثَنَا عَبْدُ اللَّهِ بْنُ يَزِيدَ عَنْ ابْنِ لَهِيعَةَ عَنْ مُوسَى بْنِ وَرْدَانَ عَنْ سَعِيدِ بْنِ الْمُسَيَّبِ عَنْ عُثْمَانَ بْنِ عَفَّانَ قَالَكُنْتُ أَبِيعُ التَّمْرَ فِي السُّوقِ فَأَقُولُ كِلْتُ فِي وَسْقِي هَذَا كَذَا فَأَدْفَعُ أَوْسَاقَ التَّمْرِ بِكَيْلِهِ وَآخُذُ شِفِّي فَدَخَلَنِي مِنْ ذَلِكَ شَيْءٌ فَسَأَلْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ إِذَا سَمَّيْتَ الْكَيْلَ فَكِلْهُ","id":"Telah menceritakan kepada kami [Ali bin Maimun Ar Raqqi] berkata, telah menceritakan kepada kami [Abdullah bin Yazid] dari [Ibnu Lahi'ah] dari [Musa bin Wardan] dari [Sa'id Ibnul Musayyab] dari [Utsman bin Affan] ia berkata, \"Aku menjual kurma di pasar, lalu aku katakan, 'Aku menakar dalam wasaqku ini seperti ini', kemudian aku serahkan wasaq yang berisi kurma itu sesuai dengan takarannya, dan aku ambil keuntunganku. Namun ada sesuatu yang mengganjal dalam hatiku, maka aku pun bertanya Rasulullah shallallahu 'alaihi wasallam, beliau lantas menjawab: \"Jika engkau katakan dengan takaran, maka takarlah.\""},"2187":{"ar":"حَدَّثَنَا هِشَامُ بْنُ عَمَّارٍ حَدَّثَنَا إِسْمَعِيلُ بْنُ عَيَّاشٍ حَدَّثَنَا مُحَمَّدُ بْنُ عَبْدِ الرَّحْمَنِ الْيَحْصُبِيُّ عَنْ عَبْدِ اللَّهِ بْنِ بُسْرٍ الْمَازِنِيِّ قَالَسَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ كِيلُوا طَعَامَكُمْ يُبَارَكْ لَكُمْ فِيهِ","id":"Telah menceritakan kepada kami [Hisyam bin Ammar] berkata, telah menceritakan kepada kami [Isma'il bin 'Ayyasy] berkata, telah menceritakan kepada kami [Muhammad bin 'Abdurrahman Al Yahshubi] dari [Abdullah bin Busr Al Mazini] ia berkata; \"Aku mendengar Rasulullah shallallahu 'alaihi wasallam bersabda: \"Timbanglah makanan kalian, maka kalian akan diberkahi.\""},"2188":{"ar":"حَدَّثَنَا عَمْرُو بْنُ عُثْمَانَ بْنِ سَعِيدِ بْنِ كَثِيرِ بْنِ دِينَارٍ الْحِمْصِيُّ حَدَّثَنَا بَقِيَّةُ بْنُ الْوَلِيدِ عَنْ بَحِيرِ بْنِ سَعْدٍ عَنْ خَالِدِ بْنِ مَعْدَانَ عَنْ الْمِقْدَامِ بْنِ مَعْدِ يكَرِبَ عَنْ أَبِي أَيُّوبَعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ كِيلُوا طَعَامَكُمْ يُبَارَكْ لَكُمْ فِيهِ","id":"Telah menceritakan kepada kami [Amru bin Utsman bin Sa'id bin Katsir bin Dinar Al Himshi] berkata, telah menceritakan kepada kami [Baqiyah Ibnul Walid] dari [Bahir bin Sa'd] dari [Khalid bin Ma'dan] dari [Al Miqdam bin Ma'diyakarib] dari [Abu Ayyub] dari Nabi shallallahu 'alaihi wasallam, beliau bersabda: \"Timbanglah makanan kalian, maka kalian akan diberkahi.\""},"2189":{"ar":"حَدَّثَنَا إِبْرَاهِيمُ بْنُ الْمُنْذِرِ الْحِزَامِيُّ حَدَّثَنَا إِسْحَقُ بْنُ إِبْرَاهِيمَ بْنِ سَعِيدٍ حَدَّثَنِي صَفْوَانُ بْنُ سُلَيْمٍ حَدَّثَنِي مُحَمَّدٌ وَعَلِيٌّ ابْنَا الْحَسَنِ بْنِ أَبِي الْحَسَنِ الْبَرَّادِ أَنَّ الزُّبَيْرَ بْنَ الْمُنْذِرِ بْنِ أَبِي أُسَيْدٍ السَّاعِدِيَّ حَدَّثَهُمَا أَنَّ أَبَاهُ الْمُنْذِرَ حَدَّثَهُ عَنْ أَبِي أُسَيْدٍأَنَّ أَبَا أُسَيْدٍ حَدَّثَهُ أَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ ذَهَبَ إِلَى سُوقِ النَّبِيطِ فَنَظَرَ إِلَيْهِ فَقَالَ لَيْسَ هَذَا لَكُمْ بِسُوقٍ ثُمَّ ذَهَبَ إِلَى سُوقٍ فَنَظَرَ إِلَيْهِ فَقَالَ لَيْسَ هَذَا لَكُمْ بِسُوقٍ ثُمَّ رَجَعَ إِلَى هَذَا السُّوقِ فَطَافَ فِيهِ ثُمَّ قَالَ هَذَا سُوقُكُمْ فَلَا يُنْتَقَصَنَّ وَلَا يُضْرَبَنَّ عَلَيْهِ خَرَاجٌ","id":"Telah menceritakan kepada kami [Ibrahim bin Al Mundzir Al Hizami] berkata, telah menceritakan kepada kami [Ishaq bin Ibrahim bin Sa'id] berkata, telah menceritakan kepadaku [Shafwan bin Sulaim] berkata, telah menceritakan kepadaku [Muhammad] dan [Ali] berkata, -keduanya putra Al Hasan bin Abu Al Hasan Al Barrad- bahwa [Zubair bin Al Mundzir bin Abu Usaid As Sa'idi] menceritakan kepada keduanya, bahwa bapaknya [Abul Mundzir] menceritakan kepadanya dari [Abu Usaid] bahwa Abu Usaid menceritakan kepadanya, Rasulullah shallallahu 'alaihi wasallam pernah pergi ke pasar Nabith, kemudian beliau melihatnya dan bersabda: \"Bukan seperti ini pasar kalian.\" Kemudian beliau pergi ke pasar lagi dan melihatnya, beliau bersabda: \"Bukan seperti ini pasar kalian.\" Kemudian kembali lagi ke pasar itu, beliau berputar mengelilinginya dan bersabda: \"Ini adalah pasar kalian, janganlah kalian saling mengurangi (takaran) dan jangan mengambil pajak.\""},"2190":{"ar":"حَدَّثَنَا إِبْرَاهِيمُ بْنُ الْمُسْتَمِرِّ الْعُرُوقِيُّ حَدَّثَنَا أَبِي حَدَّثَنَا عُبَيْسُ بْنُ مَيْمُونٍ حَدَّثَنَا عَوْنٌ الْعُقَيْلِيُّ عَنْ أَبِي عُثْمَانَ النَّهْدِيِّ عَنْ سَلْمَانَ قَالَسَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ مَنْ غَدَا إِلَى صَلَاةِ الصُّبْحِ غَدَا بِرَايَةِ الْإِيمَانِ وَمَنْ غَدَا إِلَى السُّوقِ غَدَا بِرَايَةِ إِبْلِيسَ","id":"Telah menceritakan kepada kami [Ibrahim bin Al Mustamir Al 'Uruqi] berkata, telah menceritakan kepadaku [Bapakku] berkata, telah menceritakan kepada kami [Ubais bin Maimun] berkata, telah menceritakan kepada kami [Aun Al Uqaili] dari [Abu Utsman An Nahdi] dari [Salman] ia berkata, \"Aku mendengar Rasulullah shallallahu 'alaihi wasallam bersabda: \"Barangsiapa keluar di pagi hari untuk shalat subuh, maka ia berangkat dengan membawa bendera iman, dan barangsiapa keluar di pagi hari menuju pasar, maka ia berangkat dengan membawa bendera iblis.\""},"2191":{"ar":"حَدَّثَنَا بِشْرُ بْنُ مُعَاذٍ الضَّرِيرُ حَدَّثَنَا حَمَّادُ بْنُ زَيْدٍ عَنْ عَمْرِو بْنِ دِينَارٍ مَوْلَى آلِ الزُّبَيْرِ عَنْ سَالِمِ بْنِ عَبْدِ اللَّهِ بْنِ عُمَرَ عَنْ أَبِيهِ عَنْ جَدِّهِ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَنْ قَالَ حِينَ يَدْخُلُ السُّوقَ لَا إِلَهَ إِلَّا اللَّهُ وَحْدَهُ لَا شَرِيكَ لَهُ لَهُ الْمُلْكُ وَلَهُ الْحَمْدُ يُحْيِي وَيُمِيتُ وَهُوَ حَيٌّ لَا يَمُوتُ بِيَدِهِ الْخَيْرُ كُلُّهُ وَهُوَ عَلَى كُلِّ شَيْءٍ قَدِيرٌ كَتَبَ اللَّهُ لَهُ أَلْفَ أَلْفِ حَسَنَةٍ وَمَحَا عَنْهُ أَلْفَ أَلْفِ سَيِّئَةٍ وَبَنَى لَهُ بَيْتًا فِي الْجَنَّةِ","id":"Telah menceritakan kepada kami [Bisyr bin Mu'adz Adl Dlarir] berkata, telah menceritakan kepada kami [Hammad bin Zaid] dari [Amru bin Dinar] -mantan budak keluarga Az Zubair- dari [Salim bin Abdullah bin Umar] dari [Bapaknya] dari [Kakeknya] ia berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Barangsiapa ketika masuk pasar mengucapkan; \"LAA ILAAHA ILLA AALLAHU WAHDAHUU LAA SYARIIKALAH LAHUL MULKU WA LAHUL HAMDU YUHYII WA YUMIITU WA HUWA HAYYUN LAA YAMUUTU BIYADIHIL KHAIRU WA HUWA 'ALAA KULLI SYAIIN QADIIR (Tidak ada Tuhan yang berhak untuk disembah selain Allah semata, tidak ada serikat bagi-Nya. Bagi-Nya kerajaan dan segala pujian, yang menghidupkan dan mematikan, dan Dia Maha hidup dan tidak akan mati. Di tangan-Nya segala kebaikan, Dia-lah yang berkuasa atas segala sesuatu). Maka Allah akan menuliskan baginya satu juta kebaikan, dihapuskan darinya satu juta keburukan, dan Allah akan membangunkan baginya rumah di surga.\""},"2192":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا هُشَيْمٌ عَنْ يَعْلَى بْنِ عَطَاءٍ عَنْ عُمَارَةَ بْنِ حَدِيدٍ عَنْ صَخْرٍ الْغَامِدِيِّ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ اللَّهُمَّ بَارِكْ لِأُمَّتِي فِي بُكُورِهَا قَالَ وَكَانَ إِذَا بَعَثَ سَرِيَّةً أَوْ جَيْشًا بَعَثَهُمْ فِي أَوَّلِ النَّهَارِ قَالَ وَكَانَ صَخْرٌ رَجُلًا تَاجِرًا فَكَانَ يَبْعَثُ تِجَارَتَهُ فِي أَوَّلِ النَّهَارِ فَأَثْرَى وَكَثُرَ مَالُهُ","id":"Telah menceritakan kepada kami [Abu Bakr bin Abu Syaibah] berkata, telah menceritakan kepada kami [Husyaim] dari [Ya'la bin 'Atha] dari [Umarah bin Hadid] dari [Shakhr Al Ghamidi] ia berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Ya Allah, berkahilah umatku di waktu paginya.\" Shakhr Al Ghamidi berkata, \"Beliau jika mengutus ekspedisi, atau pasukan beliau memberangkatkannya di pagi hari.\" Ia (perawi) berkata, \"Shakhr Al Ghamidi adalah seorang pedagang, ia biasa mengirim barang dagangannya di pagi hari hingga beruntung dan melimpahlah hartanya.\""},"2193":{"ar":"حَدَّثَنَا أَبُو مَرْوَانَ مُحَمَّدُ بْنُ عُثْمَانَ الْعُثْمَانِيُّ حَدَّثَنَا مُحَمَّدُ بْنُ مَيْمُونٍ الْمَدَنِيُّ عَنْ عَبْدِ الرَّحْمَنِ بْنِ أَبِي الزِّنَادِ عَنْ أَبِيهِ عَنْ الْأَعْرَجِ عَنْ أَبِي هُرَيْرَةَ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ اللَّهُمَّ بَارِكْ لِأُمَّتِي فِي بُكُورِهَا يَوْمَ الْخَمِيسِ","id":"Telah menceritakan kepada kami [Abu Marwan Muhammad bin Utsman Al Utsmani] berkata, telah menceritakan kepada kami [Muhammad bin Maimun Al Madani] dari ['Abdurrahman bin Abu Zinad] dari [Bapaknya] dari [Al A'raj] dari [Abu Hurairah] ia berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Ya Allah, berkahilah umatku di waktu paginya, dihari kamis.\""},"2194":{"ar":"حَدَّثَنَا يَعْقُوبُ بْنُ حُمَيْدِ بْنِ كَاسِبٍ حَدَّثَنَا إِسْحَقُ بْنُ جَعْفَرِ بْنِ مُحَمَّدِ بْنِ عَلِيِّ بْنِ الْحُسَيْنِ عَنْ عَبْدِ الرَّحْمَنِ بْنِ أَبِي بَكْرٍ الْجَدْعَانِيِّ عَنْ نَافِعٍ عَنْ ابْنِ عُمَرَأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ اللَّهُمَّ بَارِكْ لِأُمَّتِي فِي بُكُورِهَا","id":"Telah menceritakan kepada kami [Ya'qub bin Humaid bin Kasib] berkata, telah menceritakan kepada kami [Ishaq bin Ja'far bin Muhammad bin Ali bin Al Husain] dari ['Abdurrahman bin Abu Bakr Al Jad'ani] dari [Nafi'] dari [Ibnu Umar] bahwa Nabi shallallahu 'alaihi wasallam bersabda: \"Ya Allah, berkahilah umatku di waktu paginya.\""},"2195":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ وَعَلِيُّ بْنُ مُحَمَّدٍ قَالَا حَدَّثَنَا أَبُو أُسَامَةَ عَنْ هِشَامِ بْنِ حَسَّانَ عَنْ مُحَمَّدِ بْنِ سِيرِينَ عَنْ أَبِي هُرَيْرَةَعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ مَنْ ابْتَاعَ مُصَرَّاةً فَهُوَ بِالْخِيَارِ ثَلَاثَةَ أَيَّامٍ فَإِنْ رَدَّهَا رَدَّ مَعَهَا صَاعًا مِنْ تَمْرٍ لَا سَمْرَاءَ يَعْنِي الْحِنْطَةَ","id":"Telah menceritakan kepada kami [Abu Bakr bin Abu Syaibah] dan [Ali bin Muhammad] keduanya berkata; telah menceritakan kepada kami [Abu Usamah] dari [Hisyam bin Hassan] dari [Muhammad bin Sirin] dari [Abu Hurairah] dari Nabi shallallahu 'alaihi wasallam, beliau bersabda: \"Barangsiapa membeli Musharrah, maka ia punya hak pilih selama tiga hari. Jika ingin mengembalikan, hendaklah ia kembalikan dengan menyertakan satu sha' kurma dan bukan samra, yakni gandum.\" "},"2196":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ عَبْدِ الْمَلِكِ بْنِ أَبِي الشَّوَارِبِ حَدَّثَنَا عَبْدُ الْوَاحِدِ بْنُ زِيَادٍ حَدَّثَنَا صَدَقَةُ بْنُ سَعِيدٍ الْحَنَفِيُّ حَدَّثَنَا جُمَيْعُ بْنُ عُمَيْرٍ التَّيْمِيُّ حَدَّثَنَا عَبْدُ اللَّهِ بْنُ عُمَرَ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَا أَيُّهَا النَّاسُ مَنْ بَاعَ مُحَفَّلَةً فَهُوَ بِالْخِيَارِ ثَلَاثَةَ أَيَّامٍ فَإِنْ رَدَّهَا رَدَّ مَعَهَا مِثْلَيْ لَبَنِهَا أَوْ قَالَ مِثْلَ لَبَنِهَا قَمْحًا","id":"Telah menceritakan kepada kami [Muhammad bin Abdul Malik bin Abu Syawarib] berkata, telah menceritakan kepada kami [Abdul Wahid bin Ziyad] berkata, telah menceritakan kepada kami [Shadaqah bin Sa'id Al Hanafi] berkata, telah menceritakan kepada kami [Jumai' bin Umair At Taimi] berkata, telah menceritakan kepada kami [Abdullah bin Umar] ia berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Wahai manusia barangsiapa menjual Muhaffalah maka ia punya hak pilih selama tiga hari. Apabila ia mengembalikannya, hendaklah ia kembalikan dengan menyertakan dua yang sebanding dengan susunya, atau beliau mengatakan, \"gandum yang sebanding dengan susunya.\" "},"2197":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ إِسْمَعِيلَ حَدَّثَنَا وَكِيعٌ حَدَّثَنَا الْمَسْعُودِيُّ عَنْ جَابِرٍ عَنْ أَبِي الضُّحَى عَنْ مَسْرُوقٍ عَنْ عَبْدِ اللَّهِ بْنِ مَسْعُودٍ أَنَّهُ قَالَأَشْهَدُ عَلَى الصَّادِقِ الْمَصْدُوقِ أَبِي الْقَاسِمِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنَّهُ حَدَّثَنَا قَالَ بَيْعُ الْمُحَفَّلَاتِ خِلَابَةٌ وَلَا تَحِلُّ الْخِلَابَةُ لِمُسْلِمٍ","id":"Telah menceritakan kepada kami [Muhammad bin Isma'il] berkata, telah menceritakan kepada kami [Waki'] berkata, telah menceritakan kepada kami [Al Mas'udi] dari [Jabir] dari [Abu Adl Dluha] dari [Masruq] dari [Abdullah bin Mas'ud] ia berkata: \"Aku bersaksi atas yang jujur lagi di benarkan, Abul Qasim shallallahu 'alaihi wasallam, bahwa beliau bersabda: \"Menjual muhaffalah (hewan ternak yang susunya sengaja tidak diperah hingga kelihatan besar saat akan dijual) adalah penipuan, dan penipuan tidak dihalalkan bagi seorang muslim.\""},"2198":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ وَعَلِيُّ بْنُ مُحَمَّدٍ قَالَا حَدَّثَنَا وَكِيعٌ عَنْ ابْنِ أَبِي ذِئْبٍ عَنْ مَخْلَدِ بْنِ خُفَافِ بْنِ إِيمَاءَ بْنِ رَحَضَةَ الْغِفَارِيِّ عَنْ عُرْوَةَ بْنِ الزُّبَيْرِ عَنْ عَائِشَةَأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَضَى أَنَّ خَرَاجَ الْعَبْدِ بِضَمَانِهِ","id":"Telah menceritakan kepada kami [Abu Bakr bin Abu Syaibah] dan [Ali bin Muhammad] keduanya berkata; telah menceritakan kepada kami [Waki'] dari [Ibnu Abu Dzi`b] dari [Makhlad bin Khufaf bin Ima bin Rahadlah Al Ghifari] dari [Urwah bin Az Zubair] dari ['Aisyah] berkata, \"Rasulullah shallallahu 'alaihi wasallam memutuskan cacat yang dimungkinkan terjadi pada budak yang dijual harus memperoleh garansi\""},"2199":{"ar":"حَدَّثَنَا هِشَامُ بْنُ عَمَّارٍ حَدَّثَنَا مُسْلِمُ بْنُ خَالِدٍ الزَّنْجِيُّ حَدَّثَنَا هِشَامُ بْنُ عُرْوَةَ عَنْ أَبِيهِ عَنْ عَائِشَةَأَنَّ رَجُلًا اشْتَرَى عَبْدًا فَاسْتَغَلَّهُ ثُمَّ وَجَدَ بِهِ عَيْبًا فَرَدَّهُ فَقَالَ يَا رَسُولَ اللَّهِ إِنَّهُ قَدْ اسْتَغَلَّ غُلَامِي فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَل��َمَ الْخَرَاجُ بِالضَّمَانِ","id":"Telah menceritakan kepada kami [Hisyam bin Ammar] berkata, telah menceritakan kepada kami [Muslim bin Khalid Az Zanji] berkata, telah menceritakan kepada kami [Hisyam bin Urwah] dari [Bapaknya] dari ['Aisyah] berkata, \"Seorang laki-laki membeli budak dan memanfaatkannya. Setelah itu ia mendapatkan cacat pada budak tersebut hingga ia pun mengembalikannya. Ia berkata, \"Wahai Rasulullah, ia telah memanfaatkan tenaga budakku! \" maka Rasulullah shallallahu 'alaihi wasallam pun bersabda: \"Kekurangan yang ada pada budakmu itu ada jaminannya.\""},"2200":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ عَبْدِ اللَّهِ بْنِ نُمَيْرٍ حَدَّثَنَا عَبْدَةُ بْنُ سُلَيْمَانَ عَنْ سَعِيدٍ عَنْ قَتَادَةَ عَنْ الْحَسَنِ إِنْ شَاءَ اللَّهُ عَنْ سَمُرَةَ بْنِ جُنْدَبٍ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عُهْدَةُ الرَّقِيقِ ثَلَاثَةُ أَيَّامٍ","id":"Telah menceritakan kepada kami [Muhammad bin Abdullah bin Numair] berkata, telah menceritakan kepada kami ['Abdah bin Sulaiman] dari [Sa'id] dari [Qatadah] dari [Al Hasan] insyaallah dari [Samurah bin Jundub] ia berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Jaminan seorang budak adalah tiga hari.\""},"2201":{"ar":"حَدَّثَنَا عَمْرُو بْنُ رَافِعٍ حَدَّثَنَا هُشَيْمٌ عَنْ يُونُسَ بْنِ عُبَيْدٍ عَنْ الْحَسَنِ عَنْ عُقْبَةَ بْنِ عَامِرٍأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ لَا عُهْدَةَ بَعْدَ أَرْبَعٍ","id":"Telah menceritakan kepada kami [Amru bin Rafi'] berkata, telah menceritakan kepada kami [Husyaim] dari [Yunus bin Ubaid] dari [Al Hasan] dari [Uqbah bin Amir] bahwa Rasulullah shallallahu 'alaihi wasallam bersabda: \"Tidak ada jaminan setelah empat hari.\""},"2202":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ بَشَّارٍ حَدَّثَنَا وَهْبُ بْنُ جَرِيرٍ حَدَّثَنَا أَبِي سَمِعْتُ يَحْيَى بْنَ أَيُّوبَ يُحَدِّثُ عَنْ يَزِيدَ بْنِ أَبِي حَبِيبٍ عَنْ عَبْدِ الرَّحْمَنِ بْنِ شُمَاسَةَ عَنْ عُقْبَةَ بْنِ عَامِرٍ قَالَسَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ الْمُسْلِمُ أَخُو الْمُسْلِمِ لَا يَحِلُّ لِمُسْلِمٍ بَاعَ مِنْ أَخِيهِ بَيْعًا فِيهِ عَيْبٌ إِلَّا بَيَّنَهُ لَهُ","id":"Telah menceritakan kepada kami [Muhammad bin Basysyar] berkata, telah menceritakan kepada kami [Wahb bin Jarir] berkata, telah menceritakan kepada kami [Bapakku] berkata; aku mendengar [Yahya bin Ayyub] menceritakan dari [Yazid bin Abu Habib] dari ['Abdurrahman bin Syumasah] dari [Uqbah bin Amir] ia berkata, \"Aku mendengar Rasulullah shallallahu 'alaihi wasallam bersabda: \"Muslim satu dengan muslin lainnya itu bersaudara, maka seorang muslim tidak boleh menjual barang yang ada cacat kepada saudaranya kecuali menjelaskan kepadanya.\""},"2203":{"ar":"حَدَّثَنَا عَبْدُ الْوَهَّابِ بْنُ الضَّحَّاكِ حَدَّثَنَا بَقِيَّةُ بْنُ الْوَلِيدِ عَنْ مُعَاوِيَةَ بْنِ يَحْيَى عَنْ مَكْحُولٍ وَسُلَيْمَانَ بْنِ مُوسَى عَنْ وَاثِلَةَ بْنِ الْأَسْقَعِ قَالَسَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ مَنْ بَاعَ عَيْبًا لَمْ يُبَيِّنْهُ لَمْ يَزَلْ فِي مَقْتِ اللَّهِ وَلَمْ تَزَلْ الْمَلَائِكَةُ تَلْعَنُهُ","id":"Telah menceritakan kepada kami [Abdul Wahhab bin Adl Dlahhak] berkata, telah menceritakan kepada kami [Baqiyyah bin Al Walid] dari [Mu'awiyah bin Yahya] dari [Makhul] dan [Sulaiman bin Musa] dari [Watsilah bin Al Asyqa'] ia berkata, \"Aku mendengar Rasulullah shallallahu 'alaihi wasallam bersabda: \"Barangsiapa menjual barang jelek dan tidak menjelaskannya, maka ia senantiasa dalam murka Allah dan laknat para malaikat.\""},"2204":{"ar":"حَدَّثَنَا عَلِيُّ بْنُ مُحَمَّدٍ وَمُحَمَّدُ بْنُ إِسْمَعِيلَ قَالَا حَدَّثَنَا وَكِيعٌ حَدَّثَنَا سُفْيَانُ عَنْ جَابِرٍ عَنْ الْقَاسِمِ بْنِ عَبْدِ الرَّحْمَنِ عَنْ أَبِيهِ عَنْ عَبْدِ اللَّهِ بْنِ مَسْعُودٍ قَالَكَانَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِذَا أُتِيَ بِالسَّبْيِ أَعْطَى أَهْلَ الْبَيْتِ جَمِيعًا كَرَاهِيَةَ أَنْ يُفَرِّقَ بَيْنَهُمْ","id":"Telah menceritakan kepada kami [Ali bin Muhammad] dan [Muhammad bin Isma'il] keduanya berkata; telah menceritakan kepada kami [Waki'] berkata, telah menceritakan kepada kami [Sufyan] dari [Jabir] dari [Al Qasim bin 'Abdurrahman] dari [Bapaknya] dari [Abdullah bin Mas'ud] ia berkata, \"Jika dihadapkan kepada Nabi shallallahu 'alaihi wasallam para tawanan, beliau mengumpulkan (setiap) keluarga besar dalam satu tempat, khawatir jika mereka berpisah.\""},"2205":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ يَحْيَى حَدَّثَنَا عَفَّانُ عَنْ حَمَّادٍ أَنْبَأَنَا الْحَجَّاجُ عَنْ الْحَكَمِ عَنْ مَيْمُونِ بْنِ أَبِي شَبِيبٍ عَنْ عَلِيٍّ قَالَوَهَبَ لِي رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ غُلَامَيْنِ أَخَوَيْنِ فَبِعْتُ أَحَدَهُمَا فَقَالَ مَا فَعَلَ الْغُلَامَانِ قُلْتُ بِعْتُ أَحَدَهُمَا قَالَ رُدَّهُ","id":"Telah menceritakan kepada kami [Muhammad bin Yahya] berkata, telah menceritakan kepada kami [Affan] dari [Hammad] berkata, telah memberitakan kepada kami [Al Hajjaj] dari [Al Hakam] dari [Maimun bin Abu Syabib] dari [Ali] ia berkata, \"Rasulullah shallallahu 'alaihi wasallam memberiku hadiah dua budak bersaudara. Kemudian aku menjual seorang dari keduanya. Beliau lantas bertanya: \"Apa yang sedang dilakukan oleh kedua budak itu?\" Aku menjawab, \"Aku telah menjual salah seorang dari keduanya.\" Beliau bersabda: \"Kembalikanlah.\""},"2206":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ عُمَرَ بْنِ هَيَّاجٍ حَدَّثَنَا عُبَيْدُ اللَّهِ بْنُ مُوسَى أَنْبَأَنَا إِبْرَاهِيمُ بْنُ إِسْمَعِيلَ عَنْ طَلِيقِ بْنِ عِمْرَانَ عَنْ أَبِي بُرْدَةَ عَنْ أَبِي مُوسَى قَالَلَعَنَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَنْ فَرَّقَ بَيْنَ الْوَالِدَةِ وَوَلَدِهَا وَبَيْنَ الْأَخِ وَبَيْنَ أَخِيهِ","id":"Telah menceritakan kepada kami [Muhammad bin Umar bin Hayyaj] berkata, telah menceritakan kepada kami [Ubaidullah bin Musa] berkata, telah memberitakan kepada kami [Ibrahim bin Isma'il] dari [Thaliq bin Imran] dari [Abu Burdah] dari [Abu Musa] ia berkata, \"Rasulullah shallallahu 'alaihi wasallam melaknat orang yang memisahkan antara ibu dan anaknya, dan antara saudara dan saudaranya.\""},"2207":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ بَشَّارٍ حَدَّثَنَا عَبَّادُ بْنُ لَيْثٍ صَاحِبُ الْكَرَابِيسِيِّ حَدَّثَنَا عَبْدُ الْمَجِيدِ بْنُ وَهْبٍ قَالَ قَالَ لِي الْعَدَّاءُ بْنُ خَالِدِ بْنِ هَوْذَةَأَلَا نُقْرِئُكَ كِتَابًا كَتَبَهُ لِي رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ قُلْتُ بَلَى فَأَخْرَجَ لِي كِتَابًا فَإِذَا فِيهِ هَذَا مَا اشْتَرَى الْعَدَّاءُ بْنُ خَالِدِ بْنِ هَوْذَةَ مِنْ مُحَمَّدٍ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ اشْتَرَى مِنْهُ عَبْدًا أَوْ أَمَةً لَا دَاءَ وَلَا غَائِلَةَ وَلَا خِبْثَةَ بَيْعَ الْمُسْلِمِ لِلْمُسْلِمِ","id":"Telah menceritakan kepada kami [Muhammad bin Basyar] berkata, telah menceritakan kepada kami [Abbad bin Laits] teman Al Karabisi berkata, telah menceritakan kepada kami [Abdul Majid bin Wahb] ia berkata; [Al 'Adda bin Khalid bin Haudzah] berkata, \"Maukah kamu aku bacakan sebuah kitab yang ditulis oleh Rasulullah shallallahu 'alaihi wasallam untukku?\" Abdul Majid bin Wahb berkata, \"Aku menjawab, \"Tentu.\" Lalu ia mengeluarkan sebuah kitab kepadaku, dan ternyata di dalamnya terdapat tulisan: \"Ini adalah apa yang telah dibeli Al 'Adda bin Khalid bin Haudzah, dari Muhammad Rasulullah shallallahu 'alaihi wasallam. Dia telah membeli darinya seorang budak lelaki atau budak perempuan yang bebas dari penyakit, tidak jelek dan tidak buruk. Jual beli muslim untuk muslim.\""},"2208":{"ar":"حَدَّثَنَا عَبْدُ اللَّهِ بْنُ سَعِيدٍ حَدَّثَنَا أَبُو خَالِدٍ الْأَحْمَرُ عَنْ ابْنِ عَجْلَانَ عَنْ عَمْرِو بْنِ شُعَيْبٍ عَنْ أَبِيهِ عَنْ جَدِّهِ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِذَا اشْتَرَى أَحَدُكُمْ الْجَارِيَةَ فَلْيَقُلْ اللَّهُمَّ إِنِّي أَسْأَلُكَ خَيْرَهَا وَخَيْرَ مَا جَبَلْتَهَا عَلَيْهِ وَأَعُوذُ بِكَ مِنْ شَرِّهَا وَشَرِّ مَا جَبَلْتَهَا عَلَيْهِ وَلْيَدْعُ بِالْبَرَكَةِ وَإِذَا اشْتَرَى أَحَدُكُمْ بَعِيرًا فَلْيَأْخُذْ بِذِرْوَةِ سَنَامِهِ وَلْيَدْعُ بِالْبَرَكَةِ وَلْيَقُلْ مِثْلَ ذَلِكَ","id":"Telah menceritakan kepada kami [Abdullah bin Sa'id] berkata, telah menceritakan kepada kami [Abu Khalid Al Ahmar] dari [Ibnu 'Ajlan] dari [Amru bin Syu'aib] dari [Bapaknya] dari [Kakeknya] ia berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Apabila salah seorang dari kalian membeli seorang budak perempuan, hendaklah ia mengucapkan; \"ALLAHUMMA INNII AS`ALUKA KHAIRAHAA WA KHAIRA MAA JABALTAHAA 'ALAIHI WA A'UUDZUBIKA MIN SYARRIHAA WA SYARRI MAA JABALTAHAA 'ALAIHI (Ya Allah, sesungguhnya aku meminta kepada-Mu kebaikannya dan kebaikan yang Engkau berikan kepadanya, dan aku berlindung kepada-Mu dari keburukannya dan keburukan yang Engkau berikan kepadanya). Dan hendaklah ia berdo'a meminta berkah. Dan jika salah seorang dari kalian membeli seekor unta hendaklah ia pegang punuk untanya dan berdo'a meminta berkah sebagaimana do`a tersebut.\""},"2209":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ وَعَلِيُّ بْنُ مُحَمَّدٍ وَهِشَامُ بْنُ عَمَّارٍ وَنَصْرُ بْنُ عَلِيٍّ وَمُحَمَّدُ بْنُ الصَّبَّاحِ قَالُوا حَدَّثَنَا سُفْيَانُ بْنُ عُيَيْنَةَ عَنْ الزُّهْرِيِّ عَنْ مَالِكِ بْنِ أَوْسِ بْنِ الْحَدَثَانِ النَّصْرِيِّ قَالَ سَمِعْتُ عُمَرَ بْنَ الْخَطَّابِ يَقُولُقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ الذَّهَبُ بِالذَّهَبِ رِبًا إِلَّا هَاءَ وَهَاءَ وَالْبُرُّ بِالْبُرِّ رِبًا إِلَّا هَاءَ وَهَاءَ وَالشَّعِيرُ بِالشَّعِيرِ رِبًا إِلَّا هَاءَ وَهَاءَ وَالتَّمْرُ بِالتَّمْرِ رِبًا إِلَّا هَاءَ وَهَاءَ","id":"Telah menceritakan kepada kami [Abu Bakr bin Abu Syaibah] dan [Ali bin Muhammad] dan [Hisyam bin Ammar] dan [Nashr bin Ali] dan [Muhammad bin Ash Shabbah] mereka berkata; telah menceritakan kepada kami [Sufyan bin Uyainah] dari [Az Zuhri] dari [Malik bin Aus bin Al Hadatsani An Nashr] ia berkata, \"Aku mendengar [Umar Ibnul Khaththab] berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Emas dengan emas riba kecuali dengan tunai, biji gandum dengan biji gandum riba kecuali dengan tunai, tepung gandum dengan tepung gandum riba kecuali dengan tunai dan kurma dengan kurma riba kecuali dengan tunai.\""},"2210":{"ar":"حَدَّثَنَا حُمَيْدُ بْنُ مَسْعَدَةَ حَدَّثَنَا يَزِيدُ بْنُ زُرَيْعٍ ح و حَدَّثَنَا مُحَمَّدُ بْنُ خَالِدِ بْنِ خِدَاشٍ حَدَّثَنَا إِسْمَعِيلُ ابْنُ عُلَيَّةَ قَالَا حَدَّثَنَا سَلَمَةُ بْنُ عَلْقَمَةَ التَّمِيمِيُّ حَدَّثَنَا مُحَمَّدُ بْنُ سِيرِينَ أَنَّ مُسْلِمَ بْنَ يَسَارٍ وَعَبْدَ اللَّهِ بْنَ عُبَيْدٍ حَدَّثَاهُ قَالَاجَمَعَ الْمَنْزِلُ بَيْنَ عُبَادَةَ بْنِ الصَّامِتِ وَمُعَاوِيَةَ إِمَّا فِي كَنِيسَةٍ وَإِمَّا فِي بِيعَةٍ فَحَدَّثَهُمْ عُبَادَةُ بْنُ الصَّامِتِ فَقَالَ قَالَ نَهَانَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَنْ بَيْعِ الْوَرِقِ بِالْوَرِقِ وَالذَّهَبِ بِالذَّهَبِ وَالْبُرِّ بِالْبُرِّ وَالشَّعِيرِ بِالشَّعِيرِ وَالتَّمْرِ بِالتَّمْرِ قَالَ أَحَدُهُمَا وَالْمِلْحِ بِالْمِلْحِ وَلَمْ يَقُلْهُ الْآخَرُ وَأَمَرَنَا أَنْ نَبِيعَ الْبُرَّ بِالشَّعِيرِ وَالشَّعِيرَ بِالْبُرِّ يَدًا بِيَدٍ كَيْفَ شِئْنَا","id":"Telah menceritakan kepada kami [Humaid bin Mas'adah] berkata, telah menceritakan kepada kami [Yazid bin Zurai']. (dalam jalur lain disebutkan) Telah menceritakan kepada kami [Muhammad bin Khalid bin Khidasy] berkata, telah menceritakan kepada kami [Isma'il bin Ulayyah] keduanya berkata; telah menceritakan kepada kami [Salamah bin Alqamah At Taimi] berkata, telah menceritakan kepada kami [Muhammad bin Sirin] bahwa [Muslim bin Yasar] dan [Abdullah bin Ubaid] menceritakan kepadanya, keduanya berkata; Ubadah bin Ash Shamit dan Mu'awiyah berkumpul dalan sebuah rumah, yaitu dalam sebuah gereja, atau sinagog. [Ubadah bin Ash Shamit] menceritakan kepada mereka, ia mengatakan, \"Rasulullah shallallahu 'alaihi wasallam melarang kami untuk menjual perak dengan perak, emas dengan emas, biji gandum dengan biji gandum, tepung gandum dengan tepung gandum, dan kurma dengan kurma. Salah seorang dari keduanya berkata, \"Garam dengan garam -ini tidak disebutkan oleh yang lain- dan beliau memerintahkan kepada kami untuk biji gandum dengan tepung gandum, atau tepung gandum dengan biji gandum secara tunai berapa pun yang kami mau.\""},"2211":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا يَعْلَى بْنُ عُبَيْدٍ حَدَّثَنَا فُضَيْلُ بْنُ غَزْوَانَ عَنْ ابْنِ أَبِي نُعْمٍ عَنْ أَبِي هُرَيْرَةَعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ الْفِضَّةَ بِالْفِضَّةِ وَالذَّهَبَ بِالذَّهَبِ وَالشَّعِيرَ بِالشَّعِيرِ وَالْحِنْطَةَ بِالْحِنْطَةِ مِثْلًا بِمِثْلٍ","id":"Telah menceritakan kepada kami [Abu Bakr bin Abu Syaibah] berkata, telah menceritakan kepada kami [Ya'la bin Ubaid] berkata, telah menceritakan kepada kami [Fudlail bin Ghazwan] dari [Ibnu Abu Nu'm] dari [Abu Hurairah] dari Nabi shallallahu 'alaihi wasallam, beliau bersabda: \"Perak dengan perak, emas dengan emas, gandum dengan gandum, tepung dengan tepung sebanding.\""},"2212":{"ar":"حَدَّثَنَا أَبُو كُرَيْبٍ حَدَّثَنَا عَبْدَةُ بْنُ سُلَيْمَانَ عَنْ مُحَمَّدِ بْنِ عَمْرٍو عَنْ أَبِي سَلَمَةَ عَنْ أَبِي سَعِيدٍ قَالَكَانَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَرْزُقُنَا تَمْرًا مِنْ تَمْرِ الْجَمْعِ فَنَسْتَبْدِلُ بِهِ تَمْرًا هُوَ أَطْيَبُ مِنْهُ وَنَزِيدُ فِي السِّعْرِ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَا يَصْلُحُ صَاعُ تَمْرٍ بِصَاعَيْنِ وَلَا دِرْهَمٌ بِدِرْهَمَيْنِ وَالدِّرْهَمُ بِالدِّرْهَمِ وَالدِّينَارُ بِالدِّينَارِ لَا فَضْلَ بَيْنَهُمَا إِلَّا وَزْنًا","id":"Telah menceritakan kepada kami [Abu Kuraib] berkata, telah menceritakan kepada kami [Abdah bin Sulaiman] dari [Muhammad bin Amru] dari [Abu Salamah] dari [Abu Sa'id] ia berkata, \"Nabi shallallahu 'alaihi wasallam memberi kami kurma dari kurma zakat, lalu kami mengantinya dengan yang lebih baik dengan menambah harga. Maka Rasulullah shallallahu 'alaihi wasallam pun bersabda: \"Tidak boleh menukar kurma satu sha' dengan dua sha', dan satu dirham dengan dua dirham. Hendaklah satu dirham dengan satu dirham, dan satu dinar dengan satu dinar, tidak ada penambahan antara keduanya kecuali seimbang.\""},"2213":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ الصَّبَّاحِ حَدَّثَنَا سُفْيَانُ بْنُ عُيَيْنَةَ عَنْ عَمْرِو بْنِ دِينَارٍ عَنْ أَبِي صَالِحٍ عَنْ أَبِي هُرَيْرَةَ قَالَ سَمِعْتُ أَبَا سَعِيدٍ الْخُدْرِيَّ يَقُولُالدِّرْهَمُ بِالدِّرْهَمِ وَالدِّينَارُ بِالدِّينَارِ فَقُلْتُ إِنِّي سَمِعْتُ ابْنَ عَبَّاسٍ يَقُولُ غَيْرَ ذَلِكَ قَالَ أَمَا إِنِّي لَقِيتُ ابْنَ عَبَّاسٍ فَقُلْتُ أَخْبِرْنِي عَنْ هَذَا الَّذِي تَقُولُ فِي الصَّرْفِ أَشَيْءٌ سَمِعْتَهُ مِنْ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَمْ شَيْءٌ وَجَدْتَهُ فِي كِتَابِ اللَّهِ فَقَالَ مَا وَجَدْتُهُ فِي كِتَابِ اللَّهِ وَلَا سَمِعْتُهُ مِنْ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَلَكِنْ أَخْبَرَنِي أُسَامَةُ بْنُ زَيْدٍ أَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ إِنَّمَا الرِّبَا فِي النَّسِيئَةِ","id":"Telah menceritakan kepada kami [Muhammad bin Ash Shabbah] berkata, telah menceritakan kepada kami [Sufyan bin Uyainah] dari [Amru bin Dinar] dari [Abu Shalih] dari [Abu Hurairah], ia berkata, \"Aku mendengar [Abu Sa'id Al Khudri] berkata, \"Satu dirham dengan satu dirham dan satu dinar dengan satu dinar.\" Aku (Abu Hurairah) berkata, \"(Namun) aku pernah mendengar Ibnu Abbas mengatakan dengan sesuatu yang berbeda! Abu Sa'id berkata, \"Aku pernah bertemu dengan Ibnu Abbas, lalu aku berkata kepadanya, \"Kabarkanlah kepadaku bagaimana pendapatmu tentang Sharf, apakah itu sesuatu yang engkau dengar dari Rasulullah shallallahu 'alaihi wasallam, atau sesuatu yang engkau dapatkan dari kitabullah?\" [Ibnu Abbas] lantas menjawab, \"Aku tidak mendapatkannya dari kitabullah ataupun sunnah Rasulullah shallallahu 'alaihi wasallam, akan tetapi yang mengabariku seperti itu adalah [Usamah bin Zaid], bahwa Rasulullah shallallahu 'alaihi wasallam pernah bersabda: \"Hanyasanya riba itu ada pada penundaan.\""},"2214":{"ar":"حَدَّثَنَا أَحْمَدُ بْنُ عَبْدَةَ أَنْبَأَنَا حَمَّادُ بْنُ زَيْدٍ عَنْ سُلَيْمَانَ بْنِ عَلِيٍّ الرِّبْعِيِّ عَنْ أَبِي الْجَوْزَاءِ قَالَسَمِعْتُهُ يَأْمُرُ بِالصَّرْفِ يَعْنِي ابْنَ عَبَّاسٍ وَيُحَدَّثُ ذَلِكَ عَنْهُ ثُمَّ بَلَغَنِي أَنَّهُ رَجَعَ عَنْ ذَلِكَ فَلَقِيتُهُ بِمَكَّةَ فَقُلْتُ إِنَّهُ بَلَغَنِي أَنَّكَ رَجَعْتَ قَالَ نَعَمْ إِنَّمَا كَانَ ذَلِكَ رَأْيًا مِنِّي وَهَذَا أَبُو سَعِيدٍ يُحَدِّثُ عَنْ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنَّهُ نَهَى عَنْ الصَّرْفِ","id":"Telah menceritakan kepada kami [Ahmad bin Abdah] berkata, telah memberitakan kepada kami [Hammad bin Zaid] dari [Sulaiman bin Ali Ar Rib'i] dari [Abu Al Jauza] ia berkata, \"Aku mendengarnya -maksudnya [Ibnu Abbas] - memerintahkan Sharf. Berita itu diriwayatkan darinya (Ibnu Abbas), dan telah sampai kabar kepadaku bahwa ia telah menarik kembali pendapatnya tersebut. Maka aku menemuinya di Makkah dan bertanya kepadanya, \"Telah sampai kepadaku bahwa engkau telah menarik pendapatmu?\" Ibnu Abbas menjawab, \"Benar, hal itu hanya pendapatku saja. Dan ini ada [Abu Sa'id] yang telah meriwayatkan dari Rasulullah shallallahu 'alaihi wasallam, bahwa beliau melarang Sharf.\""},"2215":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا سُفْيَانُ بْنُ عُيَيْنَةَ عَنْ الزُّهْرِيِّ سَمِعَ مَالِكَ بْنَ أَوْسِ بْنِ الْحَدَثَانِ يَقُولُ سَمِعْتُ عُمَرَ يَقُولُقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ الذَّهَبُ بِالْوَرِقِ رِبًا إِلَّا هَاءَ وَهَاءَقَالَ أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ سَمِعْتُ سُفْيَانَ يَقُولُ الذَّهَبُ بِالْوَرِقِ احْفَظُوا","id":"Telah menceritakan kepada kami [Abu Bakr bin Abu Syaibah] berkata, telah menceritakan kepada kami [Sufyan bin Uyainah] dari [Az Zuhri] ia mendengar [Malik bin Aus bin Al Hadatsan] berkata; Aku mendengar [Umar] berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Emas dengan perak riba kecuali dengan tunai.\" Abu Bakr bin Abu Syaibah berkata, \"Aku mendengar Sufyan mengatakan, \"Emas dengan perak, ingatlah oleh kalian semua.\""},"2216":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ رُمْحٍ أَنْبَأَنَا اللَّيْثُ بْنُ سَعْدٍ عَنْ ابْنِ شِهَابٍ عَنْ مَالِكِ بْنِ أَوْسِ بْنِ الْحَدَثَانِ قَالَأَقْبَلْتُ أَقُولُ مَنْ يَصْطَرِفُ الدَّرَاهِمَ فَقَالَ طَلْحَةُ بْنُ عُبَيْدِ اللَّهِ وَهُوَ عِنْدَ عُمَرَ بْنِ الْخَطَّابِ أَرِنَا ذَهَبَكَ ثُمَّ ائْتِنَا إِذَا جَاءَ خَازِنُنَا نُعْطِكَ وَرِقَكَ فَقَالَ عُمَرُ كَلَّا وَاللَّهِ لَتُعْطِيَنَّهُ وَرِقَهُ أَوْ لَتَرُدَّنَّ إِلَيْهِ ذَهَبَهُ فَإِنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ الْوَرِقُ بِالذَّهَبِ رِبًا إِلَّا هَاءَ وَهَاءَ","id":"Telah menceritakan kepada kami [Muhammad bin Rumh] berkata, telah memberitakan kepada kami [Al Laits bin Sa'd] dari [Ibnu Syihab] dari [Malik bin Aus bin Al Hadatsan] berkata, \"Aku mulai bertanya, \"Siapa yang mau menukar dirham?\" Maka Thalhah bin Ubaidullah -waktu itu ia berada di sisi Umar Ibnul Khaththab- berkata, \"Perlihatkan dan berikanlah kepada kami emas milikmu. Jika pengawalmu datang maka akan kami berikan perak milik kami kepadamu.\" [Umar] lalu berkata, \"Tidak, demi Allah, engkau berikan perak milik kepadanya atau engkau kembalikan emas miliknya! Sungguh, Rasulullah shallallahu 'alaihi wasallam pernah bersabda: \"Perak dengan emas riba kecuali dengan tunai.\""},"2217":{"ar":"حَدَّثَنَا أَبُو إِسْحَقَ الشَّافِعِيُّ إِبْرَاهِيمُ بْنُ مُحَمَّدِ بْنِ الْعَبَّاسِ حَدَّثَنِي أَبِي عَنْ أَبِيهِ الْعَبَّاسِ بْنِ عُثْمَانَ بْنِ شَافِعٍ عَنْ عُمَرَ بْنِ مُحَمَّدِ بْنِ عَلِيِّ بْنِ أَبِي طَالِبٍ عَنْ أَبِيهِ عَنْ جَدِّهِ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ الدِّينَارُ بِالدِّينَارِ وَالدِّرْهَمُ بِالدِّرْهَمِ لَا فَضْلَ بَيْنَهُمَا فَمَنْ كَانَتْ لَهُ حَاجَةٌ بِوَرِقٍ فَلْيَصْطَرِفْهَا بِذَهَبٍ وَمَنْ كَانَتْ لَهُ حَاجَةٌ بِذَهَبٍ فَلْيَصْطَرِفْهَا بِالْوَرِقِ وَالصَّرْفُ هَاءَ وَهَاءَ","id":"Telah menceritakan kepada kami [Abu Ishaq Asy Syafi'I Ibrahim bin Muhammad bin Al Abbas] berkata, telah menceritakan kepadaku [Bapakku] dari bapaknya [Al Abbas bin Utsman bin Syafi'] dari [Umar bin Muhammad bin Ali bin Abu Thalib] dari [Bapaknya] dari [Kakeknya] ia berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Dinar dengan dinar, dirham dengan dirham tidak boleh ada lebih di antara keduanya. Barangsiapa membutuhkan perak, hendaklah ia menukarnya dengan emas. Dan barangsiapa membutuhkan emas, hendaklah dia menukarnya dengan perak. Dan penukaran itu harus dengan tunai.\""},"2218":{"ar":"حَدَّثَنَا إِسْحَقُ بْنُ إِبْرَاهِيمَ بْنِ حَبِيبٍ وَسُفْيَانُ بْنُ وَكِيعٍ وَمُحَمَّدُ بْنُ عُبَيْدِ بْنِ ثَعْلَبَةَ الْحِمَّانِيُّ قَالُوا حَدَّثَنَا عُمَرُ بْنُ عُبَيْدٍ الطَّنَافِسِيُّ حَدَّثَنَا عَطَاءُ بْنُ السَّائِبِ أَوْ سِمَاكٌ وَلَا أَعْلَمُهُ إِلَّا سِمَاكًا عَنْ سَعِيدِ بْنِ جُبَيْرٍ عَنْ ابْنِ عُمَرَ قَالَكُنْتُ أَبِيعُ الْإِبِلَ فَكُنْتُ آخُذُ الذَّهَبَ مِنْ الْفِضَّةِ وَالْفِضَّةَ مِنْ الذَّهَبِ وَالدَّنَانِيرَ مِنْ الدَّرَاهِمِ وَالدَّرَاهِمَ مِنْ الدَّنَانِيرِ فَسَأَلْتُ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ إِذَا أَخَذْتَ أَحَدَهُمَا وَأَعْطَيْتَ الْآخَرَ فَلَا تُفَارِقْ صَاحِبَكَ وَبَيْنَكَ وَبَيْنَهُ لَبْسٌحَدَّثَنَا يَحْيَى بْنُ حَكِيمٍ حَدَّثَنَا يَعْقُوبُ بْنُ إِسْحَقَ أَنْبَأَنَا حَمَّادُ بْنُ سَلَمَةَ عَنْ سِمَاكِ بْنِ حَرْبٍ عَنْ سَعِيدِ بْنِ جُبَيْرٍ عَنْ ابْنِ عُمَرَ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ نَحْوَهُ","id":"Telah menceritakan kepada kami [Ishaq bin Ibrahim bin Habib] dan [Sufyan bin Waki'] dan [Muhammad bin Ubaid bin Tsa'labah Al Himmani] mereka berkata; telah menceritakan kepada kami [Umar bin Ubaid Ath Thanafisi] berkata, telah menceritakan kepada kami ['Atha bin As Sa`ib] atau [Simak] -aku tidak mengetahuinya kecuali Simak- dari [Sa'id bin Jubair] dari [Ibnu Umar] ia berkata, \"Aku menjual unta, lalu aku mengambil emas senilai perak, dan perak senilai emas, dan dinar senilai dirham, dan dirham senilai dinar. Kemudian hal itu aku tanyakan kepada Nabi shallallahu 'alaihi wasallam, beliau menjawab: \"Jika engkau ambil salah satunya dan engkau berikan yang lain, maka janganlah engkau berpisah dengan saudaramu, sementara antaramu dengannya masih terdapat sisa (percampuran antara emas dengan perak).\" Telah menceritakan kepada kami [Yahya bin Hakim] berkata, telah menceritakan kepada kami [Ya'qub bin Ishaq] berkata, telah memberitakan kepada kami [Hammad bin Salamah] dari [Simak bin Harb] dari [Sa'id bin Jubair] dari [Ibnu Umar] dari Nabi shallallahu 'alaihi wasallam sebagaimana dalam hadits.\""},"2219":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ وَسُوَيْدُ بْنُ سَعِيدٍ وَهَارُونُ بْنُ إِسْحَقَ قَالُوا حَدَّثَنَا الْمُعْتَمِرُ بْنُ سُلَيْمَانَ عَنْ مُحَمَّدِ بْنِ فَضَاءٍ عَنْ أَبِيهِ عَنْ عَلْقَمَةَ بْنِ عَبْدِ اللَّهِ عَنْ أَبِيهِ قَالَنَهَى رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَنْ كَسْرِ سِكَّةِ الْمُسْلِمِينَ الْجَائِزَةِ بَيْنَهُمْ إِلَّا مِنْ بَأْسٍ","id":"Telah menceritakan kepada kami [Abu Bakr bin Abu Syaibah] dan [Suwaid bin Sa'id] dan [Harun bin Ishaq] mereka berkata; telah menceritakan kepada kami [Al Mu'tamir bin Sulaiman] dari [Muhammad bin Fadla] dari [Bapaknya] dari [Alqamah bin Abdullah] dari [Bapaknya] ia berkata, \"Rasulullah shallallahu 'alaihi wasallam melarang memecah mata uang kaum muslimin yang tersedia di antara mereka kecuali karena bahaya.\""},"2220":{"ar":"حَدَّثَنَا عَلِيُّ بْنُ مُحَمَّدٍ حَدَّثَنَا وَكِيعٌ وَإِسْحَقُ بْنُ سُلَيْمَانَ قَالَا حَدَّثَنَا مَالِكُ بْنُ أَنَسٍ عَنْ عَبْدِ اللَّهِ بْنِ يَزِيدَ مَوْلَى الْأَسْوَدِ بْنِ سُفْيَانَ أَنَّ زَيْدًا أَبَا عَيَّاشٍ مَوْلًى لِبَنِي زُهْرَةَ أَخْبَرَهُأَنَّهُ سَأَلَ سَعْدَ بْنَ أَبِي وَقَّاصٍ عَنْ اشْتِرَاءِ الْبَيْضَاءِ بِالسُّلْتِ فَقَالَ لَهُ سَعْدٌ أَيَّتُهُمَا أَفْضَلُ قَالَ الْبَيْضَاءُ فَنَهَانِي عَنْهُ وَقَالَ إِنِّي سَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ سُئِلَ عَنْ اشْتِرَاءِ الرُّطَبِ بِالتَّمْرِ فَقَالَ أَيَنْقُصُ الرُّطَبُ إِذَا يَبِسَ قَالُوا نَعَمْ فَنَهَى عَنْ ذَلِكَ","id":"Telah menceritakan kepada kami [Ali bin Muhammad] berkata, telah menceritakan kepada kami [Waki'] dan [Ishaq bin Sulaiman] keduanya berkata; telah menceritakan kepada kami [Malik bin Anas] dari [Abdullah bin Yazid] -mantan budak Al Aswad bin Sufyan- bahwa [Zaid Abu Ayyasy] -mantan budak bani Zuhrah- mengabarkan kepadanya, bahwa ia bertanya [Sa'd bin Abu Waqash] tentang hukum membeli Baidla (sejenis gandum) dengan alat tukar Sult (sejenis gandum). Sa'd pun ganti bertanya kepadanya, \"Mana yang lebih bagus dari keduanya?\" Zaid menjawab, \"Lebih bagus Baidla.\" Maka Sa'd pun melarang kami dari hal itu. Setelah itu ia berkata, \"Aku pernah mendengar Rasulullah shallallahu 'alaihi wasallam saat ditanya tentang hukum membeli kurma muda dengan kurma matang, beliau bersabda: \"Apakah kurma muda akan berkurang jika kering?\" para sahabat menjawab, \"Ya, \" maka beliau pun melarangnya.\""},"2221":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ رُمْحٍ أَنْبَأَنَا اللَّيْثُ بْنُ سَعْدٍ عَنْ نَافِعٍ عَنْ عَبْدِ اللَّهِ بْنِ عُمَرَ قَالَنَهَى رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَنْ الْمُزَابَنَةِ وَالْمُزَابَنَةُ أَنْ يَبِيعَ الرَّجُلُ تَمْرَ حَائِطِهِ إِنْ كَانَتْ نَخْلًا بِتَمْرٍ كَيْلًا وَإِنْ كَانَتْ كَرْمًا أَنْ يَبِيعَهُ بِزَبِيبٍ كَيْلًا وَإِنْ كَانَتْ زَرْعًا أَنْ يَبِيعَهُ بِكَيْلِ طَعَامٍ نَهَى عَنْ ذَلِكَ كُلِّهِ","id":"Telah menceritakan kepada kami [Muhammad bin Rumh] berkata, telah memberitakan kepada kami [Al Laits bin Sa'd] dari [Nafi'] dari [Abdullah bin Umar] ia berkata, \"Rasulullah shallallahu 'alaihi wasallam melarang jual beli dengan sistem Muzabanah. Muzabanah adalah, seseorang menjual buah yang masih ada dikebun jika itu berupa kurma, dengan kurma dalam takaran. Jika itu berupa anggur, maka ia menjualnya dengan anggur kering dalam takaran. Dan jika itu berupa tanaman, maka ia menjualnya dengan makanan dalam takaran. Dan beliau melarang dari semua itu.\""},"2222":{"ar":"حَدَّثَنَا أَزْهَرُ بْنُ مَرْوَانَ حَدَّثَنَا حَمَّادُ بْنُ زَيْدٍ عَنْ أَيُّوبَ عَنْ أَبِي الزُّبَيْرِ وَسَعِيدُ بْنُ مِينَاءَ عَنْ جَابِرِ بْنِ عَبْدِ اللَّهِأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ نَهَى عَنْ الْمُحَاقَلَةِ وَالْمُزَابَنَةِ","id":"Telah menceritakan kepada kami [Azhar bin Marwan] berkata, telah menceritakan kepada kami [Hammad bin Zaid] dari [Ayyub] dari [Abu Az Zubair] dari [Sa'id bin Mina] dari [Jabir bin Abdullah] berkata, \"Rasulullah shallallahu 'alaihi wasallam melarang jual beli dengan sistem Muhaqalah dan Muzabanah.\" "},"2223":{"ar":"حَدَّثَنَا هَنَّادُ بْنُ السَّرِيِّ حَدَّثَنَا أَبُو الْأَحْوَصِ عَنْ طَارِقِ بْنِ عَبْدِ الرَّحْمَنِ عَنْ سَعِيدِ بْنِ الْمُسَيِّبِ عَنْ رَافِعِ بْنِ خَدِيجٍ قَالَنَهَى رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَنْ الْمُحَاقَلَةِ وَالْمُزَابَنَةِ","id":"Telah menceritakan kepada kami [Hannad bin As Sari] berkata, telah menceritakan kepada kami [Abu Al Ahwash] dari [Thariq bin 'Abdurrahman] dari [Sa'id Ibnul Musayyab] dari [Rafi' bin Khadij] ia berkata, \"Rasulullah shallallahu 'alaihi wasallam melarang jual beli dengan sistem Muhaqalah dan Muzabanah.\" "},"2224":{"ar":"حَدَّثَنَا هِشَامُ بْنُ عَمَّارٍ وَمُحَمَّدُ بْنُ الصَّبَّاحِ قَالَا حَدَّثَنَا سُفْيَانُ بْنُ عُيَيْنَةَ عَنْ الزُّهْرِيِّ عَنْ سَالِمٍ عَنْ أَبِيهِ قَالَ حَدَّثَنِي زَيْدُ بْنُ ثَابِتٍأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ رَخَّصَ فِي الْعَرَايَا","id":"Telah menceritakan kepada kami [Hisyam bin Ammar] dan [Muhammad bin Ash Shabbah] keduanya berkata; telah menceritakan kepada kami [Sufyan bin Uyainah] dari [Az Zuhri] dari [Salim] dari [Bapaknya] ia berkata, \" [Zaid bin Tsabit] menceritakan kepadaku bahwa Rasulullah shallallahu 'alaihi wasallam memberi keringanan dalam jual beli dengan kurma muda.\""},"2225":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ رُمْحٍ أَنْبَأَنَا اللَّيْثُ بْنُ سَعْدٍ عَنْ يَحْيَى بْنِ سَعِيدٍ عَنْ نَافِعٍ عَنْ عَبْدِ اللَّهِ بْنِ عُمَرَ أَنَّهُ قَالَ حَدَّثَنِي زَيْدُ بْنُ ثَابِتٍأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَرْخَصَ فِي بَيْعِ الْعَرِيَّةِ بِخَرْصِهَا تَمْرًاقَالَ يَحْيَى الْعَرِيَّةُ أَنْ يَشْتَرِيَ الرَّجُلُ ثَمَرَ النَّخَلَاتِ بِطَعَامِ أَهْلِهِ رُطَبًا بِخَرْصِهَا تَمْرًا","id":"Telah menceritakan kepada kami [Muhammad bin Rumh] berkata, telah memberitakan kepada kami [Al Laits bin Sa'd] dari [Yahya bin Sa'id] dari [Nafi'] dari [Abdullah bin Umar] Bahwasanya ia berkata; telah menceritakan kepadaku [Zaid bin Tsabit] berkata, \"Rasulullah shallallahu 'alaihi wasallam memberi keringanan jual-beli kurma muda yang masih dalam pohon dengan ditukar kurma matang (siap santap). Yahya berkomentar, \"Maksud 'Ariyah ialah, seseorang membeli kurma matang (siap santap) dengan alat tukar kurma mentah yang masih dalam pohonnya dengan taksiran yang sepadan, karena kurma itulah makanan keseharian keluarganya."},"2226":{"ar":"حَدَّثَنَا عَبْدُ اللَّهِ بْنُ سَعِيدٍ حَدَّثَنَا عَبْدَةُ بْنُ سُلَيْمَانَ عَنْ سَعِيدِ بْنِ أَبِي عَرُوبَةَ عَنْ قَتَادَةَ عَنْ الْحَسَنِ عَنْ سَمُرَةَ بْنِ جُنْدَبٍأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ نَهَى عَنْ بَيْعِ الْحَيَوَانِ بِالْحَيَوَانِ نَسِيئَةً","id":"Telah menceritakan kepada kami [Abdullah bin Sa'id] berkata, telah menceritakan kepada kami [Abdah bin Sulaiman] dari [Sa'id bin Abu Arubah] dari [Qatadah] dari [Al Hasan] dari [Samurah bin Jundab] berkata, \"Rasulullah shallallahu 'alaihi wasallam melarang menjual hewan dengan hewan dengan sistem tempo.\""},"2227":{"ar":"حَدَّثَنَا عَبْدُ اللَّهِ بْنُ سَعِيدٍ حَدَّثَنَا حَفْصُ بْنُ غِيَاثٍ وَأَبُو خَالِدٍ عَنْ حَجَّاجٍ عَنْ أَبِي الزُّبَيْرِ عَنْ جَابِرٍأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ لَا بَأْسَ بِالْحَيَوَانِ وَاحِدًا بِاثْنَيْنِ يَدًا بِيَدٍ وَكَرِهَهُ نَسِيئَةً","id":"Telah menceritakan kepada kami [Abdullah bin Sa'id] berkata, telah menceritakan kepada kami [Hafsh bin Ghiyats] dan [Abu Khalid] dari [Hajjaj] dari [Abu Zubair] dari [Jabir] bahwa Rasulullah shallallahu 'alaihi wasallam bersabda: \"Tidak apa-apa menukar satu binatang dengan dua binatang secara kontan, dan makruh jika dengan sistem tempo.\""},"2228":{"ar":"حَدَّثَنَا نَصْرُ بْنُ عَلِيٍّ الْجَهْضَمِيُّ حَدَّثَنَا الْحُسَيْنُ بْنُ عُرْوَةَ ح و حَدَّثَنَا أَبُو عُمَرَ حَفْصُ بْنُ عُمَرَ حَدَّثَنَا عَبْدُ الرَّحْمَنِ بْنُ مَهْدِيٍّ قَالَا حَدَّثَنَا حَمَّادُ بْنُ سَلَمَةَ عَنْ ثَابِتٍ عَنْ أَنَسٍأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ اشْتَرَى صَفِيَّةَ بِسَبْعَةِ أَرْؤُسٍ قَالَ عَبْدُ الرَّحْمَنِ مِنْ دِحْيَةَ الْكَلْبِيِّ","id":"Telah menceritakan kepada kami [Nashr bin Ali Al Jahdlami] berkata, telah menceritakan kepada kami [Al Husain bin Urwah]. (dalam jalur lain disebutkan) Telah menceritakan kepada kami [Abu Umar Hafsh bin Umar] berkata, telah menceritakan kepada kami ['Abdurrahman bin Mahdi] keduanya berkata; telah menceritakan kepada kami [Hammad bin Salamah] dari [Tsabit] dari [Anas] berkata, \"Rasulullah shallallahu 'alaihi wasallam membeli Shafiah dengan menukar tujuh ekor hewan.\" 'Abdurrahman berkata, \"Beliau membeli dari Dihyah Al Kalbi.\""},"2229":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا الْحَسَنُ بْنُ مُوسَى عَنْ حَمَّادِ بْنِ سَلَمَةَ عَنْ عَلِيِّ بْنِ زَيْدٍ عَنْ أَبِي الصَّلْتِ عَنْ أَبِي هُرَيْرَةَ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَتَيْتُ لَيْلَةَ أُسْرِيَ بِي عَلَى قَوْمٍ بُطُونُهُمْ كَالْبُيُوتِ فِيهَا الْحَيَّاتُ تُرَى مِنْ خَارِجِ بُطُونِهِمْ فَقُلْتُ مَنْ هَؤُلَاءِ يَا جِبْرَائِيلُ قَالَ هَؤُلَاءِ أَكَلَةُ الرِّبَا","id":"Telah menceritakan kepada kami [Abu Bakr bin Abu Syaibah] berkata, telah menceritakan kepada kami [Al Hasan bin Musa] dari [Hammad bin Salamah] dari [Ali bin Zaid] dari [Abu Shalt] dari [Abu Hurairah] ia berkata, \"Rasulullah shallallahu 'alaihi wasallam berkata: \"Pada malam Isra mi'raj aku mendatangi suatu kaum, perut mereka seperti rumah-rumah yang dihuni oleh ular dan dapat dilihat dari luar perut-perut mereka. Aku pun bertanya: \"Wahai Jibril, siapakah mereka itu?\" ia menjawab, \"Mereka adalah pemakan riba.\""},"2230":{"ar":"حَدَّثَنَا عَبْدُ اللَّهِ بْنُ سَعِيدٍ حَدَّثَنَا عَبْدُ اللَّهِ بْنُ إِدْرِيسَ عَنْ أَبِي مَعْشَرٍ عَنْ سَعِيدٍ الْمَقْبُرِيِّ عَنْ أَبِي هُرَيْرَةَ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ الرِّبَا سَبْعُونَ حُوبًا أَيْسَرُهَا أَنْ يَنْكِحَ الرَّجُلُ أُمَّهُ","id":"Telah menceritakan kepada kami [Abdullah bin Sa'id] berkata, telah menceritakan kepada kami [Abdullah bin Idris] dari [Abu Ma'syar] dari [Sa'id Al Maqburi] dari [Abu Hurairah] ia berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Riba itu mempunyai tujuh puluh tingkatan, yang paling ringan adalah seperti seseorang yang berzina dengan ibunya.\""},"2231":{"ar":"حَدَّثَنَا عَمْرُو بْنُ عَلِيٍّ الصَّيْرَفِيُّ أَبُو حَفْصٍ حَدَّثَنَا ابْنُ أَبِي عَدِيٍّ عَنْ شُعْبَةَ عَنْ زُبَيْدٍ عَنْ إِبْرَاهِيمَ عَنْ مَسْرُوقٍ عَنْ عَبْدِ اللَّهِعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ الرِّبَا ثَلَاثَةٌ وَسَبْعُونَ بَابًا","id":"Telah menceritakan kepada kami [Amru bin Ali Ash Shairafi Abu Hafsh] berkata, telah menceritakan kepada kami [Ibnu Abu 'Adi] dari [Syu'bah] dari [Zubaid] dari [Ibrahim] dari [Masruq] dari [Abdullah] dari Nabi shallallahu 'alaihi wasallam, beliau bersabda: \"Riba itu memiliki tujuh puluh tiga pintu.\""},"2232":{"ar":"حَدَّثَنَا نَصْرُ بْنُ عَلِيٍّ الْجَهْضَمِيُّ حَدَّثَنَا خَالِدُ بْنُ الْحَارِثِ حَدَّثَنَا سَعِيدٌ عَنْ قَتَادَةَ عَنْ سَعِيدِ بْنِ الْمُسَيَّبِ عَنْ عُمَرَ بْنِ الْخَطَّابِ قَالَإِنَّ آخِرَ مَا نَزَلَتْ آيَةُ الرِّبَا وَإِنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قُبِضَ وَلَمْ يُفَسِّرْهَا لَنَا فَدَعُوا الرِّبَا وَالرِّيبَةَ","id":"Telah menceritakan kepada kami [Nashr bin Ali Al Jahdlami] berkata, telah menceritakan kepada kami [Khalid Ibnul Harits] berkata, telah menceritakan kepada kami [Sa'id] dari [Qatadah] dari [Sa'id Ibnul Musayyab] dari [Umar bin Khaththab] ia berkata, \"Sesungguhnya yang terakhir turun adalah ayat riba, dan ketika Rasulullah shallallahu 'alaihi wasallam meninggal beliau belum sempat menjelaskannya kepada kami. Maka tinggalkanlah riba dan keragu-raguan.\""},"2233":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ بَشَّارٍ حَدَّثَنَا مُحَمَّدُ بْنُ جَعْفَرٍ حَدَّثَنَا شُعْبَةُ حَدَّثَنَا سِمَاكُ بْنُ حَرْبٍ قَالَ سَمِعْتُ عَبْدَ الرَّحْمَنِ بْنَ عَبْدِ اللَّهِ يُحَدِّثُ عَنْ عَبْدِ اللَّهِ بْنِ مَسْعُودٍأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَعَنَ آكِلَ الرِّبَا وَمُؤْكِلَهُ وَشَاهِدِيهِ وَكَاتِبَهُ","id":"Telah menceritakan kepada kami [Muhammad bin Basysyar] berkata, telah menceritakan kepada kami [Muhammad bin Ja'far] berkata, telah menceritakan kepada kami [Syu'bah] berkata, telah menceritakan kepada kami [Simak bin Harb] ia berkata; Aku mendengar ['Abdurrahman bin Abdullah] menceritakan dari [Abdullah bin Mas'ud] ia berkata, \"Rasulullah shallallahu 'alaihi wasallam melaknat pemakan riba, yang mengambilkannya, yang menyaksikannya dan penulisnya.\""},"2234":{"ar":"حَدَّثَنَا عَبْدُ اللَّهِ بْنُ سَعِيدٍ حَدَّثَنَا إِسْمَعِيلُ ابْنُ عُلَيَّةَ حَدَّثَنَا دَاوُدُ بْنُ أَبِي هِنْدٍ عَنْ سَعِيدِ بْنِ أَبِي خَيْرَةَ عَنْ الْحَسَنِ عَنْ أَبِي هُرَيْرَةَ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَيَأْتِيَنَّ عَلَى النَّاسِ زَمَانٌ لَا يَبْقَى مِنْهُمْ أَحَدٌ إِلَّا آكِلُ الرِّبَا فَمَنْ لَمْ يَأْكُلْ أَصَابَهُ مِنْ غُبَارِهِ","id":"Telah menceritakan kepada kami [Abdullah bin Sa'id] berkata, telah menceritakan kepada kami [Isma'il bin 'Ulayyah] berkata, telah menceritakan kepada kami [Dawud bin Abu Hind] dari [Sa'id bin Abu Khairah] dari [Al Hasan] dari [Abu Hurairah] ia berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Benar-benar akan datang kepada manusia suatu zaman, tidak seorang pun dari mereka kecuali akan memakan riba. Dan barangsiapa tidak memakannya, maka ia akan terkena debunya.\""},"2235":{"ar":"حَدَّثَنَا الْعَبَّاسُ بْنُ جَعْفَرٍ حَدَّثَنَا عَمْرُو بْنُ عَوْنٍ حَدَّثَنَا يَحْيَى بْنُ أَبِي زَائِدَةَ عَنْ إِسْرَائِيلَ عَنْ الرُّكَيْنِ بْنِ الرَّبِيعِ بْنِ عُمَيْلَةَ عَنْ أَبِيهِ عَنْ ابْنِ مَسْعُودٍعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ مَا أَحَدٌ أَكْثَرَ مِنْ الرِّبَا إِلَّا كَانَ عَاقِبَةُ أَمْرِهِ إِلَى قِلَّةٍ","id":"Telah menceritakan kepada kami [Al Abbas bin Ja'far] berkata, telah menceritakan kepada kami [Amru bin Aun] berkata, telah menceritakan kepada kami [Yahya bin Abu Zaidah] dari [Isra'il] dari [Ar Rukain bin Ar Rabi' bin 'Umailah] dari [Bapaknya] dari [Ibnu Mas'ud] dari Nabi shallallahu 'alaihi wasallam, beliau bersabda: \"Tidaklah seseorang yang memperbanyak riba, melainkan akhir perkaranya akan merugi.\""},"2236":{"ar":"حَدَّثَنَا هِشَامُ بْنُ عَمَّارٍ حَدَّثَنَا سُفْيَانُ بْنُ عُيَيْنَةَ عَنْ ابْنِ أَبِي نَجِيحٍ عَنْ عَبْدِ اللَّهِ بْنِ كَثِيرٍ عَنْ أَبِي الْمِنْهَالِ عَنْ ابْنِ عَبَّاسٍ قَالَقَدِمَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَهُمْ يُسْلِفُونَ فِي التَّمْرِ السَّنَتَيْنِ وَالثَّلَاثَ فَقَالَ مَنْ أَسْلَفَ فِي تَمْرٍ فَلْيُسْلِفْ فِي كَيْلٍ مَعْلُومٍ وَوَزْنٍ مَعْلُومٍ إِلَى أَجَلٍ مَعْلُومٍ","id":"Telah menceritakan kepada kami [Hisyam bin Ammar] berkata, telah menceritakan kepada kami [Sufyan bin Uyainah] berkata, telah menceritakan kepada kami [Ibnu Abu Najih] dari [Abdullah bin Katsir] dari [Abu Al Minhal] dari [Ibnu Abbas] ia berkata, \"Nabi shallallahu 'alaihi wasallam datang sementara para sahabat meminjamkan kurma dalam jangka waktu dua atau tiga tahun. Beliau lalu bersabda: \"Barangsiapa memberi pinjaman kurma hendaklah ia lakukan dalam takaran yang jelas, timbangan yang jelas, dan waktu yang jelas.\""},"2237":{"ar":"حَدَّثَنَا يَعْقُوبُ بْنُ حُمَيْدِ بْنِ كَاسِبٍ حَدَّثَنَا الْوَلِيدُ بْنُ مُسْلِمٍ عَنْ مُحَمَّدِ بْنِ حَمْزَةَ بْنِ يُوسُفَ بْنِ عَبْدِ اللَّهِ بْنِ سَلَامٍ عَنْ أَبِيهِ عَنْ جَدِّهِ عَبْدِ اللَّهِ بْنِ سَلَامٍ قَالَجَاءَ رَجُلٌ إِلَى النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ إِنَّ بَنِي فُلَانٍ أَسْلَمُوا لِقَوْمٍ مِنْ الْيَهُودِ وَإِنَّهُمْ قَدْ جَاعُوا فَأَخَافُ أَنْ يَرْتَدُّوا فَقَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَنْ عِنْدَهُ فَقَالَ رَجُلٌ مِنْ الْيَهُودِ عِنْدِي كَذَا وَكَذَا لِشَيْءٍ قَدْ سَمَّاهُ أُرَاهُ قَالَ ثَلَاثُ مِائَةِ دِينَارٍ بِسِعْرِ كَذَا وَكَذَا مِنْ حَائِطِ بَنِي فُلَانٍ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِسِعْرِ كَذَا وَكَذَا إِلَى أَجَلِ كَذَا وَكَذَا وَلَيْسَ مِنْ حَائِطِ بَنِي فُلَانٍ","id":"Telah menceritakan kepada kami [Ya'qub bin Humaid bin Kasib] berkata, telah menceritakan kepada kami [Al Walid bin Muslim] dari [Muhammad bin Hamzah bin Yusuf bin Abdullah bin Salam] dari [Bapaknya] dari kakeknya [Abdullah bin Salam] ia berkata, \"Seorang laki-laki datang menemui Nabi shallallahu 'alaihi wasallam dan bertanya; \"Bani Fulan telah menyerah kepada orang-orang Yahudi, mereka dalam keadaan kelaparan hingga aku merasa khawatir mereka akan murtad.\" Nabi shallallahu 'alaihi wasallam lantas bersabda: \"Siapa yang mempunyai sesuatu? Seorang yahudi lalu berkata, \"Saya memiliki seperti ini dan seperti ini.\" menurutku ia mengatakan, \"Tiga ratus dinar dengan harga seperti ini dan seperti ini dari kebun kurma Bani fulan.\" Rasulullah shallallahu 'alaihi wasallam menjawab: \"Dengan harga seperti ini dan seperti ini sampai waktu seperti ini dan seperti ini, dan bukan dari kebun kurma Bani fulan.\""},"2238":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ بَشَّارٍ حَدَّثَنَا يَحْيَى بْنُ سَعِيدٍ وَعَبْدُ الرَّحْمَنِ بْنُ مَهْدِيٍّ قَالَا حَدَّثَنَا شُعْبَةُ قَالَ يَحْيَى عَنْ عَبْدِ اللَّهِ بْنِ أَبِي الْمُجَالِدِ وَقَالَ عَبْدُ الرَّحْمَنِ عَنْ ابْنِ أَبِي الْمُجَالِدِ قَالَامْتَرَى عَبْدُ اللَّهِ بْنُ شَدَّادٍ وَأَبُو بُرْدَةَ فِي السَّلَمِ فَأَرْسَلُونِي إِلَى عَبْدِ اللَّهِ بْنِ أَبِي أَوْفَى فَسَأَلْتُهُ فَقَالَ كُنَّا نُسْلِمُ عَلَى عَهْدِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَعَهْدِ أَبِي بَكْرٍ وَعُمَرَ فِي الْحِنْطَةِ وَالشَّعِيرِ وَالزَّبِيبِ وَالتَّمْرِ عِنْدَ قَوْمٍ مَا عِنْدَهُمْ فَسَأَلْتُ ابْنَ أَبْزَى فَقَالَ مِثْلَ ذَلِكَ","id":"Telah menceritakan kepada kami [Muhammad bin Basysyar] berkata, telah menceritakan kepada kami [Yahya bin Sa'id] dan ['Abdurrahman bin Mahdi] keduanya berkata; telah menceritakan kepada kami [Syu'bah]. (dalam jalur lain disebutkan) [Yahya] berkata; dari [Abdullah bin Abu Al Mujalid]. (dalam jalur lain disebutkan) ['Abdurrahman] berkata dari [Ibnu Abu Al Mujalid] ia berkata, \"Abdullah bin Syaddad dan Abu Burdah berselisih dalam masalah salam, maka mereka mengutusku menemui [Abdullah bin Abu Aufa]. Lantas aku menanyakan hal itu kepadanya, ia menjawab, \"Kami pernah melakukan salam pada masa Rasulullah shallallahu 'alaihi wasallam, Abu Bakar dan Umar dalam tepung, gandum, anggur dan kurma kepada suatu kaum yang tidak memilikinya. Lalu hal itu aku tanyakan juga kepada [Ibnu Abza], dan ia menjawab dengan hal yang sama.\" "},"2239":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ عَبْدِ اللَّهِ بْنِ نُمَيْرٍ حَدَّثَنَا شُجَاعُ بْنُ الْوَلِيدِ حَدَّثَنَا زِيَادُ بْنُ خَيْثَمَةَ عَنْ سَعْدٍ عَنْ عَطِيَّةَ عَنْ أَبِي سَعِيدٍ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِذَا أَسْلَفْتَ فِي شَيْءٍ فَلَا تَصْرِفْهُ إِلَى غَيْرِهِحَدَّثَنَا عَبْدُ اللَّهِ بْنُ سَعِيدٍ حَدَّثَنَا شُجَاعُ بْنُ الْوَلِيدِ عَنْ زِيَادِ بْنِ خَيْثَمَةَ عَنْ عَطِيَّةَ عَنْ أَبِي سَعِيدٍ قَالَ قَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَذَكَرَ مِثْلَهُ وَلَمْ يَذْكُرْ سَعْدًا","id":"Telah menceritakan kepada kami [Muhammad bin Abdullah bin Numair] berkata, telah menceritakan kepada kami [Syuja' bin Al Walid] berkata, telah menceritakan kepada kami [Ziyad bin Khaitsamah] dari [Sa'd] dari ['Atiyyah] dari [Abu Sa'id] ia berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Apabila kamu meminjamkan sesuatu, maka jangan merubahnya kepada sesuatu yang lain.\" Telah menceritakan kepada kami [Abdullah bin Sa'id] berkata, telah menceritakan kepada kami [Syuja' bin Al Walid] dari [Ziyad bin Khaitsamah] dari ['Atiyyah] dari [Abu Sa'id] ia berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda, lalu ia menyebutkan sebagaimana dalam hadits tersebut, hanya saja ia tidak menyebut nama Sa'd.\""},"2240":{"ar":"حَدَّثَنَا هَنَّادُ بْنُ السَّرِيِّ حَدَّثَنَا أَبُو الْأَحْوَصِ عَنْ أَبِي إِسْحَقَ عَنْ النَّجْرَانِيِّ قَالَقُلْتُ لِعَبْدِ اللَّهِ بْنِ عُمَرَ أُسْلِمُ فِي نَخْلٍ قَبْلَ أَنْ يُطْلِعَ قَالَ لَا قُلْتُ لِمَ قَالَ إِنَّ رَجُلًا أَسْلَمَ فِي حَدِيقَةِ نَخْلٍ فِي عَهْدِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَبْلَ أَنْ يُطْلِعَ النَّخْلُ فَلَمْ يُطْلِعْ النَّخْلُ شَيْئًا ذَلِكَ الْعَامَ فَقَالَ الْمُشْتَرِي هُوَ لِي حَتَّى يُطْلِعَ وَقَالَ الْبَائِعُ إِنَّمَا بِعْتُكَ النَّخْلَ هَذِهِ السَّنَةَ فَاخْتَصَمَا إِلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ لِلْبَائِعِ أَخَذَ مِنْ نَخْلِكَ شَيْئًا قَالَ لَا قَالَ فَبِمَ تَسْتَحِلُّ مَالَهُ ارْدُدْ عَلَيْهِ مَا أَخَذْتَ مِنْهُ وَلَا تُسْلِمُوا فِي نَخْلٍ حَتَّى يَبْدُوَ صَلَاحُهُ","id":"Telah menceritakan kepada kami [Hannad bin As Sari] berkata, telah menceritakan kepada kami [Abul Ahwash] dari [Abu Ishaq] dari [An Najrani] ia berkata; Aku berkata kepada [Abdullah Ibnu Umar], \"Aku melelangkan pohon kurma dengan sistem salam sebelum muncul buahnya! \" Ibnu Umar menjawab, \"Tidak boleh.\" Aku bertanya kepadanya, \"Kenapa?\" ia menjawab, \"Pernah seorang laki-laki melelang kebun kurmanya pada masa Rasulullah shallallahu 'alaihi wasallam sebelum muncul buah kurmanya. Namun pada tahun itu buahnya tidak muncul sama sekali. Kemudian si pembeli berkata, \"Dia tetap menjadi milikku hingga pohon itu berbuah. Tetapi si penjual berkata, \"Aku hanya menjual pohon kurma ini setahun saja.\" Hingga keduanya cekcok dan mengadukannya kepada Rasulullah shallallahu 'alaihi wasallam. Beliau lantas bertanya kepada si penjual: \"Apakah dia mengambil sesuatu dari pohon kurmamu? ia menjawab, \"Tidak.\" Rasulullah shallallahu 'alaihi wasallam bersabda: \"Lalu dengan alasan apa kamu menghalalkan hartanya? Kembalikanlah barang yang telah kamu ambil darinya. Dan janganlah kalian melelang pohon kurma sehingga nampak kematangan buahnya.\""},"2241":{"ar":"حَدَّثَنَا هِشَامُ بْنُ عَمَّارٍ حَدَّثَنَا مُسْلِمُ بْنُ خَالِدٍ حَدَّثَنَا زَيْدُ بْنُ أَسْلَمَ عَنْ عَطَاءِ بْنِ يَسَارٍ عَنْ أَبِي رَافِعٍأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ اسْتَسْلَفَ مِنْ رَجُلٍ بَكْرًا وَقَالَ إِذَا جَاءَتْ إِبِلُ الصَّدَقَةِ قَضَيْنَاكَ فَلَمَّا قَدِمَتْ قَالَ يَا أَبَا رَافِعٍ اقْضِ هَذَا الرَّجُلَ بَكْرَهُ فَلَمْ أَجِدْ إِلَّا رَبَاعِيًا فَصَاعِدًا فَأَخْبَرْتُ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ أَعْطِهِ فَإِنَّ خَيْرَ النَّاسِ أَحْسَنُهُمْ قَضَاءً","id":"Telah menceritakan kepada kami [Hisyam bin Ammar] berkata, telah menceritakan kepada kami [Muslim bin Khalid] berkata, telah menceritakan kepada kami [Zaid bin Aslam] dari ['Atha bin Yasar] dari [Abu Rafi'] berkata, \"Rasulullah shallallahu 'alaihi wasallam meminjam seekor unta muda dari seorang laki-laki. Beliau bersabda: \"Jika unta zakat telah tiba maka akan kami ganti.\" Ketika unta zakat itu telah tiba, beliau bersabda: \"Wahai Abu Rafi', bayarkanlah unta tersebut kepada laki-laki ini.\" Namun aku tidak mendapatkan kecuali unta yang umurnya di atas tujuh tahun lebih, lalu hal itu aku kabarkan kepada Nabi shallallahu 'alaihi wasallam. Beliau bersabda: \"Berikanlah. Sesungguhnya sebaik-baik orang adalah yang paling baik dalam memberikan pembayaran.\""},"2242":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا زَيْدُ بْنُ الْحُبَابِ حَدَّثَنَا مُعَاوِيَةُ بْنُ صَالِحٍ حَدَّثَنِي سَعِيدُ بْنُ هَانِئٍ قَالَ سَمِعْتُ الْعِرْبَاضَ بْنَ سَارِيَةَ يَقُولُكُنْتُ عِنْدَ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ أَعْرَابِيٌّ اقْضِنِي بَكْرِي فَأَعْطَاهُ بَعِيرًا مُسِنًّا فَقَالَ الْأَعْرَابِيُّ يَا رَسُولَ اللَّهِ هَذَا أَسَنُّ مِنْ بَعِيرِي فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ خَيْرُ النَّاسِ خَيْرُهُمْ قَضَاءً","id":"Telah menceritakan kepada kami [Abu Bakr bin Abu Syaibah] berkata, telah menceritakan kepada kami [Zaid bin Al Hubab] berkata, telah menceritakan kepada kami [Mu'awiyah bin Shalih] berkata, telah menceritakan kepadaku [Sa'id bin Hani] ia berkata; Aku mendengar [Al 'Irbadl bin Sariah] ia berkata, \"Aku berada di sisi Nabi shallallahu 'alaihi wasallam, lalu muncullah seorang arab badui dan berkata, \"Bayarlah unta milikku! \" beliau pun memberinya unta yang telah berumur (dewasa), hingga arab badui itu berkata, \"Wahai Rasulullah, unta ini lebih tua dari unta milikku! \" Rasulullah shallallahu 'alaihi wasallam lantas menjawab: \"Sebaik-baik orang adalah yang paling baik dalam memberi pembayarannya.\""},"2243":{"ar":"حَدَّثَنَا عُثْمَانُ وَأَبُو بَكْرٍ ابْنَا أَبِي شَيْبَةَ قَالَا حَدَّثَنَا عَبْدُ الرَّحْمَنِ بْنُ مَهْدِيٍّ عَنْ سُفْيَانَ عَنْ إِبْرَاهِيمَ بْنِ مُهَاجِرٍ عَنْ مُجَاهِدٍ عَنْ قَائِدِ السَّائِبِ عَنْ السَّائِبِقَالَ لِلنَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كُنْتَ شَرِيكِي فِي الْجَاهِلِيَّةِ فَكُنْتَ خَيْرَ شَرِيكٍ لَا تُدَارِينِي وَلَا تُمَارِينِي","id":"Telah menceritakan kepada kami [Utsman] dan [Abu Bakr] -keduanya putra Abu Syaibah-keduanya berkata; telah menceritakan kepada kami ['Abdurrahman bin Mahdi] dari [Sufyan] dari [Ibrahim bin Muhajir] dari [Mujahid] dari [Penuntun As Sa`ib] dari [Sa`ib] ia berkata kepada Nabi shallallahu 'alaihi wasallam, \"Engkau adalah temanku di masa jahiliyyah, dan engkau adalah sebaik-baik teman yang tidak memperdayaiku dan mendebatku.\""},"2244":{"ar":"حَدَّثَنَا أَبُو السَّائِبِ سَلْمُ بْنُ جُنَادَةَ حَدَّثَنَا أَبُو دَاوُدَ الْحَفَرِيُّ عَنْ سُفْيَانَ عَنْ أَبِي إِسْحَقَ عَنْ أَبِي عُبَيْدَةَ عَنْ عَبْدِ اللَّهِ قَالَاشْتَرَكْتُ أَنَا وَسَعْدٌ وَعَمَّارٌ يَوْمَ بَدْرٍ فِيمَا نُصِيبُ فَلَمْ أَجِئْ أَنَا وَلَا عَمَّارٌ بِشَيْءٍ وَجَاءَ سَعْدٌ بِرَجُلَيْنِ","id":"Telah menceritakan kepada kami [Abu Sa`ib Salam bin Junadah] berkata, telah menceritakan kepada kami [Abu Dawud Al Hafari] dari [Sufyan] dari [Abu Ishaq] dari [Abu Ubaidah] dari [Abdullah] ia berkata, \"Aku, Sa'd dan 'Ammar bersekutu pada perang Badar mengenai apa yang kami peroleh. Maka aku dan 'Ammar tidak membawa sesuatu, sedang Sa'd membawa dua lelaki.\""},"2245":{"ar":"حَدَّثَنَا الْحَسَنُ بْنُ عَلِيٍّ الْخَلَّالُ حَدَّثَنَا بِشْرُ بْنُ ثَابِتٍ الْبَزَّارُ حَدَّثَنَا نَصْرُ بْنُ الْقَاسِمِ عَنْ عَبْدِ الرَّحْمَنِ بْنِ دَاوُدَ عَنْ صَالِحِ بْنِ صُهَيْبٍ عَنْ أَبِيهِ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ ثَلَاثٌ فِيهِنَّ الْبَرَكَةُ الْبَيْعُ إِلَى أَجَلٍ وَالْمُقَارَضَةُ وَأَخْلَاطُ الْبُرِّ بِالشَّعِيرِ لِلْبَيْتِ لَا لِلْبَيْعِ","id":"Telah menceritakan kepada kami [Al Hasan bin Ali Al Khallal] berkata, telah menceritakan kepada kami [Bisyr bin Tsabit Al Bazzar] berkata, telah menceritakan kepada kami [Nashr bin Al Qasim] dari ['Abdurrahman bin Dawud] dari [Shalih bin Shuhaib] dari [Bapaknya] ia berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Tiga hal yang di dalamnya terdapat barakah; jual beli yang memberi tempo, peminjaman, dan campuran gandum dengan jelai untuk di konsumsi orang-orang rumah bukan untuk dijual.\""},"2246":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا ابْنُ أَبِي زَائِدَةَ عَنْ الْأَعْمَشِ عَنْ عُمَارَةَ بْنِ عُمَيْرٍ عَنْ عَمَّتِهِ عَنْ عَائِشَةَ قَالَتْقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِنَّ أَطْيَبَ مَا أَكَلْتُمْ مِنْ كَسْبِكُمْ وَإِنَّ أَوْلَادَكُمْ مِنْ كَسْبِكُمْ","id":"Telah menceritakan kepada kami [Abu Bakr bin Abu Syaibah] berkata, telah menceritakan kepada kami [Ibnu Abu Za`idah] dari [Al A'masy] dari [Umarah bin Umair] dari [Pamannya] dari ['Aisyah] ia berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Sesungguhnya yang paling baik untuk kalian makan adalah dari hasil usaha kalian, dan anak-anak kalian adalah hasil usaha kalian.\""},"2247":{"ar":"حَدَّثَنَا هِشَامُ بْنُ عَمَّارٍ حَدَّثَنَا عِيسَى بْنُ يُونُسَ حَدَّثَنَا يُوسُفُ بْنُ إِسْحَقَ عَنْ مُحَمَّدِ بْنِ الْمُنْكَدِرِ عَنْ جَابِرِ بْنِ عَبْدِ اللَّهِأَنَّ رَجُلًا قَالَ يَا رَسُولَ اللَّهِ إِنَّ لِي مَالًا وَوَلَدًا وَإِنَّ أَبِي يُرِيدُ أَنْ يَجْتَاحَ مَالِي فَقَالَ أَنْتَ وَمَالُكَ لِأَبِيكَ","id":"Telah menceritakan kepada kami [Hisyam bin Ammar] berkata, telah menceritakan kepada kami [Isa bin Yunus] berkata, telah menceritakan kepada kami [Yusuf bin Ishaq] dari [Muhammad bin Al Munkadir] dari [Jabir bin Abdullah] berkata, \"Seseorang lelaki berkata, \"Wahai Rasulullah, aku mempunyai harta dan anak, sementara ayahku juga membutuhkan hartaku.\" Maka beliau bersabda: \"Engkau dan hartamu milik ayahmu.\""},"2248":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ يَحْيَى وَيَحْيَى بْنُ حَكِيمٍ قَالَا حَدَّثَنَا يَزِيدُ بْنُ هَارُونَ أَنْبَأَنَا حَجَّاجٌ عَنْ عَمْرِو بْنِ شُعَيْبٍ عَنْ أَبِيهِ عَنْ جَدِّهِ قَالَجَاءَ رَجُلٌ إِلَى النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ إِنَّ أَبِي اجْتَاحَ مَالِي فَقَالَ أَنْتَ وَمَالُكَ لِأَبِيكَ وَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِنَّ أَوْلَادَكُمْ مِنْ أَطْيَبِ كَسْبِكُمْ فَكُلُوا مِنْ أَمْوَالِهِمْ","id":"Telah menceritakan kepada kami [Muhammad bin Yahya] dan [Yahya bin Hakim] keduanya berkata; telah menceritakan kepada kami [Yazid bin Harun] berkata, telah memberitakan kepada kami [Hajjaj] dari [Amru bin Syu'aib] dari [Bapaknya] dari [Kakeknya] ia berkata, \"Seorang laki-laki datang menemui Nabi shallallahu 'alaihi wasallam dan berkata, \"Bapakku meminta hartaku! \" beliau bersabda: \"Kamu dan hartamu adalah milik bapakmu.\" Rasulullah shallallahu 'alaihi wasallam melanjutkan kembali: \"Sesungguhnya anak-anak kalian adalah dari hasil usaha kalian yang terbaik, maka makanlah dari hasil usaha mereka.\""},"2249":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ وَعَلِيُّ بْنُ مُحَمَّدٍ وَأَبُو عُمَرَ الضَّرِيرُ قَالُوا حَدَّثَنَا وَكِيعٌ حَدَّثَنَا هِشَامُ بْنُ عُرْوَةَ عَنْ أَبِيهِ عَنْ عَائِشَةَ قَالَتْجَاءَتْ هِنْدٌ إِلَى النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَتْ يَا رَسُولَ اللَّهِ إِنَّ أَبَا سُفْيَانَ رَجُلٌ شَحِيحٌ لَا يُعْطِينِي مَا يَكْفِينِي وَوَلَدِي إِلَّا مَا أَخَذْتُ مِنْ مَالِهِ وَهُوَ لَا يَعْلَمُ فَقَالَ خُذِي مَا يَكْفِيكِ وَوَلَدَكِ بِالْمَعْرُوفِ","id":"Telah menceritakan kepada kami [Abu Bakr bin Abu Syaibah] berkata, telah menceritakan kepada kami [Ali bin Muhammad] dan [Abu Umar Adl Dlarir] mereka berkata; telah menceritakan kepada kami [Waki'] berkata, telah menceritakan kepada kami [Hisyam bin Urwah] dari [Bapaknya] dari ['Aisyah] ia berkata, \"Hindun datang menemui Nabi shallallahu 'alaihi wasallam dan berkata, \"Wahai Rasulullah, Abu Sufyan adalah seorang laki-laki yang pelit, ia tidak memberi nafkah yang bisa mencukupi aku dan anakku, kecuali dengan sesuatu yang aku ambil dari hartanya tanpa sepengetahuannya! \" beliau lantas bersabda: \"Ambillah uang miliknya yang bisa mencukupi nafkahmu dan juga anakmu dengan ma'ruf.\""},"2250":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ عَبْدِ اللَّهِ بْنِ نُمَيْرٍ حَدَّثَنَا أَبِي وَأَبُو مُعَاوِيَةَ عَنْ الْأَعْمَشِ عَنْ أَبِي وَائِلٍ عَنْ مَسْرُوقٍ عَنْ عَائِشَةَ قَالَتْقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِذَا أَنْفَقَتْ الْمَرْأَةُ وَقَالَ أَبِي فِي حَدِيثِهِ إِذَا أَطْعَمَتْ الْمَرْأَةُ مِنْ بَيْتِ زَوْجِهَا غَيْرَ مُفْسِدَةٍ كَانَ لَهَا أَجْرُهَا وَلَهُ مِثْلُهُ بِمَا اكْتَسَبَ وَلَهَا بِمَا أَنْفَقَتْ وَلِلْخَازِنِ مِثْلُ ذَلِكَ مِنْ غَيْرِ أَنْ يَنْقُصَ مِنْ أُجُورِهِمْ شَيْئًا","id":"Telah menceritakan kepada kami [Muhammad bin Abdullah bin Numair] berkata, telah menceritakan kepada kami [Bapakku] dan [Abu Mu'awiyah] dari [Al A'masy] dari [Abu Wail] dari [Masruq] dari ['Aisyah] ia berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Jika seorang wanita berinfak, -Bapakku menyebutkan dalam haditsnya-, \"Jika seorang wanita memberikan makan (nafkah) di rumah suaminya dengan tidak menimbulkan madlarat, maka ia mendapatkan pahala sebagaimana suaminya juga mendapatkan pahala dari usahanya. Isterinya akan mendapatkan pahala dari apa yang ia infakkan, dan bagi penjaga (harta) juga akan mendapatkan pahala tanpa mengurangi dari pahala mereka.\""},"2251":{"ar":"حَدَّثَنَا هِشَامُ بْنُ عَمَّارٍ حَدَّثَنَا إِسْمَعِيلُ بْنُ عَيَّاشٍ حَدَّثَنِي شُرَحْبِيلُ بْنُ مُسْلِمٍ الْخَوْلَانِيُّ قَالَ سَمِعْتُ أَبَا أُمَامَةَ الْبَاهِلِيَّ يَقُولُسَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ لَا تُنْفِقُ الْمَرْأَةُ مِنْ بَيْتِهَا شَيْئًا إِلَّا بِإِذْنِ زَوْجِهَا قَالُوا يَا رَسُولَ اللَّهِ وَلَا الطَّعَامَ قَالَ ذَلِكَ مِنْ أَفْضَلِ أَمْوَالِنَا","id":"Telah menceritakan kepada kami [Hisyam bin Ammar] berkata, telah menceritakan kepada kami [Isma'il bin Ayyasy] berkata, telah menceritakan kepadaku [Syurahbil bin Muslim Al Khaulani] ia berkata; aku mendengar [Abu Umamah Al Bahili] ia berkata, \"Aku mendengar Rasulullah shallallahu 'alaihi wasallam bersabda: \"Seorang wanita tidak boleh memberikan infak di dalam rumahnya kecuali dengan izin suaminya.\" Para sahabat berkata, \"Wahai Rasulullah, meskipun itu berupa makanan?\" beliau menjawab: \"Itu adalah seutama-utama harta kami.\""},"2252":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ الصَّبَّاحِ حَدَّثَنَا سُفْيَانُ ح و حَدَّثَنَا عَمْرُو بْنُ رَافِعٍ حَدَّثَنَا جَرِيرٌ عَنْ مُسْلِمٍ الْمُلَائِيِّ سَمِعَ أَنَسَ بْنَ مَالِكٍ يَقُولُكَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يُجِيبُ دَعْوَةَ الْمَمْلُوكِ","id":"Telah menceritakan kepada kami [Muhammad bin Ash Shabbah] berkata, telah menceritakan kepada kami [Sufyan]. (Dalam jalur lain disebutkan) Telah menceritakan kepada kami [Amru bin Rafi'] berkata, telah menceritakan kepada kami [Jarir] dari [Muslim Al Mullai] ia mendengar [Anas bin Malik] berkata, \"Rasulullah shallallahu 'alaihi wasallam senantiasa memenuhi undangan hamba sahaya.\""},"2253":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا حَفْصُ بْنُ غِيَاثٍ عَنْ مُحَمَّدِ بْنِ زَيْدٍ عَنْ عُمَيْرٍ مَوْلَى آبِي اللَّحْمِ قَالَكَانَ مَوْلَايَ يُعْطِينِي الشَّيْءَ فَأُطْعِمُ مِنْهُ فَمَنَعَنِي أَوْ قَالَ فَضَرَبَنِي فَسَأَلْتُ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَوْ سَأَلَهُ فَقُلْتُ لَا أَنْتَهِي أَوْ لَا أَدَعُهُ فَقَالَ الْأَجْرُ بَيْنَكُمَا","id":"Telah menceritakan kepada kami [Abu Bakr bin Abu Syaibah] berkata, telah menceritakan kepada kami [Hafsh bin Ghiyats] dari [Muhammad bin Zaid] dari [Umair] -mantan budak Abu Lahm- ia berkata, \"Majikanku memberiku sesuatu, lalu aku memberi makan orang lain dari pemberian itu, tetapi dia melarangku, atau ia berkata; tetapi dia memukulku. Lantas hal itu aku tanyakan kepada Nabi shallallahu 'alaihi wasallam, atau ia menanyakannya. Aku berkata, \"Aku tidak akan berhenti atau tidak akan meninggalkannya.\" Maka beliau bersabda: \"Kalian berdua akan mendapat pahala.\""},"2254":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا شَبَابَةُ بْنُ سَوَّارٍ ح و حَدَّثَنَا مُحَمَّدُ بْنُ بَشَّارٍ وَمُحَمَّدُ بْنُ الْوَلِيدِ قَالَا حَدَّثَنَا مُحَمَّدُ بْنُ جَعْفَرٍ حَدَّثَنَا شُعْبَةُ عَنْ أَبِي بِشْرٍ جَعْفَرِ بْنِ أَبِي إِيَاسٍ قَالَ سَمِعْتُ عَبَّادَ بْنَ شُرَحْبِيلَرَجُلًا مِنْ بَنِي غُبَرَ قَالَ أَصَابَنَا عَامُ مَخْمَصَةٍ فَأَتَيْتُ الْمَدِينَةَ فَأَتَيْتُ حَائِطًا مِنْ حِيطَانِهَا فَأَخَذْتُ سُنْبُلًا فَفَرَكْتُهُ وَأَكَلْتُهُ وَجَعَلْتُهُ فِي كِسَائِي فَجَاءَ صَاحِبُ الْحَائِطِ فَضَرَبَنِي وَأَخَذَ ثَوْبِي فَأَتَيْتُ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَأَخْبَرْتُهُ فَقَالَ لِلرَّجُلِ مَا أَطْعَمْتَهُ إِذْ كَانَ جَائِعًا أَوْ سَاغِبًا وَلَا عَلَّمْتَهُ إِذْ كَانَ جَاهِلًا فَأَمَرَهُ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَرَدَّ إِلَيْهِ ثَوْبَهُ وَأَمَرَ لَهُ بِوَسْقٍ مِنْ طَعَامٍ أَوْ نِصْفِ وَسْقٍ","id":"Telah menceritakan kepada kami [Abu Bakr bin Abu Syaibah] berkata, telah menceritakan kepada kami [Syababah bin Sawwar]. (Dalam jalur lain disebutkan) Telah menceritakan kepada kami [Muhammad bin Basysyar] dan [Muhammad Ibnul Walid] keduanya berkata; telah menceritakan kepada kami [Muhammad bin Ja'far] berkata, telah menceritakan kepada kami [Syu'bah] dari [Abu Biysr Ja'far bin Abu Iyas] ia berkata; Aku mendengar [Abbad bin Syurahbil] -seorang laki-laki dari bani Ghubar- berkata, \"Kami mengalami tahun paceklik, aku pun mendatagi salah satu kebun milik kami (penduduk madinah), aku mengambil satu tangkai dan aku keluarkan biji-bijinya. Kemudian aku makan dan aku masukkan ke dalam saku. Namun si pemilik kebun datang, ia memukul dan memegang kain bajuku. Maka, aku mendatangi Nabi shallallahu 'alaihi wasallam dan aku kabarkan hal itu kepada beliau. Beliau lalu berkata kepada pemilik kebun tersebut: \"Engkau tidak memberinya makan disaat lapar, dan engkau tidak memberitahu disaat ia bodoh! \" Nabi shallallahu 'alaihi wasallam pun memerintahkannya, hingga pemilik kebun tersebut mengembalikan kain milik laki-laki itu. Dan beliau juga memerintahkannya untuk memberi makanan satu wasaq atau setengahnya.\" "},"2255":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ الصَّبَّاحِ وَيَعْقُوبُ بْنُ حُمَيْدِ بْنِ كَاسِبٍ قَالَا حَدَّثَنَا مُعْتَمِرُ بْنُ سُلَيْمَانَ قَالَ سَمِعْتُ ابْنَ أَبِي الْحَكَمِ الْغِفَارِيَّ قَالَ حَدَّثَتْنِي جَدَّتِي عَنْ عَمِّ أَبِيهَا رَافِعِ بْنِ عَمْرٍو الْغِفَارِيِّ قَالَكُنْتُ وَأَنَا غُلَامٌ أَرْمِي نَخْلَنَا أَوْ قَالَ نَخْلَ الْأَنْصَارِ فَأُتِيَ بِيَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ يَا غُلَامُ وَقَالَ ابْنُ كَاسِبٍ فَقَالَ يَا بُنَيَّ لِمَ تَرْمِي النَّخْلَ قَالَ قُلْتُ آكُلُ قَالَ فَلَا تَرْم النَّخْلَ وَكُلْ مِمَّا يَسْقُطُ فِي أَسَافِلِهَا قَالَ ثُمَّ مَسَحَ رَأْسِي وَقَالَ اللَّهُمَّ أَشْبِعْ بَطْنَهُ","id":"Telah menceritakan kepada kami [Muhammad bin Ash Shabbah] dan [Ya'qub bin Humaid bin Kasib] keduanya berkata: telah menceritakan kepada kami [Mu'tamir bin Sulaiman] ia berkata; aku mendengar [Ibnu Abul Hakam Al Ghifari] ia berkata; telah menceritakan kepadaku [Nenekku] dari paman ayahnya [Rafi' bin Amru Al Ghifari] ia berkata, \"Saat masih kecil aku melempar pohon kurma milik kami, atau ia mengatakan, \"Pohon kurma kaum Anshar. Lalu aku bawa kepada Nabi shallallahu 'alaihi wasallam, beliau bersabda: \"Wahai anak kecil, Ibnu Kasib menyebutkan, \"Wahai anakku, kenapa kamu melempar pohon kurma?\" Rafi' bin Amru Al Ghifari berkata, \"Aku menjawab, \"Untuk aku makan.\" Beliau bersabda: \"Janganlah kamu melempar yang ada di pohon, tetapi makanlah dari apa yang jatuh di bawahnya.\" Rafi' bin Amru Al Ghifari berkata, \"Kemudian beliau mengusap kepalaku dan bersabda: \"Ya Allah, kenyangkanlah perutnya.\""},"2256":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ يَحْيَى حَدَّثَنَا يَزِيدُ بْنُ هَارُونَ أَنْبَأَنَا الْجُرَيْرِيُّ عَنْ أَبِي نَضْرَةَ عَنْ أَبِي سَعِيدٍعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ إِذَا أَتَيْتَ عَلَى رَاعٍ فَنَادِهِ ثَلَاثَ مِرَارٍ فَإِنْ أَجَابَكَ وَإِلَّا فَاشْرَبْ فِي غَيْرِ أَنْ تُفْسِدَ وَإِذَا أَتَيْتَ عَلَى حَائِطِ بُسْتَانٍ فَنَادِ صَاحِبَ الْبُسْتَانِ ثَلَاثَ مَرَّاتٍ فَإِنْ أَجَابَكَ وَإِلَّا فَكُلْ فِي أَنْ لَا تُفْسِدَ","id":"Telah menceritakan kepada kami [Muhammad bin Yahya] berkata, telah menceritakan kepada kami [Yazid bin Harun] berkata, telah memberitakan kepada kami [Al Jurairi] dari [Abu Nadlrah] dari [Abu Sa'id] dari Nabi shallallahu 'alaihi wasallam, beliau bersabda: \"Jika engkau mendatangi pengembala, serulah ia hingga tiga kali, jika ia menjawab maka mintalah izin. Namun jika tidak, hendaklah engkau minum (susu ternaknya) dengan tidak merusaknya. Dan jika engkau mendatangi sebuah kebun maka serulah pemiliknya hingga tiga kali, jika ia menjawab maka mintalah izin, namun jika tidak maka makanlah dengan tidak menimbulkan kerusakan.\""},"2257":{"ar":"حَدَّثَنَا هَدِيَّةُ بْنُ عَبْدِ الْوَهَّابِ وَأَيُّوبُ بْنُ حَسَّانَ الْوَاسِطِيُّ وَعَلِيُّ بْنُ سَلَمَةَ قَالُوا حَدَّثَنَا يَحْيَى بْنُ سُلَيْمٍ الطَّائِفِيُّ عَنْ عُبَيْدِ اللَّهِ بْنِ عُمَرَ عَنْ نَافِعٍ عَنْ ابْنِ عُمَرَ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِذَا مَرَّ أَحَدُكُمْ بِحَائِطٍ فَلْيَأْكُلْ وَلَا يَتَّخِذْ خُبْنَةً","id":"Telah menceritakan kepada kami [Hadiyyah bin Abdul Wahhab] dan [Ayyub bin Hassan Al Wasithi] dan [Ali bin Salamah] mereka berkata; telah menceritakan kepada kami [Yahya bin Sulaim At Thaifi] dari [Ubaidullah bin Umar] dari [Nafi'] dari [Ibnu Umar] ia berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Jika salah seorang dari kalian melewati sebuah kebun maka makanlah, namun jangan mengambilnya untuk bekal.\""},"2258":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ رُمْحٍ قَالَ أَنْبَأَنَا اللَّيْثُ بْنُ سَعْدٍ عَنْ نَافِعٍ عَنْ عَبْدِ اللَّهِ بْنِ عُمَرَعَنْ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنَّهُ قَامَ فَقَالَ لَا يَحْتَلِبَنَّ أَحَدُكُمْ مَاشِيَةَ رَجُلٍ بِغَيْرِ إِذْنِهِ أَيُحِبُّ أَحَدُكُمْ أَنْ تُؤْتَى مَشْرُبَتُهُ فَيُكْسَرَ بَابُ خِزَانَتِهِ فَيُنْتَثَلَ طَعَامُهُ فَإِنَّمَا تَخْزُنُ لَهُمْ ضُرُوعُ مَوَاشِيهِمْ أَطْعِمَاتِهِمْ فَلَا يَحْتَلِبَنَّ أَحَدُكُمْ مَاشِيَةَ امْرِئٍ بِغَيْرِ إِذْنِهِ","id":"Telah menceritakan kepada kami [Muhammad bin Rumh] ia berkata; telah memberitakan kepada kami [Al Laits bin Sa'd] dari [Nafi'] dari [Abdullah bin Umar] dari Rasulullah shallallahu 'alaihi wasallam, bahwasanya beliau berdiri dan bersabda: \"Jangan sekali-kali salah seorang dari kalian memerah ternak orang lain tanpa seizinnya. Apakah kalian suka jika gudang penyimpanan makanan kalian dijebol pintunya lalu semua isinya dikeluarkan? Sesungguhnya susu-susu ternak mereka itu adalah gudang penyimpanan makanan mereka, maka janganlah salah seorang dari kalian memerah ternak orang lain tanpa seizinnya.\""},"2259":{"ar":"حَدَّثَنَا إِسْمَعِيلُ بْنُ بِشْرِ بْنِ مَنْصُورٍ حَدَّثَنَا عُمَرُ بْنُ عَلِيٍّ عَنْ حَجَّاجٍ عَنْ سَلِيطِ بْنِ عَبْدِ اللَّهِ الطُّهَوِيِّ عَنْ ذُهَيْلِ بْنِ عَوْفِ بْنِ شَمَّاخٍ الطُّهَوِيِّ حَدَّثَنَا أَبُو هُرَيْرَةَ قَالَبَيْنَمَا نَحْنُ مَعَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي سَفَرٍ إِذْ رَأَيْنَا إِبِلًا مَصْرُورَةً بِعِضَاهِ الشَّجَرِ فَثُبْنَا إِلَيْهَا فَنَادَانَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَرَجَعْنَا إِلَيْهِ فَقَالَ إِنَّ هَذِهِ الْإِبِلَ لِأَهْلِ بَيْتٍ مِنْ الْمُسْلِمِينَ هُوَ قُوتُهُمْ وَيُمْنُهُمْ بَعْدَ اللَّهِ أَيَسُرُّكُمْ لَوْ رَجَعْتُمْ إِلَى مَزَاوِدِكُمْ فَوَجَدْتُمْ مَا فِيهَا قَدْ ذُهِبَ بِهِ أَتُرَوْنَ ذَلِكَ عَدْلًا قَالُوا لَا قَالَ فَإِنَّ هَذَا كَذَلِكَ قُلْنَا أَفَرَأَيْتَ إِنْ احْتَجْنَا إِلَى الطَّعَامِ وَالشَّرَابِ فَقَالَ كُلْ وَلَا تَحْمِلْ وَاشْرَبْ وَلَا تَحْمِلْ","id":"Telah menceritakan kepada kami [Isma'il bin Bisyr bin Manshur] berkata, telah menceritakan kepada kami [Umar bin Ali] dari [Hajjaj] dari [Salith bin Abdullah Ath Thuhawi] dari [Dzuhail bin 'Auf bin Syammakh Ath Thuhawi] berkata, telah menceritakan kepada kami [Abu Hurairah] ia berkata, \"Tatkala kami sedang bersama Rasulullah shallallahu 'alaihi wasallam dalam suatu perjalanan, tiba-tiba kami melihat unta yang terikat di sebatang pohon duri yang besar. Lalu kami mendekatinya, tetapi Rasulullah memanggil kami hingga kami kembali kepadanya. Beliau bersabda: \"Sesungguhnya unta ini adalah milik penduduk daerah kaum muslimin, ia adalah makanan pokok mereka dan keberkahan mereka setelah Allah. Apakah kalian senang jika kalian kembali ke tempat perbekalan kalian, kemudian kalian menemukan apa yang kalian letakkan di sana telah hilang? Apakah ini adil menurut kalian?\" Mereka menjawab, \"Tidak.\" Beliau bersabda: \"Maka demikian pula dengan hal ini.\" Kami lantas bertanya, \"Bagaimana pendapatmu jika kami butuh makan dan minum?\" beliau menjawab: \"Makan dan minumlah, namun jangan membawanya sebagai bekal.\""},"2260":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا وَكِيعٌ عَنْ هِشَامِ بْنِ عُرْوَةَ عَنْ أَبِيهِ عَنْ أُمِّ هَانِئٍأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ لَهَا اتَّخِذِي غَنَمًا فَإِنَّ فِيهَا بَرَكَةً","id":"Telah menceritakan kepada kami [Abu Bakr bin Abu Syaibah] berkata, telah menceritakan kepada kami [Waki'] dari [Hisyam bin Urwah] dari [Bapaknya] dari [Ummu Hani] bahwa Nabi shallallahu 'alaihi wasallam bersabda kepadanya: \"Ambilah kambing, sebab di dalamnya terdapat keberkahan.\""},"2261":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ عَبْدِ اللَّهِ بْنِ نُمَيْرٍ حَدَّثَنَا عَبْدُ اللَّهِ بْنُ إِدْرِيسَ عَنْ حُصَيْنٍ عَنْ عَامِرٍ عَنْ عُرْوَةَ الْبَارِقِيِّيَرْفَعُهُ قَالَ الْإِبِلُ عِزٌّ لِأَهْلِهَا وَالْغَنَمُ بَرَكَةٌ وَالْخَيْرُ مَعْقُودٌ فِي نَوَاصِي الْخَيْلِ إِلَى يَوْمِ الْقِيَامَةِ","id":"Telah menceritakan kepada kami [Muhammad bin Abdullah bin Numair] berkata, telah menceritakan kepada kami [Abdullah bin Idris] dari [Hushain] dari [Amir] dari [Urwah Al Bariqi] dan ia memarfu'kannya, beliau bersabda: \"Unta, bagi pemiliknya adalah kemuliaan, kambing adalah keberkahan, dan pada ubun-ubun kuda telah tertulis kebaikan hingga hari kiamat.\""},"2262":{"ar":"حَدَّثَنَا عِصْمَةُ بْنُ الْفَضْلِ النَّيْسَابُورِيُّ وَمُحَمَّدُ بْنُ فِرَاسٍ أَبُو هُرَيْرَةَ الصَّيْرَفِيُّ قَالَا حَدَّثَنَا حَرَمِيُّ بْنُ عُمَارَةَ حَدَّثَنَا زَرْبِيٌّ إِمَامُ مَسْجِدِ هِشَامِ بْنِ حَسَّانَ حَدَّثَنَا مُحَمَّدُ بْنُ سِيرِينَ عَنْ ابْنِ عُمَرَ رَضِيَ اللَّهُ عَنْهُ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ الشَّاةُ مِنْ دَوَابِّ الْجَنَّةِ","id":"Telah menceritakan kepada kami ['Ishmah bin Fadll An Naisaburi] dan [Muhammad bin Firas Abu Hurairah Ash Shairafi] keduanya berkata: telah menceritakan kepada kami [Harami bin Umarah] berkata, telah menceritakan kepada kami [Zarbi] -Imam Masjid Hisyam bin Hassan- berkata, telah menceritakan kepada kami [Muhammad bin Sirin] dari [Ibnu Umar radliallahu 'anhu] ia berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Kambing termasuk binatang surga.\""},"2263":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ إِسْمَعِيلَ حَدَّثَنَا عُثْمَانُ بْنُ عَبْدِ الرَّحْمَنِ حَدَّثَنَا عَلِيُّ بْنُ عُرْوَةَ عَنْ الْمَقْبُرِيِّ عَنْ أَبِي هُرَيْرَةَ رَضِيَ اللَّهُ عَنْهُ قَالَأَمَرَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ الْأَغْنِيَاءَ بِاتِّخَاذِ الْغَنَمِ وَأَمَرَ الْفُقَرَاءَ بِاتِّخَاذِ الدَّجَاجِ وَقَالَ عِنْدَ اتِّخَاذِ الْأَغْنِيَاءِ الدَّجَاجَ يَأْذَنُ اللَّهُ بِهَلَاكِ الْقُرَى","id":"Telah menceritakan kepada kami [Muhammad bin Isma'il] berkata, telah menceritakan kepada kami [Utsman bin 'Abdurrahman] berkata, telah menceritakan kepada kami [Ali bin Urwah] dari [Al Maqburi] dari [Abu Hurairah radliallahu 'anhu] ia berkata, \"Rasulullah shallallahu 'alaihi wasallam memerintahkan orang-orang kaya mengerluarkan kambing (sebagai zakat) dan memerintah orang-orang miskin mengeluarkan ayam. Ketika melihat orang-orang kaya mengeluarkan ayam beliau bersabda: \"Allah telah mengizinkan kehancuran negeri itu.\""},"2264":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا مُعَلَّى بْنُ مَنْصُورٍ عَنْ عَبْدِ اللَّهِ بْنِ جَعْفَرٍ عَنْ عُثْمَانَ بْنِ مُحَمَّدٍ عَنْ الْمَقْبُريِّ عَنْ أَبِي هُرَيْرَةَعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ مَنْ جُعِلَ قَاضِيًا بَيْنَ النَّاسِ فَقَدْ ذُبِحَ بِغَيْرِ سِكِّينٍ","id":"Telah menceritakan kepada kami [Abu Bakr bin Abu Syaibah] berkata, telah menceritakan kepada kami [Mu'alla bin Manshur] dari [Abdullah bin Ja'far] dari [Utsman bin Muhammad] dari [Al Maqburi] dari [Abu Hurairah] dari Nabi shallallahu 'alaihi wasallam, beliau bersabda: \"Barangsiapa dijadikan hakim di antara manusia, sesungguhnya ia telah disembelih tanpa menggunakan pisau.\""},"2265":{"ar":"حَدَّثَنَا عَلِيُّ بْنُ مُحَمَّدٍ وَمُحَمَّدُ بْنُ إِسْمَعِيلَ قَالَا حَدَّثَنَا وَكِيعٌ حَدَّثَنَا إِسْرَائِيلُ عَنْ عَبْدِ الْأَعْلَى عَنْ بِلَالِ بْنِ أَبِي مُوسَى عَنْ أَنَسِ بْنِ مَالِكٍ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَنْ سَأَلَ الْقَضَاءَ وُكِلَ إِلَى نَفْسِهِ وَمَنْ جُبِرَ عَلَيْهِ نَزَلَ إِلَيْهِ آلِكْ فَسَدَّدَهُ","id":"Telah menceritakan kepada kami [Ali bin Muhammad] dan [Muhammad bin Isma'il] keduanya berkata; telah menceritakan kepada kami [Waki'] berkata, telah menceritakan kepada kami [Isra'il] dari [Abdul A'la] dari [Bilal bin Abu Musa] dari [Anas bin Malik] ia berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Barangsiapa meminta untuk diangkat sebagai hakim maka ia akan ditelantarkan, dan barangsiapa dipaksa menjadi hakim maka malaikat akan turun untuk membantunya.\""},"2266":{"ar":"حَدَّثَنَا عَلِيُّ بْنُ مُحَمَّدٍ حَدَّثَنَا يَعْلَى وَأَبُو مُعَاوِيَةَ عَنْ الْأَعْمَشِ عَنْ عَمْرِو بْنِ مُرَّةَ عَنْ أَبِي الْبَخْتَرِيِّ عَنْ عَلِيٍّ قَالَبَعَثَنِي رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِلَى الْيَمَنِ فَقُلْتُ يَا رَسُولَ اللَّهِ تَبْعَثُنِي وَأَنَا شَابٌّ أَقْضِي بَيْنَهُمْ وَلَا أَدْرِي مَا الْقَضَاءُ قَالَ فَضَرَبَ بِيَدِهِ فِي صَدْرِي ثُمَّ قَالَ اللَّهُمَّ اهْدِ قَلْبَهُ وَثَبِّتْ لِسَانَهُ قَالَ فَمَا شَكَكْتُ بَعْدُ فِي قَضَاءٍ بَيْنَ اثْنَيْنِ","id":"Telah menceritakan kepada kami [Ali bin Muhammad] berkata, telah menceritakan kepada kami [Ya'la] dan [Abu Mu'awiyah] dari [Al A'masy] dari [Amru bin Murrah] dari [Abu Al Bakhtari] dari [Ali] ia berkata, \"Rasulullah shallallahu 'alaihi wasallam mengutusku ke Yaman, maka aku berkata, \"Wahai Rasulullah, engkau mengutusku untuk menjadi hakim di tengah manusia sementara aku seorang pemuda dan tidak mengerti bagaimana memberi putusan! \" Ali berkata, \"Beliau lalu meletakkan tangannya ke dadaku seraya berdoa: \"Ya Allah, tunjukilah hatinya dan teguhkanlah lisannya.\" Ali berkata, \"Setelah itu aku tidak ragu-ragu dalam memutuskan antara dua perkara.\""},"2267":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ خَلَّادٍ الْبَاهِلِيُّ حَدَّثَنَا يَحْيَى بْنُ سَعِيدٍ الْقَطَّانُ حَدَّثَنَا مُجَالِدٌ عَنْ عَامِرٍ عَنْ مَسْرُوقٍ عَنْ عَبْدِ اللَّهِ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَا مِنْ حَاكِمٍ يَحْكُمُ بَيْنَ النَّاسِ إِلَّا جَاءَ يَوْمَ الْقِيَامَةِ وَمَلَكٌ آخِذٌ بِقَفَاهُ ثُمَّ يَرْفَعُ رَأْسَهُ إِلَى السَّمَاءِ فَإِنْ قَالَ أَلْقِهِ أَلْقَاهُ فِي مَهْوَاةٍ أَرْبَعِينَ خَرِيفًا","id":"Telah menceritakan kepada kami [Abu Bakr bin Khallad Al Bahili] berkata, telah menceritakan kepada kami [Yahya bin Sa'id Al Qaththan] berkata, telah menceritakan kepada kami [Mujalid] dari [Amir] dari [Masruq] dari [Abdullah] ia berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Tidaklah seorang hakim yang mengadili manusia kecuali pada hari kiamat ia akan datang dalam keadaan tengkuknya dipegang oleh malaikat. Kemudian kepalanya akan diangkat ke langit, jika Allah berfirman, 'Lemparkanlah ia' maka malaikat akan melemparnya ke dalam neraka yang dalamnya seperti perjalanan selama tujuh puluh musim.\""},"2268":{"ar":"حَدَّثَنَا أَحْمَدُ بْنُ سِنَانَ حَدَّثَنَا مُحَمَّدُ بْنُ بِلَالٍ عَنْ عِمْرَانَ الْقَطَّانِ عَنْ حُسَيْنٍ يَعْنِي ابْنَ عِمْرَانَ عَنْ أَبِي إِسْحَقَ الشَّيْبَانِيِّ عَنْ عَبْدِ اللَّهِ بْنِ أَبِي أَوْفَى قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِنَّ اللَّهَ مَعَ الْقَاضِي مَا لَمْ يَجُرْ فَإِذَا جَارَ وَكَّلَهُ إِلَى نَفْسِهِ","id":"Telah menceritakan kepada kami [Ahmad bin Sinan] berkata, telah menceritakan kepada kami [Muhammad bin Bilal] dari [Imran Al Qaththan] dari [Husain yaitu Ibnu Imran] dari [Abu Ishaq Asy Syaibani] dari [Abdullah bin Abu Aufa] ia berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Allah akan bersama seorang hakim selama ia tidak berbuat curang. Apabila berbuat curang maka akan dibebankan kepada dirinya sendiri.\""},"2269":{"ar":"حَدَّثَنَا عَلِيُّ بْنُ مُحَمَّدٍ حَدَّثَنَا وَكِيعٌ حَدَّثَنَا ابْنُ أَبِي ذِئْبٍ عَنْ خَالِهِ الْحَارِثِ بْنِ عَبْدِ الرَّحْمَنِ عَنْ أَبِي سَلَمَةَ عَنْ عَبْدِ اللَّهِ بْنِ عَمْرٍو قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَعْنَةُ اللَّهِ عَلَى الرَّاشِي وَالْمُرْتَشِي","id":"Telah menceritakan kepada kami [Ali bin Muhammad] berkata, telah menceritakan kepada kami [Waki'] berkata, telah menceritakan kepada kami [Ibnu Abu Dzi`b] dari pamannya [Al Harits bin 'Abdurrahman] dari [Abu Salamah] dari [Abdullah bin Amru] ia berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Allah melaknat penyuap dan penerima suap.\""},"2270":{"ar":"حَدَّثَنَا هِشَامُ بْنُ عَمَّارٍ حَدَّثَنَا عَبْدُ الْعَزِيزِ بْنُ مُحَمَّدٍ الدَّرَاوَرْدِيُّ حَدَّثَنَا يَزِيدُ بْنُ عَبْدِ اللَّهِ بْنِ الْهَادِ عَنْ مُحَمَّدِ بْنِ إِبْرَاهِيمَ التَّيْمِيِّ عَنْ بُسْرِ بْنِ سَعِيدٍ عَنْ أَبِي قَيْسٍ مَوْلَى عَمْرِو بْنِ الْعَاصِ عَنْ عَمْرِو بْنِ الْعَاصِأَنَّهُ سَمِعَ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ إِذَا حَكَمَ الْحَاكِمُ فَاجْتَهَدَ فَأَصَابَ فَلَهُ أَجْرَانِ وَإِذَا حَكَمَ فَاجْتَهَدَ فَأَخْطَأَ فَلَهُ أَجْرٌقَالَ يَزِيدُ فَحَدَّثْتُ بِهِ أَبَا بَكْرِ بْنَ عَمْرِو بْنِ حَزْمٍ فَقَالَ هَكَذَا حَدَّثَنِيهِ أَبُو سَلَمَةَ عَنْ أَبِي هُرَيْرَةَ","id":"Telah menceritakan kepada kami [Hisyam bin Ammar] berkata, telah menceritakan kepada kami [Abdul Aziz bin Muhammad Ad Darawardi] berkata, telah menceritakan kepada kami [Yazid bin Abdullah Ibnul Had] dari [Muhammad bin Ibrahim At Taimi] dari [Busr bin Sa'id] dari [Abu Qais] -mantan budak Amru bin Al Ash- dari [Amru bin Al Ash] Bahwasanya ia mendengar Rasulullah shallallahu 'alaihi wasallam bersabda: \"Jika seorang hakim berijtihad dan benar maka ia mendapatkan dua pahala, dan jika ia berijtihad kemudian salah maka ia mendapat satu pahala.\" [Yazid] berkata, \"Aku ceritakan hal itu kepada [Abu Bakr bin Amru bin Hazm], lalu ia berkata, \"Seperti inilah [Abu Salamah] menceritakan kepadaku dari [Abu Hurairah].\""},"2271":{"ar":"حَدَّثَنَا إِسْمَعِيلُ بْنُ تَوْبَةَ حَدَّثَنَا خَلَفُ بْنُ خَلِيفَةَ حَدَّثَنَا أَبُو هَاشِمٍ قَالَ لَوْلَا حَدِيثُ ابْنِ بُرَيْدَةَ عَنْ أَبِيهِعَنْ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ الْقُضَاةُ ثَلَاثَةٌ اثْنَانِ فِي النَّارِ وَوَاحِدٌ فِي الْجَنَّةِ رَجُلٌ عَلِمَ الْحَقَّ فَقَضَى بِهِ فَهُوَ فِي الْجَنَّةِ وَرَجُلٌ قَضَى لِلنَّاسِ عَلَى جَهْلٍ فَهُوَ فِي النَّارِ وَرَجُلٌ جَارَ فِي الْحُكْمِ فَهُوَ فِي النَّارِ لَقُلْنَا إِنَّ الْقَاضِيَ إِذَا اجْتَهَدَ فَهُوَ فِي الْجَنَّةِ","id":"Telah menceritakan kepada kami [Isma'il bin Taubah] berkata, telah menceritakan kepada kami [Khalaf bin Khalifah] berkata, telah menceritakan kepada kami [Abu Hasyim] ia berkata: \"Kalau bukan karena hadits [Ibnu Buraidah] yang bersumber dari [Bapaknya], dari Rasulullah shallallahu 'alaihi wasallam beliau bersabda: 'Hakim itu ada tiga golongan, dua di neraka dan satu di surga; hakim yang mengetahui kebenaran lalu memutuskan perkara tersebut dengan ilmunya, maka ia berada di surga. Hakim yang memberi putusan kepada manusia atas dasar kebodohan, maka ia di neraka. Dan hakim yang berlaku curang saat memberi putusan maka ia di neraka, ' niscaya kami akan mengatakan, 'Sesungguhnya seorang hakim apabila berijtihad dia akan berada di dalam surga.\""},"2272":{"ar":"حَدَّثَنَا هِشَامُ بْنُ عَمَّارٍ وَمُحَمَّدُ بْنُ عَبْدِ اللَّهِ بْنِ يَزِيدَ وَأَحْمَدُ بْنُ ثَابِتٍ الْجَحْدَرِيُّ قَالُوا حَدَّثَنَا سُفْيَانُ بْنُ عُيَيْنَةَ عَنْ عَبْدِ الْمَلِكِ بْنِ عُمَيْرٍ أَنَّهُ سَمِعَ عَبْدَ الرَّحْمَنِ بْنَ أَبِي بَكْرَةَ عَنْ أَبِيهِأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ لَا يَقْضِي الْقَاضِي بَيْنَ اثْنَيْنِ وَهُوَ غَضْبَانُ قَالَ هِشَامٌ فِي حَدِيثِهِ لَا يَنْبَغِي لِلْحَاكِمِ أَنْ يَقْضِيَ بَيْنَ اثْنَيْنِ وَهُوَ غَضْبَانُ","id":"Telah menceritakan kepada kami [Hisyam bin Ammar] dan [Muhammad bin Abdullah bin Yazid] dan [Ahmad bin Tsabit Al Jahdari] mereka berkata; telah menceritakan kepada kami [Sufyan bin Uyainah] dari [Abdul Malik bin Umair] bahwa ia mendengar ['Abdurrahman bin Abu Bakrah] dari [Bapaknya] bahwa Rasulullah shallallahu 'alaihi wasallam bersabda: \"Seorang hakim tidak boleh memberi putusan antara dua orang dalam keadaan marah.\" Hisyam menyebutkan dalam haditsnya, \"Tidak selayaknya seorang hakim memberi putusan antara dua orang dalam keadaan marah.\""},"2273":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا وَكِيعٌ حَدَّثَنَا هِشَامُ بْنُ عُرْوَةَ عَنْ أَبِيهِ عَنْ زَيْنَبَ بِنْتِ أُمِّ سَلَمَةَ عَنْ أُمِّ سَلَمَةَ قَالَتْقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِنَّكُمْ تَخْتَصِمُونَ إِلَيَّ وَإِنَّمَا أَنَا بَشَرٌ وَلَعَلَّ بَعْضَكُمْ أَنْ يَكُونَ أَلْحَنَ بِحُجَّتِهِ مِنْ بَعْضٍ وَإِنَّمَا أَقْضِي لَكُمْ عَلَى نَحْوٍ مِمَّا أَسْمَعُ مِنْكُمْ فَمَنْ قَضَيْتُ لَهُ مِنْ حَقِّ أَخِيهِ شَيْئًا فَلَا يَأْخُذْهُ فَإِنَّمَا أَقْطَعُ لَهُ قِطْعَةً مِنْ النَّارِ يَأْتِي بِهَا يَوْمَ الْقِيَامَةِ","id":"Telah menceritakan kepada kami [Abu Bakr bin Abu Syaibah] berkata, telah menceritakan kepada kami [Waki'] berkata, telah menceritakan kepada kami [Hisyam bin Urwah] dari [Bapaknya] dari [Zainab binti Ummu Salamah] dari [Ummu Salamah] ia berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Kalian telah mendebatku, padahal aku hanyalah manusia biasa. Bisa jadi sebagian dari kalian lebih mampu bersilat lidah dalam menerangkan pendapatnya dari sebagian yang lain. Aku memberi putusan kalian sebatas yang kudengar dari kalian, maka barangsiapa yang kumenangkan urusannya dengan mencederai hak sudaranya, jangan ia ambil, sebab aku telah membuatkan bara api untuknya pada hari kiamat nanti.\""},"2274":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا مُحَمَّدُ بْنُ بِشْرٍ حَدَّثَنَا مُحَمَّدُ بْنُ عَمْرٍو عَنْ أَبِي سَلَمَةَ بْنِ عَبْدِ الرَّحْمَنِ عَنْ أَبِي هُرَيْرَةَ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِنَّمَا أَنَا بَشَرٌ وَلَعَلَّ بَعْضَكُمْ أَنْ يَكُونَ أَلْحَنَ بِحُجَّتِهِ مِنْ بَعْضٍ فَمَنْ قَطَعْتُ لَهُ مِنْ حَقِّ أَخِيهِ قِطْعَةً فَإِنَّمَا أَقْطَعُ لَهُ قِطْعَةً مِنْ النَّارِ","id":"Telah menceritakan kepada kami [Abu Bakr bin Abu Syaibah] berkata, telah menceritakan kepada kami [Muhammad bin Biysr] berkata, telah menceritakan kepada kami [Muhammad bin Amru] dari [Abu Salamah bin 'Abdurrahman] dari [Abu Hurairah] ia berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Aku hanyalah manusia biasa, bisa jadi sebagian dari kalian lebih mampu bersilat lidah dalam menerangkan pendapatnya dari sebagian yang lain. Barangsiapa yang kuputuskan urusannya dengan mencederai hak saudaranya, maka aku hanya memutuskan bara api neraka.\""},"2275":{"ar":"حَدَّثَنَا عَبْدُ الْوَارِثِ بْنُ عَبْدِ الصَّمَدِ بْنِ عَبْدِ الْوَارِثِ بْنِ سَعِيدٍ أَبُو عُبَيْدَةَ حَدَّثَنِي أَبِي عَنْ أَبِيهِ حَدَّثَنِي الْحُسَيْنُ بْنُ ذَكْوَانَ عَنْ عَبْدِ اللَّهِ بْنِ بُرَيْدَةَ قَالَ حَدَّثَنِي يَحْيَى بْنُ يَعْمَرَ أَنَّ أَبَا الْأَسْوَدِ الدِّيلِيَّ حَدَّثَهُ عَنْ أَبِي ذَرٍّأَنَّهُ سَمِعَ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ مَنْ ادَّعَى مَا لَيْسَ لَهُ فَلَيْسَ مِنَّا وَلْيَتَبَوَّأْ مَقْعَدَهُ مِنْ النَّارِ","id":"Telah menceritakan kepada kami [Abdul Warits bin Abdush Shamad bin Abdul Warits bin Sa'id Abu Ubaidah] berkata, telah menceritakan kepadaku [Bapakku] dari [Bapaknya] berkata, telah menceritakan kepadaku [Al Husain bin Dzakwan] dari [Abdullah bin Buraidah] ia berkata; telah menceritakan kepadaku [Yahya bin Ya'mar] bahwa [Abu Al Aswad Ad Daili] ia menceritakan kepadanya dari [Abu Dzar] Bahwasanya ia mendengar Rasulullah shallallahu 'alaihi wasallam bersabda: \"Barangsiapa mengaku-ngaku sesuatu yang bukan miliknya maka ia bukan dari golongan kami, dan hendaklah ia menyiapkan tempat duduknya dalam neraka.\""},"2276":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ ثَعْلَبَةَ بْنِ سَوَاءٍ حَدَّثَنِي عَمِّي مُحَمَّدُ بْنُ سَوَاءٍ عَنْ حُسَيْنٍ الْمُعَلِّمِ عَنْ مَطَرٍ الْوَرَّاقِ عَنْ نَافِعٍ عَنْ ابْنِ عُمَرَ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَنْ أَعَانَ عَلَى خُصُومَةٍ بِظُلْمٍ أَوْ يُعِينُ عَلَى ظُلْمٍ لَمْ يَزَلْ فِي سَخَطِ اللَّهِ حَتَّى يَنْزِعَ","id":"Telah menceritakan kepada kami [Muhammad bin Tsa'labah bin Sawa] berkata, telah berkata kepadaku pamanku [Muhammad bin Sawa] dari [Husain Al Mu'allim] dari [Mathar Al Warraq] dari [Nafi'] dari [Ibnu Umar] ia berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Barangsiapa membantu sengketa dengan cara zhalim, atau membantu kezhaliman, maka ia akan senantiasa dalam murka Allah hingga ia mencabut (bantuannya).\""},"2277":{"ar":"حَدَّثَنَا حَرْمَلَةُ بْنُ يَحْيَى الْمِصْرِيُّ حَدَّثَنَا عَبْدُ اللَّهِ بْنُ وَهْبٍ أَنْبَأَنَا ابْنُ جُرَيْجٍ عَنْ ابْنِ أَبِي مُلَيْكَةَ عَنْ ابْنِ عَبَّاسٍأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ لَوْ يُعْطَى النَّاسُ بِدَعْوَاهُمْ ادَّعَى نَاسٌ دِمَاءَ رِجَالٍ وَأَمْوَالَهُمْ وَلَكِنْ الْيَمِينُ عَلَى الْمُدَّعَى عَلَيْهِ","id":"Telah menceritakan kepada kami [Harmalah bin Yahya Al Mishri] berkata, telah menceritakan kepada kami [Abdullah bin Wahb] berkata, telah memberitakan kepada kami [Ibnu Juraij] dari [Ibnu Abu Mulaikah] dari [Ibnu Abbas] bahwa Rasulullah shallallahu 'alaihi wasallam bersabda: \"Sekiranya manusia itu dibebaskan untuk mengklaim, maka mereka akan mengklaim darah dan harta manusia, akan tetapi orang yang diklaim cukuplah bersumpah.\""},"2278":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ عَبْدِ اللَّهِ بْنِ نُمَيْرٍ وَعَلِيُّ بْنُ مُحَمَّدٍ قَالَا حَدَّثَنَا وَكِيعٌ وَأَبُو مُعَاوِيَةَ قَالَا حَدَّثَنَا الْأَعْمَشُ عَنْ شَقِيقٍ عَنْ الْأَشْعَثِ بْنِ قَيْسٍ قَالَكَانَ بَيْنِي وَبَيْنَ رَجُلٍ مِنْ الْيَهُودِ أَرْضٌ فَجَحَدَنِي فَقَدَّمْتُهُ إِلَى النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ لِي رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ هَلْ لَكَ بَيِّنَةٌ قُلْتُ لَا قَالَ لِلْيَهُودِيِّ احْلِفْ قُلْتُ إِذًا يَحْلِفُ فِيهِ فَيَذْهَبُ بِمَالِي فَأَنْزَلَ اللَّهُ سُبْحَانَهُ{ إِنَّ الَّذِينَ يَشْتَرُونَ بِعَهْدِ اللَّهِ وَأَيْمَانِهِمْ ثَمَنًا قَلِيلًا }إِلَخْ الْآيَةِ","id":"Telah menceritakan kepada kami [Muhammad bin Abdullah bin Numair] dan [Ali bin Muhammad] keduanya berkata; telah menceritakan kepada kami [Waki'] dan [Abu Mu'awiyah] keduanya berkata; telah menceritakan kepada kami [Al A'masy] dari [Syaqiq] dari [Al Asy'ats bin Qais] ia berkata, \"Antara aku dengan seorang laki-laki yahudi terjadi perselisihan atas sebidang tanah, dan ia ingin mengingkariku. Maka aku serahkan hal itu kepada Nabi shallallahu 'alaihi wasallam, Rasulullah shallallahu 'alaihi wasallam lantas bersabda: \"Apakah kamu mempunyai bukti?\" aku menjawab, \"Tidak.\" Beliau lalu bersabda kepada laki-laki yahudi itu, \"Silahkan kamu bersumpah! \" aku berkata, \"Jika demikian, ia akan bersumpah dan hilanglah apa yang menjadi hakku! \" maka Allah Subhaanahu menurunkan ayat: (Sesungguhnya orang-orang yang menukar janji (nya dengan) Allah dan sumpah-sumpah mereka dengan harga yang sedikit) hingga akhir ayat.\""},"2279":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ عَبْدِ اللَّهِ بْنِ نُمَيْرٍ حَدَّثَنَا وَكِيعٌ وَأَبُو مُعَاوِيَةَ قَالَا حَدَّثَنَا الْأَعْمَشُ عَنْ شَقِيقٍ عَنْ عَبْدِ اللَّهِ بْنِ مَسْعُودٍ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَنْ حَلَفَ عَلَى يَمِينٍ وَهُوَ فِيهَا فَاجِرٌ يَقْتَطِعُ بِهَا مَالَ امْرِئٍ مُسْلِمٍ لَقِيَ اللَّهَ وَهُوَ عَلَيْهِ غَضْبَانُ","id":"Telah menceritakan kepada kami [Muhammad bin Abdullah bin Numair] berkata, telah menceritakan kepada kami [Waki'] dan [Abu Mu'awiyah] keduanya berkata; telah menceritakan kepada kami [Al A'masy] dari [Syaqiq] dari [Abdullah bin Mas'ud] ia berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Barangsiapa bersumpah palsu atas sesuatu, yang dengannya akan merusak harta seorang muslim, maka ia akan berjumpa dengan Allah sementara Ia murka kepadanya.\""},"2280":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا أَبُو أُسَامَةَ عَنْ الْوَلِيدِ بْنِ كَثِيرٍ عَنْ مُحَمَّدِ بْنِ كَعْبٍ أَنَّهُ سَمِعَ أَخَاهُ عَبْدَ اللَّهِ بْنَ كَعْبٍ أَنَّ أَبَا أُمَامَةَ الْحَارِثِيَّ حَدَّثَهُأَنَّهُ سَمِعَ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ لَا يَقْتَطِعُ رَجُلٌ حَقَّ امْرِئٍ مُسْلِمٍ بِيَمِينِهِ إِلَّا حَرَّمَ اللَّهُ عَلَيْهِ الْجَنَّةَ وَأَوْجَبَ لَهُ النَّارَ فَقَالَ رَجُلٌ مِنْ الْقَوْمِ يَا رَسُولَ اللَّهِ وَإِنْ كَانَ شَيْئًا يَسِيرًا قَالَ وَإِنْ كَانَ سِوَاكًا مِنْ أَرَاكٍ","id":"Telah menceritakan kepada kami [Abu Bakr bin Abu Syaibah] berkata, telah menceritakan kepada kami [Abu Usamah] dari [Al Walid bin Katsir] dari [Muhammad bin Ka'b] bahwa ia pernah mendengar saudaranya [Abdullah bin Ka'b] bahwa [Abu Umamah Al Haritsi] menceritakan kepadanya, bahwa ia mendengar Rasulullah shallallahu 'alaihi wasallam bersabda: \"Tidaklah seorang laki-laki merusak hak orang lain dengan sumpahnya, kecuali Allah akan mengharamkan surga baginya dan memasukkannya ke dalam neraka.\" Seorang laki-laki lalu berkata, \"Wahai Rasulullah, meskipun itu sesuatu yang remeh?\" beliau menjawab: \"Meskipun itu sebatang kayu siwak.\""},"2281":{"ar":"حَدَّثَنَا عَمْرُو بْنُ رَافِعٍ حَدَّثَنَا مَرْوَانُ بْنُ مُعَاوِيَةَ ح و حَدَّثَنَا أَحْمَدُ بْنُ ثَابِتٍ الْجَحْدَرِيُّ حَدَّثَنَا صَفْوَانُ بْنُ عِيسَى قَالَا حَدَّثَنَا هَاشِمُ بْنُ هَاشِمٍ عَنْ عَبْدِ اللَّهِ بْنِ نِسْطَاسٍ عَنْ جَابِرِ بْنِ عَبْدِ اللَّهِ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَنْ حَلَفَ بِيَمِينٍ آثِمَةٍ عِنْدَ مِنْبَرِي هَذَا فَلْيَتَبَوَّأْ مَقْعَدَهُ مِنْ النَّارِ وَلَوْ عَلَى سِوَاكٍ أَخْضَرَ","id":"Telah menceritakan kepada kami [Amru bin Rafi'] berkata, telah menceritakan kepada kami [Marwan bin Mu'awiyah]. (Dalam jalur lain disebutkan) Telah menceritakan kepada kami [Ahmad bin Tsabit Al Jahdari] berkata, telah menceritakan kepada kami [Shafwah bin Isa] keduanya berkata; telah menceritakan kepada kami [Hasyim bin Hasyim] dari [Abdullah bin Nisthas] dari [Jabir bin Abdullah] ia berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Barangsiapa bersumpah palsu di samping mimbarku ini, maka hendaklah ia menyiapkan tempat duduknya di neraka meskipun itu untuk sebatang kayu siwak hijau.\""},"2282":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ يَحْيَى وَزَيْدُ بْنُ أَخْزَمَ قَالَا حَدَّثَنَا الضَّحَّاكُ بْنُ مَخْلَدٍ حَدَّثَنَا الْحَسَنُ بْنُ يَزِيدَ بْنِ فَرُّوخَ قَالَ مُحَمَّدُ بْنُ يَحْيَى وَهُوَ أَبُو يُونُسَ الْقَوِيُّ قَالَ سَمِعْتُ أَبَا سَلَمَةَ يَقُولُ سَمِعْتُ أَبَا هُرَيْرَةَ يَقُولُقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَا يَحْلِفُ عِنْدَ هَذَا الْمِنْبَرِ عَبْدٌ وَلَا أَمَةٌ عَلَى يَمِينٍ آثِمَةٍ وَلَوْ عَلَى سِوَاكٍ رَطْبٍ إِلَّا وَجَبَتْ لَهُ النَّارُ","id":"Telah menceritakan kepada kami [Muhammad bin Yahya] dan [Zaid bin Akhzam] keduanya berkata; telah menceritakan kepada kami [Adl Dlahhak bin Makhlad] berkata, telah menceritakan kepada kami [Al Hasan bin Yazid bin Farukh] -Muhammad bin Yahya berkata; dia adalah Abu Yunus Al Qawi-; Aku mendengar [Abu Salamah] berkata; aku mendengar [Abu Hurairah] berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Tidaklah seorang budak laki-laki atau perempuan yang bersumpah palsu di sisi mimbar ini meskipun untuk sebuah siwak, kecuali telah wajib baginya masuk neraka.\""},"2283":{"ar":"حَدَّثَنَا عَلِيُّ بْنُ مُحَمَّدٍ حَدَّثَنَا أَبُو مُعَاوِيَةَ عَنْ الْأَعْمَشِ عَنْ عَبْدِ اللَّهِ بْنِ مُرَّةَ عَنْ الْبَرَاءِ بْنِ عَازِبٍأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ دَعَا رَجُلًا مِنْ عُلَمَاءِ الْيَهُودِ فَقَالَ أَنْشُدُكَ بِالَّذِي أَنْزَلَ التَّوْرَاةَ عَلَى مُوسَى","id":"Telah menceritakan kepada kami [Ali bin Muhammad] berkata, telah menceritakan kepada kami [Abu Mu'awiyah] dari [Al A'masy] dari [Abdullah bin Murrah] dari [Al Bara bin 'Azib] berkata, \"Rasulullah shallallahu 'alaihi wasallam memanggil seorang ulama yahudi, beliau mengucapkan: \"Aku bersumpah atas kamu dengan Dzat yang menurunkan Taurat kepada Musa.\""},"2284":{"ar":"حَدَّثَنَا عَلِيُّ بْنُ مُحَمَّدٍ حَدَّثَنَا أَبُو أُسَامَةَ عَنْ مُجَالِدٍ أَنْبَأَنَا عَامِرٌ عَنْ جَابِرِ بْنِ عَبْدِ اللَّهِأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ لِيَهُودِيَّيْنِ أَنْشَدْتُكُمَا بِاللَّهِ الَّذِي أَنْزَلَ التَّوْرَاةَ عَلَى مُوسَى عَلَيْهِ السَّلَام","id":"Telah menceritakan kepada kami [Ali bin Muhammad] berkata, telah menceritakan kepada kami [Abu Usamah] dari [Mujalid] berkata, telah mengabarkan kepada kami [Amir] dari [Jabir bin Abdullah] bahwa Rasulullah shallallahu 'alaihi wasallam bersabda kepada dua orang Yahudi: \"Aku bersumpah atas kalian, demi Allah yang telah menurunkan Taurat kepada Musa 'Alaihis Salaam.\""},"2285":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا خَالِدُ بْنُ الْحَارِثِ حَدَّثَنَا سَعِيدُ بْنُ أَبِي عَرُوبَةَ عَنْ قَتَادَةَ عَنْ خِلَاسٍ عَنْ أَبِي رَافِعٍ عَنْ أَبِي هُرَيْرَةَأَنَّهُ ذَكَرَ أَنَّ رَجُلَيْنِ ادَّعَيَا دَابَّةً وَلَمْ يَكُنْ بَيْنَهُمَا بَيِّنَةٌ فَأَمَرَهُمَا النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنْ يَسْتَهِمَا عَلَى الْيَمِينِ","id":"Telah menceritakan kepada kami [Abu Bakr bin Abu Syaibah] berkata, telah menceritakan kepada kami [Khalid bin Al Harits] berkata, telah menceritakan kepada kami [Sa'id bin Abu Arubah] dari [Qatadah] dari [Khilas] dari [Abu Rafi'] dari [Abu Hurairah] ia menyebutkan bahwa ada dua orang lelaki yang mengaku memiliki seekor hewan tunggangan, sementara di antara keduanya tidak ada bukti. Maka Nabi shallallahu 'alaihi wasallam memerintahkan keduanya untuk saling mengundi atas dasar sumpah.\""},"2286":{"ar":"حَدَّثَنَا إِسْحَقُ بْنُ مَنْصُورٍ وَمُحَمَّدُ بْنُ مَعْمَرٍ وَزُهَيْرُ بْنُ مُحَمَّدٍ قَالُوا حَدَّثَنَا رَوْحُ بْنُ عُبَادَةَ حَدَّثَنَا سَعِيدٌ عَنْ قَتَادَةَ عَنْ سَعِيدِ بْنِ أَبِي بُرْدَةَ عَنْ أَبِيهِ عَنْ أَبِي مُوسَىأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ اخْتَصَمَ إِلَيْهِ رَجُلَانِ بَيْنَهُمَا دَابَّةٌ وَلَيْسَ لِوَاحِدٍ مِنْهُمَا بَيِّنَةٌ فَجَعَلَهَا بَيْنَهُمَا نِصْفَيْنِ","id":"Telah menceritakan kepada kami [Ishaq bin Manshur] dan [Muhammad bin Ma'mar] dan [Zuhair bin Muhammad] mereka berkata; telah menceritakan kepada kami [Rauh bin Ubadah] berkata, telah menceritakan kepada kami [Sa'id] dari [Qatadah] dari [Sa'id bin Abu Burdah] dari [Bapaknya] dari [Abu Musa] berkata, \"Ada dua orang laki-laki mengadu kepada Rasulullah shallallahu 'alaihi wasallam tentang kepemilikan hewan sementara keduanya tidak memiliki bukti. Maka beliau membagi hewan tersebut menjadi dua bagian.\""},"2287":{"ar":"حَدَّثَنَا عَلِيُّ بْنُ مُحَمَّدٍ حَدَّثَنَا أَبُو مُعَاوِيَةَ حَدَّثَنَا حَجَّاجٌ عَنْ سَعِيدِ بْنِ عُبَيْدِ بْنِ زَيْدِ بْنِ عُقْبَةَ عَنْ أَبِيهِ عَنْ سَمُرَةَ بْنِ جُنْدَبٍ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِذَا ضَاعَ لِلرَّجُلِ مَتَاعٌ أَوْ سُرِقَ لَهُ مَتَاعٌ فَوَجَدَهُ فِي يَدِ رَجُلٍ يَبِيعُهُ فَهُوَ أَحَقُّ بِهِ وَيَرْجِعُ الْمُشْتَرِي عَلَى الْبَائِعِ بِالثَّمَنِ","id":"Telah menceritakan kepada kami [Ali bin Muhammad] berkata, telah menceritakan kepada kami [Abu Mu'awiyah] berkata, telah menceritakan kepada kami [Hajjaj] dari [Sa'id bin Ubaid bin Zaid bin Uqbah] dari [Bapaknya] dari [Samurah bin Jundab] ia berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Jika barang seseorang hilang atau dicuri, kemudian ia menemukan barang tersebut di tangan seseorang dan menjualnya, maka ia (yang kehilangan) lebih berhak atas barang itu. Dan bagi pembeli ia boleh mengembalikannya kepada penjual dengan harga.\""},"2288":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ رُمْحٍ الْمِصْرِيُّ أَنْبَأَنَا اللَّيْثُ بْنُ سَعْدٍ عَنْ ابْنِ شِهَابٍ أَنَّ ابْنَ مُحَيِّصَةَ الْأَنْصَارِيَّ أَخْبَرَهُأَنَّ نَاقَةً لِلْبَرَاءِ كَانَتْ ضَارِيَةً دَخَلَتْ فِي حَائِطِ قَوْمٍ فَأَفْسَدَتْ فِيهِ فَكُلِّمَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِيهَا فَقَضَى أَنَّ حِفْظَ الْأَمْوَالِ عَلَى أَهْلِهَا بِالنَّهَارِ وَعَلَى أَهْلِ الْمَوَاشِي مَا أَصَابَتْ مَوَاشِيهِمْ بِاللَّيْلِحَدَّثَنَا الْحَسَنُ بْنُ عَلِيِّ بْنِ عَفَّانَ حَدَّثَنَا مُعَاوِيَةَ بْنُ هِشَامٍ عَنْ سُفْيَانَ عَنْ عَبْدِ اللَّهِ بْنِ عِيسَى عَنْ الزُّهْرِيِّ عَنْ حَرَامِ بْنِ مُحَيِّصَةَ عَنْ الْبَرَاءِ بْنِ عَازِبٍ أَنَّ نَاقَةً لِآلِ الْبَرَاءِ أَفْسَدَتْ شَيْئًا فَقَضَى رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِمِثْلِهِ","id":"Telah menceritakan kepada kami [Muhammad bin Rumh Al Mishri] berkata, telah memberitakan kepada kami [Al Laits bin Sa'd] dari [Ibnu Syihab] bahwa [Ibnu Muhayyishah Al Anshari] mengabarkan kepadanya bahwa unta milik Al Barra lepas dan masuk ke kebun orang lain hingga membuat kerusakan. Kejadian tersebut kemudian dilaporkan kepada Rasulullah shallallahu 'alaihi wasallam. Beliau lalu membuat keputusan bahwa bila waktu siang maka yang menjaga tanaman adalah pemilik kebun, sementara pemilik hewan ia berkewajiban mengganti kerusakan jika itu terjadi di waktu malam.\" Telah menceritakan kepada kami [Al Hasan bin Ali bin Affan] berkata, telah menceritakan kepada kami [Mu'awiyah bin Hisyam] dari [Sufyan] dari [Abdullah bin Isa] dari [Az Zuhri] dari [Haram bin Mahayyishah] dari [Al Barra bin 'Azib] bahwa unta milik keluarga Al Barra merusak sesuatu, lalu Rasulullah shallallahu 'alaihi wasallam memberikan putusan sebagaimana dalam hadits tersebut.\""},"2289":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا شَرِيكُ بْنُ عَبْدِ اللَّهِ عَنْ قَيْسِ بْنِ وَهْبٍ عَنْ رَجُلٍ مِنْ بَنِي سُوءَةَ قَالَقُلْتُ لِعَائِشَةَ أَخْبِرِينِي عَنْ خُلُقِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَتْ أَوَ مَا تَقْرَأُ الْقُرْآنَ{ وَإِنَّكَ لَعَلَى خُلُقٍ عَظِيمٍ }قَالَتْ كَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَعَ أَصْحَابِهِ فَصَنَعْتُ لَهُ طَعَامًا وَصَنَعَتْ لَهُ حَفْصَةُ طَعَامًا قَالَتْ فَسَبَقَتْنِي حَفْصَةُ فَقُلْتُ لِلْجَارِيَةِ انْطَلِقِي فَأَكْفِئِي قَصْعَتَهَا فَلَحِقَتْهَا وَقَدْ هَمَّتْ أَنْ تَضَعَ بَيْنَ يَدَيْ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَأَكْفَأَتْهَا فَانْكَسَرَتْ الْقَصْعَةُ وَانْتَشَرَ الطَّعَامُ قَالَتْ فَجَمَعَهَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَمَا فِيهَا مِنْ الطَّعَامِ عَلَى النِّطَعِ فَأَكَلُوا ثُمَّ بَعَثَ بِقَصْعَتِي فَدَفَعَهَا إِلَى حَفْصَةَ فَقَالَ خُذُوا ظَرْفًا مَكَانَ ظَرْفِكُمْ وَكُلُوا مَا فِيهَا قَالَتْ فَمَا رَأَيْتُ ذَلِكَ فِي وَجْهِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ","id":"Telah menceritakan kepada kami [Abu Bakr bin Abu Syaibah] berkata, telah menceritakan kepada kami [Syarik bin Abdullah] dari [Qais bin Wahb] dari [seorang laki-laki] dari Bani Su`ah, ia berkata, \"Aku berkata kepada ['Aisyah] beritahukanlah kepadaku bagaimana akhlak Rasulullah shallallahu 'alaihi wasallam. 'Aisyah berkata, \"Apakah kamu tidak membaca Al Qur'an? (Dan sesungguhnya kamu benar-benar di atas akhlak yang agung).\" 'Aisyah kembali menuturkan, \"Ketika Rasulullah shallallahu 'alaihi wasallam sedang bersama-sama para sahabatnya, aku membuatkan makanan untuknya, dan ternyata Hafshah juga membuatkan makanan untuk beliau.\" 'Aisyah melanjutkan, \"Ternyata Hafshah lebih dahulu dalam membuat makanan, maka aku berkata kepada budak perempuanku, \"Pergi dan tumpahkanlah mangkuk piringnya! \" Budak itu pun menyusul Hafshah, sementara Hafshah telah siap untuk meletakkan makanan itu di hadapan Rasulullah shallallahu 'alaihi wasallam. Lalu budak perempuan itu menumpahkannya hingga mangkuknya pecah dan makanannya berhamburan.\" 'Aisyah berkata, \"Rasulullah shallallahu 'alaihi wasallam kemudian mengumpulkan pecahan mangkuk dan makanan yang tertumpah di atas tikar dari kulit, hingga para sahabat dapat memakannya. Setelah itu Rasulullah mengambil mangkuk milikku dan memberikannya kepada Hafshah seraya bersabda: \"Ambilah wadah ini sebagai ganti wadah kalian dan makanlah makanan yang ada di dalamnya.\" 'Aisyah berkata, \"Aku tidak melihat tanda emosi itu di wajah Rasulullah shallallahu 'alaihi wasallam.\""},"2290":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ الْمُثَنَّى حَدَّثَنَا خَالِدُ بْنُ الْحَارِثِ حَدَّثَنَا حُمَيْدٌ عَنْ أَنَسِ بْنِ مَالِكٍ قَالَكَانَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عِنْدَ إِحْدَى أُمَّهَاتِ الْمُؤْمِنِينَ فَأَرْسَلَتْ أُخْرَى بِقَصْعَةٍ فِيهَا طَعَامٌ فَضَرَبَتْ يَدَ الرَّسُولِ فَسَقَطَتْ الْقَصْعَةُ فَانْكَسَرَتْ فَأَخَذَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ الْكِسْرَتَيْنِ فَضَمَّ إِحْدَاهُمَا إِلَى الْأُخْرَى فَجَعَلَ يَجْمَعُ فِيهَا الطَّعَامَ وَيَقُولُ غَارَتْ أُمُّكُمْ كُلُوا فَأَكَلُوا حَتَّى جَاءَتْ بِقَصْعَتِهَا الَّتِي فِي بَيْتِهَا فَدَفَعَ الْقَصْعَةَ الصَّحِيحَةَ إِلَى الرَّسُولِ وَتَرَكَ الْمَكْسُورَةَ فِي بَيْتِ الَّتِي كَسَرَتْهَا","id":"Telah menceritakan kepada kami [Muhammad Ibnul Mutsanna] berkata, telah menceritakan kepada kami [Khalid Ibnul Warits] berkata, telah menceritakan kepada kami [Humaid] dari [Anas bin Malik] ia berkata, \"Pernah Nabi shallallahu 'alaihi wasallam bersama salah seorang Ummahatul Mukminin. Lalu ada seorang dari isteri beliau yang lain mengirimkan mangkuk berisi makanan. Lalu ia (isteri yang bersama beliau) memukul tangan Rasulullah hingga mangkuk tersebut jatuh dan pecah. Rasulullah shallallahu 'alaihi wasallam kemudian memungut kembali dua belahan mangkuk tersebut seraya menggabungkannya menjadi satu, kemudian beliau meletakkan kembali makanannya di atas mangkuk. Setelah itu beliau bersabda: \"Makanlah, ibu kalian sedang cemburu.\" Para sahabat pun makan, hingga isteri beliau datang dengan membawa mangkuk yang masih utuh dari dalam rumah. Mangkuk yang masih utuh itu lalu ia berikan kepada Rasulullah shallallahu 'alaihi wasallam, sementara mangkuk telah pecah beliau tinggalkan di rumah isterinya yang telah memecahkannya.\""},"2291":{"ar":"حَدَّثَنَا هِشَامُ بْنُ عَمَّارٍ وَمُحَمَّدُ بْنُ الصَّبَّاحِ قَالَا حَدَّثَنَا سُفْيَانُ بْنُ عُيَيْنَةَ عَنْ الزُّهْرِيِّ عَنْ عَبْدِ الرَّحْمَنِ الْأَعْرَجِ قَالَ سَمِعْتُ أَبَا هُرَيْرَةَيَبْلُغُ بِهِ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ إِذَا اسْتَأْذَنَ أَحَدَكُمْ جَارُهُ أَنْ يَغْرِزَ خَشَبَةً فِي جِدَارِهِ فَلَا يَمْنَعْهُفَلَمَّا حَدَّثَهُمْ أَبُو هُرَيْرَةَ طَأْطَئُوا رُءُوسَهُمْ فَلَمَّا رَآهُمْ قَالَ مَا لِي أَرَاكُمْ عَنْهَا مُعْرِضِينَ وَاللَّهِ لَأَرْمِيَنَّ بِهَا بَيْنَ أَكْتَافِكُمْ","id":"Telah menceritakan kepada kami [Hisyam bin Ammar] dan [Muhammad bin Ash Shabbah] keduanya berkata; telah menceritakan kepada kami [Sufyan bin Uyainah] dari [Az Zuhri] dari ['Abdurrahman Al A'raj] ia berkata; Aku mendengar [Abu Hurairah] dan sampai kepada Nabi shallallahu 'alaihi wasallam, beliau bersabda: \"Jika tetangga salah seorang dari kalian meminta izin untuk menyandarkan kayu pada tembok miliknya, maka janganlah ia larang.\" Ketika Abu Hurairah menyampaikan hadits tersebut orang-orang mengangguk-anggukkan kepala mereka, ketika Abu Hurairah melihat mereka, ia pun berkata, \"Kenapa aku melihat kalian berpaling darinya! Demi Allah, benar-benar akan aku lembarkan kayu tersebut di antara pudak-pundak kalian.\""},"2292":{"ar":"حَدَّثَنَا أَبُو بِشْرٍ بَكْرُ بْنُ خَلَفٍ حَدَّثَنَا أَبُو عَاصِمٍ عَنْ ابْنِ جُرَيْجٍ عَنْ عَمْرِو بْنِ دِينَارٍ أَنَّ هِشَامَ بْنَ يَحْيَى أَخْبَرَهُ أَنَّ عِكْرِمَةَ بْنَ سَلَمَةَ أَخْبَرَهُأَنَّ أَخَوَيْنِ مِنْ بَلْمُغِيرَةِ أَعْتَقَ أَحَدَهُمَا أَنْ لَا يَغْرِزَ خَشَبًا فِي جِدَارِهِ فَأَقْبَلَ مُجَمِّعُ بْنُ يَزِيدَ وَرِجَالٌ كَثِيرٌ مِنْ الْأَنْصَارِ فَقَالُوا نَشْهَدُ أَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ لَا يَمْنَعْ أَحَدُكُمْ جَارَهُ أَنْ يَغْرِزَ خَشَبَةً فِي جِدَارِهِفَقَالَ يَا أَخِي إِنَّكَ مَقْضِيٌّ لَكَ عَلَيَّ وَقَدْ حَلَفْتُ فَاجْعَلْ أُسْطُوَانًا دُونَ حَائِطِي أَوْ جِدَارِي فَاجْعَلْ عَلَيْهِ خَشَبَكَ","id":"Telah menceritakan kepada kami [Abu Bisyr Bakr bin Khalaf] berkata, telah menceritakan kepada kami [Abu Ashim] dari [Ibnu Juraij] dari [Amru bin Dinar] bahwa [Hisyam bin Yahya] mengabarkan kepadanya, bahwa [Ikrimah bin Salamah] mengabarkan kepadanya, bahwa salah satu dari dua orang bersaudara bani Mughirah bersumpah kepada salah satunya untuk tidak menancapkan sebatang kayu (tiang) didindingnya. Lalu datanglah [Mujamma' bin Yazid] disertai beberapa orang dari kaum Anshar seraya berkata; kami bersaksi bahwa Rasulullah shallallahu 'alaihi wasallam bersabda: \"Janganlah salah seorang dari kalian melarang tetangganya untuk menancapkan sebatang kayu di dindingnya, seraya berkata; wahai sahabatku, sesungguhnya Aku tahu bahwa keputusan jatuh ditanganmu, dan aku telah bersumpah, maka buatlah tancapan pada selain dindingku lalu tancapkanlah kayumu atasnya.\""},"2293":{"ar":"حَدَّثَنَا حَرْمَلَةُ بْنُ يَحْيَى حَدَّثَنَا عَبْدُ اللَّهِ بْنُ وَهْبٍ أَخْبَرَنِي ابْنُ لَهِيعَةَ عَنْ أَبِي الْأَسْوَدِ عَنْ عِكْرِمَةَ عَنْ ابْنِ عَبَّاسٍأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ لَا يَمْنَعْ أَحَدُكُمْ جَارَهُ أَنْ يَغْرِزَ خَشَبَةً عَلَى جِدَارِهِ","id":"Telah menceritakan kepada kami [Harmalah bin Yahya] berkata, telah menceritakan kepada kami [Abdullah bin Wahb] berkata, telah mengabarkan kepadaku [Ibnu Lahi'ah] dari [Abul Aswad] dari [Ikrimah] dari [Ibnu Abbas] bahwa Rasulullah shallallahu 'alaihi wasallam bersabda: \"Janganlah salah seorang dari kalian mencegah tetangganya untuk menyandarkan kayu pada temboknya.\""},"2294":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا وَكِيعٌ حَدَّثَنَا مُثَنَّى بْنُ سَعِيدٍ الضُّبَعِيُّ عَنْ قَتَادَةَ عَنْ بُشَيْرِ بْنِ كَعْبٍ عَنْ أَبِي هُرَيْرَةَ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ اجْعَلُوا الطَّرِيقَ سَبْعَةَ أَذْرُعٍ","id":"Telah menceritakan kepada kami [Abu Bakr bin Abu Syaibah] berkata, telah menceritakan kepada kami [Waki'] berkata, telah menceritakan kepada kami [Mutsanna bin Sa'id Adl Dluba'i] dari [Qatadah] dari [Busyair bin Ka'b] dari [Abu Hurairah] ia berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Buatlah tujuh hasta untuk jalan.\""},"2295":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ يَحْيَى وَمُحَمَّدُ بْنُ عُمَرَ بْنِ هَيَّاجٍ قَالَا حَدَّثَنَا قَبِيصَةُ حَدَّثَنَا سُفْيَانُ عَنْ سِمَاكٍ عَنْ عِكْرِمَةَ عَنْ ابْنِ عَبَّاسٍ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِذَا اخْتَلَفْتُمْ فِي الطَّرِيقِ فَاجْعَلُوهُ سَبْعَةَ أَذْرُعٍ","id":"Telah menceritakan kepada kami [Muhammad bin Yahya] dan [Muhammad bin Umar bin Hayyaj] keduanya berkata; telah menceritakan kepada kami [Qabishah] berkata, telah menceritakan kepada kami [Sufyan] dari [Simak] dari [Ikrimah] dari [Ibnu Abbas] ia berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Jika kalian berselisih pada batas jalan, maka buatlah tujuh hasta.\""},"2296":{"ar":"حَدَّثَنَا عَبْدُ رَبِّهِ بْنُ خَالِدٍ النُّمَيْرِيُّ أَبُو الْمُغَلِّسِ حَدَّثَنَا فُضَيْلُ بْنُ سُلَيْمَانَ حَدَّثَنَا مُوسَى بْنُ عُقْبَةَ حَدَّثَنَا إِسْحَقُ بْنُ يَحْيَى بْنِ الْوَلِيدِ عَنْ عُبَادَةَ بْنِ الصَّامِتِأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَضَى أَنْ لَا ضَرَرَ وَلَا ضِرَارَ","id":"Telah menceritakan kepada kami [Abdu Rabbih bin Khalid An Numairi Abu Al Mughallis] berkata, telah menceritakan kepada kami [Fudlail bin Sulaiman] berkata, telah menceritakan kepada kami [Musa bin Uqbah] berkata, telah menceritakan kepada kami [Ishaq bin Yahya bin Al Walid] dari [Ubadah bin Ash Shamith] berkata, \"Rasulullah shallallahu 'alaihi wasallam memutuskan bahwa tidak boleh berbuat madlarat dan hal yang menimbulkan madlarat.\""},"2297":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ يَحْيَى حَدَّثَنَا عَبْدُ الرَّزَّاقِ أَنْبَأَنَا مَعْمَرٌ عَنْ جَابِرٍ الْجُعْفِيِّ عَنْ عِكْرِمَةَ عَنْ ابْنِ عَبَّاسٍ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَا ضَرَرَ وَلَا ضِرَارَ","id":"Telah menceritakan kepada kami [Muhammad bin Yahya] berkata, telah menceritakan kepada kami [Abdurrazaq] berkata, telah memberitakan kepada kami [Ma'mar] dari [Jabir Al Ju'fi] dari [Ikrimah] dari [Ibnu Abbas] ia berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Tidak boleh berbuat madlarat dan hal yang menimbulkan madlarat.\""},"2298":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ رُمْحٍ أَنْبَأَنَا اللَّيْثُ بْنُ سَعْدٍ عَنْ يَحْيَى بْنِ سَعِيدٍ عَنْ مُحَمَّدِ بْنِ يَحْيَى بْنِ حَبَّانَ عَنْ لُؤْلُؤَةَ عَنْ أَبِي صِرْمَةَعَنْ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ مَنْ ضَارَّ أَضَرَّ اللَّهُ بِهِ وَمَنْ شَاقَّ شَقَّ اللَّهُ عَلَيْهِ","id":"Telah menceritakan kepada kami [Muhammad bin Rumh] berkata, telah memberitakan kepada kami [Al Laits bin Sa'd] dari [Yahya bin Sa'id] dari [Muhammad bin Yahya bin Habban] dari [Lulu'ah] dari [Abu Shirmah] dari Rasulullah shallallahu 'alaihi wasallam, beliau bersabda: \"Barangsiapa berbuat kemadlaratan maka Allah akan memberinya madlarat, dan barangsiapa membuat kesusahan pada orang lain maka Allah memberinya kesusahan.\""},"2299":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ الصَّبَّاحِ وَعَمَّارُ بْنُ خَالِدٍ الْوَاسِطِيُّ قَالَا حَدَّثَنَا أَبُو بَكْرِ بْنُ عَيَّاشٍ عَنْ دَهْثَمِ بْنِ قُرَّانٍ عَنْ نِمْرَانَ بْنِ جَارِيَةَ عَنْ أَبِيهِأَنَّ قَوْمًا اخْتَصَمُوا إِلَى النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي خُصٍّ كَانَ بَيْنَهُمْ فَبَعَثَ حُذَيْفَةَ يَقْضِي بَيْنَهُمْ فَقَضَى لِلَّذِينَ يَلِيهِمْ الْقِمْطُ فَلَمَّا رَجَعَ إِلَى النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَخْبَرَهُ فَقَالَ أَصَبْتَ وَأَحْسَنْتَ","id":"Telah menceritakan kepada kami [Muhammad bin Ash Shabbah] dan [Ammar bin Khalid Al Wasithi] keduanya berkata; telah menceritakan kepada kami [Abu Bakr bin Ayyasy] dari [Dahtsam bin Qurran] dari [Nimran bin Jariyah] dari [Bapaknya] berkata; \"Suatu kaum mengadukan kepada Nabi shallallahu 'alaihi wasallam tentang persengketaan mereka atas sebuah gubuk yang terdapat di tengah-tengah mereka. Lalu beliau mengutus Hudzaifah untuk memberikan putusan di antara mereka. Hudzaifah kemudian memberi putusan bahwa gubuk itu adalah milik orang yang ada di sekitar tali pengekang. Ketika Hudzaifah kembali kepada Nabi shallallahu 'alaihi wasallam dan memberitahukan hasil putusan yang ia berikan, beliau lalu bersabda: \"Engkau tepat dan benar.\""},"2300":{"ar":"حَدَّثَنَا يَحْيَى بْنُ حَكِيمٍ حَدَّثَنَا أَبُو الْوَلِيدِ حَدَّثَنَا هَمَّامٌ عَنْ قتَادَةَ عَنْ الْحَسَنِ عَنْ سَمُرَةَ بْنِ جُنْدَبٍعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ إِذَا بِيعَ الْبَيْعُ مِنْ رَجُلَيْنِ فَالْبَيْعُ لِلْأَوَّلِقَالَ أَبُو الْوَلِيدِ فِي هَذَا الْحَدِيثِ إِبْطَالُ الْخَلَاصِ","id":"Telah menceritakan kepada kami [Yahya bin Hakim] berkata, telah menceritakan kepada kami [Abu Al Walid] berkata, telah menceritakan kepada kami [Hammam] dari [Qatadah] dari [Al Hasan] dari [Samurah bin Jundab] dari Nabi shallallahu 'alaihi wasallam, beliau bersabda: \"Jika suatu barang dijual oleh dua orang yang berbeda, maka yang sah adalah yang pertama.\""},"2301":{"ar":"حَدَّثَنَا نَصْرُ بْنُ عَلِيٍّ الْجَهْضَمِيُّ وَمُحَمَّدُ بْنُ الْمُثَنَّى قَالَا حَدَّثَنَا عَبْدُ الْأَعْلَى حَدَّثَنَا خَالِدٌ الْحَذَّاءُ عَنْ أَبِي قِلَابَةَ عَنْ أَبِي الْمُهَلَّبِ عَنْ عِمْرَانَ بْنِ حُصَيْنٍأَنَّ رَجُلًا كَانَ لَهُ سِتَّةُ مَمْلُوكِينَ لَيْسَ لَهُ مَالٌ غَيْرُهُمْ فَأَعْتَقَهُمْ عِنْدَ مَوْتِهِ فَجَزَّأَهُمْ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَأَعْتَقَ اثْنَيْنِ وَأَرَقَّ أَرْبَعَةً","id":"Telah menceritakan kepada kami [Nashr bin Ali Al Jahdlami] dan [Muhammad Ibnul Mutsanna] keduanya berkata; telah menceritakan kepada kami [Abdul A'la] berkata, telah menceritakan kepada kami [Khalid Al Hadzdza] dari [Abu Qilabah] dari [Abu Al Muhallib] dari [Imran bin Hushain] berkata, \"Ada seorang laki-laki yang memiliki enam orang budak, dan ia tidak memiliki harta apapun selain mereka. Saat akan meninggal ia memerdekakan mereka semua, namun Rasulullah shallallahu 'alaihi wasallam membagi-bagi mereka. Hingga akhirnya ia hanya memerdekakan dua orang dan menyisakan empat orang budak.\""},"2302":{"ar":"حَدَّثَنَا جَمِيلُ بْنُ الْحَسَنِ الْعَتَكِيُّ حَدَّثَنَا عَبْدُ الْأَعْلَى حَدَّثَنَا سَعِيدٌ عَنْ قَتَادَةَ عَنْ خِلَاسٍ عَنْ أَبِي رَافِعٍ عَنْ أَبِي هُرَيْرَةَأَنَّ رَجُلَيْنِ تَدَارَءَا فِي بَيْعٍ لَيْسَ لِوَاحِدٍ مِنْهُمَا بَيِّنَةٌ فَأَمَرَهُمَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنْ يَسْتَهِمَا عَلَى الْيَمِينِ أَحَبَّا ذَلِكَ أَمْ كَرِهَا","id":"Telah menceritakan kepada kami [Jamil bin Al Hasan Al 'Ataki] berkata, telah menceritakan kepada kami [Abdul A'la] berkata, telah menceritakan kepada kami [Sa'id] dari [Qatadah] dari [Khilas] dari [Abu Rafi'] dari [Abu Hurairah] berkata, \"Ada dua orang berselisih dalam masalah jual beli, dan tidak ada bukti yang dimiliki oleh keduanya. Maka Rasulullah shallallahu 'alaihi wasallam memerintahkan keduanya untuk mengundi atas sumpah, baik keduanya rela maupun tidak.\""},"2303":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا يَحْيَى بْنُ يَمَانٍ عَنْ مَعْمَرٍ عَنْ الزُّهْرِيِّ عَنْ عُرْوَةَ عَنْ عَائِشَةَأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَانَ إِذَا سَافَرَ أَقْرَعَ بَيْنَ نِسَائِهِ","id":"Telah menceritakan kepada kami [Abu Bakr bin Abu Syaibah] berkata, telah menceritakan kepada kami [Yahya bin Yaman] dari [Ma'mar] dari [Az Zuhri] dari [Urwah] dari ['Aisyah] berkata, \"Jika Nabi shallallahu 'alaihi wasallam akan pergi bersafar, beliau mengundi antara isteri-isterinya.\""},"2304":{"ar":"حَدَّثَنَا إِسْحَقُ بْنُ مَنْصُورٍ أَنْبَأَنَا عَبْدُ الرَّزَّاقِ أَنْبَأَنَا الثَّوْرِيُّ عَنْ صَالِحٍ الْهَمْدَانِيِّ عَنْ الشَّعْبِيِّ عَنْ عَبْدِ خَيْرٍ الْحَضْرَمِيِّ عَنْ زَيْدِ بْنِ أَرْقَمَ قَالَأُتِيَ عَلِيُّ بْنُ أَبِي طَالِبٍ وَهُوَ بِالْيَمَنِ فِي ثَلَاثَةٍ قَدْ وَقَعُوا عَلَى امْرَأَةٍ فِي طُهْرٍ وَاحِدٍ فَسَأَلَ اثْنَيْنِ فَقَالَ أَتُقِرَّانِ لِهَذَا بِالْوَلَدِ فَقَالَا لَا ثُمَّ سَأَلَ اثْنَيْنِ فَقَالَ أَتُقِرَّانِ لِهَذَا بِالْوَلَدِ فَقَالَا لَا فَجَعَلَ كُلَّمَا سَأَلَ اثْنَيْنِ أَتُقِرَّانِ لِهَذَا بِالْوَلَدِ قَالَا لَا فَأَقْرَعَ بَيْنَهُمْ وَأَلْحَقَ الْوَلَدَ بِالَّذِي أَصَابَتْهُ الْقُرْعَةُ وَجَعَلَ عَلَيْهِ ثُلُثَيْ الدِّيَةِ فَذُكِرَ ذَلِكَ لِلنَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَضَحِكَ حَتَّى بَدَتْ نَوَاجِذُهُ","id":"Telah menceritakan kepada kami [Ishaq bin Manshur] berkata, telah memberitakan kepada kami ['Abdurrazaq] berkata, telah memberitakan kepada kami [Ats Tsauri] dari [Shalih Al Hamdani] dari [Asy Sya'bi] dari [Khair Al Hadlrami] dari [Zaid bin Arqam] ia berkata, \"Ketika Ali bin Abu Thalib berada di Yaman, ada tiga orang yang telah mensetubui seorang wanita dihadapkan kepadanya. Ali lalu bertanya kepada dua orang, \"Apakah kalian berdua mengakui bayi ini sebagai anak?\" Keduanya menjawab, \"Tidak.\" Kemudian ia bertanya kepada keduanya lagi, \"Apakah kalian berdua mengakui bayi ini sebagai anak?\" Keduanya menjawab, \"Tidak.\" Ketika ia bertanya kepada keduanya, \"Apakah kalian berdua mengakui bayi ini sebagai anak? dan keduanya memberi jawaban, \"Tidak.\" Maka ia mengadakan undian di antara mereka dan menisbahkan anak kepada orang yang terkena undian, dan membebankan kepadanya dua pertiga diat. Lalu hal itu diceritakan kepada Nabi shallallahu 'alaihi wasallam, hingga Nabi shallallahu 'alaihi wasallam tertawa dan terlihat gigi-gigi gerahamnya.\""},"2305":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ وَهِشَامُ بْنُ عَمَّارٍ وَمُحَمَّدُ بْنُ الصَّبَّاحِ قَالُوا حَدَّثَنَا سُفْيَانُ بْنُ عُيَيْنَةَ عَنْ الزُّهْرِيِّ عَنْ عُرْوَةَ عَنْ عَائِشَةَ قَالَتْدَخَلَ عَلَيَّ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ ذَاتَ يَوْمٍ مَسْرُورًا وَهُوَ يَقُولُ يَا عَائِشَةُ أَلَمْ تَرَيْ أَنَّ مُجَزِّزًا الْمُدْلِجِيَّ دَخَلَ عَلَيَّ فَرَأَى أُسَامَةَ وَزَيْدًا عَلَيْهِمَا قَطِيفَةٌ قَدْ غَطَّيَا رُءُوسَهُمَا وَقَدْ بَدَتْ أَقْدَامُهُمَا فَقَالَ إِنَّ هَذِهِ الْأَقْدَامَ بَعْضُهَا مِنْ بَعْضٍ","id":"Telah menceritakan kepada kami [Abu Bakr bin Abu Syaibah] dan [Hisyam bin Ammar] dan [Muhammad bin Ash Shabbah] mereka berkata; telah menceritakan kepada kami [Sufyan bin Uyainah] dari [Az Zuhri] dari [Urwah] dari ['Aisyah] ia berkata, \"Suatu hari Rasulullah shallallahu 'alaihi wasallam menemuiku dalam keadaan berbunga-bunga, beliau bersabda: \"Wahai 'Aisyah, tidakkah engkau tahu, suatu ketika Mujaziz Al Mudliji masuk menemuiku, lalu ia melihat Usamah dan Zaid memakai kain yang menutupi kepala keduanya sementara kedua telapak kaki keduanya terlihat, lantas ia berkata, \"Sungguh, telapak kaki ini adalah bagian dari telapak kaki yang lainnya! \""},"2306":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ يَحْيَى حَدَّثَنَا مُحَمَّدُ بْنُ يُوسُفَ حَدَّثَنَا إِسْرَائِيلُ حَدَّثَنَا سِمَاكُ بْنُ حَرْبٍ عَنْ عِكْرِمَةَ عَنْ ابْنِ عَبَّاسٍأَنَّ قُرَيْشًا أَتَوْا امْرَأَةً كَاهِنَةً فَقَالُوا لَهَا أَخْبِرِينَا أَشْبَهَنَا أَثَرًا بِصَاحِبِ الْمَقَامِ فَقَالَتْ إِنْ أَنْتُمْ جَرَرْتُمْ كِسَاءً عَلَى هَذِهِ السِّهْلَةِ ثُمَّ مَشَيْتُمْ عَلَيْهَا أَنْبَأْتُكُمْ قَالَ فَجَرُّوا كِسَاءً ثُمَّ مَشَى النَّاسُ عَلَيْهَا فَأَبْصَرَتْ أَثَرَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَتْ هَذَا أَقْرَبُكُمْ إِلَيْهِ شَبَهًا ثُمَّ مَكَثُوا بَعْدَ ذَلِكَ عِشْرِينَ سَنَةً أَوْ مَا شَاءَ اللَّهُ ثُمَّ بَعَثَ اللَّهُ مُحَمَّدًا صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ","id":"Telah menceritakan kepada kami [Muhammad bin Yahya] berkata, telah menceritakan kepada kami [Muhammad bin Yusuf] berkata, telah menceritakan kepada kami [Isra'il] dari [Simak bin Harb] dari [Ikrimah] dari [Ibnu Abbas] berkata, \"Orang-orang Quraisy mendatangi seorang dukun wanita, mereka bertanya kepada perempuan itu, \"Kabarkanlah kepada kami, siapakah di antara kami yang jejaknya paling mirip dengan pemilik maqam (Ibrahim) ini?\" wanita itu lantas berkata, \"Jika kalian mau membentangkan kain di atas pasir ini, kemudian kalian berjalan di atasnya, maka aku akan beritakan kepada kalian.\" Ibnu Abbas berkata, \"Mereka pun membentangkan kain dan berjalan di atasnya, hingga wanita itu dapat melihat kemiripan Rasulullah shallallahu 'alaihi wasallam (dengan Ibrahim). Wanita itu lalu berkata; \"Orang inilah yang paling mirip dengannya di antara kalian semua.\" Setelah itu, mereka kemudian berdiam diri selama dua puluh tahun, atau sekehendak Allah. Kemudian Allah mengutus Muhammad shallallahu 'alaihi wasallam.\""},"2307":{"ar":"حَدَّثَنَا هِشَامُ بْنُ عَمَّارٍ حَدَّثَنَا سُفْيَانُ بْنُ عُيَيْنَةَ عَنْ زِيَادِ بْنِ سَعْدٍ عَنْ هِلَالِ بْنِ أَبِي مَيْمُونَةَ عَنْ أَبِي مَيْمُونَةَ عَنْ أَبِي هُرَيْرَةَأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ خَيَّرَ غُلَامًا بَيْنَ أَبِيهِ وَأُمِّهِ وَقَالَ يَا غُلَامُ هَذِهِ أُمُّكَ وَهَذَا أَبُوكَ","id":"Telah menceritakan kepada kami [Hisyam bin Ammar] berkata, telah menceritakan kepada kami [Sufyan bin Uyainah] dari [Ziyad bin Sa'd] dari [Hilal bin Abu Maimunah] dari [Abu Maimunah] dari [Abu Hurairah] berkata, \"Nabi shallallahu 'alaihi wasallam memberi pilihan kepada seorang anak laki-laki antara bapak dengan ibunya, beliau bersabda: \"Wahai anak kecil, ini ibumu dan ini bapakmu.\""},"2308":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا إِسْمَعِيلُ ابْنُ عُلَيَّةَ عَنْ عُثْمَانَ الْبَتِّيِّ عَنْ عَبْدِ الْحَمِيدِ بْنِ سَلَمَةَ عَنْ أَبِيهِ عَنْ جَدِّهِأَنَّ أَبَوَيْهِ اخْتَصَمَا إِلَى النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَحَدُهُمَا كَافِرٌ وَالْآخَرُ مُسْلِمٌ فَخَيَّرَهُ فَتَوَجَّهَ إِلَى الْكَافِرِ فَقَالَ اللَّهُمَّ اهْدِهِ فَتَوَجَّهَ إِلَى الْمُسْلِمِ فَقَضَى لَهُ بِهِ","id":"Telah menceritakan kepada kami [Abu Bakr bin Abu Syaibah] berkata, telah menceritakan kepada kami [Isma'il bin Ulayyah] dari [Utsman Al Batti] dari [Abdul Hamid bin Salamah] dari [Bapaknya] dari [Kakeknya] berkata, \"Kedua orang tuanya mengadukan kepada Nabi shallallahu 'alaihi wasallam, salah satunya kafir dan yang lain muslim. Nabi shallallahu 'alaihi wasallam lalu memberi pilihan kepadanya. (Anak itu) menghadap kepada yang masih kafir, beliau lalu berdoa, \"Ya Allah berilah petunjuk kepadanya (anak itu).\" Kemudian (anak itu) menghadap kepada yang muslim, hingga akhirnya beliau memutuskan bahwa anak itu mengikuti orang tuanya yang muslim.\""},"2309":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا خَالِدُ بْنُ مَخْلَدٍ حَدَّثَنَا كَثِيرُ بْنُ عَبْدِ اللَّهِ بْنِ عَمْرِو بْنِ عَوْفٍ عَنْ أَبِيهِ عَنْ جَدِّهِ قَالَسَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ الصُّلْحُ جَائِزٌ بَيْنَ الْمُسْلِمِينَ إِلَّا صُلْحًا حَرَّمَ حَلَالًا أَوْ أَحَلَّ حَرَامًا","id":"Telah menceritakan kepada kami [Abu Bakr bin Abu Syaibah] berkata, telah menceritakan kepada kami [Khalid bin Makhlad] berkata, telah menceritakan kepada kami [Katsir bin Abdullah bin Amru bin Auf] dari [Bapaknya] dari [Kakeknya] ia berkata, \"Aku mendengar Rasulullah shallallahu 'alaihi wasallam bersabda: \"Berdamai antara kaum muslimin itu boleh, kecuali damai untuk mengharamkan yang halal atau yang menghalalkan yang haram.\""},"2310":{"ar":"حَدَّثَنَا أَزْهَرُ بْنُ مَرْوَانَ حَدَّثَنَا عَبْدُ الْأَعْلَى حَدَّثَنَا سَعِيدٌ عَنْ قَتَادَةَ عَنْ أَنَسِ بْنِ مَالِكٍأَنَّ رَجُلًا كَانَ فِي عَهْدِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي عُقْدَتِهِ ضَعْفٌ وَكَانَ يُبَايِعُ وَأَنَّ أَهْلَهُ أَتَوْا النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالُوا يَا رَسُولَ اللَّهِ احْجُرْ عَلَيْهِ فَدَعَاهُ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَنَهَاهُ عَنْ ذَلِكَ فَقَالَ يَا رَسُولَ اللَّهِ إِنِّي لَا أَصْبِرُ عَنْ الْبَيْعِ فَقَال إِذَا بَايَعْتَ فَقُلْ هَا وَلَا خِلَابَةَ","id":"Telah menceritakan kepada kami [Azhar bin Marwan] berkata, telah menceritakan kepada kami [Abdul A'la] berkata, telah menceritakan kepada kami [Sa'id] dari [Qatadah] dari [Anas bin Malik] berkata, \"Pada masa Rasulullah shallallahu 'alaihi wasallam ada seorang lelaki yang janjinya tidak bisa dipegang, sementara ia adalah seorang pedagang. Keluarganya kemudian mendatangi Nabi shallallahu 'alaihi wasallam dan berkata, \"Wahai Rasulullah, cegahlah dia.\" Lalu nabi shallallahu 'alaihi wasallam memanggil orang itu dan melarangnya dari perbuatannya tersebut. Tetapi ia berkata, \"Wahai Rasulullah, aku tidak bisa menahan dari jual beli.\" Beliau bersabda: \"Apabila kamu berjual beli, maka katakanlah apa adanya dan jangan menipu.\""},"2311":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا عَبْدُ الْأَعْلَى عَنْ مُحَمَّدِ بْنِ إِسْحَقَ عَنْ مُحَمَّدِ بْنِ يَحْيَى بْنِ حَبَّانٍ قَالَهُوَ جَدِّي مُنْقِذُ بْنُ عَمْرٍو وَكَانَ رَجُلًا قَدْ أَصَابَتْهُ آمَّةٌ فِي رَأْسِهِ فَكَسَرَتْ لِسَانَهُ وَكَانَ لَا يَدَعُ عَلَى ذَلِكَ التِّجَارَةَ وَكَانَ لَا يَزَالُ يُغْبَنُ فَأَتَى النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَذَكَرَ ذَلِكَ لَهُ فَقَالَ لَهُ إِذَا أَنْتَ بَايَعْتَ فَقُلْ لَا خِلَابَةَ ثُمَّ أَنْتَ فِي كُلِّ سِلْعَةٍ ابْتَعْتَهَا بِالْخِيَارِ ثَلَاثَ لَيَالٍ فَإِنْ رَضِيتَ فَأَمْسِكْ وَإِنْ سَخِطْتَ فَارْدُدْهَا عَلَى صَاحِبِهَا","id":"Telah menceritakan kepada kami [Abu Bakr bin Abu Syaibah] berkata, telah menceritakan kepada kami [Abdul A'la] dari [Muhammad bin Ishaq] dari [Muhammad bin Yahya bin Hibban] ia berkata, \"Kakekku, Munqid bin Amru adalah seorang laki-laki yang tertimpa cacat di kepalanya dan lisannya pecah. Ia tidak mau meninggalkan perniagaannya meskipun dalam kondisi seperti itu, bahkan ia sering dibohongi. Maka ia datang menemui Nabi shallallahu 'alaihi wasallam dan menceritakan kondisinya tersebut, beliau lalu berkata kepadanya: \"Apabila kamu menjual maka katakanlah dengan jujur dan jangan menipu. Jika kamu membeli sesuatu maka engkau mempunyai hal pilih selama tiga hari, jika kamu rela maka ambillah, tetapi jika tidak maka kembalikan kepada pemiliknya.\""},"2312":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا شَبَابَةُ حَدَّثَنَا اللَّيْثُ بْنُ سَعْدٍ عَنْ بُكَيْرِ بْنِ عَبْدِ اللَّهِ بْنِ الْأَشَجِّ عَنْ عِيَاضِ بْنِ عَبْدِ اللَّهِ بْنِ سَعْدٍ عَنْ أَبِي سَعِيدٍ الْخُدْرِيِّ قَالَأُصِيبَ رَجُلٌ فِي عَهْدِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي ثِمَارٍ ابْتَاعَهَا فَكَثُرَ دَيْنُهُ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ تَصَدَّقُوا عَلَيْهِ فَتَصَدَّقَ النَّاسُ عَلَيْهِ فَلَمْ يَبْلُغْ ذَلِكَ وَفَاءَ دَيْنِهِ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ خُذُوا مَا وَجَدْتُمْ وَلَيْسَ لَكُمْ إِلَّا ذَلِكَ يَعْنِي الْغُرَمَاءَ","id":"Telah menceritakan kepada kami [Abu Bakr bin Abu Syaibah] berkata, telah menceritakan kepada kami [Syababah] berkata, telah menceritakan kepada kami [Al Laits bin Sa'd] dari [Bukair bin Abdullah Al Asyaj] dari [Iyadl bin Abdullah bin Sa'd] dari [Abu Sa'id Al Khudri] ia berkata, \"Pada masa Rasulullah shallallahu 'alaihi wasallam ada seorang laki-laki yang bangkrut karena buah-buahan yang ia jual rusak hingga hutangnya menumpuk. Rasulullah shallallahu 'alaihi wasallam lalu bersabda: \"Bersedekahlah kalian kepadanya.\" Orang-orang pun bersedekah kepadanya, namun itu semua belum cukup untuk menutup semua hutangnya. Maka Rasulullah shallallahu 'alaihi wasallam bersabda: 'Ambillah apa yang kalian dapatkan, dan kalian tidak punya hak apapun selain itu.' (Yakni kepada para pemilik modal).\""},"2313":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ بَشَّارٍ حَدَّثَنَا أَبُو عَاصِمٍ حَدَّثَنَا عَبْدُ اللَّهِ بْنُ مُسْلِمِ بْنِ هُرْمُزٍ عَنْ سَلَمَةَ الْمَكِّيِّ عَنْ جَابِرِ بْنِ عَبْدِ اللَّهِأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ خَلَعَ مُعَاذَ بْنَ جَبَلٍ مِنْ غُرَمَائِهِ ثُمَّ اسْتَعْمَلَهُ عَلَى الْيَمَنِفَقَالَ مُعَاذٌ إِنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ اسْتَخْلَصَنِي بِمَالِي ثُمَّ اسْتَعْمَلَنِي","id":"Telah menceritakan kepada kami [Muhammad bin Basysyar] berkata, telah menceritakan kepada kami [Abu 'Ashim] berkata, telah menceritakan kepada kami [Abdullah bin Muslim bin Hurmuz] dari [Salamah Al Makki] dari [Jabir bin Abdullah] berkata, \"Rasulullah shallallahu 'alaihi wasallam membebaskan Mu'adz bin Jabal dari orang-orang yang menghutanginya, kemudian beliau memperkerjakannya di Yaman. [Mu'adz] berkata, \"Sesungguhnya Rasulullah shallallahu 'alaihi wasallam membebaskanku dengan hartaku, kemudian beliau memperkerjakanku.\""},"2314":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا سُفْيَانُ بْنُ عُيَيْنَةَ ح و حَدَّثَنَا مُحَمَّدُ بْنُ رُمْحٍ أَنْبَأَنَا اللَّيْثُ بْنُ سَعْدٍ جَمِيعًا عَنْ يَحْيَى بْنِ سَعِيدٍ عَنْ أَبِي بَكْرِ بْنِ مُحَمَّدِ بْنِ عَمْرِو بْنِ حَزْمٍ عَنْ عُمَرَ بْنِ عَبْدِ الْعَزِيزِ عَنْ أَبِي بَكْرِ بْنِ عَبْدِ الرَّحْمَنِ بْنِ الْحَارِثِ بْنِ هِشَامٍ عَنْ أَبِي هُرَيْرَةَ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَنْ وَجَدَ مَتَاعَهُ بِعَيْنِهِ عِنْدَ رَجُلٍ قَدْ أَفْلَسَ فَهُوَ أَحَقُّ بِهِ مِنْ غَيْرِهِ","id":"telah menceritakan kepada kami [Abu Bakr bin Abu Syaibah] berkata, telah menceritakan kepada kami [Sufyan bin Uyainah]. (Dalam jalur lain disebutkan) Telah menceritakan kepada kami [Muhammad bin Rumh] berkata, telah memberitakan kepada kami [Al Laits bin Sa'd] semuanya dari [Yahya bin Sa'id] dari [Abu Bakr bin Muhammad bin Amru bin Hazm] dari [Umar bin Abdul Aziz] dari [Abu Bakr bin 'Abdurrahman Ibnul Harits dari Hisyam] dari [Abu Hurairah] ia berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Barangsiapa mendapatkan hartanya ada pada seorang laki-laki yang jatuh bangkrut, maka ia (pemilik modal) yang paling berhak atas harta tersebut dari selainnya.\""},"2315":{"ar":"حَدَّثَنَا هِشَامُ بْنُ عَمَّارٍ حَدَّثَنَا إِسْمَعِيلُ بْنُ عَيَّاشٍ عَنْ مُوسَى بْنِ عُقْبَةَ عَنْ الزُّهْرِيِّ عَنْ أَبِي بَكْرِ بْنِ عَبْدِ الرَّحْمَنِ بْنِ الْحَارِثِ بْنِ هِشَامٍ عَنْ أَبِي هُرَيْرَةَأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ أَيُّمَا رَجُلٍ بَاعَ سِلْعَةً فَأَدْرَكَ سِلْعَتَهُ بِعَيْنِهَا عِنْدَ رَجُلٍ وَقَدْ أَفْلَسَ وَلَمْ يَكُنْ قَبَضَ مِنْ ثَمَنِهَا شَيْئًا فَهِيَ لَهُ وَإِنْ كَانَ قَبَضَ مِنْ ثَمَنِهَا شَيْئًا فَهُوَ أُسْوَةٌ لِلْغُرَمَاءِ","id":"Telah menceritakan kepada kami [Hisyam bin Ammar] berkata, telah menceritakan kepada kami [Isma'il bin Ayyasy] dari [Musa bin Uqbah] dari [Az Zuhri] dari [Abu Bakr bin 'Abdurrahman Ibnul Harits bin Hisyam] dari [Abu Hurairah] bahwa Nabi shallallahu 'alaihi wasallam bersabda: \"Lelaki mana saja yang menjual barang kemudian ia mendapati barangnya masih ada pada seseorang yang bangkrut, sementara ia belum menerima uang pembayarannya, maka barang tersebut menjadi haknya. Jika ia telah memegang uang pembayarannya maka ia seperti pemilik hutang.\""},"2316":{"ar":"حَدَّثَنَا إِبْرَاهِيمُ بْنُ الْمُنْذِرِ الْحِزَامِيُّ وَعَبْدُ الرَّحْمَنِ بْنُ إِبْرَاهِيمَ الدِّمَشْقِيُّ قَالَا حَدَّثَنَا ابْنُ أَبِي فُدَيْكٍ عَنْ ابْنِ أَبِي ذِئْبٍ عَنْ أَبِي الْمُعْتَمِرِ بْنِ عَمْرِو بْنِ رَافِعٍ عَنْ ابْنِ خَلْدَةَ الزُّرَقِيِّ وَكَانَ قَاضِيًا بِالْمَدِينَةِ قَالَجِئْنَا أَبَا هُرَيْرَةَ فِي صَاحِبٍ لَنَا قَدْ أَفْلَسَ فَقَالَ هَذَا الَّذِي قَضَى فِيهِ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَيُّمَا رَجُلٍ مَاتَ أَوْ أَفْلَسَ فَصَاحِبُ الْمَتَاعِ أَحَقُّ بِمَتَاعِهِ إِذَا وَجَدَهُ بِعَيْنِهِ","id":"Telah menceritakan kepada kami [Ibrahim Ibnul Mundzir Al Hizami] dan ['Abdurrahman bin Ibrahim Ad Dimasyqi] keduanya berkata; telah menceritakan kepada kami [Ibnu Abu Fudaik] dari [Ibnu Abu Dzi`b] dari [Abu Al Mu'tamir bin Amru bin Rafi'] dari [Ibnu Khaldah Az Zuraqi] -ia adalah seorang hakim di Madinah- ia berkata, \"Kami mendatangi [Abu Hurairah] untuk mengadukan pengelola harta kami yang bangkrut, maka ia berkata, \"Inilah yang pernah diberi putuskan oleh Nabi shallallahu 'alaihi wasallam, bahwa laki-laki mana saja yang meninggal atau bangkrut, maka pemilik barang lebih berhak dengan barang miliknya jika ia mendapatinya masih ada.\""},"2317":{"ar":"حَدَّثَنَا عَمْرُو بْنُ عُثْمَانَ بْنِ سَعِيدِ بْنِ كَثِيرِ بْنِ دِينَارٍ الْحِمْصِيُّ حَدَّثَنَا الْيَمَانُ بْنُ عَدِيٍّ حَدَّثَنِي الزُّبَيْدِيُّ مُحَمَّدُ بْنُ الْوَلِيدِ عَنْ الزُّهْرِيِّ عَنْ أَبِي سَلَمَةَ عَنْ أَبِي هُرَيْرَةَ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَيُّمَا امْرِئٍ مَاتَ وَعِنْدَهُ مَالُ امْرِئٍ بِعَيْنِهِ اقْتَضَى مِنْهُ شَيْئًا أَوْ لَمْ يَقْتَضِ فَهُوَ أُسْوَةٌ لِلْغُرَمَاءِ","id":"Telah menceritakan kepada kami [Amru bin Utsman bin Sa'id bin Katsir bin Dinar Al Himshi] berkata, telah menceritakan kepada kami [Al Yaman bin Adi] berkata, telah menceritakan kepadaku [Az Zubaidi Muhammad Ibnul Walid] dari [Az Zuhri] dari [Abu Salamah] dari [Abu Hurairah] ia berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Siapa pun orangnya yang meninggal sementara ia memegang harta milik orang lain, baik ia telah memberikan sesuatu darinya atau belum, maka dia (pemilik harta) seperti pemilik hutang.\""},"2318":{"ar":"حَدَّثَنَا عُثْمَانُ بْنُ أَبِي شَيْبَةَ وَعَمْرُو بْنُ رَافِعٍ قَالَا حَدَّثَنَا جَرِيرٌ عَنْ مَنْصُورٍ عَنْ إِبْرَاهِيمَ عَنْ عَبِيدَةَ السَّلْمَانِيِّ قَالَ قَالَ عَبْدُ اللَّهِ بْنُ مَسْعُودٍسُئِلَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَيُّ النَّاسِ خَيْرٌ قَالَ قَرْنِي ثُمَّ الَّذِينَ يَلُونَهُمْ ثُمَّ الَّذِينَ يَلُونَهُمْ ثُمَّ يَجِيءُ قَوْمٌ تَبْدُرُ شَهَادَةُ أَحَدِهِمْ يَمِينَهُ وَيَمِينُهُ شَهَادَتَهُ","id":"Telah menceritakan kepada kami [Utsman bin Abu Syaibah] dan [Amru bin Rafi'] keduanya berkata; telah menceritakan kepada kami [Jarir] dari [Manshur] dari [Ibrahim] dari [Abidah As Salmani] berkata; [Abdullah bin Mas'ud] berkata; Rasulullah shallallahu 'alaihi wasallam pernah ditanya, \"Siapa manusia yang paling baik?\" beliau menjawab: \"Orang yang hidup dimasaku, kemudian orang-orang setelahnya, kemudian orang-orang setelahnya, kemudian akan datang suatu kaum yang persaksian salah seorang dari mereka mendahului sumpahnya, dan sumpahnya mendahului persaksiannya.\""},"2319":{"ar":"حَدَّثَنَا عَبْدُ اللَّهِ بنُ الْجَرَّاحِ حَدَّثَنَا جَرِيرٌ عَنْ عَبْدِ الْمَلِكِ بْنِ عُمَيْرٍ عَنْ جَابِرِ بْنِ سَمُرَةَ قَالَخَطَبَنَا عُمَرُ بْنُ الْخَطَّابِ بِالْجَابِيَةِ فَقَالَ إِنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَامَ فِينَا مِثْلَ مُقَامِي فِيكُمْ فَقَالَ احْفَظُونِي فِي أَصْحَابِي ثُمَّ الَّذِينَ يَلُونَهُمْ ثُمَّ الَّذِينَ يَلُونَهُمْ ثُمَّ يَفْشُو الْكَذِبُ حَتَّى يَشْهَدَ الرَّجُلُ وَمَا يُسْتَشْهَدُ وَيَحْلِفَ وَمَا يُسْتَحْلَفُ","id":"Telah menceritakan kepada kami [Abdullah Ibnul Jarrah] berkata, telah menceritakan kepada kami [Jarir] dari [Abdul Malik bin Umair] dari [Jabir bin Samurah] ia berkata; [Umar Ibnul Khtaththab] berkhutbah di Jabiah, ia berkata, \"Rasulullah shallallahu 'alaihi wasallam pernah berdiri di hadapan kami sebagaimana aku berdiri di hadapan kalian, lalu beliau bersabda: \"Jagalah (hak) sahabatku, kemudian orang-orang setelah mereka, kemudian orang-orang setelah mereka. Setelah itu akan menyebar kedustaan, hingga seorang laki-laki bersaksi tanpa diminta untuk bersaksi, dan bersumpah tanpa diminta untuk bersumpah.\""},"2320":{"ar":"حَدَّثَنَا عَلِيُّ بْنُ مُحَمَّدٍ وَمُحَمَّدُ بْنُ عَبدِ الرَّحْمَنِ الْجُعْفِيُّ قَالَا حَدَّثَنَا زَيْدُ بْنُ الْحُبَابِ الْعُكْلِيُّ أَخْبَرَنِي أُبَيُّ بْنُ عَبَّاسِ بْنِ سَهْلِ بْنِ سَعْدٍ السَّاعِدِيُّ حَدَّثَنِي أَبُو بَكْرِ بْنُ عَمْرِو بْنِ حَزْمٍ حَدَّثَنِي مُحَمَّدُ بْنُ عَبْدِ اللَّهِ بْنِ عَمْرِو بْنِ عُثْمَانَ بْنِ عَفَّانَ حَدَّثَنِي خَارِجَةُ بْنُ زَيْدِ بْنِ ثَابِتٍ أَخْبَرَنِي عَبْدُ الرَّحْمَنِ بْنُ أَبِي عَمْرَةَ الْأَنْصَارِيُّ أَنَّهُ سَمِعَ زَيْدَ بْنَ خَالِدٍ الْجُهَنِيَّ يَقُولُإِنَّهُ سَمِعَ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ خَيْرُ الشُّهُودِ مَنْ أَدَّى شَهَادَتَهُ قَبْلَ أَنْ يُسْأَلَهَا","id":"Telah menceritakan kepada kami [Ali bin Muhammad] dan [Muhammad bin 'Abdurrahman Al Ju'fi] keduanya berkata; telah menceritakan kepada kami [Zaid Ibnul Hubab Al 'Ukli] berkata, telah mengabarkan kepadaku [Ubai bin Abbas bin Sahl bin Sa'd As Sa'idi] berkata, telah menceritakan kepadaku [Abu Bakr bin Amru bin Hazm] berkata, telah menceritakan kepadaku [Muhammad bin Abdullah bin Amru bin Utsman bin Affan] berkata, telah menceritakan kepadaku [Kharijah bin Zaid bin Tsabit] berkata, telah menceritakan kepadaku ['Abdurrahman bin Abu Amrah Al Anshari] bahwasanya ia mendengar [Zaid bin Khalid Al Juhani] ia berkata, \"Bahwasanya ia mendengar Rasulullah shallallahu 'alaihi wasallam bersabda: \"Sebaik-baik pemberi saksi adalah orang yang memberikan persaksiannya sebelum diminta.\""},"2321":{"ar":"حَدَّثَنَا عُبَيْدُ اللَّهِ بْنُ يُوسُفَ الْجُبَيْرِيُّ وَجَمِيلُ بْنُ الْحَسَنِ الْعَتَكِيُّ قَالَا حَدَّثَنَا مُحَمَّدُ بْنُ مَرْوَانَ الْعِجْلِيُّ حَدَّثَنَا عَبْدُ الْمَلِكِ بْنُ أَبِي نَضْرَةَ عَنْ أَبِيهِ عَنْ أَبِي سَعِيدٍ الْخُدْرِيِّ قَالَتَلَا هَذِهِ الْآيَةَ{ يَا أَيُّهَا الَّذِينَ آمَنُوا إِذَا تَدَايَنْتُمْ بِدَيْنٍ إِلَى أَجَلٍ مُسَمًّى حَتَّى بَلَغَ فَإِنْ أَمِنَ بَعْضُكُمْ بَعْضًا }فَقَالَ هَذِهِ نَسَخَتْ مَا قَبْلَهَا","id":"Telah menceritakan kepada kami [Ubaidullah bin Yusuf Al Jubairi] dan [Jamil bin Al Hasan Al Atiki] keduanya berkata; telah menceritakan kepada kami [Muhammad bin Marwan Al Ijli] berkata, telah menceritakan kepada kami [Abdul Malik bin An Nadlrah] dari [Bapaknya] dari [Abu Sa'id Al Khudri] ia berkata ketika dia membaca ayat ini: ' Wahai orang-orang yang beriman, apabila kalian berhutang piutang untuk waktu tertentu, hendaklah kalian menuliskannya, hingga ayat: ' Akan tetapi jika sebagian kalian percaya kepada sebagian yang lain', ia mengatakan, \"Ayat ini menghapus ayat yang sebelumnya.\""},"2322":{"ar":"حَدَّثَنَا أَيُّوبُ بْنُ مُحَمَّدٍ الرَّقِّيُّ حَدَّثَنَا مُعَمَّرُ بْنُ سُلَيْمَانَ ح و حَدَّثَنَا مُحَمَّدُ بْنُ يَحْيَى حَدَّثَنَا يَزِيدُ بْنُ هَارُونَ قَالَا حَدَّثَنَا حَجَّاجُ بْنُ أَرْطَاةَ عَنْ عَمْرِو بْنِ شُعَيْبٍ عَنْ أَبِيهِ عَنْ جَدِّهِ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَا تَجُوزُ شَهَادَةُ خَائِنٍ وَلَا خَائِنَةٍ وَلَا مَحْدُودٍ فِي الْإِسْلَامِ وَلَا ذِي غِمْرٍ عَلَى أَخِيهِ","id":"Telah menceritakan kepada kami [Ayyub bin Muhammad Ar Raqqi] berkata, telah menceritakan kepada kami [Ma'mar bin Sulaiman]. (Dalam jalur lain disebutkan) Telah menceritakan kepada kami [Muhammad bin Yahya] berkata, telah menceritakan kepada kami [Yazid bin Harun] keduanya berkata; telah menceritakan kepada kami [Hajjaj bin Arthah] dari [Amru bin Syu'aib] dari [Bapaknya] dari [Kakeknya] ia berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Tidak berlaku persaksian orang yang berkhianat baik laki-laki maupun perempuan, tidak ada orang yang dihukum hudud dalam Islam, dan tidak ada permusuhan kepada saudaranya.\""},"2323":{"ar":"حَدَّثَنَا حَرْمَلَةُ بْنُ يَحْيَى حَدَّثَنَا عَبْدُ اللَّهِ بْنُ وَهْبٍ أَخْبَرَنِي نَافِعُ بْنُ يَزِيدَ عَنْ ابْنِ الْهَادِ عَنْ مُحَمَّدِ بْنِ عَمْرِو بْنِ عَطَاءٍ عَنْ عَطَاءِ بْنِ يَسَارٍ عَنْ أَبِي هُرَيْرَةَأَنَّهُ سَمِعَ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ لَا تَجُوزُ شَهَادَةُ بَدَوِيٍّ عَلَى صَاحِبِ قَرْيَةٍ","id":"Telah menceritakan kepada kami [Harmalah bin Yahya] berkata, telah menceritakan kepada kami [Abdullah bin Wahb] berkata, telah mengabarkan kepadaku [Nafi' bin Yazid] dari [Ibnu Al Had] dari [Muhammad bin Amru bin 'Atha] dari ['Atha bin Yasar] dari [Abu Hurairah] bahwasanya ia pernah mendengar Rasulullah shallallahu 'alaihi wasallam bersabda: \"Tidak boleh persaksian orang badui atas penduduk desa.\""},"2324":{"ar":"حَدَّثَنَا أَبُو مُصْعَبٍ الْمَدِينِيُّ أَحْمَدُ بْنُ عَبْدِ اللَّهِ الزُّهْرِيُّ وَيَعْقُوبُ بْنُ إِبْرَاهِيمَ الدَّوْرَقِيُّ قَالَا حَدَّثَنَا عَبْدُ الْعَزِيزِ بْنُ مُحَمَّدٍ الدَّرَاوَرْدِيُّ عَنْ رَبِيعَةَ بْنِ أَبِي عَبْدِ الرَّحْمَنِ عَنْ سُهَيْلِ بْنِ أَبِي صَالِحٍ عَنْ أَبِيهِ عَنْ أَبِي هُرَيْرَةَأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَضَى بِالْيَمِينِ مَعَ الشَّاهِدِ","id":"Telah menceritakan kepada kami [Abu Mush'ab Al Madini Ahmad bin Abdullah Az Zuhri] dan [Ya'qub bin Ibrahim Ad Dauraqqi] keduanya berkata; telah menceritakan kepada kami [Abdul Aziz bin Muhammad Ad Darawardi] dari [Rabi'ah bin Abu 'Abdurrahman] dari [Suhail bin Abu Shalih] dari [Bapaknya] dari [Abu Hurairah] berkata, \"Rasulullah shallallahu 'alaihi wasallam memutuskan bahwa sumpah harus ada saksi.\""},"2325":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ بَشَّارٍ حَدَّثَنَا عَبْدُ الْوَهَّابِ حَدَّثَنَا جَعْفَرُ بْنُ مُحَمَّدٍ عَنْ أَبِيهِ عَنْ جَابِرٍأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَضَى بِالْيَمِينِ مَعَ الشَّاهِدِ","id":"Telah menceritakan kepada kami [Muhammad bin Basysyar] berkata, telah menceritakan kepada kami [Abdul Wahhab] berkata, telah menceritakan kepada kami [Ja'far bin Muhammad] dari [Bapaknya] dari [Jabir] berkata, \"Nabi shallallahu 'alaihi wasallam memutuskan bahwa sumpah harus ada saksi.\""},"2326":{"ar":"حَدَّثَنَا أَبُو إِسْحَقَ الْهَرَوِيُّ إِبْرَاهِيمُ بْنُ عَبْدِ اللَّهِ بْنِ حَاتِمٍ حَدَّثَنَا عَبْدُ اللَّهِ بْنُ الْحَارِثِ الْمَخْزُومِيُّ حَدَّثَنَا سَيْفُ بْنُ سُلَيْمَانَ الْمَكِّيُّ أَخْبَرَنِي قَيْسُ بْنُ سَعْدٍ عَنْ عَمْرِو بْنِ دِينَارٍ عَنْ ابْنِ عَبَّاسٍ قَالَقَضَى رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِالشَّاهِدِ وَالْيَمِينِ","id":"Telah menceritakan kepada kami [Abu Ishaq Al Harawi Ibrahim bin Abdullah bin Hatim] berkata, telah menceritakan kepada kami [Abdullah bin Al Harits Al Makhzumi] berkata, telah menceritakan kepada kami [Saif bin Sulaiman Al Makki] berkata, telah mengabarkan kepadaku [Qais bin Sa'd] dari [Amru bn Dinar] dari [Ibnu Abbas] ia berkata, \"Rasulullah shallallahu 'alaihi wasallam memutuskan (dalam menyelesaikan suatu masalah) dengan adanya saksi dan sumpah.\""},"2327":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا يَزِيدُ بْنُ هَارُونَ أَنْبَأَنَا جُوَيْرِيَةُ بْنُ أَسْمَاءَ حَدَّثَنَا عَبْدُ اللَّهِ بْنُ يَزِيدَ مَوْلَى الْمُنْبَعِثِ عَنْ رَجُلٍ مِنْ أَهْلِ مِصْرَ عَنْ سُرَّقٍأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَجَازَ شَهَادَةَ الرَّجُلِ وَيَمِينَ الطَّالِبِ","id":"Telah menceritakan kepada kami [Abu Bakr bin Abu Syaibah] berkata, telah menceritakan kepada kami [Yazid bin Harun] berkata, telah memberitakan kepada kami [Juwairiyah bin Asma] berkata, telah menceritakan kepada kami [Abdullah bin Yazid] -mantan budak Al Munba'its- dari [seorang penduduk Mesir] dari [Surraq] berkata, \"Nabi shallallahu 'alaihi wasallam memperbolehkan persaksian seorang lelaki dan sumpah orang yang menuntut.\""},"2328":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا مُحَمَّدُ بْنُ عُبَيْدٍ حَدَّثَنَا سُفْيَانُ الْعُصْفُرِيُّ عَنْ أَبِيهِ عَنْ حَبِيبِ بْنِ النُّعْمَانِ الْأَسَدِيِّ عَنْ خُرَيْمِ بْنِ فَاتِكٍ الْأَسَدِيِّ قَالَصَلَّى النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ الصُّبْحَ فَلَمَّا انْصَرَفَ قَامَ قَائِمًا فَقَالَ عُدِلَتْ شَهَادَةُ الزُّورِ بِالْإِشْرَاكِ بِاللَّهِ ثَلَاثَ مَرَّاتٍ ثُمَّ تَلَا هَذِهِ الْآيَةَ{ وَاجْتَنِبُوا قَوْلَ الزُّورِ حُنَفَاءَ لِلَّهِ غَيْرَ مُشْرِكِينَ بِهِ }","id":"Telah menceritakan kepada kami [Abu Bakr bin Abu Syaibah] berkata, telah menceritakan kepada kami [Muhammad bin Ubaid] berkata, telah menceritakan kepada kami [Sufyan Al 'Ushfuri] dari [Bapaknya] dari [Habib An Nu'mani Al Asadi] dari [Khuraim bin Fatik Al Asadi] ia berkata, \"Nabi shallallahu 'alaihi wasallam melaksanakan shalat subuh, setelah selesai beliau berdiri dan bersabda: \"Persaksian palsu itu sama dengan syirik kepada Allah.\" Hal itu beliau ucapkan hingga tiga kali, setelah itu beliau membaca ayat: ' maka jauhilah olehmu berhala-berhala yang najis itu dan jauhilah perkataan-perkataan dusta. dengan ikhlas kepada Allah, tidak mempersekutukan sesuatu dengan Dia'. QS. Al Hajj: 30-31.\""},"2329":{"ar":"حَدَّثَنَا سُوَيْدُ بْنُ سَعِيدٍ حَدَّثَنَا مُحَمَّدُ بْنُ الْفُرَاتِ عَنْ مُحَارِبِ بْنِ دِثَارٍ عَنْ ابْنِ عُمَرَ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَنْ تَزُولَ قَدَمَا شَاهِدِ الزُّورِ حَتَّى يُوجِبَ اللَّهُ لَهُ النَّارَ","id":"Telah menceritakan kepada kami [Suwaid bin Sa'id] berkata, telah menceritakan kepada kami [Muhammad bin Al Furat] dari [Muharib bin Ditsar] dari [Ibnu Umar] ia berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Sekali-kali kedua kaki orang yang bersumpah palsu tidak akan bergeser hingga Allah memasukannya ke dalam neraka.\""},"2330":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ طَرِيفٍ حَدَّثَنَا أَبُو خَالِدٍ الْأَحْمَرُ عَنْ مُجَالِدٍ عَنْ عَامِرٍ عَنْ جَابِرِ بْنِ عَبْدِ اللَّهِأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَجَازَ شَهَادَةَ أَهْلِ الْكِتَابِ بَعْضِهِمْ عَلَى بَعْضٍ","id":"Telah menceritakan kepada kami [Muhammad bin Tharif] berkata, telah menceritakan kepada kami [Abu Khalid Al Ahmar] dari [Mujalid] dari [Amir] dari [Jabir bin Abdullah] berkata, \"Rasulullah shallallahu 'alaihi wasallam memperbolehkan persaksian ahli kitab sebagian mereka atas sebagian yang lain.\""},"2331":{"ar":"حَدَّثَنَا أَبُو بِشْرٍ بَكْرُ بْنُ خَلَفٍ حَدَّثَنَا يَزِيدُ بْنُ زُرَيْعٍ عَنْ دَاوُدَ بْنِ أَبِي هِنْدٍ عَنْ الشَّعْبِيِّ عَنْ النُّعْمَانِ بْنِ بَشِيرٍ قَالَانْطَلَقَ بِهِ أَبُوهُ يَحْمِلُهُ إِلَى النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ اشْهَدْ أَنِّي قَدْ نَحَلْتُ النُّعْمَانَ مِنْ مَالِي كَذَا وَكَذَا قَالَ فَكُلَّ بَنِيكَ نَحَلْتَ مِثْلَ الَّذِي نَحَلْتَ النُّعْمَانَ قَالَ لَا قَالَ فَأَشْهِدْ عَلَى هَذَا غَيْرِي قَالَ أَلَيْسَ يَسُرُّكَ أَنْ يَكُونُوا لَكَ فِي الْبِرِّ سَوَاءً قَالَ بَلَى قَالَ فَلَا إِذًا","id":"Telah menceritakan kepada kami [Abu Bisyr Bakr bin Khalaf] berkata, telah menceritakan kepada kami [Yazid bin Zurai'] dari [Dawud bin Abu Hind] dari [Asy Sya'bi] dari [An Nu'man bin Basyir] mengatakan bahwa bapaknya pernah mengajaknya menghadap Nabi shallallahu 'alaihi wasallam dan berkata, \"Saksikanlah, sesungguhnya aku telah memberi An Nu'man dari uangku sekian dan sekian! \" beliau bersabda: \"Apakah ini juga engkau lakukan untuk anakmu yang lain, sebagaimana yang engkau lakukan terhadap Nu'man?\" ia menjawab, \"Tidak.\" Beliau bersabda: \"Carilah orang lain untuk menjadi saksi.\" Kemudian beliau melanjutkan: \"Tidakkah engkau suka, jika kebaikan mereka untukmu juga sama?\" ia menjawab, \"Tentu.\" Beliau bersabda: \"Maka janganlah engkau lakukan hal itu.\""},"2332":{"ar":"حَدَّثَنَا هِشَامُ بْنُ عَمَّارٍ حَدَّثَنَا سُفْيَانُ عَنْ الزُّهْرِيِّ عَنْ حُمَيْدِ بْنِ عَبْدِ الرَّحْمَنِ وَمُحَمَّدِ بْنِ النُّعْمَانِ بْنِ بَشِيرٍ أَخْبَرَاهُ عَنْ النُّعْمَانِ بْنِ بَشِيرٍأَنَّ أَبَاهُ نَحَلَهُ غُلَامًا وَأَنَّهُ جَاءَ إِلَى النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يُشْهِدُهُ فَقَالَ أَكُلَّ وَلَدِكَ نَحَلْتَهُ قَالَ لَا قَالَ فَارْدُدْهُ","id":"Telah menceritakan kepada kami [Hisyam bin Ammar] berkata, telah menceritakan kepada kami [Sufyan] dari [Az Zuhri] dari [Humaid bin 'Abdurrahman] dan [Muhammad bin An Nu'man bin Basyir] keduanya telah mengabarkan kepadanya dari [An Nu'man bin Basyir] bahwa bapaknya memberikan seorang budak kepadanya, lalu bapaknya mengajak menemui Nabi shallallahu 'alaihi wasallam untuk menjadi saksi. Beliau lalu bersabda: \"Apakah semua anakmu engkau beri?\" ia menjawab, \"Tidak.\" Beliau bersabda: \"Kembalikanlah budak itu.\""},"2333":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ بَشَّارٍ وَأَبُو بَكْرِ بْنُ خَلَّادٍ الْبَاهِلِيُّ قَالَا حَدَّثَنَا ابْنُ أَبِي عَدِيٍّ عَنْ حُسَيْنٍ الْمُعَلِّمِ عَنْ عَمْرِو بْنِ شُعَيْبٍ عَنْ طَاوُسٍ عَنْ ابْنِ عَبَّاسٍ وَابْنِ عُمَرَيَرْفَعَانِ الْحَدِيثَ إِلَى النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ لَا يَحِلُّ لِلرَّجُلِ أَنْ يُعْطِيَ الْعَطِيَّةَ ثُمَّ يَرْجِعَ فِيهَا إِلَّا الْوَالِدَ فِيمَا يُعْطِي وَلَدَهُ","id":"Telah menceritakan kepada kami [Muhammad bin Basysyar] dan [Abu Bakr bin Khallad Al Bahili] keduanya berkata; telah menceritakan kepada kami [Ibnu Abu Adi] dari [Husain Al Mu'allim] dari [Amru bin Syu'aib] dari [Thawus] dari [Ibnu Abbas] dan [Ibnu Umar] keduanya memarfu'kan hadits tersebut kepada Nabi shallallahu 'alaihi wasallam, beliau bersabda: \"Tidak halal seorang laki-laki memberikan suatu pemberian kemudian diminta kembali, kecuali orang tua terhadap sesuatu yang ia berikan kepada anaknya.\""},"2334":{"ar":"حَدَّثَنَا جَمِيلُ بْنُ الْحَسَنِ حَدَّثَنَا عَبْدُ الْأَعْلَى حَدَّثَنَا سَعِيدٌ عَنْ عَامِرٍ الْأَحْوَلِ عَنْ عَمْرِو بْنِ شُعَيْبٍ عَنْ أَبِيهِ عَنْ جَدِّهِأَنَّ نَبِيَّ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ لَا يَرْجِعْ أَحَدُكُمْ فِي هِبَتِهِ إِلَّا الْوَالِدَ مِنْ وَلَدِهِ","id":"Telah menceritakan kepada kami [Jamil bin Al Hasan] berkata, telah menceritakan kepada kami [Abdul A'la] Telah menceritakan kepada kami [Sa'id] dari [Amir Al Ahwal] dari [Amru bin Syu'aib] dari [Bapaknya] dari [Kakeknya] bahwa Nabi Allah shallallahu 'alaihi wasallam bersabda: \"Janganlah salah seorang dari kalian mengambil kembali barang yang telah ia berikan, kecuali orang tua kepada anaknya.\""},"2335":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا يَحْيَى بْنُ زَكَرِيَّا بْنِ أَبِي زَائِدَةَ عَنْ مُحَمَّدِ بْنِ عَمْرٍو عَنْ أَبِي سَلَمَةَ عَنْ أَبِي هُرَيْرَةَ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَا عُمْرَى فَمَنْ أُعْمِرَ شَيْئًا فَهُوَ لَهُ","id":"Telah menceritakan kepada kami [Abu Bakr bin Abu Syaibah] berkata, telah menceritakan kepada kami [Yahya bin Zakaria bin Abu Za`idah] dari [Muhammad bin Amru] dari [Abu Salamah] dari [Abu Hurairah] ia berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Tidak ada umra, maka barangsiapa diberi umra atas sesuatu maka ia (sesuatu) menjadi miliknya.\" "},"2336":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ رُمْحٍ أَنْبَأَنَا اللَّيْثُ بْنُ سَعْدٍ عَنْ ابْنِ شِهَابٍ عَنْ أَبِي سَلَمَةَ عَنْ جَابِرٍ قَالَسَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ مَنْ أَعْمَرَ رَجُلًا عُمْرَى لَهُ وَلِعَقِبِهِ فَقَدْ قَطَعَ قَوْلُهُ حَقَّهُ فِيهَا فَهِيَ لِمَنْ أُعْمِرَ وَلِعَقِبِهِ","id":"Telah menceritakan kepada kami [Muhammad bin Rumh] berkata, telah memberitakan kepada kami [Al Laits bin Sa'd] dari [Ibnu Syihab] dari [Abu Salamah] dari [Jabir] ia berkata, \"Aku mendengar Rasulullah shallallahu 'alaihi wasallam bersabda: \"Barangsiapa memberikan umra untuk seseorang dan keturunannya, sungguh ucapannya tersebut memutus haknya untuk mendapatkan umra itu kembali. Maka umra tersebut akan menjadi milik seseorang yang telah diserahi dan keturunannya.\""},"2337":{"ar":"حَدَّثَنَا هِشَامُ بْنُ عَمَّارٍ حَدَّثَنَا سُفْيَانُ عَنْ عَمْرِو بْنِ دِينَارٍ عَنْ طَاوُسٍ عَنْ حُجْرٍ الْمَدَرِيِّ عَنْ زَيْدِ بْنِ ثَابِتٍأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ جَعَلَ الْعُمْرَى لِلْوَارِثِ","id":"Telah menceritakan kepada kami [Hisyam bin Ammar] berkata, telah menceritakan kepada kami [Sufyan] dari [Amru bin Dinar] dari [Thawus] dari [Hujr Al Madari] dari [Zaid bin Tsabit] berkata, \"Nabi shallallahu 'alaihi wasallam menetapkan bahwa umra bisa dimiliki oleh ahli warits.\""},"2338":{"ar":"حَدَّثَنَا إِسْحَقُ بْنُ مَنْصُورٍ أَنْبَأَنَا عَبْدُ الرَّزَّاقِ أَنْبَأَنَا ابْنُ جُرَيْجٍ عَنْ عَطَاءٍ عَنْ حَبِيبِ بْنِ أَبِي ثَابِتٍ عَنْ ابْنِ عُمَرَ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَا رُقْبَى فَمَنْ أُرْقِبَ شَيْئًا فَهُوَ لَهُ حَيَاتَهُ وَمَمَاتَهُقَالَ وَالرُّقْبَى أَنْ يَقُولَ هُوَ لِلْآخَرِ مِنِّي وَمِنْكَ مَوْتًا","id":"Telah menceritakan kepada kami [Ishaq bin Manshur] berkata, telah mengabarkan kepada kami [Abdurrazaq] berkata, telah memberitakan kepada kami [Ibnu Juraij] dari ['Atha] dari [Habib bin Abu Tsabit] dari [Ibnu Umar] ia berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Tidak ada ruqba, barangsiapa diberi ruqba maka ia berhak memilikinya baik dimasa hidup dan setelah matinya.\" Ibnu Umar menjelaskan: \"Ruqba adalah Seseorang mengatakan, 'Ia akan menjadi milik orang lain yang telah meninggal antara aku dan kamu'.\""},"2339":{"ar":"حَدَّثَنَا عَمْرُو بْنُ رَافِعٍ حَدَّثَنَا هُشَيْمٌ ح و حَدَّثَنَا عَلِيُّ بْنُ مُحَمَّدٍ حَدَّثَنَا أَبُو مُعَاوِيَةَ قَالَا حَدَّثَنَا دَاوُدُ عَنْ أَبِي الزُّبَيْرِ عَنْ جَابِرِ بْنِ عَبْدِ اللَّهِ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ الْعُمْرَى جَائِزَةٌ لِمَنْ أُعْمِرَهَا وَالرُّقْبَى جَائِزَةٌ لِمَنْ أُرْقِبَهَا","id":"Telah menceritakan kepada kami [Amru bin Rafi'] berkata, telah menceritakan kepada kami [Husyaim]. (Dalam jalur lain disebutkan) Telah menceritakan kepada kami [Ali bin Muhammad] berkata, telah menceritakan kepada kami [Abu Mu'awiyah] keduanya berkata; telah menceritakan kepada kami [Dawud] dari [Abu Az Zubair] dari [Jabir bin Abdullah] ia berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Umra boleh bagi orang yang diberi, dan ruqba boleh bagi orang yang diberi.\" "},"2340":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا أَبُو أُسَامَةَ عَنْ عَوْفٍ عَنْ خِلَاسٍ عَنْ أَبِي هُرَيْرَةَ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِنَّ مَثَلَ الَّذِي يَعُودُ فِي عَطِيَّتِهِ كَمَثَلِ الْكَلْبِ أَكَلَ حَتَّى إِذَا شَبِعَ قَاءَ ثُمَّ عَادَ فِي قَيْئِهِ فَأَكَلَهُ","id":"Telah menceritakan kepada kami [Abu Bakr bin Abu Syaibah] berkata, telah menceritakan kepada kami [Abu Usamah] dari [Auf] dari [Khilas] dari [Abu Hurairah] ia berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Permisalan orang yang meminta kembali sesuatu yang telah ia berikan seperti seekor anjing yang makan, jika kenyang ia memuntahkannya kemudian kembali memakannya.\""},"2341":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ بَشَّارٍ وَمُحَمَّدُ بْنُ الْمُثَنَّى قَالَا حَدَّثَنَا مُحَمَّدُ بْنُ جَعْفَرٍ حَدَّثَنَا شُعْبَةُ قَالَ سَمِعْتُ قَتَادَةَ يُحَدِّثُ عَنْ سَعِيدِ بْنِ الْمُسَيَّبِ عَنْ ابْنِ عَبَّاسٍ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ الْعَائِدُ فِي هِبَتِهِ كَالْعَائِدِ فِي قَيْئِهِ","id":"Telah menceritakan kepada kami [Muhammad bin Basysyar] dan [Muhammad bin Al Mutsanna] keduanya berkata; telah menceritakan kepada kami [Muhammad bin Ja'far] berkata, telah menceritakan kepada kami [Syu'bah] ia berkata; Aku mendengar [Qatadah] menceritakan dari [Sa'id bin Al Musayyab] dari [Ibnu Abbas] ia berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Orang yang kembali meminta pemberiannya seperti orang yang memakan kembali muntahannya.\""},"2342":{"ar":"حَدَّثَنَا أَحْمَدُ بْنُ عَبْدِ اللَّهِ بْنِ يُوسُفَ الْعَرْعَرِيُّ حَدَّثَنَا يَزِيدُ بْنُ أَبِي حَكِيمٍ حَدَّثَنَا الْعُمَرِيُّ عَنْ زَيْدِ بْنِ أَسْلَمَ عَنْ ابْنِ عُمَرَعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ الْعَائِدُ فِي هِبَتِهِ كَالْكَلْبِ يَعُودُ فِي قَيْئِهِ","id":"Telah menceritakan kepada kami [Ahmad bin Abdullah bin Yusuf Al 'Ar'ari] berkata, telah menceritakan kepada kami [Yazid bin Abu Hakim] berkata, telah menceritakan kepada kami [Al 'Umari] dari [Zaid bin Aslam] dari [Ibnu Umar] dari Nabi shallallahu 'alaihi wasallam bersabda: \"Orang yang meminta kembali pemberiannya bagaikan anjing yang mengambil kembali muntahannya.\""},"2343":{"ar":"حَدَّثَنَا عَلِيُّ بْنُ مُحَمَّدٍ وَمُحَمَّدُ بْنُ إِسْمَعِيلَ قَالَا حَدَّثَنَا وَكِيعٌ حَدَّثَنَا إِبْرَاهِيمُ بْنُ إِسْمَعِيلَ بْنِ مُجَمِّعِ بْنِ جَارِيَةَ الْأَنْصَارِيُّ عَنْ عَمْرِو بْنِ دِينَارٍ عَنْ أَبِي هُرَيْرَةَقَالَ قَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ الرَّجُلُ أَحَقُّ بِهِبَتِهِ مَا لَمْ يُثَبْ مِنْهَا","id":"Telah menceritakan kepada kami [Ali bin Muhammad] dan [Muhammad bin Ismai] keduanya berkata; telah menceritakan kepada kami [Waki'] berkata, telah menceritakan kepada kami [Ibrahim bin Isma'il bin Mujammi' bin Jariyah Al Anshar] dari [Amru bin Dinar] dari [Abu Hurairah] ia berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Seseorang lebih berhak atas pemberiannya selagi ia menguasainya (belum memberikannya kepada yang lain).\""},"2344":{"ar":"حَدَّثَنَا أَبُو يُوسُفَ الرَّقِّيُّ مُحَمَّدُ بْنُ أَحْمَدَ الصَّيْدَلَانِيُّ حَدَّثَنَا مُحَمَّدُ بْنُ سَلَمَةَ عَنْ الْمُثَنَّى بْنِ الصَّبَّاحِ عَنْ عَمْرِو بْنِ شُعَيْبٍ عَنْ أَبِيهِ عَنْ جَدِّهِأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ فِي خُطْبَةٍ خَطَبَهَا لَا يَجُوزُ لِامْرَأَةٍ فِي مَالِهَا إِلَّا بِإِذْنِ زَوْجِهَا إِذَا هُوَ مَلَكَ عِصْمَتَهَا","id":"Telah menceritakan kepada kami [Abu Yusuf Ar Raqqi Muhammad bin Ahmad Ash Shaidalani] berkata, telah menceritakan kepada kami [Muhammad bin Salamah] dari [Al Mutsanna bin Ash Shabbah] dari [Amru bin Syu'aib] dari [Bapaknya] dari [Kakeknya] bahwa Rasulullah shallallahu 'alaihi wasallam bersabda dalam khutbahnya: \"Seorang wanita tidak boleh menggunakan uang miliknya tanpa izin suaminya, jika suaminya telah sah menikahinya.\""},"2345":{"ar":"حَدَّثَنَا حَرْمَلَةُ بْنُ يَحْيَى حَدَّثَنَا عَبْدُ اللَّهِ بْنُ وَهْبٍ أَخْبَرَنِي اللَّيْثُ بْنُ سَعْدٍ عَنْ عَبْدِ اللَّهِ بْنِ يَحْيَى رَجُلٌ مِنْ وَلَدِ كَعْبِ بْنِ مَالِكٍ عَنْ أَبِيهِ عَنْ جَدِّهِأَنَّ جَدَّتَهُ خَيْرَةَ امْرَأَةَ كَعْبِ بْنِ مَالِكٍ أَتَتْ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِحُلِيٍّ لَهَا فَقَالَتْ إِنِّي تَصَدَّقْتُ بِهَذَا فَقَالَ لَهَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَا يَجُوزُ لِلْمَرْأَةِ فِي مَالِهَا إِلَّا بِإِذْنِ زَوْجِهَا فَهَلْ اسْتَأْذَنْتِ كَعْبًا قَالَتْ نَعَمْ فَبَعَثَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِلَى كَعْبِ بْنِ مَالِكٍ زَوْجِهَا فَقَالَ هَلْ أَذِنْتَ لِخَيْرَةَ أَنْ تَتَصَدَّقَ بِحُلِيِّهَا فَقَال نَعَمْ فَقَبِلَهُ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مِنْهَا","id":"Telah menceritakan kepada kami [Harmalah bi Yahya] berkata, telah menceritakan kepada kami [Abdullah bin Wahb] berkata, telah mengabarkan kepadaku [Al Laits bin Sa'd] dari [Abdullah bin Yahya] -seorang lelaki anak dari Ka'b bin Malik- dari [Bapaknya] dari [Kakeknya] bahwa neneknya Khairah -istri Ka'b bin Malik- datang menemui Rasulullah shallallahu 'alaihi wasallam dengan membawa perhiasannya, lalu ia berkata, \"Aku ingin mensedekahkan perhiasan ini.\" Rasulullah shallallahu 'alaihi wasallam lalu bersabda kepadanya: \"Seorang istri tidak boleh mensedekahkan hartanya kecuali atas izin suaminya. Apakah kamu sudah meminta izin kepada Ka'b?\" ia menjawab: \"Ya.\" Rasulullah shallallahu 'alaihi wasallam kemudian mengutus seseorang menemui Ka'b bin Malik suaminya untuk menanyakan: \"Apakah kamu sudah mengizinkan Khairah untuk bersedekah dengan perhiasan miliknya?\" Ka'b menjawab, \"Ya.\" Akhirnya Rasulullah shallallahu 'alaihi wasallam pun menerima sedekahnya.\""},"2346":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا وَكِيعٌ حَدَّثَنَا هِشَامُ بْنُ سَعْدٍ عَنْ زَيْدِ بْنِ أَسْلَمَ عَنْ أَبِيهِ عَنْ عُمَرَ بْنِ الْخَطَّابِأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ لَا تَعُدْ فِي صَدَقَتِكَ","id":"Telah menceritakan kepada kami [Abu Bakr bin Abu Syaibah] berkata, telah menceritakan kepada kami [Waki'] berkata, telah menceritakan kepada kami [Hisyam bin Sa'd] dari [Zaid bin Aslam] dari [Bapaknya] dari [Umar bin Al Khaththab] bahwa Rasulullah shallallahu 'alaihi wasallam bersabda: \"Janganlah engkau minta kembali sedekahmu.\""},"2347":{"ar":"حَدَّثَنَا عَبْدُ الرَّحْمَنِ بْنُ إِبْرَاهِيمَ الدِّمَشْقِيُّ حَدَّثَنَا الْوَلِيدُ بْنُ مُسْلِمٍ حَدَّثَنَا الْأَوْزَاعِيُّ حَدَّثَنِي أَبُو جَعْفَرٍ مُحَمَّدُ بْنُ عَلِيٍّ حَدَّثَنِي سَعِيدُ بْنُ الْمُسَيَّبِ حَدَّثَنِي عَبْدُ اللَّهِ بْنُ الْعَبَّاسِ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَثَلُ الَّذِي يَتَصَدَّقُ ثُمَّ يَرْجِعُ فِي صَدَقَتِهِ مَثَلُ الْكَلْبِ يَقِيءُ ثُمَّ يَرْجِعُ فَيَأْكُلُ قَيْئَهُ","id":"Telah menceritakan kepada kami ['Abdurrahman bin Ibrahim Ad Dimasyqi] berkata, telah menceritakan kepada kami [Al Walid bin Muslim] berkata, telah menceritakan kepada kami [Al Auza'i] berkata, telah menceritakan kepadaku [Abu Ja'far Muhammad bin Ali] berkata, telah menceritakan kepadaku [Sa'id Ibnul Musayyab] berkata, telah menceritakan kepadaku [Abdullah bin Al Abbas] ia berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Permisalah orang yang bersedekah kemudian memintanya kembali seperti anjing yang muntah kemudian memakannya kembali.\""},"2348":{"ar":"حَدَّثَنَا تَمِيمُ بْنُ الْمُنْتَصِرِ الْوَاسِطِيُّ حَدَّثَنَا إِسْحَقُ بْنُ يُوسُفَ عَنْ شَرِيكٍ عَنْ هِشَامِ بْنِ عُرْوَةَ عَنْ عُمَرَ بْنِ عَبْدِ اللَّهِ بْنِ عُمَرَ يَعْنِي عَنْ أَبِيهِ عَنْ جَدِّهِ عُمَرَأَنَّهُ تَصَدَّقَ بِفَرَسٍ عَلَى عَهْدِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَأَبْصَرَ صَاحِبَهَا يَبِيعُهَا بِكَسْرٍ فَأَتَى النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَسَأَلَهُ عَنْ ذَلِكَ فَقَالَ لَا تَبْتَعْ صَدَقَتَكَ","id":"Telah menceritakan kepada kami [Tamim bin Al Muntashir Al Wasithi] berkata, telah menceritakan kepada kami [Ishaq bin Yusuf] dari [Syarik] dari [Hisyam bin Urwah] dari [Umar bin Abdullah bin Umar] yakni dari [Bapaknya] dari kakeknya [Umar] bahwa pada masa Rasulullah shallallahu 'alaihi wasallam, ia pernah bersedekah seekor kuda (kepad seseorang), lalu pemiliknya menjualnya kembali dengan harga murah. Maka ia mendatangi Nabi shallallahu 'alaihi wasallam dan menanyakan tentang hal itu, beliau lalu menjawab: \"Jangan engkau beli kembali sedekahmu.\""},"2349":{"ar":"حَدَّثَنَا يَحْيَى بْنُ حَكِيمٍ حَدَّثَنَا يَزِيدُ بْنُ هَارُونَ حَدَّثَنَا سُلَيْمَانُ التَّيْمِيُّ عَنْ أَبِي عُثْمَانَ النَّهْدِيِّ عَنْ عَبْدِ اللَّهِ بْنِ عَامِرٍ عَنْ الزُّبَيْرِ بْنِ الْعَوَّامِأَنَّهُ حَمَلَ عَلَى فَرَسٍ يُقَالُ لَهُ غَمْرٌ أَوْ غَمْرَةٌ فَرَأَى مُهْرًا أَوْ مُهْرَةً مِنْ أَفْلَائِهَا يُبَاعُ يُنْسَبُ إِلَى فَرَسِهِ فَنَهَى عَنْهَا","id":"Telah menceritakan kepada kami [Yahya bin Hakim] berkata, telah menceritakan kepada kami [Yazid bin Harun] berkata, telah menceritakan kepada kami [Sualaiman At Taimi] dari [Abu Utsman An Nahdi] dari [Abdullah bin Amir] dari [Zubair bin Awwam] bahwa dia menaiki seekor kuda yang diberi nama Ghamrun atau Ghamrah, kemudian dia melihat seekor anak kuda jantan atau betina dari beberapa anak kuda yang dijual dan dinisbahkan kepada kudanya, maka dia melarangnya.\""},"2350":{"ar":"حَدَّثَنَا عَلِيُّ بْنُ مُحَمَّدٍ حَدَّثَنَا وَكِيعٌ عَنْ سُفْيَانَ عَنْ عَبْدِ اللَّهِ بْنِ عَطَاءٍ عَنْ عَبْدِ اللَّهِ بْنِ بُرَيْدَةَ عَنْ أَبِيهِ قَالَجَاءَتْ امْرَأَةٌ إِلَى النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَتْ يَا رَسُولَ اللَّهِ إِنِّي تَصَدَّقْتُ عَلَى أُمِّي بِجَارِيَةٍ وَإِنَّهَا مَاتَتْ فَقَالَ آجَرَكِ اللَّهُ وَرَدَّ عَلَيْكِ الْمِيرَاثَ","id":"Telah menceritakan kepada kami [Ali bin Muhammad] berkata, telah menceritakan kepada kami [Waki'] dari [Sufyan] dari [Abdullah bin 'Atha] dari [Abdullah bin Buraidah] dari [Bapaknya] ia berkata, \"Seorang wanita datang menemui Nabi shallallahu 'alaihi wasallam dan berkata, \"Wahai Rasulullah, aku bersedekah kepada ibuku dengan memberikan seorang budak wanita, tetapi ibuku meninggal?\" beliau menjawab: \"Semoga Allah memberimu pahala, dan Allah akan mengembalikannya kepadamu sebagai warisan.\""},"2351":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ يَحْيَى حَدَّثَنَا عَبْدُ اللَّهِ بْنُ جَعْفَرٍ الرَّقِّيُّ حَدَّثَنَا عُبَيْدُ اللَّهِ عَنْ عَبْدِ الْكَرِيمِ عَنْ عَمْرِو بْنِ شُعَيْبٍ عَنْ أَبِيهِ عَنْ جَدِّهِ قَالَجَاءَ رَجُلٌ إِلَى النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ إِنِّي أَعْطَيْتُ أُمِّي حَدِيقَةً لِي وَإِنَّهَا مَاتَتْ وَلَمْ تَتْرُكْ وَارِثًا غَيْرِي فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَجَبَتْ صَدَقَتُكَ وَرَجَعَتْ إِلَيْكَ حَدِيقَتُكَ","id":"Telah menceritakan kepada kami [Muhammad bin Yahya] berkata, telah menceritakan kepada kami [Abdullah bin Ja'far Ar Raqqi] berkata, telah menceritakan kepada kami [Ubaidullah] dari [Abdul Karim] dari [Amru bin Syu'aib] dari [Bapaknya] dari [Kakeknya] ia berkata, \"Seorang laki-laki datang menemui Nabi shallallahu 'alaihi wasallam dan bertanya, \"Aku memberikan kebun milikku kepada ibuku, namun ia meninggal. Dan ibuku tidak meninggalkan ahli waris kecuali aku?\" maka Rasulullah shallallahu 'alaihi wasallam bersabda: \"Sedekahmu telah diterima, dan kebun itu akan kembali kepadamu (sebagai warisan).\""},"2352":{"ar":"حَدَّثَنَا نَصْرُ بْنُ عَلِيٍّ الْجَهْضَمِيُّ حَدَّثَنَا مُعْتَمِرُ بْنُ سُلَيْمَانَ عَنْ ابْنِ عَوْنٍ عَنْ نَافِعٍ عَنْ ابْنِ عُمَرَ قَالَأَصَابَ عُمَرُ بْنُ الْخَطَّابِ أَرْضًا بِخَيْبَرَ فَأَتَى النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَاسْتَأْمَرَهُ فَقَالَ يَا رَسُولَ اللَّهِ إِنِّي أَصَبْتُ مَالًا بِخَيْبَرَ لَمْ أُصِبْ مَالًا قَطُّ هُوَ أَنْفَسُ عِنْدِي مِنْهُ فَمَا تَأْمُرُنِي بِهِ فَقَالَ إِنْ شِئْتَ حَبَّسْتَ أَصْلَهَا وَتَصَدَّقْتَ بِهَاقَالَ فَعَمِلَ بِهَا عُمَرُ عَلَى أَنْ لَا يُبَاعَ أَصْلُهَا وَلَا يُوهَبَ وَلَا يُورَثَ تَصَدَّقَ بِهَا لِلْفُقَرَاءِ وَفِي الْقُرْبَى وَفِي الرِّقَابِ وَفِي سَبِيلِ اللَّهِ وَابْنِ السَّبِيلِ وَالضَّيْفِ لَا جُنَاحَ عَلَى مَنْ وَلِيَهَا أَنْ يَأْكُلَهَا بِالْمَعْرُوفِ أَوْ يُطْعِمَ صَدِيقًا غَيْرَ مُتَمَوِّلٍ","id":"Telah menceritakan kepada kami [Nashr bin Ali Al Jahdlami] berkata, telah menceritakan kepada kami [Mu'tamir bin Sulaiman] dari [Ibnu Aun] dari [Nafi'] dari [Ibnu Umar] ia berkata; Umar bin Al Khaththab mendapatkan bagian sebidang tanah di khaibar, lalu ia mendatangi Nabi shallallahu 'alaihi wasallam meminta solusi. Ia lalu berkata, \"Wahai Rasulullah, aku mendapatkan harta berupa sebidang tanah di khaibar, dan aku tidak memiliki harta yang paling aku sukai selain itu, lalu apa yang engkau perintahkan kepadaku?\" beliau bersabda: \"Jika engkau mau, tetaplah engkau pegang tanah itu dan silahkan engkau bersedekah darinya.\" Ibnu Umar berkata, \"Lalu Umar melakukan hal itu, ia tidak menjual, tidak menghibahkan, dan tidak mewariskan tanah tersebut. Ia sedekahkah harta tersebut kepada orang-orang fakir, kerabat, fi sabilillah, Ibnu Sabil, dan tamu. Dan bagi orang-orang yang mengurusinya ia boleh memakannya dengan ma'ruf, atau menjamu temannya tanpa mengkomersilkannya.\""},"2353":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ أَبِي عُمَرَ الْعَدَنِيُّ حَدَّثَنَا سُفْيَانُ عَنْ عُبَيْدِ اللَّه بْنِ عُمَرَ عَنْ نَافِعٍ عَنْ ابْنِ عُمَرَ قَالَ قَالَ عُمَرُ بْنُ الْخَطَّابِيَا رَسُولَ اللَّهِ إِنَّ الْمِائَةَ سَهْمٍ الَّتِي بِخَيْبَرَ لَمْ أُصِبْ مَالًا قَطُّ هُوَ أَحَبُّ إِلَيَّ مِنْهَا وَقَدْ أَرَدْتُ أَنْ أَتَصَدَّقَ بِهَا فَقَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ احْبِسْ أَصْلَهَا وَسَبِّلْ ثَمَرَهَاقَالَ ابْنُ أَبِي عُمَرَ فَوَجَدْتُ هَذَا الْحَدِيثَ فِي مَوْضِعٍ آخَرَ فِي كِتَابِي عَنْ سُفْيَانَ عَنْ عَبْدِ اللَّهِ عَنْ نَافِعٍ عَنْ ابْنِ عُمَرَ قَالَ قَالَ عُمَرُ فَذَكَرَ نَحْوَهُ","id":"Telah menceritakan kepada kami [Muhammad bin Abu Umar Al 'Adani] berkata, telah menceritakan kepada kami [Sufyan] dari [Ubaidullah bin Umar] dari [Nafi'] dari [Ibnu Umar] ia berkata, \" [Umar bin Al Khaththab] berkata, \"Wahai Rasulullah, seratus saham yang ada di Khaibar, aku tidak pernah mendapatkan harta yang paling aku sukai selain itu. Dan aku ingin mensedekahkan harta itu! \" Nabi shallallahu 'alaihi wasallam kemudian bersabda: \"Tahanlah tanah itu dan sedekahkanlah buahnya.\" [Ibnu Abu Umar] berkata, \"Dalam bukuku aku mendapatkan hadits ini dalam tempat lain; dari [Sufyan], dari [Abdullah], dari [Nafi'], dari [Ibnu Umar] ia berkata, \" [Umar] berkata, lalu ia menyebutkan sebagaimana dalam hadits tersebut.\""},"2354":{"ar":"حَدَّثَنَا هِشَامُ بْنُ عَمَّارٍ حَدَّثَنَا إِسْمَعِيلُ بْنُ عَيَّاشٍ حَدَّثَنَا شُرَحْبِيلُ بْنُ مُسْلِمٍ قَالَ سَمِعْتُ أَبَا أُمَامَةَ يَقُولُسَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ الْعَارِيَةُ مُؤَدَّاةٌ وَالْمِنْحَةُ مَرْدُودَةٌ","id":"Telah menceritakan kepada kami [Hisyam bin Ammar] berkata, telah menceritakan kepada kami [Isma'il bin Ayyasy] berkata, telah menceritakan kepada kami [Syurahbil bin Muslim] ia berkata; Aku mendengar [Abu Umamah] berkata, \"Aku mendengar Rasulullah shallallahu 'alaihi wasallam bersabda: \"Barang pinjaman itu harus dikembalikan, dan pemberian juga dikembalikan.\""},"2355":{"ar":"حَدَّثَنَا هِشَامُ بْنُ عَمَّارٍ وَعَبْدُ الرَّحْمَنِ بْنُ إِبْرَاهِيمَ الدِّمَشْقِيَّانِ قَالَا حَدَّثَنَا مُحَمَّدُ بْنُ شُعَيْبٍ عَنْ عَبْدِ الرَّحْمَنِ بْنِ يَزِيدَ عَنْ سَعِيدِ بْنِ أَبِي سَعِيدٍ عَنْ أَنَسِ بْنِ مَالِكٍ قَالَسَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ الْعَارِيَةُ مُؤَدَّاةٌ وَالْمِنْحَةُ مَرْدُودَةٌ","id":"Telah menceritakan kepada kami [Hisyam bin Ammar] dan ['Abdurrahman bin Ibrahim] -keduanya dari Damaskus- keduanya berkata; telah menceritakan kepada kami [Muhammad bin Syu'aib] dari ['Abdurrahman bin Yazid] dari [Sa'id bin Abu Sa'id] dari [Anas bin Malik] ia berkata, \"Aku mendengar Rasulullah shallallahu 'alaihi wasallam bersabda: \"Barang pinjaman itu harus dikembalikan, dan pemberian juga dikembalikan.\""},"2356":{"ar":"حَدَّثَنَا إِبْرَاهِيمُ بْنُ الْمُسْتَمِرِّ حَدَّثَنَا مُحَمَّدُ بْنُ عَبْدِ اللَّهِ ح و حَدَّثَنَا يَحْيَى بْنُ حَكِيمٍ حَدَّثَنَا ابْنُ أَبِي عَدِيٍّ جَمِيعًا عَنْ سَعِيدٍ عَنْ قَتَادَةَ عَنْ الْحَسَنِ عَنْ سَمُرَةَأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ عَلَى الْيَدِ مَا أَخَذَتْ حَتَّى تُؤَدِّيَهُ","id":"Telah menceritakan kepada kami [Ibrahim bin Al Mustamir] berkata, telah menceritakan kepada kami [Muhammad bin Abdullah]. (Dalam jalur lain disebutkan) Telah menceritakan kepada kami [Yahya bin Hakim] berkata, telah menceritakan kepada kami [Ibnu Abu Adi] semuanya dari [Said] dari [Qatadah] dari [Al Hasan] dari [Samurah] bahwa Rasulullah shallallahu 'alaihi wasallam bersabda: \"Setiap orang wajib menjamin apa yang telah diambil hingga ia menggantinya.\""},"2357":{"ar":"حَدَّثَنَا عُبَيْدُ اللَّهِ بْنُ الْجَهْمِ الْأَنْمَاطِيُّ حَدَّثَنَا أَيُّوبُ بْنُ سُوَيْدٍ عَنْ الْمُثَنَّى عَنْ عَمْرِو بْنِ شُعَيْبٍ عَنْ أَبِيهِ عَنْ جَدِّهِ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَنْ أُودِعَ وَدِيعَةً فَلَا ضَمَانَ عَلَيْهِ","id":"Telah menceritakan kepada kami [Ubaidullah bin Al Jahm Al Anmathi] berkata, telah menceritakan kepada kami [Ayyub bin Suwaid] dari [Al Mutsanna] dari [Amru bin Syu'aib] dari [Bapaknya] dari [Kakeknya] ia berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Barangsiapa menitipkan titipan, maka tidak ada tanggungan baginya.\""},"2358":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا سُفْيَانُ بْنُ عُيَيْنَةَ عَنْ شَبِيبِ بْنِ غَرْقَدَةَ عَنْ عُرْوَةَ الْبَارِقِيِّأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَعْطَاهُ دِينَارًا يَشْتَرِي لَهُ شَاةً فَاشْتَرَى لَهُ شَاتَيْنِ فَبَاعَ إِحْدَاهُمَا بِدِينَارٍ فَأَتَى النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِدِينَارٍ وَشَاةٍ فَدَعَا لَهُ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِالْبَرَكَةِ قَالَ فَكَانَ لَوْ اشْتَرَى التُّرَابَ لَرَبِحَ فِيهِحَدَّثَنَا أَحْمَدُ بْنُ سَعِيدٍ الدَّارِمِيُّ حَدَّثَنَا حَبَّانُ بْنُ هِلَالٍ حَدَّثَنَا سَعِيدُ بْنُ زَيْدٍ عَنْ الزُّبَيْرِ بْنِ الْخِرِّيتِ عَنْ أَبِي لَبِيدٍ لِمَازَةُ بْنِ زَبَّارٍ عَنْ عُرْوَةَ بْنِ أَبِي الْجَعْدِ الْبَارِقِيِّ قَالَ قَدِمَ جَلَبٌ فَأَعْطَانِي النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ دِينَارًا فَذَكَرَ نَحْوَهُ","id":"Telah menceritakan kepada kami [Abu Bakr bin Abu Syaibah] berkata, telah menceritakan kepada kami [Sufyan bin Uyainah] dari [Syabib bin Gharqadah] dari [Urwah Al Bariqi] bahwa Nabi shallallahu 'alaihi wasallam pernah memberikan uang satu dinar kepadanya agar ia gunakan untuk membeli seekor kambing. Lalu ia memberi dua ekor kambing, kemudian menjual salah satunya dengan harga satu dinar. Setelah itu ia datang menemui Nabi shallallahu 'alaihi wasallam dengan membawa uang satu dinar dan seekor kambing. Nabi shallallahu 'alaihi wasallam lalu mendoakannya dengan keberkahan.\" Beliau bersabda: \"Sungguh, sekiranya ia membeli tanah, ia akan tetap beruntung.\" Telah menceritakan kepada kami [Ahmad bin Sa'id Ad Darimi] berkata, telah menceritakan kepada kami [Habban bin Hilal] berkata, telah menceritakan kepada kami [Sa'id bin Zaid] dari [Az Zubair bin Al Khirrib] dari [Abu Labid Limazah bin Zabbar] dari [Urwah bin Abu Al Ju'd Al Bariqi] ia berkata, \"Ketika barang (impor) datang Nabi shallallahu 'alaihi wasallam memberiku uang satu dinar, lalu ia menyebutkan sebagaimana dalam hadits.\""},"2359":{"ar":"حَدَّثَنَا هِشَامُ بْنُ عَمَّارٍ حَدَّثَنَا سُفْيَانُ بْنُ عُيَيْنَةَ عَنْ أَبِي الزِّنَادِ عَنْ الْأَعْرَجِ عَنْ أَبِي هُرَيْرَةَ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ الظُّلْمُ مَطْلُ الْغَنِيِّ وَإِذَا أُتْبِعَ أَحَدُكُمْ عَلَى مَلِيءٍ فَلْيَتْبَعْ","id":"Telah menceritakan kepada kami [Hisyam bin Ammar] berkata, telah menceritakan kepada kami [Sufyan bin Uyainah] dari [Abu Az Zinad] dari [Al A'raj] dari [Abu Hurairah] ia berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Orang kaya yang menunda-nunda membayar hutang adalah zhalim, dan jika hutang salah seorang dari kalian dipindahkan (kewajiban untuk membayar) kepada orang kaya hendaklah menerimanya.\""},"2360":{"ar":"حَدَّثَنَا إِسْمَعِيلُ بْنُ تَوْبَةَ حَدَّثَنَا هُشَيْمٌ عَنْ يُونُسَ بْنِ عُبَيْدٍ عَنْ نَافِعٍ عَنْ ابْنِ عُمَرَ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَطْلُ الْغَنِيِّ ظُلْمٌ وَإِذَا أُحِلْتَ عَلَى مَلِيءٍ فَاتْبَعْهُ","id":"Telah menceritakan kepada kami [Isma'il bin Taubah] berkata, telah menceritakan kepada kami [Husyaim] dari [Yunus bin Ubaid] dari [Nafi'] dari [Ibnu Umar] ia berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Orang kaya yang menunda-nunda membayar hutang adalah zhalim, dan jika hutang salah seorang dari kalian dihalalkan oleh orang kaya hendaklah menerimanya.\""},"2361":{"ar":"حَدَّثَنَا هِشَامُ بْنُ عَمَّارٍ وَالْحَسَنُ بْنُ عَرَفَةَ قَالَا حَدَّثَنَا إِسْمَعِيلُ بْنُ عَيَّاشٍ حَدَّثَنِي شُرَحْبِيلُ بْنُ مُسْلِمٍ الْخَوْلَانِيُّ قَالَ سَمِعْتُ أَبَا أُمَامَةَ الْبَاهِلِيَّ يَقُولُسَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ الزَّعِيمُ غَارِمٌ وَالدَّيْنُ مَقْضِيٌّ","id":"Telah menceritakan kepada kami [Hisyam bin Ammar] dan [Al Hasan bin Arafah] keduanya berkata; telah menceritakan kepada kami [Isma'il bin 'Ayyasy] berkata, telah berkata kepadaku [Syurahbil bin Muslim Al Khaulani] ia berkata; aku mendengar [Abu Umamah Al Bahili] berkata, \"Aku mendengar Rasulullah shallallahu 'alaihi wasallam bersabda: \"Menaggung berarti berhutang, dan hutang harus dibayar.\""},"2362":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ الصَّبَّاحِ حَدَّثَنَا عَبْدُ الْعَزِيزِ بْنُ مُحَمَّدٍ الدَّارَوَرْدِيُّ عَنْ عَمْرِو بْنِ أَبِي عَمْرٍو عَنْ عِكْرِمَةَ عَنْ ابْنِ عَبَّاسٍأَنَّ رَجُلًا لَزِمَ غَرِيمًا لَهُ بِعَشَرَةِ دَنَانِيرَ عَلَى عَهْدِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ مَا عِنْدِي شَيْءٌ أُعْطِيكَهُ فَقَالَ لَا وَاللَّهِ لَا أُفَارِقُكَ حَتَّى تَقْضِيَنِي أَوْ تَأْتِيَنِي بِحَمِيلٍ فَجَرَّهُ إِلَى النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ لَهُ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَمْ تَسْتَنْظِرُهُ فَقَالَ شَهْرًا فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَأَنَا أَحْمِلُ لَهُ فَجَاءَهُ فِي الْوَقْتِ الَّذِي قَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ لَهُ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مِنْ أَيْنَ أَصَبْتَ هَذَا قَالَ مِنْ مَعْدِنٍ قَالَ لَا خَيْرَ فِيهَا وَقَضَاهَا عَنْهُ","id":"Telah menceritakan kepada kami [Muhammad bin Ash Shabbah] berkata, telah menceritakan kepada kami [Abdul Aziz bin Muhammad Ad Darawardi] dari [Amru bin Abu Amru] dari [Ikrimah] dari [Ibnu Abbas] berkata, \"Pada masa Rasulullah shallallahu 'alaihi wasallam ada seseorang yang mempunyai tanggungan hutang sebanyak sepuluh dinar kepada orang yang meminjaminya. Lalu ia (peminjam) berkata, \"Aku tidak memiliki sesuatu untuk aku berikan kepadamu.\" Ia (pemilik uang) berkata, \"Tidak, demi Allah. Aku tidak akan meninggalkanmu hingga kamu membayarku, atau kamu mendatangkan kepadaku seorang jaminan.\" Lalu ia membawanya kepada Nabi shallallahu 'alaihi wasallam, Nabi shallallahu 'alaihi wasallam lantas bertanya: \"Berapa lama waktu yang kamu berikan untuknya?\" ia menjawab, \"Satu bulan.\" Rasulullah shallallahu 'alaihi wasallam kemudian bersabda: \"Aku yang akan menjadi penjamin.\" Maka dia datang di waktu yang telah dikatakan Nabi shallallahu 'alaihi wasallam. Nabi shallallahu 'alaihi wasallam lalu bertanya kepadanya: \"Dari mana kamu dapatkan ini?\" Ia menjawab, \"Dari harta temuan (harta karun).\" Beliau bersabda: \"Tidak ada kebaikan di sana.\" Lalu beliau pun membayarkan hutangnya.\""},"2363":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ بَشَّارٍ حَدَّثَنَا أَبُو عَامِرٍ حَدَّثَنَا شُعْبَةُ عَنْ عُثْمَانَ بْنِ عَبْدِ اللَّهِ بْنِ مَوْهَبٍ قَالَ سَمِعْتُ عَبْدَ اللَّهِ بْنَ أَبِي قَتَادَةَ عَنْ أَبِيهِأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أُتِيَ بِجَنَازَةٍ لِيُصَلِّيَ عَلَيْهَا فَقَالَ صَلُّوا عَلَى صَاحِبِكُمْ فَإِنَّ عَلَيْهِ دَيْنًا فَقَالَ أَبُو قَتَادَةَ أَنَا أَتَكَفَّلُ بِهِ قَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِالْوَفَاءِ قَالَ بِالْوَفَاءِ وَكَانَ الَّذِي عَلَيْهِ ثَمَانِيَةَ عَشَرَ أَوْ تِسْعَةَ عَشَرَ دِرْهَمًا","id":"Telah menceritakan kepada kami [Muhammad bin Basysyar] berkata, telah menceritakan kepada kami [Abu Amir] berkata, telah menceritakan kepada kami [Syu'bah] dari [Utsman bin Abdullah bin Mauhab] ia berkata; aku mendengar [Abdullah bin Abu Qatadah] dari [Bapaknya] berkata, \"Pernah didatangkan jenazah kepada Nabi shallallahu 'alaihi wasallam agar dishalati, namun beliau bersabda: \"Shalatlah untuk sahabat kalian. Sesungguhnya ia masih mempunyai hutang.\" Abu Qatadah lalu berkata, \"Aku yang akan menaggungnya.\" Nabi shallallahu 'alaihi wasallam bersabda: \"Dengan sempurna?\" ia menjawab, \"Dengan sempurna.\" Dan hutang yang menjadi tanggungan jenazah itu adalah delapan belas atau sembilan belas dirham.\""},"2364":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا عَبِيدَةُ بْنُ حُمَيْدٍ عَنْ مَنْصُورٍ عَنْ زِيَادِ بْنِ عَمْرِو بْنِ هِنْدٍ عَنْ ابْنِ حُذَيْفَةَ هُوَ عِمْرَانُ عَنْ أُمِّ الْمُؤْمِنِينَ مَيْمُونَةَ قَالَكَانَتْ تَدَّانُ دَيْنًا فَقَالَ لَهَا بَعْضُ أَهْلِهَا لَا تَفْعَلِي وَأَنْكَرَ ذَلِكَ عَلَيْهَا قَالَتْ بَلَى إِنِّي سَمِعْتُ نَبِيِّي وَخَلِيلِي صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ مَا مِنْ مُسْلِمٍ يَدَّانُ دَيْنًا يَعْلَمُ اللَّهُ مِنْهُ أَنَّهُ يُرِيدُ أَدَاءَهُ إِلَّا أَدَّاهُ اللَّهُ عَنْهُ فِي الدُّنْيَا","id":"Telah menceritakan kepada kami [Abu Bakar bin Abi Syaibah] berkata, telah menceritakan kepada kami [Ubaidah bin Humaid] dari [Mansur] dari [Ziyad bin Amru bin Hind] dari [Ibnu Hudzaifah yaitu Imran] dari [Ummul Mukminin Maimunah], Imran berkata, \"Maimunah pernah berhutang, hingga keluarganya berkata kepadanya, \"Janganlah kamu melakukannya.\" Dan mereka mengingkari perbuatannya tersebut.\" Maimunah berkata, \"Memang benar, aku mendengar Nabiku dan kekasihku shallallahu 'alaihi wasallam bersabda: \"Tidaklah seorang muslim berhutang, sementara Allah mengetahui bahwa ia ingin membayarnya, maka Allah akan membayarkannya di dunia.\""},"2365":{"ar":"حَدَّثَنَا إِبْرَاهِيمُ بْنُ الْمُنْذِرِ حَدَّثَنَا ابْنُ أَبِي فُدَيْكٍ حَدَّثَنَا سَعِيدُ بْنُ سُفْيَانَ مَوْلَى الْأَسْلَمِيِّينَ عَنْ جَعْفَرِ بْنِ مُحَمَّدٍ عَنْ أَبِيهِ عَنْ عَبْدِ اللَّهِ بْنِ جَعْفَرٍ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَانَ اللَّهُ مَعَ الدَّائِنِ حَتَّى يَقْضِيَ دَيْنَهُ مَا لَمْ يَكُنْ فِيمَا يَكْرَهُ اللَّهُقَالَ فَكَانَ عَبْدُ اللَّهِ بْنُ جَعْفَرٍ يَقُولُ لِخَازِنِهِ اذْهَبْ فَخُذْ لِي بِدَيْنٍ فَإِنِّي أَكْرَهُ أَنْ أَبِيتَ لَيْلَةً إِلَّا وَاللَّهُ مَعِي بَعْدَ الَّذِي سَمِعْتُ مِنْ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ","id":"Telah menceritakan kepada kami [Ibrahim Al Mundzir] berkata, telah menceritakan kepada kami [Abu Fudaik] berkata, telah menceritakan kepada kami [Sa'id bin Sufyan] -mantan budak Al Aslamiyiin- dari [Ja'far bin Muhammad] dari [Bapaknya] dari [Abdullah bin Ja'far] ia berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Allah bersama orang yang berhutang sehingga dia melunasi hutangnya, selagi ia tidak berada pada sesuatu yang dibenci Allah.\" Ia (perawai) berkata, \"Abdullah bin Ja'far pernah berkata kepada bendaharanya, \"Pergi dan ambilkan uang untukku sebagai hutang, sebab setelah mendengar sabda Rasulullah shallallahu 'alaihi wasallam aku tidak ingin jika bermalam satu malam kecuali Allah bersamaku.\""},"2366":{"ar":"حَدَّثَنَا هِشَامُ بْنُ عَمَّارٍ حَدَّثَنَا يُوسُفُ بْنُ مُحَمَّدِ بْنِ صَيْفِيِّ بْنِ صُهَيْبِ الْخَيْرِ حَدَّثَنِي عَبْدُ الْحَمِيدِ بْنُ زِيَادِ بْنِ صَيْفِيِّ بْنِ صُهَيْبٍ عَنْ شُعَيْبِ بْنِ عَمْرٍو حَدَّثَنَا صُهَيْبُ الْخَيْرِعَنْ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ أَيُّمَا رَجُلٍ يَدِينُ دَيْنًا وَهُوَ مُجْمِعٌ أَنْ لَا يُوَفِّيَهُ إِيَّاهُ لَقِيَ اللَّهَ سَارِقًاحَدَّثَنَا إِبْرَاهِيمُ بْنُ الْمُنْذِرِ الْحِزَامِيُّ حَدَّثَنَا يُوسُفُ بْنُ مُحَمَّدِ بْنِ صَيْفِيٍّ عَنْ عَبْدِ الْحَمِيدِ بْنِ زِيَادٍ عَنْ أَبِيهِ عَنْ جَدِّهِ صُهَيْبٍ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ نَحْوَهُ","id":"Telah menceritakan kepada kami [Hisyam bin Ammar] berkata, telah menceritakan kepada kami [Yusuf bin Muhammad bin Shaifi bin Shuhaib Al Khair] berkata; telah menceritakan kepadaku [Abdul Hamid bin Ziyad bin Shaifi bin Shuhaib] dari [Syu'aib bin Amru] berkata, telah menceritakan kepada kami [Shuhaib Al Khair] dari Rasulullah shallallahu 'alaihi wasallam, beliau bersabda: \"Siapa saja berhutang dan ia berencana untuk tidak membayarnya kepada pemiliknya, maka ia akan menjumpai Allah dengan status sebagai pencuri.\" Telah menceritakan kepada kami [Ibrahim Ibnul Mundzir Al Hizami] berkata, telah menceritakan kepada kami [Yusuf bin Muhammad bin Shaifi] dari [Abdul Hamid bin Ziyad] dari [Bapaknya] dari kakeknya [Shuhaib] dari Nabi shallallahu 'alaihi wasallam dengan Hadist yang serupa.\""},"2367":{"ar":"حَدَّثَنَا يَعْقُوبُ بْنُ حُمَيْدِ بْنِ كَاسِبٍ حَدَّثَنَا عَبْدُ الْعَزِيزِ بْنُ مُحَمَّدٍ عَنْ ثَوْرِ بْنِ زَيْدٍ الدِّيلِيِّ عَنْ أَبِي الْغَيْثِ مَوْلَى ابْنِ مُطِيعٍ عَنْ أَبِي هُرَيْرَةَأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ مَنْ أَخَذَ أَمْوَالَ النَّاسِ يُرِيدُ إِتْلَافَهَا أَتْلَفَهُ اللَّهُ","id":"Telah menceritakan kepada kami [Ya'qub bin Humaid bin Kasib] berkata, telah menceritakan kepada kami [Abdil Aziz bin Muhammad] dari [Tsaur bin Zaid Ad Dil] dari [Abu Al Ghaits] -mantan budak Ibnu Muthi'- dari [Abu Hurairah] bahwa Nabi shallallahu 'alaihi wasallam bersabda: \"Barangsiapa mengambil harta orang lain dengan niat merusaknya maka Allah akan (membalas) merusaknya.\""},"2368":{"ar":"حَدَّثَنَا حُمَيْدُ بْنُ مَسْعَدَةَ حَدَّثَنَا خَالِدُ بْنُ الْحَارِثِ حَدَّثَنَا سَعِيدٌ عَنْ قَتَادَةَ عَنْ سَالِمِ بْنِ أَبِي الْجَعْدِ عَنْ مَعْدَانَ بْنِ أَبِي طَلْحَةَ عَنْ ثَوْبَانَ مَوْلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَعَنْ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنَّهُ قَالَ مَنْ فَارَقَ الرُّوحُ الْجَسَدَ وَهُوَ بَرِيءٌ مِنْ ثَلَاثٍ دَخَلَ الْجَنَّةَ مِنْ الْكِبْرِ وَالْغُلُولِ وَالدَّيْنِ","id":"Telah menceritakan kepada kami [Humaid bin Mas'adah] berkata, telah menceritakan kepada kami [Khalid Ibnul Harits] berkata, telah menceritakan kepada kami [Sa'id] dari [Qatadah] dari [Salim bin Abu Al Ja'd] dari [Ma'dan bin Abu Thalhah] dari [Tsauban] -mantan budak- Rasulullah shallallahu 'alaihi wasallam, dari Rasulullah shallallahu 'alaihi wasallam, bahwasanya beliau bersabda: \"Barangsiapa disaat ruhnya berpisah dengan jasadnya ia terbebas dari tiga hal maka ia akan masuk surga, yaitu; sombong, mencuri ghanimah sebelum dibagi dan hutang.\""},"2369":{"ar":"حَدَّثَنَا أَبُو مَرْوَانَ الْعُثْمَانِيُّ حَدَّثَنَا إِبْرَاهِيمُ بْنُ سَعْدٍ عَنْ أَبِيهِ عَنْ عُمَرَ بْنِ أَبِي سَلَمَةَ عَنْ أَبِيهِ عَنْ أَبِي هُرَيْرَةَ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ نَفْسُ الْمُؤْمِنِ مُعَلَّقَةٌ بِدَيْنِهِ حَتَّى يُقْضَى عَنْهُ","id":"Telah menceritakan kepada kami [Abu Marwan Al Utsmani] berkata, telah menceritakan kepada kami [Ibrahim bin Sa'd] dari [Bapaknya] dari [Umar bin Abu Salamah] dari [Bapaknya] dari [Abu Hurairah] ia berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Jiwa seorang mukmin itu bergantung dengan hutangnya hingga terbayar.\""},"2370":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ ثَعْلَبَةَ بْنِ سَوَاءٍ حَدَّثَنَا عَمِّي مُحَمَّدُ بْنُ سَوَاءٍ عَنْ حُسَيْنٍ الْمُعَلِّمِ عَنْ مَطَرٍ الْوَرَّاقِ عَنْ نَافِعٍ عَنْ ابْنِ عُمَرَ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَنْ مَاتَ وَعَلَيْهِ دِينَارٌ أَوْ دِرْهَمٌ قُضِيَ مِنْ حَسَنَاتِهِ لَيْسَ ثَمَّ دِينَارٌ وَلَا دِرْهَمٌ","id":"Telah menceritakan kepada kami [Muhammad bin Tsa'labah bin Sawa] berkata, telah menceritakan kepada kami pamanku [Muhammad bin Sawa] dari [Husain Al Mu'allim] dari [Mathar Al Warraq] dari [Nafi'] dari [Ibnu Umar] ia berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Barangsiapa meninggal sementara ia mempunyai tanggungan hutang satu dinar atau satu dirham, maka akan diganti dari pahala kebaikannya pada hari yang dinar dan dirham tidak berguna lagi.\""},"2371":{"ar":"حَدَّثَنَا أَحْمَدُ بْنُ عَمْرِو بْنِ السَّرْحِ الْمِصْرِيُّ حَدَّثَنَا عَبْدُ اللَّهِ بْنُ وَهْبٍ أَخْبَرَنِي يُونُسُ عَنْ ابْنِ شِهَابٍ عَنْ أَبِي سَلَمَةَ عَنْ أَبِي هُرَيْرَةَأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَانَ يَقُولُ إِذَا تُوُفِّيَ الْمُؤْمِنُ فِي عَهْدِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَعَلَيْهِ الدَّيْنُ فَيَسْأَلُ هَلْ تَرَكَ لِدَيْنِهِ مِنْ قَضَاءٍ فَإِنْ قَالُوا نَعَمْ صَلَّى عَلَيْهِ وَإِنْ قَالُوا لَا قَالَ صَلُّوا عَلَى صَاحِبِكُمْ فَلَمَّا فَتَحَ اللَّهُ عَلَى رَسُولِهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ الْفُتُوحَ قَالَ أَنَا أَوْلَى بِالْمُؤْمِنِينَ مِنْ أَنْفُسِهِمْ فَمَنْ تُوُفِّيَ وَعَلَيْهِ دَيْنٌ فَعَلَيَّ قَضَاؤُهُ وَمَنْ تَرَكَ مَالًا فَهُوَ لِوَرَثَتِهِ","id":"Telah menceritakan kepada kami [Ahmad bin Amru bin As Sarh Al Mishri] berkata, telah menceritakan kepada kami [Abdullah bin Wahb] berkata, telah mengabarkan kepadaku [Yunus] dari [Ibnu Syihab] dari [Abu Salamah] dari [Abu Hurairah] dari Rasulullah shallallahu 'alaihi wasallam; Abu Hurairah berkata; \"Jika ada seorang mukmin meninggal pada masa Rasulullah shallallahu 'alaihi wasallam dengan meninggalkan hutang, beliau bertanya: \"Apakah ia meninggalkan sesuatu yang dapat digunakan untuk membayar hutangnya?\" jika para sahabat menjawab 'Ya', beliau menshalatinya. Namun jika para sahabat menjawab 'tidak', beliau bersabda: \"Shalatlah untuk sahabat kalian.\" Ketika Allah memberikan banyak kemenangan kepada Rasulullah shallallahu 'alaihi wasallam, beliau bersabda: \"Aku lebih berhak atas jiwa seorang mukmin dari diri mereka sendiri, barangsiapa meninggal sementara ia mempunyai hutang maka akulah yang akan membayarnya, dan barangsiapa meninggalkan harta, maka harta itu untuk ahli warisnya.\""},"2372":{"ar":"حَدَّثَنَا عَلِيُّ بْنُ مُحَمَّدٍ حَدَّثَنَا وَكِيعٌ حَدَّثَنَا سُفْيَانُ عَنْ جَعْفَرِ بْنِ مُحَمَّدٍ عَنْ أَبِيهِ عَنْ جَابِرٍ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَنْ تَرَكَ مَالًا فَلِوَرَثَتِهِ وَمَنْ تَرَكَ دَيْنًا أَوْ ضَيَاعًا فَعَلَيَّ وَإِلَيَّ وَأَنَا أَوْلَى بِالْمُؤْمِنِينَ","id":"Telah menceritakan kepada kami [Ali bin Muhammad] berkata, telah menceritakan kepada kami [Waki'] berkata, telah menceritakan kepada kami [Sufyan] dari [Ja'far bin Muhammad] dari [Bapaknya] dari [Jabir] ia berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Barangsiapa meninggalkan harta hendaklah untuk ahli warisnya, dan barangsiapa meninggalkan hutang, atau kerabat (yang butuh pengayoman) maka kepadakulah kewajiban itu. Aku adalah orang yang paling berhak atas seorang mukmin.\""},"2373":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا أَبُو مُعَاوِيَةَ عَنْ الْأَعْمَشِ عَنْ أَبِي صَالِحٍ عَنْ أَبِي هُرَيْرَةَ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَنْ يَسَّرَ عَلَى مُعْسِرٍ يَسَّرَ اللَّهُ عَلَيْهِ فِي الدُّنْيَا وَالْآخِرَةِ","id":"Telah menceritakan kepada kami [Abu Bakar bin Abi Syaibah] berkata, telah menceritakan kepada kami [Abu Mu'awiyah] dari [Al A'masy] dari [Abu Shalih] dari [Abu Hurairah] ia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Barangsiapa memberi kemudahan kepada orang yang kesulitan, maka Allah akan memudahkannya di dunia dan akhirat.\""},"2374":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ عَبْدِ اللَّهِ بْنِ نُمَيْرٍ حَدَّثَنَا أَبِي حَدَّثَنَا الْأَعْمَشُ عَنْ نُفَيْعٍ أَبِي دَاوُدَ عَنْ بُرَيْدَةَ الْأَسْلَمِيِّعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ مَنْ أَنْظَرَ مُعْسِرًا كَانَ لَهُ بِكُلِّ يَوْمٍ صَدَقَةٌ وَمَنْ أَنْظَرَهُ بَعْدَ حِلِّهِ كَانَ لَهُ مِثْلُهُ فِي كُلِّ يَوْمٍ صَدَقَةٌ","id":"Telah menceritakan kepada kami [Muhammad bin Abdullah bin Numair] berkata, telah menceritakan kepada kami [Bapakku] berkata, telah menceritakan kepada kami [Al A'masy] dari [Nufai' Abu Dawud] dari [Buraidah Al Aslami] dari Nabi shallallahu 'alaihi wasallam, beliau bersabda: \"Barangsiapa memberi kemudahan (dengan menangguhkan pembayarannya) kepada orang yang kesusahan, maka pada setiap harinya ia akan mendapatkan pahala sedekah. Dan barangsiapa memberikan kemudahan setelah jatuh tempo, ia juga akan mendapatkan pahala sedekah pada setiap harinya.\""},"2375":{"ar":"حَدَّثَنَا يَعْقُوبُ بْنُ إِبْرَاهِيمَ الدَّوْرَقِيُّ حَدَّثَنَا إِسْمَعِيلُ بْنُ إِبْرَاهِيمَ عَنْ عَبْدِ الرَّحْمَنِ بْنِ إِسْحَقَ عَنْ عَبْدِ الرَّحْمَنِ بْنِ مُعَاوِيَةَ عَنْ حَنْظَلَةَ بْنِ قَيْسٍ عَنْ أَبِي الْيَسَرِ صَاحِبِ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَنْ أَحَبَّ أَنْ يُظِلَّهُ اللَّهُ فِي ظِلِّهِ فَلْيُنْظِرْ مُعْسِرًا أَوْ لِيَضَعْ لَهُ","id":"Telah menceritakan kepada kami [Ya'qub bin Ibrahim Ad Dauraqi] berkata, telah menceritakan kepada kami [Isma'il bin Ibrahim] dari ['Abdurrahman bin Ishaq] dari ['Abdurrahman bin Mu'awiyah] dari [Hanzhalah bin Qais] dari [Abu Al Yasar] -seorang sahabat Nabi shallallahu 'alaihi wasallam- ia berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Barangsiapa yang ingin dilindungi Allah dalam lindungan-Nya, hendaklah ia memberi kemudahan atau membebaskan (hutang) orang yang kesusahan.\""},"2376":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ بَشَّارٍ حَدَّثَنَا أَبُو عَامِرٍ حَدَّثَنَا شُعْبَةُ عَنْ عَبْدِ الْمَلِكِ بْنِ عُمَيْرٍ قَالَ سَمِعْتُ رِبْعِيَّ بْنَ حِرَاشٍ يُحَدِّثُ عَنْ حُذَيْفَةَعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنَّ رَجُلًا مَاتَ فَقِيلَ لَهُ مَا عَمِلْتَ فَإِمَّا ذَكَرَ أَوْ ذُكِّرَ قَالَ إِنِّي كُنْتُ أَتَجَوَّزُ فِي السِّكَّةِ وَالنَّقْدِ وَأُنْظِرُ الْمُعْسِرَ فَغَفَرَ اللَّهُ لَهُقَالَ أَبُو مَسْعُودٍ أَنَا قَدْ سَمِعْتُ هَذَا مِنْ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ","id":"Telah menceritakan kepada kami [Muhammad bin Basysyar] berkata; telah menceritakan kepada kami [Abu Amir] berkata, telah menceritakan kepada kami [Syu'bah] dari [Abdul Malik bin Umair] ia berkata; aku mendengar [Rib'i bin Hirasy] menceritakan dari [Hudzaifah] dari Nabi shallallahu 'alaihi wasallam, beliau bersabda: \"Seorang laki-laki meninggal, kemudian dikatakan kepadanya, \"Apa yang telah engkau lakukan?\" -ia menyebutkan atau disebutkan kepadanya- laki-laki itu berkata, 'Aku memberi toleransi dan kemudahan dalam masalah hutang kepada orang yang kesusahan.' Lalu Allah pun mengampuninya.\" [Abu bin Mas'ud] berkata; \"Aku mendengar hadits ini dari Rasulullah shallallahu 'alaihi wasallam.\""},"2377":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ خَلَفٍ الْعَسْقَلَانِيُّ وَمُحَمَّدُ بْنُ يَحْيَى قَالَا حَدَّثَنَا ابْنُ أَبِي مَرْيَمَ حَدَّثَنَا يَحْيَى بْنُ أَيُّوبَ عَنْ عُبَيْدِ اللَّهِ بْنِ أَبِي جَعْفَرٍ عَنْ نَافِعٍ عَنْ ابْنِ عُمَرَ وَعَائِشَةَأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ مَنْ طَالَبَ حَقًّا فَلْيَطْلُبْهُ فِي عَفَافٍ وَافٍ أَوْ غَيْرِ وَافٍ","id":"Telah menceritakan kepada kami [Muhammad bin Khalaf Al Asqalani] dan [Muhammad bin Yahya] keduanya berkata; telah menceritakan kepada kami [Ibnu Abu Maryam] berkata, telah menceritakan kepada kami [Yahya bin Ayyub] dari [Ubaidullah bin Abu Ja'far] dari [Nafi'] dari [Ibnu Umar] dan ['Aisyah] bahwa Rasulullah shallallahu 'alaihi wasallam bersabda: \"Barangsiapa menuntut hak, hendaklah ia menuntut dengan cara terhormat, baik ia menunaikannya atau pun tidak.\""},"2378":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ الْمُؤَمَّلِ بْنِ الصَّبَّاحِ الْقَيْسِيُّ حَدَّثَنَا مُحَمَّدُ بْنُ مُحَبَّبٍ الْقُرَشِيُّ حَدَّثَنَا سَعِيدُ بْنُ السَّائِبِ الطَّائِفِيُّ عَنْ عَبْدِ اللَّهِ بْنِ يَامِينَ عَنْ أَبِي هُرَيْرَةَأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ لِصَاحِبِ الْحَقِّ خُذْ حَقَّكَ فِي عَفَافٍ وَافٍ أَوْ غَيْرِ وَافٍ","id":"Telah menceritakan kepada kami [Muhammad bin Al Muammal bin Ash Shabbah Al Qaisi] berkata, telah menceritakan kepada kami [Muhammad bin Muhabbib Al Qurasyi] berkata, telah menceritakan kepada kami [Sa'id bin Muhammad bin As Saib At Thaifi] dari [Abdullah bin Yamin] dari [Abu Hurairah] bahwasanya Rasulullah shallallahu 'alaihi wasallam bersabda kepada pemilik hak: \"Ambillah hakmu dengan cara terhormat, baik ia menunaikannya atau tidak.\""},"2379":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا شَبَابَةُ ح و حَدَّثَنَا مُحَمَّدُ بْنُ بَشَّارٍ حَدَّثَنَا مُحَمَّدُ بْنُ جَعْفَرٍ قَالَا حَدَّثَنَا شُعْبَةُ عَنْ سَلَمَةَ بْنِ كُهَيْلٍ سَمِعْتُ أَبَا سَلَمَةَ بْنَ عَبْدِ الرَّحْمَنِ يُحَدِّثُ عَنْ أَبِي هُرَيْرَةَ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِنَّ خَيْرَكُمْ أَوْ مِنْ خَيْرِكُمْ أَحَاسِنُكُمْ قَضَاءً","id":"Telah menceritakan kepada kami [Abu Bakr bin Abu Syaibah] berkata; telah menceritakan kepada kami [Syababah]. (Dalam jalur lain disebutkan) Telah menceritakan kepada kami [Muhammad bin Basysyar] berkata, telah menceritakan kepada kami [Muhammad bin Ja'far] keduanya berkata; telah menceritakan kepada kami [Syu'bah] dari [Salamah bin Kuhail] berkata, \"Aku mendengar [Abu Salamah bin 'Abdurrahman] menceritakan dari [Abu Hurairah] ia berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Sesungguhnya sebaik-baik kalian, atau beliau mengatakan, \"dari sebaik-baik kalian adalah yang paling baik dalam membayar hutang.\""},"2380":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا وَكِيعٌ حَدَّثَنَا إِسْمَعِيلُ بْنُ إِبْرَاهِيمَ بْنِ عَبْدِ اللَّهِ بْنِ أَبِي رَبِيعَةَ الْمَخْزُومِيُّ عَنْ أَبِيهِ عَنْ جَدِّهِأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ اسْتَلَفَ مِنْهُ حِينَ غَزَا حُنَيْنًا ثَلَاثِينَ أَوْ أَرْبَعِينَ أَلْفًا فَلَمَّا قَدِمَ قَضَاهَا إِيَّاهُ ثُمَّ قَالَ لَهُ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بَارَكَ اللَّهُ لَكَ فِي أَهْلِكَ وَمَالِكَ إِنَّمَا جَزَاءُ السَّلَفِ الْوَفَاءُ وَالْحَمْدُ","id":"Telah menceritakan kepada kami [Abu Bakr bin Abu Syaibah] berkata, telah menceritakan kepada kami [Waki'] berkata, telah menceritakan kepada kami [Isma'il bin Ibrahim bin Abdullah bin Abu Rabi'ah Al Makhzumi] dari [Bapaknya] dari [Kakeknya] bahwasannya ketika terjadi perang Hunain Nabi shallallahu 'alaihi wasallam pernah meminjam kepadanya tiga puluh atau empat puluh ribu. Maka, ketika telah tiba (Madinah) beliau melunasinya. Setelah itu Nabi shallallahu 'alaihi wasallam bersabda kepadanya: \"Semoga Allah memberi berkah pada keluarga dan hartamu. Sesungguhnya balasan salaf (pinjaman) adalah pembayaran dan pujian.\""},"2381":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ عَبْدِ الْأَعْلَى الصَّنْعَانِيُّ حَدَّثَنَا مُعْتَمِرُ بْنُ سُلَيْمَانَ عَنْ أَبِيهِ عَنْ حَنَشٍ عَنْ عِكْرِمَةَ عَنْ ابْنِ عَبَّاسٍ قَالَجَاءَ رَجُلٌ يَطْلُبُ نَبِيَّ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِدَيْنٍ أَوْ بِحَقٍّ فَتَكَلَّمَ بِبَعْضِ الْكَلَامِ فَهَمَّ صَحَابَةُ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِهِ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَهْ إِنَّ صَاحِبَ الدَّيْنِ لَهُ سُلْطَانٌ عَلَى صَاحِبِهِ حَتَّى يَقْضِيَهُ","id":"Telah menceritakan kepada kami [Muhammad bin Abdul A'la Ash Shan'ani] berkata, telah menceritakan kepada kami [Mu'tamir bin Sulaiman] dari [Bapaknya] dari [Hanasy] dari [Ikrimah] dari [Ibnu 'Abbas] ia berkata, \"Seorang laki-laki datang dan meminta pembayaran hutang, atau hak kepada Nabi shallallahu 'alaihi wasallam, ia berbicara dengan beberapa perkataan, hingga para sahabat hendak memukul laki-laki itu. Rasulullah shallallahu 'alaihi wasallam kemudian bersabda: \"Cukup! sesungguhnya pemberi hutang punya kuasa atas orang yang berhutang hingga ia membayarnya.\""},"2382":{"ar":"حَدَّثَنَا إِبْرَاهِيمُ بْنُ عَبْدِ اللَّهِ بْنِ مُحَمَّدِ بْنِ عُثْمَانَ أَبُو شَيْبَةَ حَدَّثَنَا ابْنُ أَبِي عُبَيْدَةَ أَظُنُّهُ قَالَ حَدَّثَنَا أَبِي عَنْ الْأَعْمَشِ عَنْ أَبِي صَالِحٍ عَنْ أَبِي سَعِيدٍ الْخُدْرِيِّ قَالَجَاءَ أَعْرَابِيٌّ إِلَى النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَتَقَاضَاهُ دَيْنًا كَانَ عَلَيْهِ فَاشْتَدَّ عَلَيْهِ حَتَّى قَالَ لَهُ أُحَرِّجُ عَلَيْكَ إِلَّا قَضَيْتَنِي فَانْتَهَرَهُ أَصْحَابُهُ وَقَالُوا وَيْحَكَ تَدْرِي مَنْ تُكَلِّمُ قَالَ إِنِّي أَطْلُبُ حَقِّي فَقَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ هَلَّا مَعَ صَاحِبِ الْحَقِّ كُنْتُمْ ثُمَّ أَرْسَلَ إِلَى خَوْلَةَ بِنْتِ قَيْسٍ فَقَالَ لَهَا إِنْ كَانَ عِنْدَكِ تَمْرٌ فَأَقْرِضِينَا حَتَّى يَأْتِيَنَا تَمْرُنَا فَنَقْضِيَكِ فَقَالَتْ نَعَمْ بِأَبِي أَنْتَ يَا رَسُولَ اللَّهِ قَالَ فَأَقْرَضَتْهُ فَقَضَى الْأَعْرَابِيَّ وَأَطْعَمَهُ فَقَالَ أَوْفَيْتَ أَوْفَى اللَّهُ لَكَ فَقَالَ أُولَئِكَ خِيَارُ النَّاسِ إِنَّهُ لَا قُدِّسَتْ أُمَّةٌ لَا يَأْخُذُ الضَّعِيفُ فِيهَا حَقَّهُ غَيْرَ مُتَعْتَعٍ","id":"Telah menceritakan kepada kami [Ibrahim bin Abdullah bin Muhammad bin Utsman Abu Syaibah] berkata, telah menceritakan kepada kami [Ibnu Abu Ubaidah] menurutku ia mengatakan; telah menceritakan kepada kami [Ayahku] dari [Al A'masy] dari [Abu Shalih] dari [Abu Sa'id Al Khudri] ia berkata, \"Seorang arab badui datang kepada Nabi shallallahu 'alaihi wasallam meminta pelunasan hutang dari beliau, badui tersebut memaksa beliau hingga ia berkata kepada beliau, \"Aku akan menekanmu hingga engkau membayar kepadaku.\" Maka para sahabat pun menghardik dan berkata, \"Celaka kamu! Tidak tahukah siapa yang kamu ajak bicara?\" badui itu menjawab, \"Aku hanya menuntut hakku.\" Nabi shallallahu 'alaihi wasallam kemudian bersabda: \"Hendaklah kalian membantu pemilik hak hingga ia mendapatkan haknya.\" Kemudian beliau mengutus seseorang kepada Khaulah binti Qais, beliau mengatakan kepadanya: \"Jika kamu mempunyai kurma maka pinjamilah kami, jika kurma kami telah tiba maka akan kami ganti.\" Khaulah berkata, \"Ya, demi bapakku, untukmu wahai Rasulullah.\" Abu Sa'id berkata, \"Khaulah kemudian meminjami Rasulullah hingga beliau melunasi hutangnya pada arab badui itu dan memberinya makan. Badui itu kemudian berkata: \"Engkau telah menepati pembayarannya, semoga Allah akan menepatinya bagimu.\" Beliau lalu bersabda: \"Mereka itulah sebaik-baik umat, tidaklah suatu kaum akan dibersihkan dari dosa hingga orang yang lemah dari mereka dapat mengambil haknya tanpa ada rasa takut.\""},"2383":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ وَعَلِيُّ بْنُ مُحَمَّدٍ قَالَا حَدَّثَنَا وَكِيعٌ حَدَّثَنَا وَبْرُ بْنُ أَبِي دُلَيْلَةَ الطَّائِفِيُّ حَدَّثَنِي مُحَمَّدُ بْنُ مَيْمُونِ بْنِ مُسَيْكَةَ قَالَ وَكِيعٌ وَأَثْنَى عَلَيْهِ خَيْرًا عَنْ عَمْرِو بْنِ الشَّرِيدِ عَنْ أَبِيهِ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَيُّ الْوَاجِدِ يُحِلُّ عِرْضَهُ وَعُقُوبَتَهُقَالَ عَلِيٌّ الطَّنَافِسِيُّ يَعْنِي عِرْضَهُ شِكَايَتَهُ وَعُقُوبَتَهُ سِجْنَهُ","id":"Telah menceritakan kepada kami [Abu Bakr bin Abu Syaibah] dan [Ali bin Muhammad] keduanya berkata; telah menceritakan kepada kami [Waki'] berkata, telah menceritakan kepada kami [Wabr bin Abu Dulailah Ath Thaifi] Telah menceritakan kepada kami [Muhammad bin Maimun bin Musaikah] -Waki' berkata; 'Ia memujinya dengan kebaikan' - dari [Amru bin Asy Syarid] dari [Bapaknya] ia berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Orang kaya yang menunda-nunda dalam membayar hutang, halal atas kerhormatan dan hukumannya.\" Ali Ath Thanafisi berkata, \"Kehormatan maksudnya pengaduan, dan hukuman maksudnya pemenjaraan.\""},"2384":{"ar":"حَدَّثَنَا هَدِيَّةُ بْنُ عَبْدِ الْوَهَّابِ حَدَّثَنَا النَّضْرُ بْنُ شُمَيْلٍ حَدَّثَنَا الْهِرْمَاسُ بْنُ حَبِيبٍ عَنْ أَبِيهِ عَنْ جَدِّهِ قَالَأَتَيْتُ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِغَرِيمٍ لِي فَقَالَ لِي الْزَمْهُ ثُمَّ مَرَّ بِي آخِرَ النَّهَارِ فَقَالَ مَا فَعَلَ أَسِيرُكَ يَا أَخَا بَنِي تَمِيمٍ","id":"Telah menceritakan kepada kami [Hadiah bin Abdul Wahhab] berkata, telah menceritakan kepada kami [An Nadlr bin Syumail] berkata, telah menceritakan kepada kami [Al Hirmas bin Habib] dari [Bapaknya] dari [Kakeknya] ia berkata, \"Aku mendatangi Nabi shallallahu 'alaihi wasallam bersama orang yang meminjam uangku, beliau lalu bersabda kepadaku: \"Mintalah kepadanya! \" Kemudian beliau berjumpa denganku di sore hari, beliau bertanya: \"Apa yang dikerjakan oleh tawananmu wahai saudara bani Tamim?\""},"2385":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ يَحْيَى وَيَحْيَى بْنُ حَكِيمٍ قَالَا حَدَّثَنَا عُثْمَانُ بْنُ عُمَرَ أَنْبَأَنَا يُونُسُ بْنُ يَزِيدَ عَنْ الزُّهْرِيِّ عَنْ عَبْدِ اللَّهِ بْنِ كَعْبِ بْنِ مَالِكٍ عَنْ أَبِيهِأَنَّهُ تَقَاضَى ابْنَ أَبِي حَدْرَدٍ دَيْنًا لَهُ عَلَيْهِ فِي الْمَسْجِدِ حَتَّى ارْتَفَعَتْ أَصْوَاتُهُمَا حَتَّى سَمِعَهُمَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَهُوَ فِي بَيْتِهِ فَخَرَجَ إِلَيْهِمَا فَنَادَى كَعْبًا فَقَالَ لَبَّيْكَ يَا رَسُولَ اللَّهِ قَالَ دَعْ مِنْ دَيْنِكَ هَذَا وَأَوْمَأَ بِيَدِهِ إِلَى الشَّطْرِ فَقَالَ قَدْ فَعَلْتُ قَالَ قُمْ فَاقْضِهِ","id":"Telah menceritakan kepada kami [Muhammad bin Yahya] dan [Yahya bin Hakim] keduanya berkata; telah menceritakan kepada kami [Utsman bin Umar] berkata, telah memberitakan kepada kami [Yunus bin Yazid] dari [Az Zuhri] dari [Abdullah bin Ka'b bin Malik] dari [Bapaknya] Bahwasanya ia pernah menagih hutang kepada Ibnu Abu Hadrad di masjid, suara keduanya begitu keras hingga terdengar oleh Rasulullah shallallahu 'alaihi wasallam dari dalam rumah. Beliau kemudian keluar dan memanggil Ka'b, Ka'b kemudian menjawab, \"Aku penuhi panggilanmu wahai Rasulullah! \" beliau bersabda: \"Lepaskanlah tagihan hutangmu ini.\" Beliau kemudian memberi isyarat dengan tangannya agar Ka'b membebaskan setengah dari tagihan hutangnya. Ia berkata, \"Aku telah lakukan.\" Beliau bersabda: \"Berdiri dan berilah putusan.\""},"2386":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ خَلَفٍ الْعَسْقَلَانِيُّ حَدَّثَنَا يَعْلَى حَدَّثَنَا سُلَيْمَانُ بْنُ يَسِيرٍ عَنْ قَيْسِ بْنِ رُومِيٍّ قَالَ كَانَ سُلَيْمَانُ بْنُ أُذُنَانٍ يُقْرِضُ عَلْقَمَةَ أَلْفَ دِرْهَمٍ إِلَى عَطَائِهِ فَلَمَّا خَرَجَ عَطَاؤُهُ تَقَاضَاهَا مِنْهُ وَاشْتَدَّ عَلَيْهِ فَقَضَاهُ فَكَأَنَّ عَلْقَمَةَ غَضِبَ فَمَكَثَ أَشْهُرًا ثُمَّ أَتَاهُ فَقَالَ أَقْرِضْنِي أَلْفَ دِرْهَمٍ إِلَى عَطَائِي قَالَ نَعَمْ وَكَرَامَةً يَا أُمَّ عُتْبَةَ هَلُمِّي تِلْكَ الْخَرِيطَةَ الْمَخْتُومَةَ الَّتِي عِنْدَكِ فَجَاءَتْ بِهَا فَقَالَ أَمَا وَاللَّهِ إِنَّهَا لَدَرَاهِمُكَ الَّتِي قَضَيْتَنِي مَا حَرَّكْتُ مِنْهَا دِرْهَمًا وَاحِدًا قَالَ فَلِلَّهِ أَبُوكَ مَا حَمَلَكَ عَلَى مَا فَعَلْتَ بِي قَالَ مَا سَمِعْتُ مِنْكَ قَالَ مَا سَمِعْتَ مِنِّي قَالَ سَمِعْتُكَ تَذْكُرُعَنْ ابْنِ مَسْعُودٍ أَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ مَا مِنْ مُسْلِمٍ يُقْرِضُ مُسْلِمًا قَرْضًا مَرَّتَيْنِ إِلَّا كَانَ كَصَدَقَتِهَا مَرَّةً قَالَ كَذَلِكَ أَنْبَأَنِي ابْنُ مَسْعُودٍ","id":"Telah menceritakan kepada kami [Muhammad bin Khalaf Al Asqalani] berkata, telah menceritakan kepada kami [Ya'la] berkata, telah menceritakan kepada kami [Sulaiman bin Yasir] dari [Qais bin Rumi] ia berkata, \"Sulaiman bin Udzunan meminjami Alqamah seribu dirham sampai waktu yang telah ditentukan, ketika waktu yang telah ditentukan habis, Sulaiman meminta dan memaksa agar ia melunasinya, Alqamah pun membayarnya. Namun seakan-akan [Alqamah] marah hingga ia berdiam diri selama beberapa bulan. Kemudian Alqamah datang kembali kepadanya dan berkata, \"Pinjami aku seribu dirham sampai batas waktu yang telah engkau berikan kepadaku dulu.\" Sulaiman menjawab, \"Baiklah, dan dengan rasa hormat wahai Ummu Utbah, berikanlah kantung milikmu yang tertutup itu.\" Ia pun datang dengan membawa kantung tersebut, kemudian Sulaiman berkata, \"Demi Allah, sesungguhnya itu adalah dirham-dirham milikmu yang pernah engkau bayarkan kepadaku, aku tidak merubah dirham itu sedikitpun.\" Alqamah berkata, \"Demi Allah, apa yang mendorongmu melakukan ini kepadaku?\" ia menjawab, \"Karena sesuatu yang aku dengar darimu.\" Ia bertanya, \"Apa yang kamu dengar dariku?\" ia menjawab, \"Aku mendengarmu menyebutkan dari [Ibnu Mas'ud] berkata, \"Sesungguhnya Nabi shallallahu 'alaihi wasallam bersabda: \"Tidaklah seorang muslim memberi pinjaman kepada orang lain dua kali, kecuali seperti sedekahnya yang pertama.\" Ia berkata, \"Seperti itu pula yang di beritakan Ibnu Mas'ud kepadaku.\""},"2387":{"ar":"حَدَّثَنَا عُبَيْدُ اللَّهِ بْنُ عَبْدِ الْكَرِيمِ حَدَّثَنَا هِشَامُ بْنُ خَالِدٍ حَدَّثَنَا خَالِدُ بْنُ يَزِيدَ و حَدَّثَنَا أَبُو حَاتِمٍ حَدَّثَنَا هِشَامُ بْنُ خَالِدٍ حَدَّثَنَا خَالِدُ بْنُ يَزِيدَ بْنِ أَبِي مَالِكٍ عَنْ أَبِيهِ عَنْ أَنَسِ بْنِ مَالِكٍ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ رَأَيْتُ لَيْلَةَ أُسْرِيَ بِي عَلَى بَابِ الْجَنَّةِ مَكْتُوبًا الصَّدَقَةُ بِعَشْرِ أَمْثَالِهَا وَالْقَرْضُ بِثَمَانِيَةَ عَشَرَ فَقُلْتُ يَا جِبْرِيلُ مَا بَالُ الْقَرْضِ أَفْضَلُ مِنْ الصَّدَقَةِ قَالَ لِأَنَّ السَّائِلَ يَسْأَلُ وَعِنْدَهُ وَالْمُسْتَقْرِضُ لَا يَسْتَقْرِضُ إِلَّا مِنْ حَاجَةٍ","id":"Telah menceritakan kepada kami [Ubaidullah bin Abdul Karim] berkata, telah menceritakan kepada kami [Hisyam bin Khalid] berkata, telah menceritakan kepada kami [Khalid bin Yazid]. Dan telah menceritakan kepada kami [Abu Hatim] berkata, telah menceritakan kepada kami [Hisyam bin Khalid] berkata, telah menceritakan kepada kami [Khalid bin Yazid bin Abu Malik] dari [Bapaknya] dari [Anas bin Malik] ia berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Pada malam aku diisrakan aku melihat di atas pintu surga tertulis 'Sedekah akan dikalikan menjadi sepuluh kali lipat, dan memberi pinjaman dengan delapan belas kali lipat'. Maka aku pun bertanya: \"Wahai Jibril, apa sebabnya memberi hutang lebih utama ketimbang sedekah?\" Jibril menjawab: \"Karena saat seorang peminta meminta, (terkadang) ia masih memiliki (harta), sementara orang yang meminta pinjaman, ia tidak meminta pinjaman kecuali karena ada butuh.\""},"2388":{"ar":"حَدَّثَنَا هِشَامُ بْنُ عَمَّارٍ حَدَّثَنَا إِسْمَعِيلُ بْنُ عَيَّاشٍ حَدَّثَنِي عُتْبَةُ بْنُ حُمَيْدٍ الضَّبِّيُّ عَنْ يَحْيَى بْنِ أَبِي إِسْحَقَ الْهُنَائِيِّ قَالَ سَأَلْتُ أَنَسَ بْنَ مَالِكٍالرَّجُلُ مِنَّا يُقْرِضُ أَخَاهُ الْمَالَ فَيُهْدِي لَهُ قَالَ قَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِذَا أَقْرَضَ أَحَدُكُمْ قَرْضًا فَأَهْدَى لَهُ أَوْ حَمَلَهُ عَلَى الدَّابَّةِ فَلَا يَرْكَبْهَا وَلَا يَقْبَلْهُ إِلَّا أَنْ يَكُونَ جَرَى بَيْنَهُ وَبَيْنَهُ قَبْلَ ذَلِكَ","id":"Telah menceritakan kepada kami [Hisyam bin Ammar] berkata, telah menceritakan kepada kami [Isma'il bin Ayyasy] berkata, telah menceritakan kepadaku [Utbah bin Humaid Adl Dlabbi] dari [Yahya bin Abu Ishaq Al Huna`i] ia berkata, \"Aku bertanya kepada [Anas bin Malik]; \"Seorang lelaki dari kami meminjamkan harta kepada saudaranya, lalu ia memberi hadiah kepada yang memberi pinjaman?\" Anas berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Apabila salah seorang kalian memberi hutang (pada seseorang) kemudian dia memberi hadiah kepadanya, atau membantunya naik ke atas kendaraan maka janganlah ia menaikinya dan jangan menerimanya, kecuali jika hal itu telah terjadi antara keduanya sebelum itu.\""},"2389":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا عَفَّانُ حَدَّثَنَا حَمَّادُ بْنُ سَلَمَةَ أَخْبَرَنِي عَبْدُ الْمَلِكِ أَبُو جَعْفَرٍ عَنْ أَبِي نَضْرَةَ عَنْ سَعْدِ بْنِ الْأَطْوَلِأَنَّ أَخَاهُ مَاتَ وَتَرَكَ ثَلَاثَ مِائَةِ دِرْهَمٍ وَتَرَكَ عِيَالًا فَأَرَدْتُ أَنْ أُنْفِقَهَا عَلَى عِيَالِهِ فَقَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِنَّ أَخَاكَ مُحْتَبَسٌ بِدَيْنِهِ فَاقْضِ عَنْهُ فَقَالَ يَا رَسُولَ اللَّهِ قَدْ أَدَّيْتُ عَنْهُ إِلَّا دِينَارَيْنِ ادَّعَتْهُمَا امْرَأَةٌ وَلَيْسَ لَهَا بَيِّنَةٌ قَالَ فَأَعْطِهَا فَإِنَّهَا مُحِقَّةٌ","id":"Telah menceritakan kepada kami [Abu Bakr bin Abu Syaibah] berkata, telah menceritakan kepada kami [Affan] berkata, telah menceritakan kepada kami [Hammad bin Salamah] berkata, telah mengabarkan kepadaku [Abdul Malik Abu Ja'far] dari [Abu Nadlrah] dari [Sa'd bin Athwal] bahwa saudaranya wafat dengan meninggalkan tiga ratus dirham dan keluarga (anak dan isteri), lalu aku ingin mensedekahkannya kepada keluarganya. Nabi shallallahu 'alaihi wasallam bersabda: \"Sesungguhnya saudaramu tertahan karena hutangnya, maka bayarlah hutangnya.\" Ia berkata, \"Wahai Rasulullah, aku telah melunasinya, kecuali dua dinar yang diklaim oleh seorang wanita sementara ia tidak mempunyai bukti! \" beliau bersabda: \"Berikanlah kepada wanita itu, karena ia berhak.\""},"2390":{"ar":"حَدَّثَنَا عَبْدُ الرَّحْمَنِ بْنُ إِبْرَاهِيمَ الدِّمَشْقِيُّ حَدَّثَنَا شُعَيْبُ بْنُ إِسْحَقَ حَدَّثَنَا هِشَامُ بْنُ عُرْوَةَ عَنْ وَهْبِ بْنِ كَيْسَانَ عَنْ جَابِرِ بْنِ عَبْدِ اللَّهِأَنَّ أَبَاهُ تُوُفِّيَ وَتَرَكَ عَلَيْهِ ثَلَاثِينَ وَسْقًا لِرَجُلٍ مِنْ الْيَهُودِ فَاسْتَنْظَرَهُ جَابِرُ بْنُ عَبْدِ اللَّهِ فَأَبَى أَنْ يُنْظِرَهُ فَكَلَّمَ جَابِرٌ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لِيَشْفَعَ لَهُ إِلَيْهِ فَجَاءَهُ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَكَلَّمَ الْيَهُودِيَّ لِيَأْخُذَ ثَمَرَ نَخْلِهِ بِالَّذِي لَهُ عَلَيْهِ فَأَبَى عَلَيْهِ فَكَلَّمَهُ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَأَبَى أَنْ يُنْظِرَهُ فَدَخَلَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ النَّخْلَ فَمَشَى فِيهَا ثُمَّ قَالَ لِجَابِرٍ جُدَّ لَهُ فَأَوْفِهِ الَّذِي لَهُ فَجَدَّ لَهُ بَعْدَ مَا رَجَعَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ ثَلَاثِينَ وَسْقًا وَفَضَلَ لَهُ اثْنَا عَشَرَ وَسْقًا فَجَاءَ جَابِرٌ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لِيُخْبِرَهُ بِالَّذِي كَانَ فَوَجَدَ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ غَائِبًا فَلَمَّا انْصَرَفَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ جَاءَهُ فَأَخْبَرَهُ أَنَّهُ قَدْ أَوْفَاهُ وَأَخْبَرَهُ بِالْفَضْلِ الَّذِي فَضَلَ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَخْبِرْ بِذَلِكَ عُمَرَ بْنَ الْخَطَّابِ فَذَهَبَ جَابِرٌ إِلَى عُمَرَ فَأَخْبَرَهُ فَقَالَ لَهُ عُمَرُ لَقَدْ عَلِمْتُ حِينَ مَشَى فِيهِ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَيُبَارِكَنَّ اللَّهُ فِيهَا","id":"Telah menceritakan kepada kami ['Abdurrahman bin Ibrahim Ad Dimasyqi] berkata, telah menceritakan kepada kami [Syu'aib bin Ishaq] berkata, telah menceritakan kepada kami [Hisyam bin Urwah] dari [Wahb bin Kaisan] dari [Jabir bin Abdullah] bahwa ayahnya wafat dan meninggalkan hutang tiga puluh wasaq kepada seorang yahudi. Jabir kemudian meminta perpanjangan waktu kepadanya, namun orang yahudi tersebut tidak mau memberi perpanjangan kepadanya. Jabir kemudian berbicara kepada Rasulullah shallallahu 'alaihi wasallam agar beliau bisa membantunya menghadapi yahudi itu. Maka datanglah Rasulullah shallallahu 'alaihi wasallam menemui orang yahudi itu dan mengatakan kepadanya agar mengambil buah kurma sebagai ganti hutang Jabir kepadanya, tetapi dia menolaknya. Rasulullah shallallahu 'alaihi wasallam pun mengajaknya bicara lagi, tetapi dia tetap menolak untuk memberi perpanjangan waktu kepada Jabir. Rasulullah shallallahu 'alaihi wasallam kemudian masuk ke dalam kebun kurma dan mengitarinya, beliau lantas berkata kepada Jabir: \"Petiklah buah itu dan bayarkan kepadanya.\" Setelah Rasulullah shallallahu 'alaihi wasallam kembali ia memetik buah kurma sebanyak tiga puluh wasaq, dan masih mempunyai sisa dua belas wasaq. Jabir kemudian menemui Rasulullah shallallahu 'alaihi wasallam untuk mengabarkan apa yang ia lakukan kepada beliau, namun ia tidak mendapati Rasulullah shallallahu 'alaihi wasallam di tempat. Saat Rasulullah shallallahu 'alaihi wasallam kembali, Jabir kembali datang dan mengabarkan bahwa ia telah membayarkannya, dan mengabarkan kepada beliau kelebihan yang ia dapatkan. Rasulullah shallallahu 'alaihi wasallam kemudian bersabda: \"Kabarkanlah hal itu kepada Umar Ibnul Khaththab.\" Jabir lalu pergi menemui Umar dan mengabarkan kepadanya. Umar lantas berkata kepadanya, \"Aku telah mengetahui hal itu tatkala Rasulullah shallallahu 'alaihi wasallam berjalan di sana, Sungguh Allah telah memberkahi kebun kurma itu.\""},"2391":{"ar":"حَدَّثَنَا أَبُو كُرَيْبٍ حَدَّثَنَا رِشْدِينُ بْنُ سَعْدٍ وَعَبْدُ الرَّحْمَنِ الْمُحَارِبِيُّ وَأَبُو أُسَامَةَ وَجَعْفَرُ بْنُ عَوْنٍ عَنْ ابْنِ أَنْعُمٍ قَالَ أَبُو كُرَيْبٍ وَحَدَّثَنَا وَكِيعٌ عَنْ سُفْيَانَ عَنْ ابْنِ أَنْعُمٍ عَنْ عِمْرَانَ بْنِ عَبْدٍ الْمَعَافِرِيِّ عَنْ عَبْدِ اللَّهِ بْنِ عَمْرٍو قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِنَّ الدَّيْنَ يُقْضَى مِنْ صَاحِبِهِ يَوْمَ الْقِيَامَةِ إِذَا مَاتَ إِلَّا مَنْ يَدِينُ فِي ثَلَاثِ خِلَالٍ الرَّجُلُ تَضْعُفُ قُوَّتُهُ فِي سَبِيلِ اللَّهِ فَيَسْتَدِينُ يَتَقَوَّى بِهِ لِعَدُوِّ اللَّهِ وَعَدُوِّهِ وَرَجُلٌ يَمُوتُ عِنْدَهُ مُسْلِمٌ لَا يَجِدُ مَا يُكَفِّنُهُ وَيُوَارِيهِ إِلَّا بِدَيْنٍ وَرَجُلٌ خَافَ اللَّهَ عَلَى نَفْسِهِ الْعُزْبَةَ فَيَنْكِحُ خَشْيَةً عَلَى دِينِهِ فَإِنَّ اللَّهَ يَقْضِي عَنْ هَؤُلَاءِ يَوْمَ الْقِيَامَةِ","id":"Telah menceritakan kepada kami [Abu Kuraib] berkata, telah menceritakan kepada kami [Risydin bin Sa'd] dan ['Abdurrahman Al Muharibi] dan [Abu Usamah] dan [Ja'far bin Aun] dari [Ibnu An'um]. [Abu Kuraib] berkata; Telah menceritakan kepada kami [Waki'] dari [Sufyan] dari [Ibnu An'um] dari [Imran bin Abad Al Ma'arifi] dari [Abdullah bin Amru] ia berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Pada hari kiamat hutang itu akan diminta pembayarannya dari pemiliknya kecuali seseorang yang berhutang dalam tiga kondisi; seseorang yang berada di jalan Allah dalam keadaan lemah kemudian ia berhutang untuk menambah kekuatannya dalam menghadapai musuh Allah dan musuhnya. Dan seorang lelaki yang meninggal sementara disampingnya ada seorang muslim yang tidak mendapatkan kain untuk membungkus dan mengkafaninya kecuali dengan berhutang. Serta seorang lelaki yang takut kepada Allah lantaran dirinya dalam keadaan bujang, sehingga ia berhutang untuk menikah demi menjaga agamanya. Maka Allah akan membayarkan hutang mereka pada hari kiamat.\""},"2392":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا حَفْصُ بْنُ غِيَاثٍ عَنْ الْأَعْمَشِ عَنْ إِبْرَاهِيمَ حَدَّثَنِي الْأَسْوَدُ عَنْ عَائِشَةَأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ اشْتَرَى مِنْ يَهُودِيٍّ طَعَامًا إِلَى أَجَلٍ وَرَهَنَهُ دِرْعَهُ","id":"Telah menceritakan kepada kami [Abu Bakr bin Abu Syaibah] berkata, telah menceritakan kepada kami [Hafsh bin Ghiyats] dari [Al A'masy] dari [Ibrahim] berkata, telah menceritakan kepadaku [Al Aswad] dari ['Aisyah] berkata, \"Nabi shallallahu 'alaihi wasallam pernah membeli makanan dari seorang yahudi dengan tempo, kemudian menggadaikan baju perangnya.\""},"2393":{"ar":"حَدَّثَنَا نَصْرُ بْنُ عَلِيٍّ الْجَهْضَمِيُّ حَدَّثَنِي أَبِي حَدَّثَنَا هِشَامٌ عَنْ قَتَادَةَ عَنْ أَنَسٍ قَالَلَقَدْ رَهَنَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ دِرْعَهُ عِنْدَ يَهُودِيٍّ بِالْمَدِينَةِ فَأَخَذَ لِأَهْلِهِ مِنْهُ شَعِيرًا","id":"Telah menceritakan kepada kami [Nashr bin Ali Al Jahdlami] berkata, telah menceritakan kepadaku [Bapakku] berkata, telah menceritakan kepada kami [Hisyam] dari [Qatadah] dari [Anas] ia berkata, \"Rasulullah shallallahu 'alaihi wasallam pernah menggadaikan baju perangnya kepada seorang yahudi di Madinah, lalu beliau meminta gandum dari yahudi tersebut untuk diberikan kepada keluarganya.\""},"2394":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا وَكِيعٌ عَنْ عَبْدِ الْحَمِيدِ بْنِ بَهْرَامَ عَنْ شَهْرِ بْنِ حَوْشَبٍ عَنْ أَسْمَاءَ بِنْتِ يَزِيدَأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ تُوُفِّيَ وَدِرْعُهُ مَرْهُونَةٌ عِنْدَ يَهُودِيٍّ بِطَعَامٍ","id":"Telah menceritakan kepada kami [Abu Bakr bin Abu Syaibah] berkata, telah menceritakan kepada kami [Waki'] dari [Abdul Hamid bin Bahram] dari [Syahr bin Hausyab] dari [Asma binti Yazid] berkata, \"Nabi shallallahu 'alaihi wasallam meninggal sementara baju perangnya tergadaikan ditangan yahudi untuk mendapatkan makanan.\""},"2395":{"ar":"حَدَّثَنَا عَبْدُ اللَّهِ بْنُ مُعَاوِيَةَ الْجُمَحِيُّ حَدَّثَنَا ثَابِتُ بْنُ يَزِيدَ حَدَّثَنَا هِلَالُ بْنُ خَبَّابٍ عَنْ عِكْرِمَةَ عَنْ ابْنِ عَبَّاسٍأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَاتَ وَدِرْعُهُ رَهْنٌ عِنْدَ يَهُودِيٍّ بِثَلَاثِينَ صَاعًا مِنْ شَعِيرٍ","id":"Telah menceritakan kepada kami [Abdullah bin Mu'awiyah Al Jumahi] berkata, telah menceritakan kepada kami [Tsabit bin Yazid] berkata, telah menceritakan kepada kami [Hilal bin Khabbab] dari [Ikrimah] dari [Ibnu Abbas] berkata, \"Rasulullah shallallahu 'alaihi wasallam meninggal sementara baju perangnya tergadai di tangan yahudi untuk mendapatkan tiga puluh sha' gandum.\""},"2396":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا وَكِيعٌ عَنْ زَكَرِيَّا عَنْ الشَّعْبِيِّ عَنْ أَبِي هُرَيْرَةَ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ الظَّهْرُ يُرْكَبُ إِذَا كَانَ مَرْهُونًا وَلَبَنُ الدَّرِّ يُشْرَبُ إِذَا كَانَ مَرْهُونًا وَعَلَى الَّذِي يَرْكَبُ وَيَشْرَبُ نَفَقَتُهُ","id":"Telah menceritakan kepada kami [Abu Bakr bin Abu Syaibah] berkata, telah menceritakan kepada kami [Waki'] dari [Zakariya] dari [Asy Sya'bi] dari [Abu Hurairah] ia berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Punggung kendaraan boleh dinaiki jika tergadai, susu boleh diminum jika tergadai, dan bagi orang yang menaiki dan meminum wajib memberikan nafkahnya (biaya perawatan).\""},"2397":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ حُمَيْدٍ حَدَّثَنَا إِبْرَاهِيمُ بْنُ الْمُخْتَارِ عَنْ إِسْحَقَ بْنِ رَاشِدٍ عَنْ الزُّهْرِيِّ عَنْ سَعِيدِ بْنِ الْمُسَيَّبِ عَنْ أَبِي هُرَيْرَةَأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ لَا يَغْلَقُ الرَّهْنُ","id":"Telah menceritakan kepada kami [Muhammad bin Humaid] berkata, telah menceritakan kepada kami [Ibrahim bin Mukhtar] dari [Ishaq bin Rasyid] dari [Az Zuhri] dari [Sa'id bin Musayyab] dari [Abu Hurairah] bahwa Rasulullah shallallahu 'alaihi wasallam bersabda: \"Gadai tidak bisa dimiliki.\""},"2398":{"ar":"حَدَّثَنَا سُوَيْدُ بْنُ سَعِيدٍ حَدَّثَنَا يَحْيَى بْنُ سَلِيمٍ عَنْ إِسْمَعِيلَ بْنِ أُمَيَّةَ عَنْ سَعِيدِ بْنِ أَبِي سَعِيدٍ الْمَقْبُرِيِّ عَنْ أَبِي هُرَيْرَةَ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ ثَلَاثَةٌ أَنَا خَصْمُهُمْ يَوْمَ الْقِيَامَةِ وَمَنْ كُنْتُ خَصْمَهُ خَصَمْتُهُ يَوْمَ الْقِيَامَةِ رَجُلٌ أَعْطَى بِي ثُمَّ غَدَرَ وَرَجُلٌ بَاعَ حُرًّا فَأَكَلَ ثَمَنَهُ وَرَجُلٌ اسْتَأْجَرَ أَجِيرًا فَاسْتَوْفَى مِنْهُ وَلَمْ يُوفِهِ أَجْرَهُ","id":"Telah menceritakan kepada kami [Suwaid bin Sa'id] berkata, telah menceritakan kepada kami [Yahya bin Sulim] dari [Isma'il bin Umayyah] dari [Sa'id bin Abu Sa'id Al Maqburi] dari [Abu Hurairah] ia berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Tiga orang yang akan menjadi musuhku pada hari kiamat, dan barangsiapa aku sebagai lawannya, maka aku akan memusuhinya pada hari kiamat; seorang laki-laki yang memberi dengan namaku tetapi dia berkhianat, seorang laki-laki yang menjual orang merdeka kemudian dia memakan hasil penjualan, dan seorang laki-laki yang menyewa pekerja, kemudian saat diminta pembayaran dia tidak mau membayar upahnya.\""},"2399":{"ar":"حَدَّثَنَا الْعَبَّاسُ بْنُ الْوَلِيدِ الدِّمَشْقِيُّ حَدَّثَنَا وَهْبُ بْنُ سَعِيدِ بْنِ عَطِيَّةَ السَّلَمِيُّ حَدَّثَنَا عَبْدُ الرَّحْمَنِ بْنُ زَيْدِ بْنِ أَسْلَمَ عَنْ أَبِيهِ عَنْ عَبْدِ اللَّهِ بْنِ عُمَرَ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَعْطُوا الْأَجِيرَ أَجْرَهُ قَبْلَ أَنْ يَجِفَّ عَرَقُهُ","id":"Telah menceritakan kepada kami [Al Abbas bin Al Walid Ad Dimasyqi] berkata, telah menceritakan kepada kami [Wahb bin Sa'id bin Athiah As Salami] berkata, telah menceritakan kepada kami ['Abdurrahman bin Zaid bin Aslam] dari [Bapaknya] dari [Abdullah bin Umar] ia berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Berikanlah upah kepada pekerja sebelum kering keringatnya.\""},"2400":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ الْمُصَفَّى الْحِمْصِيُّ حَدَّثَنَا بَقِيَّةُ بْنُ الْوَلِيدِ عَنْ مَسْلَمَةَ بْنِ عَلِيٍّ عَنْ سَعِيدِ بْنِ أَبِي أَيُّوبَ عَنْ الْحَارِثِ بْنِ يَزِيدَ عَنْ عُلَيِّ بْنِ رَبَاحٍ قَالَ سَمِعْتُ عُتْبَةَ بْنَ النُّدَّرِ يَقُولُكُنَّا عِنْدَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَرَأَ طس حَتَّى إِذَا بَلَغَ قِصَّةَ مُوسَى قَالَ إِنَّ مُوسَى صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ آجَرَ نَفْسَهُ ثَمَانِيَ سِنِينَ أَوْ عَشْرًا عَلَى عِفَّةِ فَرْجِهِ وَطَعَامِ بَطْنِهِ","id":"Telah menceritakan kepada kami [Muhammad bin Mushaffa Al Himshi] berkata, telah menceritakan kepada kami [Baqiyyah bin Al Walid] dari [Maslamah bin Ali] dari [Sa'id bin Abu Ayyub] dari [Al Harits bin Yazid] dari ['Ulay bin Rabah] ia berkata; Aku mendengar [Utbah bin An Nudar] berkata, \"Ketika kami berada di sisi Rasulullah shallallahu 'alaihi wasallam, beliau membaca surat Thaa Siin. Dan ketika bacaan beliau sampai kisah Musa, beliau bersabda: \"Sesungguhnya Musa memperkerjakan dirinya selama delapan tahun atau sepuluh tahun demi menjaga kehormatan kemaluannya dan makanan untuk ia makan.\""},"2401":{"ar":"حَدَّثَنَا أَبُو عُمَرَ حَفْصُ بْنُ عَمْرٍو حَدَّثَنَا عَبْدُ الرَّحْمَنِ بْنُ مَهْدِيٍّ حَدَّثَنَا سَلِيمُ بْنُ حَيَّانَ سَمِعْتُ أَبِي يَقُولُ سَمِعْتُ أَبَا هُرَيْرَةَ يَقُولُنَشَأْتُ يَتِيمًا وَهَاجَرْتُ مِسْكِينًا وَكُنْتُ أَجِيرًا لِابْنَةِ غَزْوَانَ بِطَعَامِ بَطْنِي وَعُقْبَةِ رِجْلِي أَحْطِبُ لَهُمْ إِذَا نَزَلُوا وَأَحْدُو لَهُمْ إِذَا رَكِبُوا فَالْحَمْدُ لِلَّهِ الَّذِي جَعَلَ الدِّينَ قِوَامًا وَجَعَلَ أَبَا هُرَيْرَةَ إِمَامًا","id":"Telah menceritakan kepada kami [Abu Umar Hafsh bin Amru] berkata, telah menceritakan kepada kami ['Abdurrahman bin Mahdi] berkata, telah menceritakan kepada kami [Salim bin Hayyan] berkata; aku mendengar [Ayahku] berkata; aku mendengar [Abu Hurairah] berkata, \"Aku tumbuh dalam keadaan yatim dan aku hijrah dalam keadaan miskin. Aku bekerja sebagai tukang upah untuk anak perempuannya Ghazwan dengan diupah makanan pengisi perutku, siang malam kakiku mengumpulkan kayu bakar untuk mereka saat mereka singgah, dan menggiring hewan saat mereka mengendarainya. Maka segala puji bagi Allah yang telah menjadikan agama ini lurus dan menjadikan Abu Hurairah seorang imam.\""},"2402":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ عَبْدِ الْأَعْلَى الصَّنْعَانِيُّ حَدَّثَنَا الْمُعْتَمِرُ بْنُ سُلَيْمَانَ عَنْ أَبِيهِ عَنْ حَنَشٍ عَنْ عِكْرِمَةَ عَنْ ابْنِ عَبَّاسٍ قَالَأَصَابَ نَبِيَّ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ خَصَاصَةٌ فَبَلَغَ ذَلِكَ عَلِيًّا فَخَرَجَ يَلْتَمِسُ عَمَلًا يُصِيبُ فِيهِ شَيْئًا لِيُقِيتَ بِهِ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَأَتَى بُسْتَانًا لِرَجُلٍ مِنْ الْيَهُودِ فَاسْتَقَى لَهُ سَبْعَةَ عَشَرَ دَلْوًا كُلُّ دَلْوٍ بِتَمْرَةٍ فَخَيَّرَهُ الْيَهُودِيُّ مِنْ تَمْرِهِ سَبْعَ عَشَرَةَ عَجْوَةً فَجَاءَ بِهَا إِلَى نَبِيِّ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ","id":"Telah menceritakan kepada kami [Muhammad bin Abdul A'la Ash Shan'ani] berkata, telah menceritakan kepada kami [Al Mu'tamir bin Sulaiman] dari [Bapaknya] dari [Hanasy] dari [Ikrimah] dari [Ibnu Abbas] ia berkata, \"Rasulullah shallallahu 'alaihi wasallam tertimpa kekurangan, dan sampailah berita itu kepada Ali. Kemudian Ali keluar mencari kerja dan menghasilkan sesuatu hingga ia dapat memberi makanan kepada Rasulullah shallallahu 'alaihi wasallam. Lalu ia datang ke sebuah kebun milik yahudi, dia menyiram tanamannya sebanyak tujuh belas ember dengan perhitungan setiap ember satu kurma. Orang yahudi itu kemudian memilihkan tujuh belas kurma Ajwah untuknya, setelah itu dia membawa kurma tersebut kepada Nabi shallallahu 'alaihi wasallam.\""},"2403":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ بَشَّارٍ حَدَّثَنَا عَبْدُ الرَّحْمَنِ حَدَّثَنَا سُفْيَانُ عَنْ أَبِي إِسْحَقَ عَنْ أَبِي حَيَّةَ عَنْ عَلِيٍّ قَالَكُنْتُ أَدْلُو الدَّلْوَ بِتَمْرَةٍ وَأَشْتَرِطُ أَنَّهَا جَلْدَةٌ","id":"Telah menceritakan kepada kami [Muhammad bin Basysyar] berkata, telah menceritakan kepada kami ['Abdurrahman] berkata, telah menceritakan kepada kami [Sufyan] dari [Abu Ishaq] dari [Abu Hayyah] dari [Ali] ia berkata, \"Aku menimba ember dengan balasan kurma, dan aku membuat persyaratan agar kurma yang diberikan itu kurma yang bagus.\""},"2404":{"ar":"حَدَّثَنَا عَلِيُّ بْنُ الْمُنْذِرِ حَدَّثَنَا مُحَمَّدُ بْنُ فُضَيْلٍ حَدَّثَنَا عَبْدُ اللَّهِ بْنُ سَعِيدٍ عَنْ جَدِّهِ عَنْ أَبِي هُرَيْرَةَ قَالَجَاءَ رَجُلٌ مِنْ الْأَنْصَارِ فَقَالَ يَا رَسُولَ اللَّهِ مَا لِي أَرَى لَوْنَكَ مُنْكَفِئًا قَالَ الْخَمْصُ فَانْطَلَقَ الْأَنْصَارِيُّ إِلَى رَحْلِهِ فَلَمْ يَجِدْ فِي رَحْلِهِ شَيْئًا فَخَرَجَ يَطْلُبُ فَإِذَا هُوَ بِيَهُودِيٍّ يَسْقِي نَخْلًا فَقَالَ الْأَنْصَارِيُّ لِلْيَهُودِيِّ أَسْقِي نَخْلَكَ قَالَ نَعَمْ قَالَ كُلُّ دَلْوٍ بِتَمْرَةٍ وَاشْتَرَطَ الْأَنْصَارِيُّ أَنْ لَا يَأْخُذَ خَدِرَةً وَلَا تَارِزَةً وَلَا حَشَفَةً وَلَا يَأْخُذَ إِلَّا جَلْدَةً فَاسْتَقَى بِنَحْوٍ مِنْ صَاعَيْنِ فَجَاءَ بِهِ إِلَى النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ","id":"Telah menceritakan kepada kami [Ali Ibnul Mundzir] berkata, telah menceritakan kepada kami [Muhammad bin Fudlail] berkata, telah menceritakan kepada kami [Abdullah bin Sa'id] dari [Kakeknya] dari [Abu Hurairah] ia berkata, \"Seorang sahabat Anshar berkata, \"Wahai Rasulullah, kenapa aku melihatmu pucat?\" Beliau menjawab: \"Aku lapar.\" Sahabat Anshar itu kemudian pergi ke rumahnya tetapi ia juga tidak mendapatkan apa-apa di rumahnya. Kemudian ia pergi mencari (makan), lalu ia menjumpai seorang yahudi yang sedang menyiram kurmanya, lantas sahabat Anshar itu berkata kepada si yahudi, \"Bagaimana jika aku yang menyirami kurmamu?\" yahudi itu menjawab, \"Silahkan.\" Ia berkata lagi, \"Setiap ember dengan satu biji kurma.\" Dan sahabat Anshar itu memberikan syarat bahwa ia tidak ingin mengambil kurma yang keras, kering, dan rusak. Ia hanya mau mengambil kurma yang bagus. Kemudian ia menyiram sampai kira-kira mendapatkan dua gantang kurma, setelah itu ia datang menemui Nabi shallallahu 'alaihi wasallam dengan membawa kurma.\""},"2405":{"ar":"حَدَّثَنَا هَنَّادُ بْنُ السَّرِيِّ حَدَّثَنَا أَبُو الْأَحْوَصِ عَنْ طَارِقِ بْنِ عَبْدِ الرَّحْمَنِ عَنْ سَعِيدِ بْنِ الْمُسَيَّبِ عَنْ رَافِعِ بْنِ خَدِيجٍ قَالَنَهَى رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَنْ الْمُحَاقَلَةِ وَالْمُزَابَنَةِ وَقَالَ إِنَّمَا يَزْرَعُ ثَلَاثَةٌ رَجُلٌ لَهُ أَرْضٌ فَهُوَ يَزْرَعُهَا وَرَجُلٌ مُنِحَ أَرْضًا فَهُوَ يَزْرَعُ مَا مُنِحَ وَرَجُلٌ اسْتَكْرَى أَرْضًا بِذَهَبٍ أَوْ فِضَّةٍ","id":"Telah menceritakan kepada kami [Hannad bin As Sari] berkata, telah menceritakan kepada kami [Abu Al Ahwash] dari [Thariq bin 'Abdurrahman] dari [Sa'id bin Al Musayyab] dari [Rafi' bin Khadij] ia berkata, \"Rasulullah shallallahu 'alaihi wasallam melarang praktik Muhaqalah dan Muzabanah. Ia berkata lagi, \"Orang yang bercocok tanam itu ada tiga; seorang laki-laki yang mempunyai sebidang tanah kemudian ia menanaminya, dan seorang laki-laki yang diberi sebidang tanah kemudian ia menanaminya, serta seorang laki-laki yang menyewakan tanahnya dengan imbalan emas atau perak.\""},"2406":{"ar":"حَدَّثَنَا هِشَامُ بْنُ عَمَّارٍ وَمُحَمَّدُ بْنُ الصَّبَّاحِ قَالَا حَدَّثَنَا سُفْيَانُ بْنُ عُيَيْنَةَ عَنْ عَمْرِو بْنِ دِينَارٍ قَالَ سَمِعْتُ ابْنَ عُمَرَ يَقُولُكُنَّا نُخَابِرُ وَلَا نَرَى بِذَلِكَ بَأْسًا حَتَّى سَمِعْنَا رَافِعَ بْنَ خَدِيجٍ يَقُولُ نَهَى رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَنْهُ فَتَرَكْنَاهُ لِقَوْلِهِ","id":"Telah menceritakan kepada kami [Hisyam bin Ammar] dan [Muhammad bin Ash Shabbah] keduanya berkata; telah menceritakan kepada kami [Sufyan bin Uyainah] dari [Amru bin Dinar] ia berkata; Aku mendengar [Ibnu Umar] berkata, \"Kami melakukan perjanjian pengolahan tanah dengan bagi hasil, dan kami tidak mempermasalahkan hal itu hingga kami mendengar [Rafi' bin Khadij] mengatakan, 'Rasulullah shallallahu 'alaihi wasallam telah melarangnya', maka kami pun meninggalkannya karena perkataannya itu.\""},"2407":{"ar":"حَدَّثَنَا عَبْدُ الرَّحْمَنِ بْنُ إِبْرَاهِيمَ الدِّمَشْقِيُّ حَدَّثَنَا الْوَلِيدُ بْنُ مُسْلِمٍ حَدَّثَنَا الْأَوْزَاعِيُّ حَدَّثَنِي عَطَاءٌ قَالَ سَمِعْتُ جَابِرَ بْنَ عَبْدِ اللَّهِ يَقُولُكَانَتْ لِرِجَالٍ مِنَّا فُضُولُ أَرَضِينَ يُؤَاجِرُونَهَا عَلَى الثُّلُثِ وَالرُّبُعِ فَقَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَنْ كَانَتْ لَهُ فُضُولُ أَرْضِينَ فَلْيَزْرَعْهَا أَوْ لِيُزْرِعْهَا أَخَاهُ فَإِنْ أَبَى فَلْيُمْسِكْ أَرْضَهُ","id":"Telah menceritakan kepada kami ['Abdurrahman bin Ibrahim Ad Dimasyqi] berkata, telah menceritakan kepada kami [Al Walid bin Muslim] berkata, telah menceritakan kepada kami [Al Auza'i] berkata, telah menceritakan kepadaku ['Atha] ia berkata, \"Aku mendengar [Jabir bin Abdullah] berkata, \"Beberapa di antara kami memiliki kelebihan lahan tanah hingga mereka menyewakannya kepada orang lain dengan sistem pembagian sepertiga atau seperempat. Maka Nabi shallallahu 'alaihi wasallam bersabda: \"Barangsiapa memiliki kelebihan lahan tanah hendaklah ia menanaminya, atau ia suruh saudaranya untuk menanaminya, namun jika menolak hendaklah ia tahan tanahnya.\""},"2408":{"ar":"حَدَّثَنَا إِبْرَاهِيمُ بْنُ سَعِيدٍ الْجَوْهَرِيُّ حَدَّثَنَا أَبُو تَوْبَةَ الرَّبِيعُ بْنُ نَافِعٍ حَدَّثَنَا مُعَاوِيَةُ بْنُ سَلَّامٍ عَنْ يَحْيَى بْنِ أَبِي كَثِيرٍ عَنْ أَبِي سَلَمَةَ عَنْ أَبِي هُرَيْرَةَ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَنْ كَانَتْ لَهُ أَرْضٌ فَلْيَزْرَعْهَا أَوْ لِيَمْنَحْهَا أَخَاهُ فَإِنْ أَبَى فَلْيُمْسِكْ أَرْضَهُ","id":"Telah menceritakan kepada kami [Ibrahim bin Sa'id Al Jauhari] berkata, telah menceritakan kepada kami [Abu Taubah Ar Rabi' bin Nafi'] berkata, telah menceritakan kepada kami [Mu'awiyah bin Salam] dari [Yahya bin Abu Katsir] dari [Abu Salamah] dari [Abu Hurairah] ia berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Barangsiapa memiliki sebidang tanah hendaklah ia menanaminya atau ia berikan pengolahannya kepada saudaranya, namun jika menolak hendaklah ia tahan tanahnya.\""},"2409":{"ar":"حَدَّثَنَا أَبُو كُرَيْبٍ حَدَّثَنَا عَبْدَةُ بْنُ سُلَيْمَانَ وَأَبُو أُسَامَةَ وَمُحَمَّدُ بْنُ عُبَيْدٍ عَنْ عُبَيْدِ اللَّهِ أَوْ قَالَ عَبْدِ اللَّهِ بْنِ عُمَرَ عَنْ نَافِعٍ عَنْ ابْنِ عُمَرَأَنَّهُ كَانَ يُكْرِي أَرْضًا لَهُ مَزَارِعًا فَأَتَاهُ إِنْسَانٌ فَأَخْبَرَهُ عَنْ رَافِعِ بْنِ خَدِيجٍ أَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ نَهَى عَنْ كِرَاءِ الْمَزَارِعِ فَذَهَبَ ابْنُ عُمَرَ وَذَهَبْتُ مَعَهُ حَتَّى أَتَاهُ بِالْبَلَاطِ فَسَأَلَهُ عَنْ ذَلِكَ فَأَخْبَرَهُ أَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ نَهَى عَنْ كِرَاءِ الْمَزَارِعِفَتَرَكَ عَبْدُ اللَّهِ كِرَاءَهَا","id":"Telah menceritakan kepada kami [Abu Kuraib] berkata, telah menceritakan kepada kami [Abdah bin Sulaiman] dan [Abu Usamah] dan [Muhammad bin Ubaid] dari [Ubaidullah] atau ia mengatakan; Abdullah bin Umar dari [Nafi'] dari [Ibnu Umar] Bahwasanya ia pernah menyewakan tanah miliknya kepada orang lain, lalu seorang laki-laki mendatanginya dan mengabarkan kepadanya sebuah hadits dari [Rafi' bin Khadij], bahwa Rasulullah shallallahu 'alaihi wasallam melarang untuk menyewakan tanah. Ibnu Umar dan aku pergi menemui Rafi' bin Khadij di suatu tempat yang bernama Balath, Ibnu Umar kemudian menanyakan perihal hadits tersebut kepadanya. Rafi' bin Khadij lantas mengabarkan bahwa Rasulullah shallallahu 'alaihi wasallam melarang untuk menyewakan tanah, maka Ibnu Umar pun menghentikan penyewaan tanahnya.\""},"2410":{"ar":"حَدَّثَنَا عَمْرُو بْنُ عُثْمَانَ بْنِ سَعِيدِ بْنِ كَثِيرِ بْنِ دِينَارٍ الْحِمْصِيُّ حَدَّثَنَا ضَمْرَةُ بْنُ رَبِيعَةَ عَنْ ابْنِ شَوْذَبٍ عَنْ مَطَرٍ عَنْ عَطَاءٍ عَنْ جَابِرِ بْنِ عَبْدِ اللَّهِ قَالَخَطَبَنَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ مَنْ كَانَتْ لَهُ أَرْضٌ فَلْيَزْرَعْهَا أَوْ لِيُزْرِعْهَا وَلَا يُؤَاجِرْهَا","id":"Telah menceritakan kepada kami [Amru bin Utsman bin Sa'id bin Katsir bin Dinar Al Himshi] berkata, telah menceritakan kepada kami [Dlamrah bin Rabi'ah] dari [Ibnu Syaudzab] dari [Mathar] dari ['Atha] dari [Jabir bin Abdullah] ia berkata; Rasulullah shallallahu 'alaihi wasallam berkhutbah di hadapan kami, beliau bersabda: \"Barangsiapa memiliki tanah hendaklah ia tanami atau ia serahkan pengolahannya kepada saudaranya, dan jangan menyewakannya.\""},"2411":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ يَحْيَى حَدَّثَنَا مُطَرِّفُ بْنُ عَبْدِ اللَّهِ حَدَّثَنَا مَالِكٌ عَنْ دَاوُدَ بْنِ الْحُصَيْنِ عَنْ أَبِي سُفْيَانَ مَوْلَى ابْنِ أَبِي أَحْمَدَ أَنَّهُ أَخْبَرَهُ أَنَّهُ سَمِعَ أَبَا سَعِيدٍ الْخُدْرِيَّ يَقُولُنَهَى رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَنْ الْمُحَاقَلَةِ وَالْمُحَاقَلَةُ اسْتِكْرَاءُ الْأَرْضِ","id":"Telah menceritakan kepada kami [Muhammad bin Yahya] berkata, telah menceritakan kepada kami [Mutharrif bin Abdullah] berkata, telah menceritakan kepada kami [Malik] dari [Dawud bin Al Hushain] dari [Abu Sufyan] mantan budak Ibnu Abu Ahmad, ia mengabarkan kepadanya bahwasanya ia pernah mendengar [Abu Sa'id Al Khudri] berkata, \"Rasulullah shallallahu 'alaihi wasallam melarang dari Muhaqalah, dan Muhaqalah adalah menyewakan tanah.\""},"2412":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ رُمْحٍ أَنْبَأَنَا اللَّيْثُ بْنُ سَعْدٍ عَنْ عَبْدِ الْمَلِكِ بْنِ عَبْدِ الْعَزِيزِ بْنِ جُرَيْجٍ عَنْ عَمْرِو بْنِ دِينَارٍ عَنْ طَاوُسٍ عَنْ ابْنِ عَبَّاسٍأَنَّهُ لَمَّا سَمِعَ إِكْثَارَ النَّاسِ فِي كِرَاءِ الْأَرْضِ قَالَ سُبْحَانَ اللَّهِ إِنَّمَا قَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَلَا مَنَحَهَا أَحَدُكُمْ أَخَاهُ وَلَمْ يَنْهَ عَنْ كِرَائِهَا","id":"Telah menceritakan kepada kami [Muhammad bin Rumh] berkata, telah memberitakan kepada kami [Al Laits bin Sa'd] dari [Abdul Malik bin Abdul Aziz bin Juraij] dari [Amru bin Dinar] dari [Thawus] dari [Ibnu Abbas] Bahwasanya ketika ia mendengar banyak manusia yang menyewakan tanah, ia berkata, \"Subhanaallahu, hanyasanya Rasulullah shallallahu 'alaihi wasallam bersabda: 'Kenapa salah seorang dari kalian tidak memberikannya kepada saudaranya, ' beliau tidak melarang untuk menyewakannya.\""},"2413":{"ar":"حَدَّثَنَا الْعَبَّاسُ بْنُ عَبْدِ الْعَظِيمِ الْعَنْبَرِيُّ حَدَّثَنَا عَبْدُ الرَّزَّاقِ أَنْبَأَنَا مَعْمَرٌ عَنْ ابْنِ طَاوُسٍ عَنْ أَبِيهِ عَنْ ابْنِ عَبَّاسٍ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَأَنْ يَمْنَحَ أَحَدُكُمْ أَخَاهُ أَرْضَهُ خَيْرٌ لَهُ مِنْ أَنْ يَأْخُذَ عَلَيْهَا كَذَا وَكَذَا لِشَيْءٍ مَعْلُومٍ فَقَالَ ابْنُ عَبَّاسٍ هُوَ الْحَقْلُ وَهُوَ بِلِسَانِ الْأَنْصَارِ الْمُحَاقَلَةُ","id":"Telah menceritakan kepada kami [Al Abbas bin Abdul Azhim Al 'Anbari] berkata, telah menceritakan kepada kami [Abdurrazaq] berkata, telah memberitakan kepada kami [Ma'mar] dari [Ibnu Thawus] dari [Bapaknya] dari [Ibnu Abbas] ia berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Sekiranya salah seorang dari kalian menyerahkan pengolahan tanahnya kepada saudaranya, maka itu lebih baik baginya daripada ia meminta bagian darinya sekian dan sekian.\" Ibnu Abbas berkata, \"Seperti itu disebut Al Hagl, sementara orang-orang Anshar menyebutnya Muhaqalah.\""},"2414":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ الصَّبَّاحِ حَدَّثَنَا سُفْيَانُ بْنُ عُيَيْنَةَ عَنْ يَحْيَى بْنِ سَعِيدٍ عَنْ حَنْظَلَةَ بْنِ قَيْسٍ قَالَ سَأَلْتُ رَافِعَ بْنَ خَدِيجٍ قَالَكُنَّا نُكْرِي الْأَرْضَ عَلَى أَنَّ لَكَ مَا أَخْرَجَتْ هَذِهِ وَلِي مَا أَخْرَجَتْ هَذِهِ فَنُهِينَا أَنْ نُكْرِيَهَا بِمَا أَخْرَجَتْ وَلَمْ نُنْهَ أَنْ نُكْرِيَ الْأَرْضَ بِالْوَرِقِ","id":"Telah menceritakan kepada kami [Muhammad bin Ash Shabbah] berkata, telah menceritakan kepada kami [Sufyan bin Uyainah] dari [Yahya bin Sa'id] dari [Hanzhalah bin Qais] ia berkata; Aku pernah bertanya kepada [Rafi' bin Khadij] (tentang sewa), ia berkata, \"Kami menyewakan tanah dengan perhitungan bahwa bagianmu adalah apa yang keluar dari bagian ini, dan bagianku adalah apa yang keluar dari bagian ini. Namun kami dilarang untuk menyewakan dengan imbalan hasil panen, dan kami tidak dilarang untuk menyewakan tanah dengan imbalan uang.\""},"2415":{"ar":"حَدَّثَنَا عَبْدُ الرَّحْمَنِ بْنُ إِبْرَاهِيمَ الدِّمَشْقِيُّ حَدَّثَنَا الْوَلِيدُ بْنُ مُسْلِمٍ حَدَّثَنَا الْأَوْزَاعِيُّ حَدَّثَنِي أَبُو النَّجَاشِيِّ أَنَّهُ سَمِعَ رَافِعَ بْنَ خَدِيجٍ يُحَدِّثُ عَنْ عَمِّهِ ظُهَيْرٍ قَالَنَهَانَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَنْ أَمْرٍ كَانَ لَنَا رَافِقًا فَقُلْتُ مَا قَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَهُوَ حَقٌّ فَقَالَ قَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَا تَصْنَعُونَ بِمَحَاقِلِكُمْ قُلْنَا نُؤَاجِرُهَا عَلَى الثُّلُثِ وَالرُّبُعِ وَالْأَوْسُقِ مِنْ الْبُرِّ وَالشَّعِيرِ فَقَالَ فَلَا تَفْعَلُوا ازْرَعُوهَا أَوْ أَزْرِعُوهَا","id":"Telah menceritakan kepada kami ['Abdurrahman bin Ibrahim Ad Dimasyqi] berkata, telah menceritakan kepada kami [Al Walid bin Muslim] berkata, telah menceritakan kepada kami [Al Auza'i] berkata, telah menceritakan kepadaku [Abu An Najasyi] Bahwasannya ia mendengar [Rafi' bin Khadij] menceritakan dari pamannya [Zhuhair] ia berkata, \"Rasulullah shallallahu 'alaihi wasallam melarang kami melakukan suatu perkara yang menurut kami remeh.\" Aku berkata, \"Sesuatu yang dikatakan Rasulullah shallallahu 'alaihi wasallam adalah benar! \" lalu ia berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Apa yang kalian lakukan dengan lahan-lahan kalian?\" kami menjawab, \"Kami sewakan dengan bagi hasil sepertiga, atau seperempat, atau beberapa wasaq gandum dan tepung.\" Beliau bersabda: \"Janganlah kalian lakukan, tapi tanamilah.\""},"2416":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ يَحْيَى أَنْبَأَنَا عَبْدُ الرَّزَّاقِ أَنْبَأَنَا الثَّوْرِيُّ عَنْ مَنْصُورٍ عَنْ مُجَاهِدٍ عَنْ أُسَيْدِ بْنِ ظُهَيْرٍ ابْن أَخِي رَافِعِ بْنِ خَدِيجٍ عَنْ رَافِعِ بْنِ خَدِيجٍ قَالَكَانَ أَحَدُنَا إِذَا اسْتَغْنَى عَنْ أَرْضِهِ أَعْطَاهَا بِالثُّلُثِ وَالرُّبُعِ وَالنِّصْفِ وَاشْتَرَطَ ثَلَاثَ جَدَاوِلَ وَالْقُصَارَةَ وَمَا يَسْقِي الرَّبِيعُ وَكَانَ الْعَيْشُ إِذْ ذَاكَ شَدِيدًا وَكَانَ يَعْمَلُ فِيهَا بِالْحَدِيدِ وَبِمَا شَاءَ اللَّهُ وَيُصِيبُ مِنْهَا مَنْفَعَةً فَأَتَانَا رَافِعُ بْنُ خَدِيجٍ فَقَالَ إِنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ نَهَاكُمْ عَنْ أَمْرٍ كَانَ لَكُمْ نَافِعًا وَطَاعَةُ اللَّهِ وَطَاعَةُ رَسُولِهِ أَنْفَعُ لَكُمْ إِنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَنْهَاكُمْ عَنْ الْحَقْلِ وَيَقُولُ مَنْ اسْتَغْنَى عَنْ أَرْضِهِ فَلْيَمْنَحْهَا أَخَاهُ أ��وْ لِيَدَعْ","id":"Telah menceritakan kepada kami [Muhammad bin Yahya] berkata, telah memberitakan kepada kami [Abdurrazaq] berkata, telah memberitakan kepada kami [Ats Tsauri] dari [Manshur] dari [Mujahid] dari [Usaid bin Zhuhair] -putra saudara Rafi' bin Khadij- dari [Rafi' bin Khadij] ia berkata; \"Salah seorang dari kami apabila mempunyai kelebihan tanah, biasa menyuruh orang lain untuk menggarapnya dengan cara bagi hasil sepertiga, seperempat atau setengahnya. Hal itu terjadi dengan syarat si pemilik tanah mempuyai tiga sungai kecil, dan bibit, serta mempunyai anak sungai yang dapat mengairinya. Kehidupan pada saat itu cukup sulit, hingga pekerjaannya pun menggunakan besi, dan apa saja yang sudah Allah kehendaki yang kemudian dapat menghasilkan suatu manfaat bagi kami. Lalu kami mendatangi Rafi' bin Khudaij, ia pun berkata; Sesungguhnya Rasulullah shallallahu 'alaihi wasallam melarang kalian dari suatu perkara, meskipun hal itu memberi manfaat bagi kalian. Keta'atan kepada Allah dan RasulNya, itu lebih bermanfa'at bagi kalian. Sesungguhnya Rasulullah shallallahu 'alaihi wasallam melarang kalian dari Al Haqlu (menjual makanan yang masih berada di dalam tanah dengan tukar gandum). Beliau bersabda: \"Barang siapa yang mempunyai kelebihan tanah, maka hendaklah memberikannya kepada saudaranya atau membiarkannya.\""},"2417":{"ar":"حَدَّثَنَا يَعْقُوبُ بْنُ إِبْرَاهِيمَ الدَّوْرَقِيُّ حَدَّثَنَا إِسْمَعِيلُ ابْنُ عُلَيَّةَ حَدَّثَنَا عَبْدُ الرَّحْمَنِ بْنُ إِسْحَقَ حَدَّثَنِي أَبُو عُبَيْدَةَ بْنُ مُحَمَّدِ بْنِ عَمَّارِ بْنِ يَاسِرٍ عَنْ الْوَلِيدِ بْنِ أَبِي الْوَلِيدِ عَنْ عُرْوَةَ بْنِ الزُّبَيْرِ قَالَ قَالَ زَيْدُ بْنُ ثَابِتٍيَغْفِرُ اللَّهُ لِرَافِعِ بْنِ خَدِيجٍ أَنَا وَاللَّهِ أَعْلَمُ بِالْحَدِيثِ مِنْهُ إِنَّمَا أَتَى رَجُلَانِ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَقَدْ اقْتَتَلَا فَقَالَ إِنْ كَانَ هَذَا شَأْنُكُمْ فَلَا تُكْرُوا الْمَزَارِعَ فَسَمِعَ رَافِعُ بْنُ خَدِيجٍ قَوْلَهُ فَلَا تُكْرُوا الْمَزَارِعَ","id":"Telah menceritakan kepada kami [Ya'qub bin Ibrahim Ad Dauraqi] berkata, telah menceritakan kepada kami [Isma'il bin Ulayyah] berkata, telah menceritakan kepada kami ['Abdurrahman bin Ishaq] berkata, telah menceritakan kepadaku [Abu Ubaidah bin Muhammad bin Ammar bin Yasir] dari [Al Walid bin Abu Al Walid] dari [Urwah bin Az Zubair] ia berkata; [Zaid bin Tsabit] berkata, \"Semoga Allah mengampuni Rafi' bin Khadij. Demi Allah, aku lebih tahu tentang hadits dari pada dia! Bahwasanya pernah datang dua orang laki-laki kepada Nabi shallallahu 'alaihi wasallam, dan mereka hampir-hampir saling bunuh. Beliau lalu bersabda: \"Jika kalian seperti ini, maka janganlah kalian menyewakan tanah.\" Lalu Rafi' bin Khadij hanya mendengar ucapan beliau: 'maka janganlah kalian menyewakan tanah'.\""},"2418":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ الصَّبَّاحِ أَنْبَأَنَا سُفْيَانُ بْنُ عُيَيْنَةَ عَنْ عَمْرِو بْنِ دِينَارٍ قَالَ قُلْتُ لِطَاوُسٍ يَا أَبَا عَبْدِ الرَّحْمَنِ لَوْ تَرَكْتَ هَذِهِ الْمُخَابَرَةَ فَإِنَّهُمْ يَزْعُمُونَ أَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ نَهَى عَنْهُ فَقَالَ أَيْ عَمْرُو إِنِّي أُعِينُهُمْ وَأُعْطِيهِمْ وَإِنَّ مُعَاذَ بْنَ جَبَلٍ أَخَذَ النَّاسَ عَلَيْهَا عِنْدَنَا وَإِنَّ أَعْلَمَهُمْ يَعْنِي ابْنَ عَبَّاسٍ أَخْبَرَنِيأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَمْ يَنْهَ عَنْهَا وَلَكِنْ قَالَ لَأَنْ يَمْنَحَ أَحَدُكُمْ أَخَاهُ خَيْرٌ لَهُ مِنْ أَنْ يَأْخُذَ عَلَيْهَا أَجْرًا مَعْلُومًا","id":"Telah menceritakan kepada kami [Muhammad bin Ash Shabbah] berkata, telah memberitakan kepada kami [Sufyan bin Uyainah] dari [Amru bin Dinar] ia berkata; aku berkata kepada [Thawus], \"Wahai Abu 'Abdurrahman, sekiranya engkau tinggalkan Mukhabarah ini, sesungguhnya mereka pasti menganggap bahwa Rasulullah shallallahu 'alaihi wasallam telah melarang dari hal itu.\" Thawus berkata, \"Wahai Amru, aku hanya menolong mereka dan memberikan bagiannya kepada mereka. Mu'adz bin Jabal pun menganjurkan orang lain untuk melakukannya, sesungguhnya orang yang paling tahu di antara mereka, [Ibnu Abbas] mengabarkan kepadaku bahwa Rasulullah shallallahu 'alaihi wasallam tidak melarang dari hal itu, namun beliau bersabda: \"Sekiranya salah seorang dari kalian menyerahkan (pengelolaan tanahnya) kepada saudaranya, maka itu lebih baik baginya daripada meminta bagian hasil tertentu.\" "},"2419":{"ar":"حَدَّثَنَا أَحْمَدُ بْنُ ثَابِتٍ الْجَحْدَرِيُّ حَدَّثَنَا عَبْدُ الْوَهَّابِ عَنْ خَالِدٍ عَنْ مُجَاهِدٍ عَنْ طَاوُسٍأَنَّ مُعَاذَ بْنَ جَبَلٍ أَكْرَى الْأَرْضَ عَلَى عَهْدِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَأَبِي بَكْرٍ وَعُمَرَ وَعُثْمَانَ عَلَى الثُّلُثِ وَالرُّبُعِ فَهُوَ يُعْمَلُ بِهِ إِلَى يَوْمِكَ هَذَا","id":"Telah menceritakan kepada kami [Ahmad bin Tsabit Al Jahdari] berkata, telah menceritakan kepada kami [Abdul Wahhab] dari [Khalid] dari [Mujahid] dari [Thawus] berkata, \" [Mu'adz bin Jabal] pernah menyewakan tanah pada masa Rasulullah shallallahu 'alaihi wasallam, demikian juga Abu Bakar, Umar dan Utsman dengan bagi hasil sepertiga atau seperempat, dan hal itu masih dilakukannya sampai harimu ini.\""},"2420":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ خَلَّادٍ الْبَاهِلِيُّ وَمُحَمَّدُ بْنُ إِسْمَعِيلَ قَالَا حَدَّثَنَا وَكِيعٌ عَنْ سُفْيَانَ عَنْ عَمْرِو بْنِ دِينَارٍ عَنْ طَاوُسٍ قَالَ قَالَ ابْنُ عَبَّاسٍإِنَّمَا قَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَأَنْ يَمْنَحَ أَحَدُكُمْ أَخَاهُ الْأَرْضَ خَيْرٌ لَهُ مِنْ أَنْ يَأْخُذَ خَرَاجًا مَعْلُومًا","id":"Telah menceritakan kepada kami [Abu Bakr bin Khallad Al Bahili] dan [Muhammad bin Isma'il] keduanya berkata; telah menceritakan kepada kami [Waki'] dari [Sufyan] dari [Amru bin Dinar] dari [Thawus] ia berkata, [Ibnu Abbas] berkata; \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Sekiranya salah seorang dari kaliam menyerahkan (pengelolaan tanahnya) kepada saudaranya, maka itu lebih baik baginya daripada meminta bagian tertentu.\""},"2421":{"ar":"حَدَّثَنَا حُمَيْدُ بْنُ مَسْعَدَةَ حَدَّثَنَا خَالِدُ بْنُ الْحَارِثِ حَدَّثَنَا سَعِيدُ بْنُ أَبِي عَرُوبَةَ عَنْ يَعْلَى بْنِ حَكِيمٍ عَنْ سُلَيْمَانَ بْنِ يَسَارٍ عَنْ رَافِعِ بْنِ خَدِيجٍ قَالَكُنَّا نُحَاقِلُ عَلَى عَهْدِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَزَعَمَ أَنَّ بَعْضَ عُمُومَتِهِ أَتَاهُمْ فَقَالَ قَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَنْ كَانَتْ لَهُ أَرْضٌ فَلَا يُكْرِيهَا بِطَعَامٍ مُسَمَّى","id":"Telah menceritakan kepada kami [Humaid bin Mas'adah] berkata, telah menceritakan kepada kami [Khalid bin Al Harits] berkata, telah menceritakan kepada kami [Sa'id bin Abu Arubah] dari [Ya'la bin Hakim] dari [Sulaiman bin Yasar] dari [Rafi' bin Khadij] ia berkata, \"Pada masa Rasulullah shallallahu 'alaihi wasallam kami menyewakan tanah, \" lalu ia mengkalim bahwa sebagian dari paman-pamannya mendatanginya dan berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Barangsiapa memiliki tanah, maka janganlah menyewakannya dengan ditukar makanan yang telah ditentukan.\""},"2422":{"ar":"حَدَّثَنَا عَبْدُ اللَّهِ بْنُ عَامِرِ بْنِ زُرَارَةَ حَدَّثَنَا شَرِيكٌ عَنْ أَبِي إِسْحَقَ عَنْ عَطَاءٍ عَنْ رَافِعِ بْنِ خَدِيجٍ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَنْ زَرَعَ فِي أَرْضِ قَوْمٍ بِغَيْرِ إِذْنِهِمْ فَلَيْسَ لَهُ مِنْ الزَّرْعِ شَيْءٌ وَتُرَدُّ عَلَيْهِ نَفَقَتُهُ","id":"Telah menceritakan kepada kami [Abdullah bin Amir bin Zurarah] berkata, telah menceritakan kepada kami [Syarik] dari [Abu Ishaq] dari ['Atha] dari [Rafi' bin Khadij] ia berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Barangsiapa bercocok tanam di tanah milik orang lain tanpa seizin mereka, maka ia tidak akan mendapatkan apapun dari hasil tanaman, sementara modal tanamannya akan dikembalikan kepadanya.\""},"2423":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ الصَّبَّاحِ وَسَهْلُ بْنُ أَبِي سَهْلٍ وَإِسْحَقُ بْنُ مَنْصُورٍ قَالُوا حَدَّثَنَا يَحْيَى بْنُ سَعِيدٍ الْقَطَّانُ عَنْ عُبَيْدِ اللَّهِ بْنِ عُمَرَ عَنْ نَافِعٍ عَنْ ابْنِ عُمَرَأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَامَلَ أَهْلَ خَيْبَرَ بِالشَّطْرِ مِمَّا يَخْرُجُ مِنْ ثَمَرٍ أَوْ زَرْعٍ","id":"Telah menceritakan kepada kami [Muhammad bin Ash Shabbah] dan [Sahl bin Abu Sahl] dan [Ishaq bin Manshur] mereka berkata; telah menceritakan kepada kami [Yahya bin Sa'id Al Qaththan] dari [Ubaidullah bin Umar] dari [Nafi'] dari [Ibnu Umar] berkata, \"Rasulullah shallallahu 'alaihi wasallam memperkerjakan penduduk Khaibar dengan pembagian hasil lima puluh persen dari buah atau hasil panen.\""},"2424":{"ar":"حَدَّثَنَا إِسْمَعِيلُ بْنُ تَوْبَةَ حَدَّثَنَا هُشَيْمٌ عَنْ ابْنِ أَبِي لَيْلَى عَنْ الْحَكَمِ بْنِ عُتَيْبَةَ عَنْ مِقْسَمٍ عَنْ ابْنِ عَبَّاسٍأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَعْطَى خَيْبَرَ أَهْلَهَا عَلَى النِّصْفِ نَخْلِهَا وَأَرْضِهَا","id":"Telah menceritakan kepada kami [Isma'il bin Taubah] berkata, telah menceritakan kepada kami [Husyaim] dari [Ibnu Abu Laila] dari [Al Hakam bin Utaibah] dari [Miqsam] dari [Ibnu Abbas] berkata, \"Rasulullah shallallahu 'alaihi wasallam memberikan tanah Khaibar kepada penduduknya dengan bagi hasil setengah dari kurma dan tanahnya.\""},"2425":{"ar":"حَدَّثَنَا عَلِيُّ بْنُ الْمُنْذِرِ حَدَّثَنَا مُحَمَّدُ بْنُ فُضَيْلٍ عَنْ مُسْلِمٍ الْأَعْوَرِ عَنْ أَنَسِ بْنِ مَالِكٍ قَالَلَمَّا افْتَتَحَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ خَيْبَرَ أَعْطَاهَا عَلَى النِّصْفِ","id":"Telah menceritakan kepada kami [Ali bin Al Mundzir] berkata, telah menceritakan kepada kami [Muhammad bin Fudlail] dari [Muslim Al A'war] dari [Anas bin Malik] ia berkata, \"Ketika Rasulullah shallallahu 'alaihi wasallam berhasil membuka Khaibar beliau memberikan kepada mereka setengah dari hasil panen.\""},"2426":{"ar":"حَدَّثَنَا عَلِيُّ بْنُ مُحَمَّدٍ حَدَّثَنَا عُبَيْدُ اللَّهِ بْنُ مُوسَى عَنْ إِسْرَائِيلَ عَنْ سِمَاكٍ أَنَّهُ سَمِعَ مُوسَى بْنَ طَلْحَةَ بْنِ عُبَيْدِ اللَّهِ يُحَدِّثُ عَنْ أَبِيهِ قَالَمَرَرْتُ مَعَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي نَخْلٍ فَرَأَى قَوْمًا يُلَقِّحُونَ النَّخْلَ فَقَالَ مَا يَصْنَعُ هَؤُلَاءِ قَالُوا يَأْخُذُونَ مِنْ الذَّكَرِ فَيَجْعَلُونَهُ فِي الْأُنْثَى قَالَ مَا أَظُنُّ ذَلِكَ يُغْنِي شَيْئًا فَبَلَغَهُمْ فَتَرَكُوهُ فَنَزَلُوا عَنْهَا فَبَلَغَ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ إِنَّمَا هُوَ الظَّنُّ إِنْ كَانَ يُغْنِي شَيْئًا فَاصْنَعُوهُ فَإِنَّمَا أَنَا بَشَرٌ مِثْلُكُمْ وَإِنَّ الظَّنَّ يُخْطِئُ وَيُصِيبُ وَلَكِنْ مَا قُلْتُ لَكُمْ قَالَ اللَّهُ فَلَنْ أَكْذِبَ عَلَى اللَّهِ","id":"Telah menceritakan kepada kami [Ali bin Muhammad] berkata, telah menceritakan kepada kami [Ubaidullah bin Musa] dari [Isra'il] dari [Simak] Bahwasanya ia mendengar [Musa bin Thalhah bin Ubaidullah] menceritakan dari [Bapaknya] ia berkata, \"Aku bersama Rasulullah shallallahu 'alaihi wasallam melewati kebun kurma, beliau melihat orang-orang mengawinkan kurma. Lalu beliau bersabda: \"Apa yang mereka lakukan?\" para sahabat menjawab, \"Mereka mengambil yang laki-laki untuk digabungkan dengan yang perempuan.\" Beliau bersabda: \"Aku melihat bahwa perbuatan mereka tidak ada gunanya.\" Perkataan beliau itu sampai ke telinga mereka hingga mereka meninggalkannya sehingga hasil panen mereka pun gagal. Kejadian tersebut akhirnya juga sampai kepada Nabi shallallahu 'alaihi wasallam, beliau lalu bersabda: \"Ucapan itu hanya perkiraan, jika memang pengawinan itu bermanfaat hendaklah mereka melakukannya. Aku hanyalah manusia biasa sebagaimana kalian, perkiraan itu bisa benar dan bisa salah. Tetapi apa yang aku katakan kepada kalian adalah firman Allah, maka sekali-kali aku tidak akan berdusta kepada Allah.\""},"2427":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ يَحْيَى حَدَّثَنَا عَفَّانُ حَدَّثَنَا حَمَّادٌ حَدَّثَنَا ثَابِتٌ عَنْ أَنَسِ بْنِ مَالِكٍ وَهِشَامُ بْنُ عُرْوَةَ عَنْ أَبِيهِ عَنْ عَائِشَةَأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ سَمِعَ أَصْوَاتًا فَقَالَ مَا هَذَا الصَّوْتُ قَالُوا النَّخْلُ يُؤَبِّرُونَهَا فَقَالَ لَوْ لَمْ يَفْعَلُوا لَصَلَحَ فَلَمْ يُؤَبِّرُوا عَامَئِذٍ فَصَارَ شِيصًا فَذَكَرُوا لِلنَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ إِنْ كَانَ شَيْئًا مِنْ أَمْرِ دُنْيَاكُمْ فَشَأْنُكُمْ بِهِ وَإِنْ كَانَ مِنْ أُمُ��رِ دِينِكُمْ فَإِلَيَّ","id":"Telah menceritakan kepada kami [Muhammad bin Yahya] berkata, telah menceritakan kepada kami [Affan] berkata, telah menceritakan kepada kami [Hammad] berkata, telah menceritakan kepada kami [Tsabit] dari [Anas bin Malik] dan [Hisyam bin Urwah] dari [Bapaknya] dari ['Aisyah] berkata; \"Nabi shallallahu 'alaihi wasallam mendengar suara-suara, beliau lalu bertanya, \"Suara apa ini?\" para sahabat berkata, \"Kurma yang mereka kawinkan.\" Beliau bersabda: \"Sekiranya mereka tidak melakukannya, kurma itu akan (tetap) baik.\" Maka, pada tahun itu para sahabat tidak lagi mengawinkan hingga kurma-kurma mereka rusak. Mereka kemudian menyampaikan hal itu kepada Nabi shallallahu 'alaihi wasallam, beliau lalu bersabda: \"Jika sesuatu itu menyangkut urusan dunia kalian maka itu urusan kalian, tetapi jika menyangkut urusan agama kalian maka kembalikanlah kepadaku.\""},"2428":{"ar":"حَدَّثَنَا عَبْدُ اللَّهِ بْنُ سَعِيدٍ حَدَّثَنَا عَبْدُ اللَّهِ بْنُ خِرَاشِ بْنِ حَوْشَبٍ الشَّيْبَانِيُّ عَنْ الْعَوَّامِ بْنِ حَوْشَبٍ عَنْ مُجَاهِدٍ عَنْ ابْنِ عَبَّاسٍ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ الْمُسْلِمُونَ شُرَكَاءُ فِي ثَلَاثٍ فِي الْمَاءِ وَالْكَلَإِ وَالنَّارِ وَثَمَنُهُ حَرَامٌقَالَ أَبُو سَعِيدٍ يَعْنِي الْمَاءَ الْجَارِيَ","id":"Telah menceritakan kepada kami [Abdullah bin Sa'id] berkata, telah menceritakan kepada kami [Abdullah bin Khirasy bin Hausyab Asy Syaibani] dari [Al Awwam bin Hausyab] dari [Mujahid] dari [Ibnu Abbas] ia berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Kaum muslimin berserikat dalam tiga hal; air, rumput dan api. Dan harganya adalah haram.\" Abu Sa'id berkata, \"Yang dimaksud adalah air yang mengalir.\""},"2429":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ عَبْدِ اللَّهِ بْنِ يَزِيدَ حَدَّثَنَا سُفْيَانُ عَنْ أَبِي الزِّنَادِ عَنْ الْأَعْرَجِ عَنْ أَبِي هُرَيْرَةَأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ ثَلَاثٌ لَا يُمْنَعْنَ الْمَاءُ وَالْكَلَأُ وَالنَّارُ","id":"Telah menceritakan kepada kami [Muhammad bin Abdullah bin Yazid] berkata, telah menceritakan kepada kami [Sufyan] dari [Abu Az Zinad] dari [Al A'raj] dari [Abu Hurairah] bahwa Rasulullah shallallahu 'alaihi wasallam bersabda: \"Tiga hal yang tidak boleh untuk dimonopoli; air, rumput dan api.\""},"2430":{"ar":"حَدَّثَنَا عَمَّارُ بْنُ خَالِدٍ الْوَاسِطِيُّ حَدَّثَنَا عَلِيُّ بْنُ غُرَابٍ عَنْ زُهَيْرِ بْنِ مَرْزُوقٍ عَنْ عَلِيِّ بْنِ زَيْدِ بْنِ جَدْعَانَ عَنْ سَعِيدِ بْنِ الْمُسَيَّبِ عَنْ عَائِشَةَ أَنَّهَا قَالَتْيَا رَسُولَ اللَّهِ مَا الشَّيْءُ الَّذِي لَا يَحِلُّ مَنْعُهُ قَالَ الْمَاءُ وَالْمِلْحُ وَالنَّارُ قَالَتْ قُلْتُ يَا رَسُولَ اللَّهِ هَذَا الْمَاءُ قَدْ عَرَفْنَاهُ فَمَا بَالُ الْمِلْحِ وَالنَّارِ قَالَ يَا حُمَيْرَاءُ مَنْ أَعْطَى نَارًا فَكَأَنَّمَا تَصَدَّقَ بِجَمِيعِ مَا أَنْضَجَتْ تِلْكَ النَّارُ وَمَنْ أَعْطَى مِلْحًا فَكَأَنَّمَا تَصَدَّقَ بِجَمِيعِ مَا طَيَّبَ ذَلِكَ الْمِلْحُ وَمَنْ سَقَى مُسْلِمًا شَرْبَةً مِنْ مَاءٍ حَيْثُ يُوجَدُ الْمَاءُ فَكَأَنَّمَا أَعْتَقَ رَقَبَةً وَمَنْ سَقَى مُسْلِمًا شَرْبَةً مِنْ مَاءٍ حَيْثُ لَا يُوجَدُ الْمَاءُ فَكَأَنَّمَا أَحْيَاهَا","id":"Telah menceritakan kepada kami [Ammar bin Khalid Al Wasithi] berkata, telah menceritakan kepada kami [Ali bin Ghurab] dari [Zuhair bin Marzuq] dari [Ali bin Zaid bin Jad'an] dari [Sa'id bin Al Musayyab] dari ['Aisyah] Bahwasanya ia berkata, \"Wahai Rasulullah, sesuatu apakah yang tidak boleh dilarang untuk mengambilnya?\" Beliau menjawab: \"Air, garam dan api.\" 'Aisyah berkata, \"Aku bertanya, \"Wahai Rasulullah, masalah air kami telah mengetahuinya, tapi bagaimana dengan garam dan api?\" Beliau menjawab: \"Wahai Humaira, barangsiapa memberi api seakan-akan ia telah bersedekah dengan semua yang telah dimatangkan oleh api itu, barangsiapa memberi garam, seakan-akan ia telah bersedekah dengan semua yang telah dibuat nikmat oleh garam itu, barangsiapa memberi minum seorang muslim satu teguk saat ia mendapatkan air, seakan-akan ia telah membebaskan seorang budak, dan barangsiapa memberi minum seorang muslim satu teguk saat ia tidak mendapatkan air, maka seakan-akan ia telah menghidupkannya.\""},"2431":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ أَبِي عُمَرَ الْعَدَنِيُّ حَدَّثَنَا فَرَجُ بْنُ سَعِيدِ بْنِ عَلْقَمَةَ بْنِ سَعِيدِ بْنِ أَبْيَضَ بْنِ حَمَّالٍ حَدَّثَنِي عَمِّي ثَابِتُ بْنُ سَعِيدِ بْنِ أَبْيَضَ بْنِ حَمَّالٍ عَنْ أَبِيهِ سَعِيدٍ عَنْ أَبِيهِ أَبْيَضَ بْنِ حَمَّالٍأَنَّهُ اسْتَقْطَعَ الْمِلْحَ الَّذِي يُقَالُ لَهُ مِلْحُ سُدِّ مَأْرِبٍ فَأَقْطَعَهُ لَهُ ثُمَّ إِنَّ الْأَقْرَعَ بْنَ حَابِسٍ التَّمِيمِيَّ أَتَى رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ يَا رَسُولَ اللَّهِ إِنِّي قَدْ وَرَدْتُ الْمِلْحَ فِي الْجَاهِلِيَّةِ وَهُوَ بِأَرْضٍ لَيْسَ بِهَا مَاءٌ وَمَنْ وَرَدَهُ أَخَذَهُ وَهُوَ مِثْلُ الْمَاءِ الْعِدِّ فَاسْتَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَبْيَضَ بْنَ حَمَّالٍ فِي قَطِيعَتِهِ فِي الْمِلْحِ فَقَالَ قَدْ أَقَلْتُكَ مِنْهُ عَلَى أَنْ تَجْعَلَهُ مِنِّي صَدَقَةً فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ هُوَ مِنْكَ صَدَقَةٌ وَهُوَ مِثْلُ الْمَاءِ الْعِدِّ مَنْ وَرَدَهُ أَخَذَهُ قَالَ فَرَجٌ وَهُوَ الْيَوْمَ عَلَى ذَلِكَ مَنْ وَرَدَهُ أَخَذَهُ قَالَ فَقَطَعَ لَهُ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَرْضًا وَنَخْلًا بِالْجَوْفِ جَوْفِ مُرَادٍ مَكَانَهُ حِينَ أَقَالَهُ مِنْهُ","id":"Telah menceritakan kepada kami [Muhammad bin Abu Umar Al 'Adani] berkata, telah menceritakan kepada kami [Faraj bin Sa'id bin Alqamah bin Sa'id bin Abyadl bin Hammal] berkata, telah menceritakan kepadaku pamanku [Tsabit bin Sa'id bin Abyadl bin Hammal] dari [Bapaknya] dari [Abyadl bin Hammal] bahwa ia pernah mengumpulkan garam yang disebut dengan garam bendungan Ma'rib, ia mengumpulkan untuk dirinya sendiri. Kemudian Al Aqra' bin Habis At Tamimi mendatangi Rasulullah shallallahu 'alaihi wasallam dan berkata, \"Wahai Rasulullah, aku pernah melewati (kumpulan) garam di masa jahiliyah, ia terdapat di suatu daerah yang tidak berair. Siapa saja yang mendatanginya ia bebas untuk mengambilnya, ia seperti air yang mengalir.\" Maka Rasulullah shallallahu 'alaihi wasallam kemudian meminta pembatalan Abyadl bin Hammal dari garam yang dikumpulkan, Ia lalu berkata, \"Aku telah merelakan pembatalan itu dengan syarat Tuan jadikan sebagai (pahala) sedekah dariku.\" Rasulullah shallallahu 'alaihi wasallam menjawab: \"Ia adalah sedekah darimu, dan ia seperti air yang mengalir. Barangsiapa mendatanginya maka ia bebas mengambilnya.\" Faraj berkata, \"Hari ini masih berlaku seperti dulu, siapa yang melewatinya bebas untuk mengambilnya.\" Ia (perawi) berkata, \"Lalu Nabi shallallahu 'alaihi wasallam memberikan bagian tanah dan pohon kurma di Jauf. Jauf adalah tempat saat ia memberi pembatalan kepada Rasulullah.\""},"2432":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا سُفْيَانُ بْنُ عُيَيْنَةَ عَنْ عَمْرِو بْنِ دِينَارٍ عَنْ أَبِي الْمِنْهَالِ سَمِعْتُ إِيَاسَ بْنَ عَبْدٍ الْمُزَنِيَّ وَرَأَى نَاسًا يَبِيعُونَ الْمَاءَ فَقَالَلَا تَبِيعُوا الْمَاءَ فَإِنِّي سَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ نَهَى أَنْ يُبَاعَ الْمَاءُ","id":"Telah menceritakan kepada kami [Abu Bakr bin Abu Syaibah] berkata, telah menceritakan kepada kami [Sufyan bin Uyainah] dari [Amru bin Dinar] dari [Abu Al Minhal] berkata; Aku mendengar [Iyas bin Abd Al Muzanni] ia melihat orang-orang menjual air, maka ia berkata, \"Janganlah kalian menjual air, sesungguhnya aku mendengar Rasulullah shallallahu 'alaihi wasallam melarang untuk menjual air.\""},"2433":{"ar":"حَدَّثَنَا عَلِيُّ بْنُ مُحَمَّدٍ وَإِبْرَاهِيمُ بْنُ سَعِيدٍ الْجَوْهَرِيُّ قَالَا حَدَّثَنَا وَكِيعٌ حَدَّثَنَا ابْنُ جُرَيْجٍ عَنْ أَبِي الزُّبَيْرِ عَنْ جَابِرٍ قَالَنَهَى رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَنْ بَيْعِ فَضْلِ الْمَاءِ","id":"Telah menceritakan kepada kami [Ali bin Muhammad] dan [Ibrahim bin Sa'id Al Jauhari] keduanya berkata; telah menceritakan kepada kami [Waki'] berkata, telah menceritakan kepada kami [Ibnu Juraij] dari [Abu Az Zubair] dari [Jabir] ia berkata, \"Rasulullah shallallahu 'alaihi wasallam melarang menjual kelebihan air.\""},"2434":{"ar":"حَدَّثَنَا هِشَامُ بْنُ عَمَّارٍ حَدَّثَنَا سُفْيَانُ عَنْ أَبِي الزِّنَادِ عَنْ الْأَعْرَجِ عَنْ أَبِي هُرَيْرَةَعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ لَا يَمْنَعْ أَحَدُكُمْ فَضْلَ مَاءٍ لِيَمْنَعَ بِهِ الْكَلَأَ","id":"Telah menceritakan kepada kami [Hisyam bin Ammar] berkata, telah menceritakan kepada kami [Sufyan] dari [Abu Az Zinad] dari [Al A'raj] dari [Abu Hurairah] dari Nabi shallallahu 'alaihi wasallam, beliau bersabda: \"Janganlah salah seorang dari kalian menahan kelebihan air untuk menahan munculnya rerumputan.\""},"2435":{"ar":"حَدَّثَنَا عَبْدُ اللَّهِ بْنُ سَعِيدٍ حَدَّثَنَا عَبْدَةُ بْنُ سُلَيْمَانَ عَنْ حَارِثَةَ عَنْ عَمْرَةَ عَنْ عَائِشَةَ قَالَتْقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَا يُمْنَعُ فَضْلُ الْمَاءِ وَلَا يُمْنَعُ نَقْعُ الْبِئْرِ","id":"Telah menceritakan kepada kami [Abdullah bin Sa'id] berkata, telah menceritakan kepada kami [Abdah bin Sulaiman] dari [Haritsah] dari [Amrah] dari ['Aisyah] ia berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Kelebihan air tidak boleh ditahan, sebagaimana genangan air yang ada dalam sumur.\""},"2436":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ رُمْحٍ أَنْبَأَنَا اللَّيْثُ بْنُ سَعْدٍ عَنْ ابْنِ شِهَابٍ عَنْ عُرْوَةَ بْنِ الزُّبَيْرِ عَنْ عَبْدِ اللَّهِ بْنِ الزُّبَيْرِأَنَّ رَجُلًا مِنْ الْأَنْصَارِ خَاصَمَ الزُّبَيْرَ عِنْدَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي شِرَاجِ الْحَرَّةِ الَّتِي يَسْقُونَ بِهَا النَّخْلَ فَقَالَ الْأَنْصَارِيُّ سَرِّحْ الْمَاءَ يَمُرَّ فَأَبَى عَلَيْهِ فَاخْتَصَمَا عِنْدَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ اسْقِ يَا زُبَيْرُ ثُمَّ أَرْسِلْ الْمَاءَ إِلَى جَارِكَ فَغَضِبَ الْأَنْصَارِيُّ فَقَالَ يَا رَسُولَ اللَّهِ أَنْ كَانَ ابْنَ عَمَّتِكَ فَتَلَوَّنَ وَجْهُ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ ثُمَّ قَالَ يَا زُبَيْرُ اسْقِ ثُمَّ احْبِسْ الْمَاءَ حَتَّى يَرْجِعَ إِلَى الْجَدْرِقَالَ فَقَالَ الزُّبَيْرُ وَاللَّهِ إِنِّي لَأَحْسِبُ هَذِهِ الْآيَةَ نَزَلَتْ فِي ذَلِكَ{ فَلَا وَرَبِّكَ لَا يُؤْمِنُونَ حَتَّى يُحَكِّمُوكَ فِيمَا شَجَرَ بَيْنَهُمْ ثُمَّ لَا يَجِدُوا فِي أَنْفُسِهِمْ حَرَجًا مِمَّا قَضَيْتَ وَيُسَلِّمُوا تَسْلِيمًا }","id":"Telah menceritakan kepada kami [Muhammad bin Rumh] berkata, telah memberitakan kepada kami [Al Laits bin Sa'd] dari [Ibnu Syihab] dari [Urwah bin Az Zubair] dari [Abdullah bin Az Zubair] bahwa seorang laki-laki Anshar berselisih dengan Az Zubair di sisi Rasulullah shallallahu 'alaihi wasallam atas mata air Al Harrah yang biasa mereka gunakan untuk mengairi pohon kurma. Laki-laki Anshar itu berkata, \"Biarkan air mengalir! \" namun Az Zubair menolak. Akhirnya keduanya mengadukan hal itu kepada Rasulullah shallallahu 'alaihi wasallam, Rasulullah shallallahu 'alaihi wasallam kemudian bersabda: \"Alirilah kebunmu wahai Zubair, setelah itu berikanlah kepada tetanggamu.\" Tetapi laki-laki Anshar itu marah seraya berkata, \"Wahai Rasulullah, apakah karena ia anak dari pamanmu! \" Wajah Rasulullah shallallahu 'alaihi wasallam memerah, kemudian beliau bersabda: \"Wahai Zubair, airilah kebunmu, setelah itu tahanlah hingga airnya kembali ke dalam tanah! \" Abdullah bin Az Zubair berkata, \"Az Zubair kemudian berkata, \"Sungguh, aku perkirakan bahwa ayat ini turun berkenaan dengan peristiwa itu: ' Maka demi Tuhanmu, mereka (pada hakekatnya) tidak beriman hingga mereka menjadikan kamu hakim terhadap perkara yang mereka perselisihkan, kemudian mereka tidak merasa dalam hati mereka sesuatu keberatan terhadap putusan yang kamu berikan, dan mereka menerima dengan sepenuhnya'.\""},"2437":{"ar":"حَدَّثَنَا إِبْرَاهِيمُ بْنُ الْمُنْذِرِ الْحِزَامِيُّ حَدَّثَنَا زَكَرِيَّا بْنُ مَنْظُورِ بْنِ ثَعْلَبَةَ بْنِ أَبِي مَالِكٍ حَدَّثَنِي مُحَمَّدُ بْنُ عُقْبَةَ بْنِ أَبِي مَالِكٍ عَنْ عَمِّهِ ثَعْلَبَةَ بْنِ أَبِي مَالِكٍ قَالَقَضَى رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي سَيْلِ مَهْزُورٍ الْأَعْلَى فَوْقَ الْأَسْفَلِ يَسْقِي الْأَعْلَى إِلَى الْكَعْبَيْنِ ثُمَّ يُرْسِلُ إِلَى مَنْ هُوَ أَسْفَلُ مِنْهُ","id":"Telah menceritakan kepada kami [Ibrahim bin Al Mundzir Al Hizami] berkata, telah menceritakan kepada kami [Zakariya bin Manzhur bin Tsa'labah bin Abu Malik] berkata, telah menceritakan kepadaku [Muhammad bin Uqbah bin Abu Malik] dari pamannya [Tsa'labah bin Abu Malik] ia berkata, \"Rasulullah shallallahu 'alaihi wasallam memberi putusan pada penggunaan aliran air Mahruz bahwa yang di atas harus di dahulukan dari yang berada di bawah, yakni sebatas dua mata kaki kemudian dialirkan untuk orang berada di bawah.\""},"2438":{"ar":"حَدَّثَنَا أَحْمَدُ بْنُ عَبْدَةَ أَنْبَأَنَا الْمُغِيرَةُ بْنُ عَبْدِ الرَّحْمَنِ حَدَّثَنِي أَبِي عَنْ عَمْرِو بْنِ شُعَيْبٍ عَنْ أَبِيهِ عَنْ جَدِّهِأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَضَى فِي سَيْلِ مَهْزُورٍ أَنْ يُمْسِكَ حَتَّى يَبْلُغَ الْكَعْبَيْنِ ثُمَّ يُرْسِلَ الْمَاءَ","id":"Telah menceritakan kepada kami [Ahmad bin Abdah] berkata, telah memberitakan kepada kami [Al Mughirah bin 'Abdurrahman] berkata, telah menceritakan kepadaku [Bapakku] dari [Amru bin Syu'aib] dari [Bapaknya] dari [Kakeknya] ia berkata, \"Rasulullah shallallahu 'alaihi wasallam memberikan putusan tentang pembagian aliran air di Mahruz, agar (orang yang di atas) menahan air hingga genangannya mencapai dua mata kaki, setelah itu memberikannya kepada yang di bawah.\""},"2439":{"ar":"حَدَّثَنَا أَبُو الْمُغَلِّسِ حَدَّثَنَا فُضَيْلُ بْنُ سُلَيْمَانَ حَدَّثَنَا مُوسَى بْنُ عُقْبَةَ عَنْ إِسْحَقَ بْنِ يَحْيَى بْنِ الْوَلِيدِ عَنْ عُبَادَةَ بْنِ الصَّامِتِأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَضَى فِي شُرْبِ النَّخْلِ مِنْ السَّيْلِ أَنَّ الْأَعْلَى فَالْأَعْلَى يَشْرَبُ قَبْلَ الْأَسْفَلِ وَيُتْرَكُ الْمَاءُ إِلَى الْكَعْبَيْنِ ثُمَّ يُرْسَلُ الْمَاءُ إِلَى الْأَسْفَلِ الَّذِي يَلِيهِ وَكَذَلِكَ حَتَّى تَنْقَضِيَ الْحَوَائِطُ أَوْ يَفْنَى الْمَاءُ","id":"Telah menceritakan kepada kami [Abu Al Mughallis] berkata, telah menceritakan kepada kami [Fudlail bin Sulaiman] berkata, telah menceritakan kepada kami [Musa bin Uqbah] dari [Ishaq bin Yahya bin Al Walid] dari [Ubadah bin Ash Shamit] berkata, \"Rasulullah shallallahu 'alaihi wasallam memberi putusan tentang pembagian jatah penyiraman pohon kurma, bahwa yang di atas didahulukan dari yang bawah secara berurutan, dan air tetap dibiarkan hingga genangannya mencapai batas mata kaki, setelah itu air dialirkan ke tempat yang ada di bawahnya. Begitu seterusnya hingga semua kebun mendapatkan bagiannya atau airnya habis.\""},"2440":{"ar":"حَدَّثَنَا إِبْرَاهِيمُ بْنُ الْمُنْذِرِ الْحِزَامِيُّ أَنْبَأَنَا أَبُو الْجَعْدِ عَبْدُ الرَّحْمَنِ بْنُ عَبْدِ اللَّهِ عَنْ كَثِيرِ بْنِ عَبْدِ اللَّهِ بْنِ عَوْفٍ الْمُزَنِيِّ عَنْ أَبِيهِ عَنْ جَدِّهِ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يُبَدَّأُ بِالْخَيْلِ يَوْمَ وِرْدِهَا","id":"Telah menceritakan kepada kami [Ibrahim Ibnul Mundzir Al Hizami] berkata, telah memberitakan kepada kami [Abu Al Ja'd 'Abdurrahman bin Abdullah] dari [Katisr bin Abdullah bin Auf Al Muzani] dari [Bapaknya] dari [Kakeknya] ia berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Kuda didahulukan saat memberi minum kepada hewan ternak lainnya.\""},"2441":{"ar":"حَدَّثَنَا الْعَبَّاسُ بْنُ جَعْفَرٍ حَدَّثَنَا مُوسَى بْنُ دَاوُدَ حَدَّثَنَا مُحَمَّدُ بْنُ مُسْلِمٍ الطَّائِفِيُّ عَنْ عَمْرِو بْنِ دِينَارٍ عَنْ أَبِي الشَّعْثَاءِ عَنْ ابْنِ عَبَّاسٍ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كُلُّ قَسْمٍ قُسِمَ فِي الْجَاهِلِيَّةِ فَهُوَ عَلَى مَا قُسِمَ وَكُلُّ قَسْمٍ أَدْرَكَهُ الْإِسْلَامُ فَهُوَ عَلَى قَسْمِ الْإِسْلَامِ","id":"Telah menceritakan kepada kami [Al Abbas bin Ja'far] berkata, telah menceritakan kepada kami [Musa bin Dawud] berkata, telah menceritakan kepada kami [Muhammad bin Muslim Ath Thaifi] dari [Amru bin Dinar] dari [Abu Asy Sya'tsa] dari [Ibnu Abbas] ia berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Setiap pembagian (harta waris) yang dibagikan pada masa jahiliyyah maka ia tetap berlaku atas apa yang telah dibagikan. Setelah Islam datang, maka pembagiannya sesuai dengan pembagian Islam.\""},"2442":{"ar":"حَدَّثَنَا الْوَلِيدُ بْنُ عَمْرِو بْنِ سُكَيْنٍ حَدَّثَنَا مُحَمَّدُ بْنُ عَبْدِ اللَّهِ بْنِ الْمُثَنَّى ح و حَدَّثَنَا الْحَسَنُ بْنُ مُحَمَّدِ بْنِ الصَّبَّاحِ حَدَّثَنَا عَبْدُ الْوَهَّابِ بْنُ عَطَاءٍ قَالَا حَدَّثَنَا إِسْمَعِيلُ الْمَكِيُّ عَنْ الْحَسَنِ عَنْ عَبْدِ اللَّهِ بْنِ مُغَفَّلٍأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ مَنْ حَفَرَ بِئْرًا فَلَهُ أَرْبَعُونَ ذِرَاعًا عَطَنًا لِمَاشِيَتِهِ","id":"Telah menceritakan kepada kami [Al Walid bin Amru bin Sukain] berkata, telah menceritakan kepada kami [Muhammad bin Abdullah Ibnul Mutsanna]. (dalam jalur lain disebutkan) Telah menceritakan kepada kami [Al Hasan bin Muhammad bin Ash Shabbah] berkata, telah menceritakan kepada kami [Abdul Wahhab bin 'Atha] keduanya berkata; telah menceritakan kepada kami [Isma'il Al Makki] dari [Al Hasan] dari [Abdullah bin Mughaffal] bahwa Nabi shallallahu 'alaihi wasallam bersabda: \"Barangsiapa menggali sumur maka baginya empat puluh hasta sebagai tempat menderum binatang ternak.\""},"2443":{"ar":"حَدَّثَنَا سَهْلُ بْنُ أَبِي الصُّغْدِيِّ حَدَّثَنَا مَنْصُورُ بْنُ صُقَيْرٍ حَدَّثَنَا ثَابِتُ بْنُ مُحَمَّدٍ عَنْ نَافِعٍ أَبِي غَالِبٍ عَنْ أَبِي سَعِيدٍ الْخُدْرِيِّ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ حَرِيمُ الْبِئْرِ مَدُّ رِشَائِهَا","id":"Telah menceritakan kepada kami [Sahl bin Abu Ash Shughdi] berkata, telah menceritakan kepada kami [Manshur bin Shuqair] berkata, telah menceritakan kepada kami [Tsabit bin Muhammad] dari [Nafi' Abu Ghalib] dari [Abu Sa'id Al Khudri] ia berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Batas wilayah sumur adalah sejauh rerumputan yang tumbuh di sekitarnya.\""},"2444":{"ar":"حَدَّثَنَا عَبْدُ رَبِّهِ بْنُ خَالِدٍ النُّمَيْرِيُّ أَبُو الْمُغَلِّسِ حَدَّثَنَا الْفُضَيْلُ بْنُ سُلَيْمَانَ حَدَّثَنَا مُوسَى بْنُ عُقْبَةَ أَخْبَرَنِي إِسْحَقُ بْنُ يَحْيَى بْنِ الْوَلِيدِ عَنْ عُبَادَةَ بْنِ الصَّامِتِأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَضَى فِي النَّخْلَةِ وَالنَّخْلَتَيْنِ وَالثَّلَاثَةِ لِلرَّجُلِ فِي النَّخْلِ فَيَخْتَلِفُونَ فِي حُقُوقِ ذَلِكَ فَقَضَى أَنَّ لِكُلِّ نَخْلَةٍ مِنْ أُولَئِكَ مِنْ الْأَسْفَلِ مَبْلَغُ جَرِيدِهَا حَرِيمٌ لَهَا","id":"Telah menceritakan kepada kami [Abdu Rabbih bin Khalid An Numair Abu Al Mughallis] berkata, telah menceritakan kepada kami [Al Fudlail bin Sulaiman] berkata, telah menceritakan kepada kami [Musa bin Uqbah] berkata, telah mengabarkan kepadaku [Ishaq bin Yahya bin Al Walid] dari [Ubadah bin Ash Shamit] berkata, \"Rasulullah shallallahu 'alaihi wasallam memberi keputusan tentang satu pohon kurma, dua pohon kurma dan tiga untuk seorang dari beberapa pohon kurma, maka mereka berbeda-beda di hak-hak itu, sehingga beliau memberi keputusan bahwa batas setiap pohon kurma bagi mereka adalah dari bawah sampai dahannya.\""},"2445":{"ar":"حَدَّثَنَا سَهْلُ بْنُ أَبِي الصُّغْدِيِّ حَدَّثَنَا مَنْصُورُ بْنُ صُقَيْرٍ حَدَّثَنَا ثَابِتُ بْنُ مُحَمَّدٍ الْعَبْدِيُّ عَنْ ابْنِ عُمَرَ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ حَرِيمُ النَّخْلَةِ مَدُّ جَرِيدِهَا","id":"Telah menceritakan kepada kami [Sahl bin Abu Ash Shughdi] berkata, telah menceritakan kepada kami [Manshur bin Shuqair] berkata, telah menceritakan kepada kami [Tsabit bin Muhammad Al 'Abdi] dari [Ibnu Umar] ia berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Wilayah bagi sebatang pohon kurma adalah sepanjang dahannya.\""},"2446":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا وَكِيعٌ حَدَّثَنَا إِسْمَعِيلُ بْنُ إِبْرَاهِيمَ بْنِ مُهَاجِرٍ عَنْ عَبْدِ الْمَلِكِ بْنِ عُمَيْرٍ عَنْ سَعِيدِ بْنِ حُرَيْثٍ قَالَسَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ مَنْ بَاعَ دَارًا أَوْ عَقَارًا فَلَمْ يَجْعَلْ ثَمَنَهُ فِي مِثْلِهِ كَانَ قَمِنًا أَنْ لَا يُبَارَكَ فِيهِحَدَّثَنَا مُحَمَّدُ بْنُ بَشَّارٍ حَدَّثَنَا عُبَيْدُ اللَّهِ بْنُ عَبْدِ الْمَجِيدِ حَدَّثَنِي إِسْمَعِيلُ بْنُ إِبْرَاهِيمَ بْنِ مُهَاجِرٍ عَنْ عَبْدِ الْمَلِكِ بْنِ عُمَيْرٍ عَنْ عَمْرِو بْنِ حُرَيْثٍ عَنْ أَخِيهِ سَعِيدِ بْنِ حُرَيْثٍ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مِثْلَهُ","id":"Telah menceritakan kepada kami [Abu Bakr bin Abu Syaibah] berkata, telah menceritakan kepada kami [Waki'] berkata, telah menceritakan kepada kami [Isma'il bin Ibrahim bin Muhajir] dari [Abdul Malik bin Umair] dari [Sa'id bin Huraits] ia berkata, \"Aku mendengar Rasulullah shallallahu 'alaihi wasallam bersabda: \"Barangsiapa menjual rumah atau penginapan lalu ia tidak memasang harga sebagaimana umumnya maka ia layak untuk tidak mendapatkan berkah di dalamnya.\" Telah menceritakan kepada kami [Muhammad bin Basysyar] berkata, telah menceritakan kepada kami [Ubaidullah bin Abdul Majid] berkata, telah menceritakan kepadaku [Isma'il bin Ibrahim bin Muhajir] dari [Abdul Malik bin Umair] dari [Amru bin Huraits] dari saudaranya [Sa'id bin Huraits] dari Nabi shallallahu 'alaihi wasallam sebagaimana dalam hadits.\""},"2447":{"ar":"حَدَّثَنَا هِشَامُ بْنُ عَمَّارٍ وَعَمْرُو بْنُ رَافِعٍ قَالَا حَدَّثَنَا مَرْوَانُ بْنُ مُعَاوِيَةَ حَدَّثَنَا أَبُو مَالِكٍ النَّخَعِيُّ عَنْ يُوسُفَ بْنِ مَيْمُونٍ عَنْ أَبِي عُبَيْدَةَ بْنِ حُذَيْفَةَ عَنْ أَبِيهِ حُذَيْفَةَ بْنِ الْيَمَانِ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَنْ بَاعَ دَارًا وَلَمْ يَجْعَلْ ثَمَنَهَا فِي مِثْلِهَا لَمْ يُبَارَكْ لَهُ فِيهَا","id":"Telah menceritakan kepada kami [Hisyam bin Ammar] dan [Amru bin Rafi'] keduanya berkata; telah menceritakan kepada kami [Marwan bin Mu'awiyah] berkata, telah menceritakan kepada kami [Abu Malik An Nakha'i] dari [Yusuf bin Maimun] dari [Abu Ubaidah bin Khudzaifah] dari bapaknya [Khudzaifah bin Al Yaman] ia berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Barangsiapa menjual tempat tinggal dengan harga yang tidak wajar (dengan harga umum), maka ia tidak akan mendapatkan berkah dalam penjualannya.\""},"2448":{"ar":"حَدَّثَنَا هِشَامُ بْنُ عَمَّارٍ وَمُحَمَّدُ بْنُ الصَّبَّاحِ قَالَا حَدَّثَنَا سُفْيَانُ بْنُ عُيَيْنَةَ عَنْ أَبِي الزُّبَيْرِ عَنْ جَابِرٍ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَنْ كَانَتْ لَهُ نَخْلٌ أَوْ أَرْضٌ فَلَا يَبِيعُهَا حَتَّى يَعْرِضَهَا عَلَى شَرِيكِهِ","id":"Telah menceritakan kepada kami [Hisyam bin Ammar] dan [Muhammad bin Ash Shabbah] keduanya berkata; telah menceritakan kepada kami [Sufyan bin Uyainah] dari [Abu Az Zubair] dari [Jabir] ia berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Barangsiapa memiliki pohon kurma atau sebidang tanah, maka janganlah menjualnya hingga ia perlihatkan kepada sekutunya.\""},"2449":{"ar":"حَدَّثَنَا أَحْمَدُ بْنُ سِنَانَ وَالْعَلَاءُ بْنُ سَالِمٍ قَالَا حَدَّثَنَا يَزِيدُ بْنُ هَارُونَ أَنْبَأَنَا شَرِيكٌ عَنْ سِمَاكٍ عَنْ عِكْرِمَةَ عَنْ ابْنِ عَبَّاسٍعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ مَنْ كَانَتْ لَهُ أَرْضٌ فَأَرَادَ بَيْعَهَا فَلْيَعْرِضْهَا عَلَى جَارِهِ","id":"Telah menceritakan kepada kami [Ahmad bin Sinan] dan [Al 'Ala bin Salim] keduanya berkata; telah menceritakan kepada kami [Yazid bin Harun] berkata, telah memberitakan kepada kami [Syarik] dari [Simak] dari [Ikrimah] dari [Ibnu Abbas] dari Nabi shallallahu 'alaihi wasallam, beliau bersabda: \"Barangsiapa memiliki tanah kemudian ingin menjualnya, maka hendaklah ia tawarkan kepada tetangganya.\""},"2450":{"ar":"حَدَّثَنَا عُثْمَانُ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا هُشَيْمٌ أَنْبَأَنَا عَبْدُ الْمَلِكِ عَنْ عَطَاءٍ عَنْ جَابِرٍ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ الْجَارُ أَحَقُّ بِشُفْعَةِ جَارِهِ يَنْتَظِرُ بِهَا وَإِنْ كَانَ غَائِبًا إِذَا كَانَ طَرِيقُهُمَا وَاحِدًا","id":"Telah menceritakan kepada kami [Utsman bin Abu Syaibah] berkata, telah menceritakan kepada kami [Husyaim] berkata, telah memberitakan kepada kami [Abdul Malik] dari ['Atha] dari [Jabir] ia berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Tetangga itu lebih berhak atas syuf'ah tetangganya (dari orang lain), jika ia tidak ada hendaklah ia menunggunya jika memang jalan keduanya hanya satu.\" "},"2451":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ وَعَلِيُّ بْنُ مُحَمَّدٍ قَالَا حَدَّثَنَا سُفْيَانُ بْنُ عُيَيْنَةَ عَنْ إِبْرَاهِيمَ بْنِ مَيْسَرَةَ عَنْ عَمْرِو بْنِ الشَّرِيدِ عَنْ أَبِي رَافِعٍأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ الْجَارُ أَحَقُّ بِسَقَبِهِ","id":"Telah menceritakan kepada kami [Abu Bakr bin Abu Syaibah] dan [Ali bin Muhammad] keduanya berkata; telah menceritakan kepada kami [Sufyan bin Uyainah] dari [Ibrahim bin Maisarah] dari [Amru bin Ash Syarid] dari [Abu Rafi'] bahwa Rasulullah shallallahu 'alaihi wasallam bersabda: \"Tetangga itu lebih berhak karena kedekatannya.\""},"2452":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا أَبُو أُسَامَةَ عَنْ حُسَيْنٍ الْمُعَلِّمِ عَنْ عَمْرِو بْنِ شُعَيْبٍ عَنْ عَمْرِو بْنِ الشَّرِيدِ بْنِ سُوَيْدٍ عَنْ أَبِيهِ الشَّرِيدِ بْنِ سُوَيْدٍ قَالَقُلْتُ يَا رَسُولَ اللَّهِ أَرْضٌ لَيْسَ فِيهَا لِأَحَدٍ قِسْمٌ وَلَا شِرْكٌ إِلَّا الْجِوَارُ قَالَ الْجَارُ أَحَقُّ بِسَقَبِهِ","id":"Telah menceritakan kepada kami [Abu Bakr bin Abu Syaibah] berkata, telah menceritakan kepada kami [Abu Usamah] dari [Husain Al Mu'allim] dari [Amru bin Syu'aib] dari [Amru bin Asy Syarid bin Suwaid] dari bapaknya [Asy Syarid bin Suwaid] ia berkata, \"Aku berkata, \"Wahai Rasulullah, sebidang tanah tidak ada pembagian dan persekutuan (dalam kepemilikannya) kecuali tetangga?\" beliau bersabda: \"Tetangga itu lebih berhak karena kedekatannya.\""},"2453":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ يَحْيَى وَعَبْدُ الرَّحْمَنِ بْنُ عُمَرَ قَالَا حَدَّثَنَا أَبُو عَاصِمٍ حَدَّثَنَا مَالِكُ بْنُ أَنَسٍ عَنْ الزُّهْرِيِّ عَنْ سَعِيدِ بْنِ الْمُسَيَّبِ وَأَبِي سَلَمَةَ بْنِ عَبْدِ الرَّحْمَنِ عَنْ أَبِي هُرَيْرَةَأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَضَى بِالشُّفْعَةِ فِيمَا لَمْ يُقْسَمْ فَإِذَا وَقَعَتْ الْحُدُودُ فَلَا شُفْعَةَحَدَّثَنَا مُحَمَّدُ بْنُ حَمَّادٍ الطِّهْرَانِيُّ حَدَّثَنَا أَبُو عَاصِمٍ عَنْ مَالِكٍ عَنْ الزُّهْرِيِّ عَنْ سَعِيدِ بْنِ الْمُسَيَّبِ وَأَبِي سَلَمَةَ عَنْ أَبِي هُرَيْرَةَ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ نَحْوَهُ قَالَ أَبُو عَاصِمٍ سَعِيدُ بْنُ الْمُسَيَّبِ مُرْسَلٌ وَأَبُو سَلَمَةَ عَنْ أَبِي هُرَيْرَةَ مُتَّصِلٌ","id":"Telah menceritakan kepada kami [Muhammad bin Yahya] dan ['Abdurrahman bin Umar] keduanya berkata; telah menceritakan kepada kami [Abu 'Ashim] berkata, telah menceritakan kepada kami [Malik bin Anas] dari [Az Zuhri] dari [Sa'id Ibnul Musayyab] dan [Abu Salamah bin Abdurrahman] dari [Abu Hurairah] berkata, \"Rasulullah shallallahu 'alaihi wasallam memberi putusan bahwa syuf'ah yang belum dibagi jika batas-batasnya telah jelas, maka tidak ada syuf'ah lagi.\" Dan telah menceritakan kepada kami [Muhammad bin Hammad Ath Thahrani] telah menceritakan kepada kami [Abu 'Ashim] dari [Malik] dari [Az Zuhri] dari [Sa'id bin Al Musayyab] dan [Abu Salamah] dari [Abu Hurairah] dari Nabi shallallahu 'alaihi wasallam seperti hadits di atas, Abu 'Ashim berkata; (riwayat dari) Sa'id bin Al Musayyab mursal, sementara (riwayat dari) Abu Salamah dari Abu Hurairah bersambung."},"2454":{"ar":"حَدَّثَنَا عَبْدُ اللَّهِ بْنُ الْجَرَّاحِ حَدَّثَنَا سُفْيَانُ بْنُ عُيَيْنَةَ عَنْ إِبْرَاهِيمَ بْنِ مَيْسَرَةَ عَنْ عَمْرِو بْنِ الشَّرِيدِ عَنْ أَبِي رَافِعٍ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ الشَّرِيكُ أَحَقُّ بِسَقَبِهِ مَا كَانَ","id":"Telah menceritakan kepada kami [Abdullah bin Jarrah] berkata, telah menceritakan kepada kami [Sufyan bin Uyainah] dari [Ibrahim bin Maisarah] dari [Amru bin Asy Syarid] dari [Abu Rafi'] ia berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Sekutu itu lebih berhak karena kedekatannya, apapun keadaannya.\""},"2455":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ يَحْيَى حَدَّثَنَا عَبْدُ الرَّزَّاقِ عَنْ مَعْمَرٍ عَنْ الزُّهْرِيِّ عَنْ أَبِي سَلَمَةَ عَنْ جَابِرِ بْنِ عَبْدِ اللَّهِ قَالَإِنَّمَا جَعَلَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ الشُّفْعَةَ فِي كُلِّ مَا لَمْ يُقْسَمْ فَإِذَا وَقَعَتْ الْحُدُودُ وَصُرِّفَتْ الطُّرُقُ فَلَا شُفْعَةَ","id":"Telah menceritakan kepada kami [Muhammad bin Yahya] berkata, telah menceritakan kepada kami [Abdurrazaq] dari [Ma'mar] dari [Az Zuhri] dari [Abu Salamah] dari [Jabir bin Abdullah] ia berkata, \"Rasulullah shallallahu 'alaihi wasallam memberlakukan syuf'ah atas setiap sesuatu yang belum dibagi, jika batas-batas telah jelas dan jalan-jalan telah dibagi maka tidak ada lagi syuf'ah.\""},"2456":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ بَشَّارٍ حَدَّثَنَا مُحَمَّدُ بْنُ الْحَارِثِ عَنْ مُحَمَّدِ بْنِ عَبْدِ الرَّحْمَنِ الْبَيْلَمَانِيِّ عَنْ أَبِيهِ عَنْ ابْنِ عُمَرَ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ الشُّفْعَةُ كَحَلِّ الْعِقَالِ","id":"Telah menceritakan kepada kami [Muhammad bin Basysyar] berkata, telah menceritakan kepada kami [Muhammad bin Al Harits] dari [Muhammad bin 'Abdurrahman Al Bailamani] dari [Bapaknya] dari [Ibnu Umar] ia berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Syuf'ah itu seperti melepas belenggu.\""},"2457":{"ar":"حَدَّثَنَا سُوَيْدُ بْنُ سَعِيدٍ قَالَ حَدَّثَنَا مُحَمَّدُ بْنُ الْحَارِثِ عَنْ مُحَمَّدِ بْنِ عَبْدِ الرَّحْمَنِ الْبَيْلَمَانِيِّ عَنْ أَبِيهِ عَنْ ابْنِ عُمَرَ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَا شُفْعَةَ لِشَرِيكٍ عَلَى شَرِيكٍ إِذَا سَبَقَهُ بِالشِّرَاءِ وَلَا لِصَغِيرٍ وَلَا لِغَائِبٍ","id":"Telah menceritakan kepada kami [Suwaid bin Sa'id] ia berkata; telah menceritakan kepada kami [Muhammad bin Al Harits] dari [Muhammad bin 'Abdurrahman Al Bailamani] dari [Bapaknya] [Ibnu Umar] ia berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Tidak ada syuf'ah bagi sekutu atas sekutunya bila didahului oleh jual beli, tidak pula bagi anak kecil dan orang yang tidak hadir.\""},"2458":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ الْمُثَنَّى حَدَّثَنَا يَحْيَى بْنُ سَعِيدٍ عَنْ حُمَيْدٍ الطَّوِيلِ عَنْ الْحَسَنِ عَنْ مُطَرِّفِ بْنِ عَبْدِ اللَّهِ بْنِ الشِّخِّيرِ عَنْ أَبِيهِ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ ضَالَّةُ الْمُسْلِمِ حَرَقُ النَّارِ","id":"Telah menceritakan kepada kami [Muhammad Ibnul Mutsanna] berkata, telah menceritakan kepada kami [Yahya bin Sa'id] dari [Humaid Ath Thawil] dari [Al Hasan] dari [Mutharrif bin Abdullah bin Asy Syikhkhir] dari [Bapaknya] ia berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Hilangnya (barang) seorang muslim akan membawa ke dalam neraka (bagi yang mencurinya).\""},"2459":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ بَشَّارٍ حَدَّثَنَا يَحْيَى بْنُ سَعِيدٍ حَدَّثَنَا أَبُو حَيَّانَ التَّيْمِيُّ حَدَّثَنَا الضَّحَّاكُ خَالُ الْمُنْذِرِ بْنِ جَرِيرٍ عَنْ الْمُنْذِرِ بْنِ جَرِيرٍ قَالَكُنْتُ مَعَ أَبِي بِالْبَوَازِيجِ فَرَاحَتْ الْبَقَرُ فَرَأَى بَقَرَةً أَنْكَرَهَا فَقَالَ مَا هَذِهِ قَالُوا بَقَرَةٌ لَحِقَتْ بِالْبَقَرِ قَالَ فَأَمَرَ بِهَا فَطُرِدَتْ حَتَّى تَوَارَتْ ثُمَّ قَالَ سَمِعْتَ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ لَا يُؤْوِي الضَّالَّةَ إِلَّا ضَالٌّ","id":"Telah menceritakan kepada kami [Muhammad bin Basysyar] berkata, telah menceritakan kepada kami [Yahya bin Sa'id] berkata, telah menceritakan kepada kami [Abu Hayyan At Taimi] berkata, telah menceritakan kepada kami [Adl Dlahhak] -paman Al Mundzir bin Jarir- dari [Al Mundzir bin Jarir] ia berkata, \"Aku bersama [bapakku] di Bawazikh, ketika sapi-sapi akan mengandang ia melihat ada seekor sapi (asing). Ia lalu berkata, \"Apa ini! \" mereka menjawab, \"Sapi yang mengikuti sapi yang lain.\" Al Mundzir berkata, \"Lalu bapakku memerintahkan agar sapi (asing) itu dikeluarkan, maka sapi itu pun dikeluarkan dan pergi hingga tidak terlihat. Setelah itu ia berkata, \"Aku pernah mendengar Rasulullah shallallahu 'alaihi wasallam bersabda: \"Tidaklah seseorang menyembunyikan hewan yang tersesat kecuali ia (orang yang) tersesat.\""},"2460":{"ar":"حَدَّثَنَا إِسْحَقُ بْنُ إِسْمَعِيلَ بْنِ الْعَلَاءِ الْأَيْلِيُّ حَدَّثَنَا سُفْيَانُ بْنُ عُيَيْنَةَ عَنْ يَحْيَى بْنِ سَعِيدٍ عَنْ رَبِيعَةَ بْنِ أَبِي عَبْدِ الرَّحْمَنِ عَنْ يَزِيدَ مَوْلَى الْمُنْبَعِثِ عَنْ زَيْدِ بْنِ خَالِدٍ الْجُهَنِيِّ فَلَقِيتُ رَبِيعَةَ فَسَأَلْتُهُ فَقَالَ حَدَّثَنِي يَزِيدُ عَنْ زَيْدِ بْنِ خَالِدٍ الْجُهَنِيِّعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ سُئِلَ عَنْ ضَالَّةِ الْإِبِلِ فَغَضِبَ وَاحْمَرَّتْ وَجْنَتَاهُ فَقَالَ مَا لَكَ وَلَهَا مَعَهَا الْحِذَاءُ وَالسِّقَاءُ تَرِدُ الْمَاءَ وَتَأْكُلُ الشَّجَرَ حَتَّى يَلْقَاهَا رَبُّهَا وَسُئِلَ عَنْ ضَالَّةِ الْغَنَمِ فَقَالَ خُذْهَا فَإِنَّمَا هِيَ لَكَ أَوْ لِأَخِيكَ أَوْ لِلذِّئْبِ وَسُئِلَ عَنْ اللُّقَطَةِ فَقَالَ اعْرِفْ عِفَاصَهَا وَوِكَاءَهَا وَعَرِّفْهَا سَنَةً فَإِنْ اعْتُرِفَتْ وَإِلَّا فَاخْلِطْهَا بِمَالِكَ","id":"Telah menceritakan kepada kami [Ishaq bin Isma'il bin Al 'Ala Al Aili] berkata, telah menceritakan kepada kami [Sufyan bin Uyainah] dari [Yahya bin Sa'id] dari [Rabi'ah bin Abu 'Abdurrahman] dari [Yazid] -mantan budak Al Munba'its- dari [Zaid bin Khalid Al Juhani] -aku bertemu Rabi'ah maka aku tanyakan kepadanya, ia berkata; Yazid menceritakan kepadaku dari Zaid bin Khalid Al Juhani- dari Nabi shallallahu 'alaihi wasallam, ia berkata, \"Beliau pernah ditanya tentang seekor unta yang tersesat, maka beliau marah dan wajahnya memerah, beliau bersabda: \"Apa urusanmu dengan unta tersebut, ia masih punya kaki, bisa minum air dan makan pepohonan hingga pemiliknya menemukannya! \" Lalu beliau ditanya tentang kambing yang tersesat, maka beliau bersabda: \"Ambillah kambing tersebut, sebab ia milikmu, atau milik saudaramu, atau bahkan milik serigala.\" Dan beliau juga ditanya tentang barang temuan, beliau bersabda: \"Kenalilah bejana dan tali pengikatnya, setelah itu umumkanlah selama satu tahun, jika temuan itu dikenali maka berikanlah, namun jika tidak maka campurlah dengan harta milikmu.\""},"2461":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا عَبْدُ الْوَهَّابِ الثَّقَفِيُّ عَنْ خَالِدٍ الْحَذَّاءِ عَنْ أَبِي الْعَلَاءِ عَنْ مُطَرِّفٍ عَنْ عِيَاضِ بْنِ حِمَارٍ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَنْ وَجَدَ لُقَطَةً فَلْيُشْهِدْ ذَا عَدْلٍ أَوْ ذَوَيْ عَدْلٍ ثُمَّ لَا يُغَيِّرْهُ وَلَا يَكْتُمْ فَإِنْ جَاءَ رَبُّهَا فَهُوَ أَحَقُّ بِهَا وَإِلَّا فَهُوَ مَالُ اللَّهِ يُؤْتِيهِ مَنْ يَشَاءُ","id":"Telah menceritakan kepada kami [Abu Bakr bin Abu Syaibah] berkata, telah menceritakan kepada kami [Abdul Wahhab Ats Tsaqafi] dari [Khalid Al Hadza] dari [Abu Al 'Ala] dari [Mutharrif] dari [Iyadl bin Himar] ia berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Barangsiapa mendapatkan barang temuan hendaklah ia persaksikan kepada orang yang adil, setelah itu janganlah ia mengubah atau menutupinya, jika pemiliknya datang maka ia lebih berhak, namun jika tidak datang maka itu adalah harta Allah yang Dia berikan kepada siapa saja yang dikehendaki-Nya.\""},"2462":{"ar":"حَدَّثَنَا عَلِيُّ بْنُ مُحَمَّدٍ حَدَّثَنَا وَكِيعٌ حَدَّثَنَا سُفْيَانُ عَنْ سَلَمَةَ بْنِ كُهَيْلٍ عَنْ سُوَيْدِ بْنِ غَفَلَةَ قَالَخَرَجْتُ مَعَ زَيْدِ بْنِ صُوحَانَ وَسَلْمَانَ بْنِ رَبِيعَةَ حَتَّى إِذَا كُنَّا بِالْعُذَيْبِ الْتَقَطْتُ سَوْطًا فَقَالَا لِي أَلْقِهِ فَأَبَيْتُ فَلَمَّا قَدِمْنَا الْمَدِينَةَ أَتَيْتُ أُبَيَّ بْنَ كَعْبٍ فَذَكَرْتُ ذَلِكَ لَهُ فَقَالَ أَصَبْتَ الْتَقَطْتُ مِائَةَ دِينَارٍ عَلَى عَهْدِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَسَأَلْتُهُ فَقَالَ عَرِّفْهَا سَنَةً فَعَرَّفْتُهَا فَلَمْ أَجِدْ أَحَدًا يَعْرِفُهَا فَسَأَلْتُهُ فَقَالَ عَرِّفْهَا فَعَرَّفْتُهَا فَلَمْ أَجِدْ أَحَدًا يَعْرِفُهَا فَقَالَ اعْرِفْ وِعَا��َهَا وَوِكَاءَهَا وَعَدَدَهَا ثُمَّ عَرِّفْهَا سَنَةً فَإِنْ جَاءَ مَنْ يَعْرِفُهَا وَإِلَّا فَهِيَ كَسَبِيلِ مَالِكَ","id":"Telah menceritakan kepada kami [Ali bin Muhammad] berkata, telah menceritakan kepada kami [Waki'] berkata, telah menceritakan kepada kami [Sufyan] dari [Salamah bin Kuhail] dari [Suwaid bin Ghafalah] ia berkata; Aku keluar bersama Zaid bin Shuhan dan Sulaiman bin Rabi'ah, hingga ketika sampai di 'Udzaib, aku menemukan cambuk. Keduanya berkata, \"Buanglah cambuk itu, \" namun aku mengabaikannya. Ketika kami tiba di Madinah, aku mendatangi [Ubay bin Ka'b], lalu aku ceritakan hal itu kepadanya. Ia lantas berkata, \"Engkau benar, pada masa Rasulullah shallallahu 'alaihi wasallam aku pernah menemukan seratus dinar. Kemudian hal itu aku tanyakan kepada beliau, beliau lalu menjawab: \"Umumkanlah selama satu tahun, \" maka aku umumkan selama satu tahun, tetapi tidak ada yang mengenalnya (uang temuan). Beliau bersabda: \"Umumkanlah, \" lalu uang itu aku umumkan lagi, tetapi tidak ada seorang pun yang mengenalnya. Beliau lantas bersabda: \"Kenalilah bejana, tali pengikat dan jumlahnya. Kemudian umumkan sekali lagi selama satu tahun, jika ada orang yang mengetahuinya (berikanlah), jika tidak maka itu seperti uangmu sendiri.\""},"2463":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ بَشَّارٍ حَدَّثَنَا أَبُو بَكْرٍ الْحَنَفِيُّ ح و حَدَّثَنَا حَرْمَلَةُ بْنُ يَحْيَى حَدَّثَنَا عَبْدُ اللَّهِ بْنُ وَهْبٍ قَالَا حَدَّثَنَا الضَّحَّاكُ بْنُ عُثْمَانَ الْقُرَشِيُّ حَدَّثَنِي سَالِمٌ أَبُو النَّضْرِ عَنْ بُسْرِ بْنِ سَعِيدٍ عَنْ زَيْدِ بْنِ خَالِدٍ الْجُهَنِيِّأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ سُئِلَ عَنْ اللُّقَطَةِ فَقَالَ عَرِّفْهَا سَنَةً فَإِنْ اعْتُرِفَتْ فَأَدِّهَا فَإِنْ لَمْ تُعْتَرَفْ فَاعْرِفْ عِفَاصَهَا وَوِعَاءَهَا ثُمَّ كُلْهَا فَإِنْ جَاءَ صَاحِبُهَا فَأَدِّهَا إِلَيْهِ","id":"Telah menceritakan kepada kami [Muhammad bin Basyar] berkata, telah menceritakan kepada kami [Abu Bakr Al Hanafi]. (dalam jalur lain disebutkan) Telah menceritakan kepada kami [Harmalah bin Yahya] berkata, telah menceritakan kepada kami [Abdullah bin Wahb] keduanya berkata; telah menceritakan kepada kami [Adl Dlahhak bin Utsman Al Qurasyi] berkata, telah menceritakan kepadaku [Salim Abu An Nadlr] dari [Busr bin Sa'id] dari [Zaid bin Khalid Al Juhani] berkata, \"Rasulullah shallallahu 'alaihi wasallam pernah ditanya tentang barang temuan, beliau bersabda: \"Umumkanlah selama satu tahun, jika ada yang mengakuinya maka berikanlah. Tetapi jika tidak ada yang mengakuinya, maka kenalilah bejana dan tali penutupnya, setelah itu makanlah jika ada pemiliknya datang berikanlah kepadanya.\""},"2464":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ بَشَّارٍ حَدَّثَنَا مُحَمَّدُ بْنُ خَالِدِ بْنِ عَثْمَةَ حَدَّثَنِي مُوسَى بْنُ يَعْقُوبَ الزَّمْعِيُّ حَدَّثَتْنِي عَمَّتِي قُرَيْبَةُ بِنْتُ عَبْدِ اللَّهِ أَنَّ أُمَّهَا كَرِيمَةَ بِنْتَ الْمِقْدَادِ بْنِ عَمْرٍو أَخْبَرَتْهَا عَنْ ضُبَاعَةَ بِنْتِ الزُّبَيْرِ عَنْ الْمِقْدَادِ بْنِ عَمْرٍوأَنَّهُ خَرَجَ ذَاتَ يَوْمٍ إِلَى الْبَقِيعِ وَهُوَ الْمَقْبَرَةُ لِحَاجَتِهِ وَكَانَ النَّاسُ لَا يَذْهَبُ أَحَدُهُمْ فِي حَاجَتِهِ إِلَّا فِي الْيَوْمَيْنِ وَالثَّلَاثَةِ فَإِنَّمَا يَبْعَرُ كَمَا تَبْعَرُ الْإِبِلُ ثُمَّ دَخَلَ خَرِبَةً فَبَيْنَمَا هُوَ جَالِسٌ لِحَاجَتِهِ إِذْ رَأَى جُرَذًا أَخْرَجَ مِنْ جُحْرٍ دِينَارًا ثُمَّ دَخَلَ فَأَخْرَجَ آخَرَ حَتَّى أَخْرَجَ سَبْعَةَ عَشَرَ دِينَارًا ثُمَّ أَخْرَجَ طَرَفَ خِرْقَةٍ حَمْرَاءَ قَالَ الْمِقْدَادُ فَسَلَلْتُ الْخِرْقَةَ فَوَجَدْتُ فِيهَا دِينَارًا فَتَمَّتْ ثَمَانِيَةَ عَشَرَ دِينَارًا فَخَرَجْتُ بِهَا حَتَّى أَتَيْتُ بِهَا رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَأَخْبَرْتُهُ خَبَرَهَا فَقُلْتُ خُذْ صَدَقَتَهَا يَا رَسُولَ اللَّهِ قَالَ ارْجِعْ بِهَا لَا صَدَقَةَ فِيهَا بَارَكَ اللَّهُ لَكَ فِيهَا ثُمَّ قَالَ لَعَلَّكَ أَتْبَعْتَ يَدَكَ فِي الْجُحْرِ قُلْتُ لَا وَالَّذِي أَكْرَمَكَ بِالْحَقِّ قَالَ فَلَمْ يَفْنَ آخِرُهَا حَتَّى مَاتَ","id":"Telah menceritakan kepada kami [Muhammad bin Basysyar] berkata, telah menceritakan kepada kami [Muhammad bin Khalid bin Atsmah] berkata, telah menceritakan kepadaku [Musa bin Ya'qub Az Zam'i] berkata, telah menceritakan kepadaku bibiku [Quraibah binti Abdullah] bahwa ibunya [Karimah binti Al Miqdad bin Amru] mengabarkan kepadanya, dari [Dluba'ah binti Az Zubair] dari [Al Miqdad bin Amru] bahwa suatu hari ia keluar menuju pekuburan Baqi', yaitu pekuburan yang biasa ia gunakan untuk buang hajat. Biasanya orang-orang tidak buang hajat kecuali setelah dua atau tiga hari. Dan ia buang hajat layaknya unta, setelah itu ia masuk ke dalam reruntuhan. Saat ia jonggkok buang hajat, ia melihat seekor tikus mengeluarkan uang satu dinar dari dalam lubang, kemudian tikus itu masuk dan mengeluarkan lagi uang yang lainnya sehingga genap tujuh belas dinar. Setelah itu, tikus tersebut mengeluarkan sepucuk kain berwarna merah. Al Miqdad berkata, \"Aku lalu menarik potongan kain itu, dan ternyata di sana masih satu dinar lagi hingga genaplah delapan belas dinar. Lalu aku keluar membawa uang tersebut menemui Rasulullah shallallahu 'alaihi wasallam, dan aku kabarkan hal itu kepada beliau. Aku katakan kepada beliau, \"Ambillah zakatnya wahai Rasulullah! \" Beliau bersabda: \"Bawalah pulang uangnya, tidak ada zakat padanya. Dan semoga Allah memberkatimu di dalam dinar itu.\" Kemudian beliau bertanya: \"Apakah kamu memasukkan tanganmu ke dalam lubang?\" aku menjawab, \"Tidak, demi Dzat yang telah memuliakanmu dengan kebenaran! \" Ia (perawi) berkata, \"Uang itu tidak habis hingga ia meninggal.\""},"2465":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ مَيْمُونٍ الْمَكِّيُّ وَهِشَامُ بْنُ عَمَّارٍ قَالَا حَدَّثَنَا سُفْيَانُ بْنُ عُيَيْنَةَ عَنْ الزُّهْرِيِّ عَنْ سَعِيدٍ وَأَبِي سَلَمَةَ عَنْ أَبِي هُرَيْرَةَأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ فِي الرِّكَازِ الْخُمُسُ","id":"Telah menceritakan kepada kami [Muhammad bin Maimun Al Makki] dan [Hisyam bin Ammar] keduanya berkata; telah menceritakan kepada kami [Sufyan bin Uyainah] dari [Az Zuhri] dari [Sa'id] dan [Abu Salamah] dari [Abu Hurairah] bahwa Rasulullah shallallahu 'alaihi wasallam bersabda tentang harta yang terpendam: \"Zakatnya adalah seperlima.\""},"2466":{"ar":"حَدَّثَنَا نَصْرُ بْنُ عَلِيٍّ الْجَهْضَمِيُّ حَدَّثَنَا أَبُو أَحْمَدَ عَنْ إِسْرَائِيلَ عَنْ سِمَاكٍ عَنْ عِكْرِمَةَ عَنْ ابْنِ عَبَّاسٍ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي الرِّكَازِ الْخُمُسُ","id":"Telah menceritakan kepada kami [Nashr bin 'Ali Al Jahdhami], telah menceritakan kepada kami [Abu Ahmad] dari [Isra'il] dari [Simak] dari [Ikrimah] dari [Ibnu Abbas] berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Dalam rikaz (harta karun yang disimpan di dalam tanah) terdapat kewajiban zakat sebesar seperlima.\""},"2467":{"ar":"حَدَّثَنَا أَحْمَدُ بْنُ ثَابِتٍ الْجَحْدَرِيُّ حَدَّثَنَا يَعْقُوبُ بْنُ إِسْحَقَ الْحَضْرَمِيُّ حَدَّثَنَا سَلِيمُ بْنُ حَيَّانَ سَمِعْتُ أَبِي يُحَدِّثُ عَنْ أَبِي هُرَيْرَةَعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ كَانَ فِيمَنْ كَانَ قَبْلَكُمْ رَجُلٌ اشْتَرَى عَقَارًا فَوَجَدَ فِيهَا جَرَّةً مِنْ ذَهَبٍ فَقَالَ اشْتَرَيْتُ مِنْكَ الْأَرْضَ وَلَمْ أَشْتَرِ مِنْكَ الذَّهَبَ فَقَالَ الرَّجُلُ إِنَّمَا بِعْتُكَ الْأَرْضَ بِمَا فِيهَا فَتَحَاكَمَا إِلَى رَجُلٍ فَقَالَ أَلَكُمَا وَلَدٌ فَقَالَ أَحَدُهُمَا لِي غُلَامٌ وَقَالَ الْآخَرُ لِي جَارِيَةٌ قَالَ فَأَنْكِحَا الْغُلَامَ الْجَارِيَةَ وَلْيُنْفِقَا عَلَى أَنْفُسِهِمَا مِنْهُ وَلْيَتَصَدَّقَا","id":"Telah menceritakan kepada kami [Ahmad bin Tsabit Al Jahdari], telah menceritakan kepada kami [Ya'qub bin Ishaq Al Hadlrami], telah menceritakan kepada kami [Salim bin Hayyan], aku mendengar [Ayahku] menceritakan dari [Abu Hurairah] dari Nabi shallallahu 'alaihi wasallam beliau bersabda: \"Sebelum kalian ada, terdapat seorang laki-laki membeli bangunan, di dalamnya laki-laki ini menemukan bejana besar yang terbuat dari emas. la berkata kepada pemilik rumah 'Aku hanya membeli rumah darimu dan tidak membeli emas ini.\" Pemilik rumah berkata; sungguh aku menjual tanah beserta segala yang ada di dalamnya.\" Keduanya lalu menemui seorang hakim, hakim tersebut berkata, \"Apakah kalian berdua memilki anak?\" Salah satu dari keduanya menjawab, \"Aku memiliki seorang anak laki-laki, dan yang lain menjawab, \"Aku memiliki seorang anak perempuan.\" Hakim tadi berkata, \"Kalian nikahkan saja anak yang lelaki kamu dengan anak perempuan tadi dan berikanlah mereka nafkah dari bejana emas tersebut, serta sedekahkan sisanya.\""},"2468":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ عَبْدِ اللَّهِ بْنِ نُمَيْرٍ وَعَلِيُّ بْنُ مُحَمَّدٍ قَالَا حَدَّثَنَا وَكِيعٌ حَدَّثَنَا إِسْمَعِيلُ بْنُ أَبِي خَالِدٍ عَنْ سَلَمَةَ بْنِ كُهَيْلٍ عَنْ عَطَاءٍ عَنْ جَابِرٍأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بَاعَ الْمُدَبَّرِ","id":"Telah menceritakan kepada kami [Muhammad bin Abdullah bin Numair] dan [Ali bin Muhammad], keduanya berkata; telah menceritakan kepada kami [Waki'], telah menceritakan kepada kami [Isma'il bin Abu Khalid] dari [Salamah bin Kuhail] dari ['Atha'] dari [Jabir] berkata, \"Sesungguhnya Rasulullah menjual seorang budak mudabbar.\" "},"2469":{"ar":"حَدَّثَنَا هِشَامُ بْنُ عَمَّارٍ حَدَّثَنَا سُفْيَانُ بْنُ عُيَيْنَةَ عَنْ عَمْرِو بْنِ دِينَارٍ عَنْ جَابِرِ بْنِ عَبْدِ اللَّهِ قَالَدَبَّرَ رَجُلٌ مِنَّا غُلَامًا وَلَمْ يَكُنْ لَهُ مَالٌ غَيْرُهُ فَبَاعَهُ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَاشْتَرَاهُ ابْنُ النَّحَّامِ رَجُلٌ مِنْ بَنِي عَدِيٍّ","id":"Telah menceritakan kepada kami [Hisyam bin 'Ammar], telah menceritakan kepada kami [Sufyan bin Uyainah] dari [Amru bin Dinar] dari [Jabir bin Abdullah] berkata; \"Seseorang kabilah kami telah berjanji akan memerdekakan seorang budak dan ia tidak memiliki harta selainnya. Kemudian Rasulullah menjualnya dan dibeli oleh Ibnu An-Nahham seorang laki-laki dari bani Adi.\""},"2470":{"ar":"حَدَّثَنَا عُثْمَانُ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا عَلِيُّ بْنُ ظَبْيَانَ عَنْ عُبَيْدِ اللَّهِ عَنْ نَافِعٍ عَنْ ابْنِ عُمَرَأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ الْمُدَبَّرُ مِنْ الثُّلُثِقَالَ ابْن مَاجَةَ سَمِعْتُ عُثْمَانَ يَعْنِي ابْنَ أَبِي شَيْبَةَ يَقُولُ هَذَا خَطَأٌ يَعْنِي حَدِيثَ الْمُدَبَّرُ مِنْ الثُّلُثِ قَالَ أَبُو عَبْد اللَّهِ لَيْسَ لَهُ أَصْلٌ","id":"Telah menceritakan kepada kami [Utsman bin Abu Syaibah], telah menceritakan kepada kami [Ali bin Zhabyan] dari [Ubaidullah] dari [Nafi'] dari [Ibnu 'Umar] bahwasanya Nabi shallallahu 'alaihi wasallam bersabda: \"Budak Mudabbar itu dari sepertiga\". Berkata Ibnu Majah; aku mendengar Utsman yaitu Ibnu Abu Syaibah berkata; \"Hadits ini salah, yang dimaksud adalah Hadits; \"Budak Mudabbar itu dari sepertiga\". Abu Abdillah berkata; \"Tidak mempunyai dasar.\""},"2471":{"ar":"حَدَّثَنَا عَلِيُّ بْنُ مُحَمَّدٍ وَمُحَمَّدُ بْنُ إِسْمَعِيلَ قَالَا حَدَّثَنَا وَكِيعٌ حَدَّثَنَا شَرِيكٌ عَنْ حُسَيْنِ بْنِ عَبْدِ اللَّهِ بْنِ عُبَيْدِ اللَّهِ بْنِ عَبَّاسٍ عَنْ عِكْرِمَةَ عَنْ ابْنِ عَبَّاسٍ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَيُّمَا رَجُلٍ وَلَدَتْ أَمَتُهُ مِنْهُ فَهِيَ مُعْتَقَةٌ عَنْ دُبُرٍ مِنْهُ","id":"Telah menceritakan kepada kami [Ali bin Muhammad] dan [Muhammad bin Isma'il] keduanya berkata; telah menceritakan kepada kami [Waki'], telah menceritakan kepada kami [Syariik] dari [Husain bin Abdullah bin Ubaidullah bin Abbas] dari [Ikrimah] dari [Ibnu Abbas] berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Mana saja seseorang yang mensetubuhi budaknya, setelah ia melahirkan anak maka ia menjadi merdeka.\""},"2472":{"ar":"حَدَّثَنَا أَحْمَدُ بْنُ يُوسُفَ حَدَّثَنَا أَبُو عَاصِمٍ حَدَّثَنَا أَبُو بَكْرٍ يَعْنِي النَّهْشَلِيَّ عَنْ الْحُسَيْنِ بْنِ عَبْدِ اللَّهِ عَنْ عِكْرِمَةَ عَنْ ابْنِ عَبَّاسٍ قَالَذُكِرَتْ أُمُّ إِبْرَاهِيمَ عِنْدَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ أَعْتَقَهَا وَلَدُهَا","id":"Telah menceritakan kepada kami [Ahmad bin Yusuf], telah menceritakan kepada kami [Abu 'Ashim], telah menceritakan kepada kami [Abu Bakar An Nahsyali] dari [Husain bin Abdullah] dari [Ikrimah] dari [Ibnu Abbas] ia berkata; \"Disebutlah ibu Ibrahim disamping Rasulullah shallallahu 'alaihi wasallam, maka beliau bersabda: 'Anaknya telah memerdekakannya.'"},"2473":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ يَحْيَى وَإِسْحَقُ بْنُ مَنْصُورٍ قَالَا حَدَّثَنَا عَبْدُ الرَّزَّاقِ عَنْ ابْنِ جُرَيْجٍ أَخْبَرَنِي أَبُو الزُّبَيْرِ أَنَّهُ سَمِعَ جَابِرَ بْنَ عَبْدِ اللَّهِ يَقُولُكُنَّا نَبِيعُ سَرَارِيَّنَا وَأُمَّهَاتِ أَوْلَادِنَا وَالنَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِينَا حَيٌّ لَا نَرَى بِذَلِكَ بَأْسًا","id":"Telah menceritakan kepada kami [Muhammad bin Yahya] dan [Ishaq bin Manshur], keduanya berkata; telah menceritakan kepada kami [Abdurrazak] dari [Ibnu Juraij], telah mengkabarkan kepadaku [Abu Zubair] bahwa ia mendengar dari [Jabir bin Abdullah], ia berkata, \"Kami menjual hamba sahaya perempuan yang hanya digunakan untuk disetubuhi (selir atau dayang) dan ummahatul Aulad (budak perempuan yang melahirkan anak dari majikannya) kami, sementara saat itu Nabi shallallahu 'alaihi wasallam masih hidup di tengah-tengah kami dan kami tidak melihat larangan dalam hal itu.\""},"2474":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ وَعَبْدُ اللَّهِ بْنُ سَعِيدٍ قَالَا حَدَّثَنَا أَبُو خَالِدٍ الْأَحْمَرُ عَنْ ابْنِ عَجْلَانَ عَنْ سَعِيدِ بْنِ أَبِي سَعِيدٍ عَنْ أَبِي هُرَيْرَةَ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ ثَلَاثَةٌ كُلُّهُمْ حَقٌّ عَلَى اللَّهِ عَوْنُهُ الْغَازِي فِي سَبِيلِ اللَّهِ وَالْمُكَاتَبُ الَّذِي يُرِيدُ الْأَدَاءَ وَالنَّاكِحُ الَّذِي يُرِيدُ التَّعَفُّفَ","id":"Telah menceritakan kepada kami [Abu Bakar bin Abu Syaibah] dan [Abdullah bin Sa'id], keduanya berkata; telah menceritakan kepada kami [Abu Khalid Al 'Ahmar] dari [Ibnu 'Ajlan] dari [Sa'id bin Abu Sa'id] dari [Abu Hurairah] berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Ada tiga orang yang berhak di tolong oleh Allah; orang yang berperang di jalan Allah, seorang budak mukatab yang ingin merdeka dengan melaksanakan kesepakatan bersama tuannya serta seorang laki-laki yang menikah dengan tujuan menjaga kehormatan diri.\""},"2475":{"ar":"حَدَّثَنَا أَبُو كُرَيْبٍ حَدَّثَنَا عَبْدُ اللَّهِ بْنُ نُمَيْرٍ وَمُحَمَّدُ بْنُ فُضَيْلٍ عَنْ حَجَّاجٍ عَنْ عَمْرِو بْنِ شُعَيْبٍ عَنْ أَبِيهِ عَنْ جَدِّهِ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَيُّمَا عَبْدٍ كُوتِبَ عَلَى مِائَةِ أُوقِيَّةٍ فَأَدَّاهَا إِلَّا عَشْرَ أُوقِيَّاتٍ فَهُوَ رَقِيقٌ","id":"Telah menceritakan kepada kami [Abu Kuraib], telah menceritakan kepada kami [Abdullah bin Numair] dan [Muhammad bin Fudhail] dari [Hajjaj] dari [Amru bin Syu'aib] dari [Ayahnya] dari [Kakeknya] berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Hamba sahaya manapun yang memiliki kesanggupan merdeka dengan membayar seratus Uqiyah, kemudian ia menunaikannya kecuali hanya dengan sepuluh Uqiyah saja, maka ia masih seorang hamba sahaya.\""},"2476":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا سُفْيَانُ بْنُ عُيَيْنَةَ عَنْ الزُّهْرِيِّ عَنْ نَبْهَانَ مَوْلَى أُمِّ سَلَمَةَ عَنْ أُمِّ سَلَمَةَ أَنَّهَا أَخْبَرَتْعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنَّهُ قَالَ إِذَا كَانَ لِإِحْدَاكُنَّ مُكَاتَبٌ وَكَانَ عِنْدَهُ مَا يُؤَدِّي فَلْتَحْتَجِبْ مِنْهُ","id":"Telah menceritakan kepada kami [Abu Bakar bin Abu Syaibah], telah menceritakan kepada kami [Sufyan bin Uyainah] dari [Az Zuhri] dari [Nabhan] mantan budak Ummu Salamah dari [Ummu Salamah] bahwa ia mengkabarkan dari Rasulullah shallallahu 'alaihi wasallam beliau bersabda: \"Bila ada di antara kalian salah seorang mukatab (budak yang ingin bebas) dan ia memiliki apa yang ia bisa tebus maka berikanlah untuknya.\""},"2477":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ وَعَلِيُّ بْنُ مُحَمَّدٍ قَالَا حَدَّثَنَا وَكِيعٌ عَنْ هِشَامِ بْنِ عُرْوَةَ عَنْ أَبِيهِ عَنْ عَائِشَةَ زَوْجِ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَأَنَّ بَرِيرَةَ أَتَتْهَا وَهِيَ مُكَاتَبَةٌ قَدْ كَاتَبَهَا أَهْلُهَا عَلَى تِسْعِ أَوَاقٍ فَقَالَتْ لَهَا إِنْ شَاءَ أَهْلُكِ عَدَدْتُ لَهُمْ عَدَّةً وَاحِدَةً وَكَانَ الْوَلَاءُ لِي قَالَ فَأَتَتْ أَهْلَهَا فَذَكَرَتْ ذَلِكَ لَهُمْ فَأَبَوْا إِلَّا أَنْ تَشْتَرِطَ الْوَلَاءَ لَهُمْ فَذَكَرَتْ عَائِشَةُ ذَلِكَ لِلنَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ افْعَلِي قَالَ فَقَامَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَخَطَبَ النَّاسَ فَحَمِدَ اللَّهَ وَأَثْنَى عَلَيْهِ ثُمَّ قَالَ مَا بَالُ رِجَالٍ يَشْتَرِطُونَ شُرُوطًا لَيْسَتْ فِي كِتَابِ اللَّهِ كُلُّ شَرْطٍ لَيْسَ فِي كِتَابِ اللَّهِ فَهُوَ بَاطِلٌ وَإِنْ كَانَ مِائَةَ شَرْطٍ كِتَابُ اللَّهِ أَحَقُّ وَشَرْطُ اللَّهِ أَوْثَقُ وَالْوَلَاءُ لِمَنْ أَعْتَقَ","id":"Telah menceritakan kepada kami [Abu Bakar bin Abu Syaibah] dan [Ali bin Muhammad] keduanya berkata; telah menceritakan kepada kami [Waki'] dari [Hisyam bin Urwah] dari [Ayahnya] dari [Aisyah], isteri Nabi shallallahu 'alaihi wasallam bahwa Barirah datang menemuinya. Barirah adalah seorang budak mukatab di sebuah keluarga dengan tebusan sembilan Uqiyah. Aisyah berkata kepadanya; \"Apabila keluargamu menghendaki, maka aku telah menyiapkan sebuah perhitungan, bahwa hak perwalian adalah hakku.\" Maka Aisyah datang menjumpai keluarganya dan mengemukakan keinginannya kepada mereka, tetapi mereka menolak kecuali apabila hak perwalian tetap milik mereka. Aisyah mengemukakan hal tersebut kepada Nabi shallallahu 'alaihi wasallam, maka Nabi shallallahu 'alaihi wasallam bersabda: \"Lakukanlah!.\" Lalu Nabi berdiri berpidato di hadapan masyarakat. Setelah memuji Allah, beliau berkata; \"Mengapa orang-orang menerapkan syarat-syarat yang tidak terdapat di dalam Al Qur'an. Syarat apapun yang tidak terdapat dalam Al Qur'an, maka syarat tersebut tidak sah, walaupun seratus syarat. \"Kitabullah (Al Qur'an) merupakan sesuatu yang Benar, syarat dari Allah adalah lebih terpercaya dan hak perwalian diberikan kepada orang yang memerdekakan budak.\""},"2478":{"ar":"حَدَّثَنَا أَبُو كُرَيْبٍ حَدَّثَنَا أَبُو مُعَاوِيَةَ عَنْ الْأَعْمَشِ عَنْ عَمْرِو بْنِ مُرَّةَ عَنْ سَالِمِ بْنِ أَبِي الْجَعْدِ عَنْ شُرَحْبِيلَ بْنِ السِّمْطِ قَالَ قُلْتُ لِكَعْبٍ يَا كَعْبَ بْنَ مُرَّةَ حَدِّثْنَا عَنْ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَاحْذَرْ قَالَسَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ مَنْ أَعْتَقَ امْرَأً مُسْلِمًا كَانَ فِكَاكَهُ مِنْ النَّارِ يُجْزِئُ كُلُّ عَظْمٍ مِنْهُ بِكُلِّ عَظْمٍ مِنْهُ وَمَنْ أَعْتَقَ امْرَأَتَيْنِ مُسْلِمَتَيْنِ كَانَتَا فِكَاكَهُ مِنْ النَّارِ يُجْزِئُ بِكُلِّ عَظْمَيْنِ مِنْهُمَا عَظْمٌ مِنْهُ","id":"Telah menceritakan kepada kami [Abu Kuraib], telah menceritakan kepada kami [Abu Mu'awiyah] dari [Al 'Amasy] dari [Amru bin Murrah] dari [Salim bin Abul Ja'd] dari [Syurahbil bin As Simth], ia berkata; \"Aku katakan kepada [Ka'b], 'Wahai Ka'b bin Murrah! Ceritakanlah kepada kami mengenai Rasulullah shallallahu 'alaihi wasallam dan berhati-hatilah'.\" Syurahbil berkata; \"Aku mendengar Rasulullah shallallahu 'alaihi wasallam bersabda: 'Barangsiapa yang memerdekakan seorang hamba sahaya yang muslim, maka ia. dibebaskan dari api neraka. Setiap tulang-belulang dari hamba sahaya tersebut akan memberikan balasan amal perbuatan kepada orang tersebut. Dan Barangsiapa yang memerdekakan dua orang hamba sahaya wanita muslimah, maka keduanya dapat membebaskannya dari neraka. Setiap satu tulang belulang dari keduanya akan membalas amal kebaikan orang tersebut.\""},"2479":{"ar":"حَدَّثَنَا أَحْمَدُ بْنُ سِنَانٍ حَدَّثَنَا أَبُو مُعَاوِيَةَ حَدَّثَنَا هِشَامُ بْنُ عُرْوَةَ عَنْ أَبِيهِ عَنْ أَبِي مُرَاوِحٍ عَنْ أَبِي ذَرٍّ قَالَقُلْتُ يَا رَسُولَ اللَّهِ أَيُّ الرِّقَابِ أَفْضَلُ قَالَ أَنْفَسُهَا عِنْدَ أَهْلِهَا وَأَغْلَاهَا ثَمَنًا","id":"Telah menceritakan kepada kami [Ahmad bin Sinan], telah menceritakan kepada kami [Abu Mu'awiyah], telah menceritakan kepada kami [Hisyam bin Urwah] dari [Ayahnya] dari [Abu Murawih] dari [Abu Dzar], ia berkata, Aku berkata, Wahai Rasulullah, hamba sahaya bagaimana yang paling utama?\" Rasulullah shallallahu 'alaihi wasallam bersabda: \"Hamba sahaya yang paling berharga bagi pemiliknya dan paling mahal harganya.\""},"2480":{"ar":"حَدَّثَنَا عُقْبَةُ بْنُ مُكْرَمٍ وَإِسْحَقُ بْنُ مَنْصُورٍ قَالَا حَدَّثَنَا مُحَمَّدُ بْنُ بَكْرٍ الْبُرْسَانِيُّ عَنْ حَمَّادِ بْنِ سَلَمَةَ عَنْ قَتَادَةَ وَعَاصِمٍ عَنْ الْحَسَنِ عَنْ سَمُرَةَ بْنِ جُنْدَبٍعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ مَنْ مَلَكَ ذَا رَحِمٍ مَحْرَمٍ فَهُوَ حُرٌّ","id":"Telah menceritakan kepada kami [Uqbah bin Mukram] dan [Ishaq bin Manshur] keduanya berkata; telah menceritakan kepada kami [Muhammad bin Bakar Al Bursani] dari [Hammad bin Salamah] dari [Qatadah] dan ['Ashim] dari [Hasan] dari [Samurah bin Jundub] dari Rasulullah shallallahu 'alaihi wasallam bersabda: \"Barangsiapa memiliki kekerabatan terhadap seorang budak, maka berarti ia merdeka.\""},"2481":{"ar":"حَدَّثَنَا رَاشِدُ بْنُ سَعِيدٍ الرَّمْلِيُّ وَعُبَيْدُ اللَّهِ بْنُ الْجَهْمِ الْأَنْمَاطِيُّ قَالَا حَدَّثَنَا ضَمْرَةُ بْنُ رَبِيعَةَ عَنْ سُفْيَانَ عَنْ عَبْدِ اللَّهِ بْنِ دِينَارٍ عَنْ ابْنِ عُمَرَ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَنْ مَلَكَ ذَا رَحِمٍ مَحْرَمٍ فَهُوَ حُرٌّ","id":"Telah menceritakan kepada kami [Rasyid bin Sa'id Ar Ramli] dan [Ubaidullah bin Juhmi Al 'Anmathi], keduanya berkata; telah menceritakan kepada kami [Dlamrah bin Rabi'ah] dari [Sufyan] dari [Abdullah bin Dinar] dari [Ibnu 'Umar], ia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Barang siapa memiliki seorang budak yang memiliki hubungan kekerabatan maka dia merdeka\"."},"2482":{"ar":"حَدَّثَنَا عَبْدُ اللَّهِ بْنُ مُعَاوِيَةَ الْجُمَحِيُّ حَدَّثَنَا حَمَّادُ بْنُ سَلَمَةَ عَنْ سَعِيدِ بْنِ جُمْهَانَ عَنْ سَفِينَةَ أَبِي عَبْدِ الرَّحْمَنِ قَالَأَعْتَقَتْنِي أُمُّ سَلَمَةَ وَاشْتَرَطَتْ عَلَيَّ أَنْ أَخْدُمَ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَا عَاشَ","id":"Telah menceritakan kepada kami [Abdullah bin Mu'awiyah Al Jumahi], telah menceritakan kepada kami [Hammad bin Salamah] dari [Sa'id bin Jumhan] dari [Safinah Abu Abdurrahman] ia berkata; \"Ummu Salamah memerdekakanku dan memberikan syarat agar aku membantu Nabi shallallahu 'alaihi wasallam selama masa hidup beliau.\""},"2483":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا عَلِيُّ بْنُ مُسْهِرٍ وَمُحَمَّدُ بْنُ بِشْرٍ عَنْ سَعِيدِ بْنِ أَبِي عَرُوبَةَ عَنْ قَتَادَةَ عَنْ النَّضْرِ بْنِ أَنَسٍ عَنْ بَشِيرِ بْنِ نَهِيكٍ عَنْ أَبِي هُرَيْرَةَ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَنْ أَعْتَقَ نَصِيبًا لَهُ فِي مَمْلُوكٍ أَوْ شِقْصًا فَعَلَيْهِ خَلَاصُهُ مِنْ مَالِهِ إِنْ كَانَ لَهُ مَالٌ فَإِنْ لَمْ يَكُنْ لَهُ مَالٌ اسْتُسْعِيَ الْعَبْدُ فِي قِيمَتِهِ غَيْرَ مَشْقُوقٍ عَلَيْهِ","id":"Telah menceritakan kepada kami [Abu Bakar bin Abu Syaibah], telah menceritakan kepada kami [Ali bin Mushir] dan [Muhammad bin Bisyir] dari [Sa'id bin Abu 'Arubah] dari [Qatadah] dari [Nadlar bin Anas] dari [Basyir bin Nahiik] dari [Abu Hurairah] ia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Barangsiapa yang memerdekakan seorang hamba sahaya dengan sebagian hartanya, maka hendaknya ia melunasinya dengan hartanya pula, yaitu apabila ia memiliki harta. Apabila tidak memiliki harta, maka hendaknya diusahakan ada perbincangan mengenai nilai hamba sahaya tersebut yang tidak memberatkan.\""},"2484":{"ar":"حَدَّثَنَا يَحْيَى بْنُ حَكِيمٍ حَدَّثَنَا عُثْمَانُ بْنُ عُمَرَ حَدَّثَنَا مَالِكُ بْنُ أَنَسٍ عَنْ نَافِعٍ عَنْ ابْنِ عُمَرَ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَنْ أَعْتَقَ شِرْكًا لَهُ فِي عَبْدٍ أُقِيمَ عَلَيْهِ بِقِيمَةِ عَدْلٍ فَأَعْطَى شُرَكَاءَهُ حِصَصَهُمْ إِنْ كَانَ لَهُ مِنْ الْمَالِ مَا يَبْلُغُ ثَمَنَهُ وَعَتَقَ عَلَيْهِ الْعَبْدُ وَإِلَّا فَقَدْ عَتَقَ مِنْهُ مَا عَتَقَ","id":"Telah menceritakan kepada kami [Yahya bin Hakim] Telah menceritakan kepada kami [Utsman bin Umar] Telah menceritakan kepada kami [Malik bin Anas] dari [Nafi'] dari [Ibnu Umar] dia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Barang siapa yang memerdekakan budak, sedangkan ia memiliki partner dalam pembebasan budak, kemudian memiliki harta seharga budak tersebut, maka ia harus membayar bagiannya kepada partnernya secara adil, jika tidak seperti itu, maka ia hanya membebaskan dengan bagiannya saja.\""},"2485":{"ar":"حَدَّثَنَا حَرْمَلَةُ بْنُ يَحْيَى حَدَّثَنَا عَبْدُ اللَّهِ بْنُ وَهْبٍ أَخْبَرَنِي ابْنُ لَهِيعَةَ ح و حَدَّثَنَا مُحَمَّدُ بْنُ يَحْيَى حَدَّثَنَا سَعِيدُ بْنُ أَبِي مَرْيَمَ أَنْبَأَنَا اللَّيْثُ بْنُ سَعْدٍ جَمِيعًا عَنْ عُبَيْدِ اللَّهِ بْنِ أَبِي جَعْفَرٍ عَنْ بُكَيْرِ بْنِ الْأَشَجِّ عَنْ نَافِعٍ عَنْ ابْنِ عُمَرَ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَنْ أَعْتَقَ عَبْدًا وَلَهُ مَالٌ فَمَالُ الْعَبْدِ لَهُ إِلَّا أَنْ يَشْتَرِطَ السَّيِّدُ مَالَهُ فَيَكُونَ لَهُ وَقَالَ ابْنُ لَهِيعَةَ إِلَّا أَنْ يَسْتَثْنِيَهُ السَّيِّدُ","id":"Telah menceritakan kepada kami [Harmalah bin Yahya], telah menceritakan kepada kami [Abdullah bin Wahab], telah mengkabarkan kepadaku [Ibnu Lahi'ah], (demikian juga diriwayatkan dari jalur lain) telah menceritakan kepada kami [Muhammad bin Yahya], telah menceritakan kepada kami [Sa'id bin Abu Maryam], telah memberitakan kepada kami [Laits bin Sa'ad] semuanya dari [Ubaidullah bin Abu Ja'far] dari [Bukair bin Asyajj] dari [Nafi'] dari [Ibnu Umar] berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Barangsiapa memerdekakan seorang hamba sahaya yang memiliki harta, maka harta tersebut menjadi miliknya (orang yang memerdekakan), kecuali apabila si majikan mensyaratkan harta tersebut menjadi miliknya (majikan). Ibnu Lahi'ah berkata; \"Kecuali yang dikhususkan perlakuannya oleh majikannya.\""},"2486":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ يَحْيَى حَدَّثَنَا سَعِيدُ بْنُ مُحَمَّدٍ الْجَرْمِيُّ حَدَّثَنَا الْمُطَّلِبُ بْنُ زِيَادٍ عَنْ إِسْحَقَ بْنِ إِبْرَاهِيمَ عَنْ جَدِّهِ عُمَيْرٍ وَهُوَ مَوْلَى ابْنِ مَسْعُودٍ أَنَّ عَبْدَ اللَّهِ قَالَ لَهُيَا عُمَيْرُ إِنِّي أَعْتَقْتُكَ عِتْقًا هَنِيئًا إِنِّي سَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ أَيُّمَا رَجُلٍ أَعْتَقَ غُلَامًا وَلَمْ يُسَمِّ مَالَهُ فَالْمَالُ لَهُ فَأَخْبِرْنِي مَا مَالُكَحَدَّثَنَا مُحَمَّدُ بْنُ عَبْدِ اللَّهِ بْنِ نُمَيْرٍ حَدَّثَنَا الْمُطَّلِبُ بْنُ زِيَادٍ عَنْ إِسْحَقَ بْنِ إِبْرَاهِيمَ قَالَ قَالَ عَبْدُ اللَّهِ بْنُ مَسْعُودٍ لِجَدِّي فَذَكَرَ نَحْوَهُ","id":"Telah menceritakan kepada kami [Muhammad bin Yahya], telah menceritakan kepada kami [Sa'id bin Muhammad Al Jarmi], telah menceritakan kepada kami [Al Muthallib bin Ziyad] dari [Ishaq bin Ibrahim] dari kakeknya ['Umair] mantan budak Ibnu Mas'ud, bahwasanya [Abdullah] berkata kepadanya; \"Wahai 'Umair, sesungguhnya aku telah memerdekakanmu dengan baik-baik, sesungguhnya aku mendengar Rasulullah shallallahu 'alaihi wasallam bersabda: \"Siapa saja orangnya yang memerdekakan seorang budak tanpa menyebut hartanya, maka hartanya adalah baginya.\" Maka beritahukan kepadaku apa hartamu? Telah menceritakan kepada kami [Muhammad bin Abdullah bin Numair], telah menceritakan kepada kami [Muthallib bin Ziyad] dari [Ishaq bin Ibrahim] berkata; [Abdullah bin Mas'ud] berkata kepada kakekku lalu ia sebutkan hadits serupa."},"2487":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا الْفَضْلُ بْنُ دُكَيْنٍ حَدَّثَنَا إِسْرَائِيلُ عَنْ زَيْدِ بْنِ جُبَيْرٍ عَنْ أَبِي يَزِيدَ الضَّبِّيِّ عَنْ مَيْمُونَةَ بِنْتِ سَعْدٍ مَوْلَاةِ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ سُئِلَ عَنْ وَلَدِ الزِّنَا فَقَالَ نَعْلَانِ أُجَاهِدُ فِيهِمَا خَيْرٌ مِنْ أَنْ أُعْتِقَ وَلَدَ الزِّنَا","id":"Telah menceritakan kepada kami [Abu Bakar bin Abu Syaibah], telah menceritakan kepada kami [Fadlal bin Dukain], telah menceritakan kepada kami [Isra'il] dari [Zaid bin Jubair] dari [Abu Yazid Adl Dlibbi] dari [Maimunah binti Sa'ad] mantan budak perempuan Nabi shallallahu 'alaihi wasallam bahwa Rasulullah shallallahu 'alaihi wasallam ditanya tentang anak pezina, beliau bersabda: \"Dua sandal yang aku pakai lebih baik dari aku memerdekakkan anak zina.\""},"2488":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ بَشَّارٍ حَدَّثَنَا حَمَّادُ بْنُ مَسْعَدَةَ ح و حَدَّثَنَا مُحَمَّدُ بْنُ خَلَفٍ الْعَسْقَلَانِيُّ وَإِسْحَقُ بْنُ مَنْصُورٍ قَالَا حَدَّثَنَا عُبَيْدُ اللَّهِ بْنُ عَبْدِ الْمَجِيدِ حَدَّثَنَا عُبَيْدُ اللَّهِ بْنُ عَبْدِ الرَّحْمَنِ بْنِ مَوْهَبٍ عَنْ الْقَاسِمِ بْنِ مُحَمَّدٍ عَنْ عَائِشَةَأَنَّهَا كَانَ لَهَا غُلَامٌ وَجَارِيَةٌ زَوْجٌ فَقَالَتْ يَا رَسُولَ اللَّهِ إِنِّي أُرِيدُ أَنْ أُعْتِقَهُمَا فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِنْ أَعْتَقْتِهِمَا فَابْدَئِي بِالرَّجُلِ قَبْلَ الْمَرْأَةِ","id":"Telah menceritakan kepada kami [Muhammad bin Basyar], telah menceritakan kepada kami [Hammad bin Mas'adah], (Demikian juga diriwayatkan dari jalur lain), Telah menceritakan kepada kami [Muhammad bin Khalaf Al 'Asqalani] dan [Ishaq bin Manshur], keduanya berkata; telah menceritakan kepada kami [Ubaidullah bin Abdul Majid], telah menceritakan kepada kami [Ubaidullah bin Abdurrahman bin Mauhab] dari [Qasim bin Muhammad] dari ['Aisyah], sesungguhnya dia memiliki seorang budak lelaki dan budak perempuan istrinya, maka dia berkata kepada Rasulullah; \"Sesungguhnya aku ingin membebaskan mereka berdua\". Maka Rasulullah shallallahu 'alaihi wasallam bersabda: \"Jika kamu hendak membebaskannya maka mulailah dengan yang lelaki sebelum yang perempuan.\""},"2489":{"ar":"حَدَّثَنَا أَحْمَدُ بْنُ عَبْدَةَ أَنْبَأَنَا حَمَّادُ بْنُ زَيْدٍ عَنْ يَحْيَى بْنِ سَعِيدٍ عَنْ أَبِي أُمَامَةَ بْنِ سَهْلِ بْنِ حُنَيْفٍأَنَّ عُثْمَانَ بْنَ عَفَّانَ أَشْرَفَ عَلَيْهِمْ فَسَمِعَهُمْ وَهُمْ يَذْكُرُونَ الْقَتْلَ فَقَالَ إِنَّهُمْ لَيَتَوَاعَدُونِي بِالْقَتْلِ فَلِمَ يَقْتُلُونِي وَقَدْ سَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ لَا يَحِلُّ دَمُ امْرِئٍ مُسْلِمٍ إِلَّا فِي إِحْدَى ثَلَاثٍ رَجُلٌ زَنَى وَهُوَ مُحْصَنٌ فَرُجِمَ أَوْ رَجُلٌ قَتَلَ نَفْسًا بِغَيْرِ نَفْسٍ أَوْ رَجُلٌ ارْتَدَّ بَعْدَ إِسْلَامِهِ فَوَاللَّهِ مَا زَنَيْتُ ��ِي جَاهِلِيَّةٍ وَلَا فِي إِسْلَامٍ وَلَا قَتَلْتُ نَفْسًا مُسْلِمَةً وَلَا ارْتَدَدْتُ مُنْذُ أَسْلَمْتُ","id":"Telah menceritakan kepada kami [Ahmad bin Abdah], telah memberitakan kepada kami [Hammad bin Zaid] dari [Yahya bin Sa'id] dari [Abu Umamah bin Sahal bin Hunaif] bahwa Utsman bin Affan suatu ketika memimpin sebuah rombongan. Lalu Utsman mendengar bahwa mereka membicarakan masalah pembunuhan. [Utsman bin Affan] berkata; \"Mereka mengancam akan membunuhku! Mengapa mereka ingin membunuhku? Padahal aku mendengar Rasulullah shallallahu 'alaihi wasallam bersabda: \"Tidaklah halal darah seorang muslim, kecuali pada salah satu dari tiga hal: seseorang yang berzina dan ia (telah menikah), maka ia harus dirajam. seseorang yang membunuh orang lain tanpa hak, atau seseorang yang murtad setelah ia memeluk Islam.' Demi Allah aku tidak pernah berzina baik masa jahiliyah maupun Islam, aku juga tidak pernah membunuh seorang muslim dan aku tidak pernah murtad setelah aku memeluk Islam.\""},"2490":{"ar":"حَدَّثَنَا عَلِيُّ بْنُ مُحَمَّدٍ وَأَبُو بَكْرِ بْنِ خَلَّادٍ الْبَاهِلِيُّ قَالَا حَدَّثَنَا وَكِيعٌ عَنْ الْأَعْمَشِ عَنْ عَبْدِ اللَّهِ بْنِ مُرَّةَ عَنْ مَسْرُوقٍ عَنْ عَبْدِ اللَّهِ وَهُوَ ابْنُ مَسْعُودٍ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَا يَحِلُّ دَمُ امْرِئٍ مُسْلِمٍ يَشْهَدُ أَنْ لَا إِلَهَ إِلَّا اللَّهُ وَأَنِّي رَسُولُ اللَّهِ إِلَّا أَحَدُ ثَلَاثَةِ نَفَرٍ النَّفْسُ بِالنَّفْسِ وَالثَّيِّبُ الزَّانِي وَالتَّارِكُ لِدِينِهِ الْمُفَارِقُ لِلْجَمَاعَةِ","id":"Telah menceritakan kepada kami [Ali bin Muhammad] dan [Abu Bakar bin Khallad AL Bahili], keduanya berkata; telah menceritakan kepada kami [Waki'] dari ['A'masy] dari [Abdullah bin Murrah] dari [Masruq] dari [Abdullah bin Mas'ud] berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Tidaklah halal darah seorang muslim yang telah mengucap syahadat, kecuali pada salah satu dari tiga hal: seseorang yang membunuh orang lain tanpa hak, seorang yang pernah nikah namun ia berzina dan seseorang yang keluar dari jama'ah yaitu murtad meninggalkan Islam.'"},"2491":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ الصَّبَّاحِ أَنْبَأَنَا سُفْيَانُ بْنُ عُيَيْنَةَ عَنْ أَيُّوبَ عَنْ عِكْرِمَةَ عَنْ ابْنِ عَبَّاسٍ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَنْ بَدَّلَ دِينَهُ فَاقْتُلُوهُ","id":"Telah menceritakan kepada kami [Muhammad bin Shabah], telah memberitakan kepada kami [Sufyan bin Uyainah] dari [Ayyub] dari [Ikrimah] dari [Ibnu Abbas], ia berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Barangsiapa mengganti agamanya, maka bunuhlah ia.\""},"2492":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا أَبُو أُسَامَةَ عَنْ بَهْزِ بْنِ حَكِيمٍ عَنْ أَبِيهِ عَنْ جَدِّهِ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَا يَقْبَلُ اللَّهُ مِنْ مُشْرِكٍ أَشْرَكَ بَعْدَ مَا أَسْلَمَ عَمَلًا حَتَّى يُفَارِقَ الْمُشْرِكِينَ إِلَى الْمُسْلِمِينَ","id":"Telah menceritakan kepada kami [Abu Bakar bin Abu Syaibah], telah menceritakan kepada kami [Abu Usamah] dari [Bahz bin Hakim] dari [Ayahnya] dari [Kakeknya] berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Allah subhanahu wata'ala tidak menerima amal seorang musyrik yang menyekutukan Allah setelah sebelumnya masuk Islam, sampai ia memisahkan diri dengan orang-orang musyrik dan bergabung dengan kaum muslimin.\""},"2493":{"ar":"حَدَّثَنَا هِشَامُ بْنُ عَمَّارٍ حَدَّثَنَا الْوَلِيدُ بْنُ مُسْلِمٍ حَدَّثَنَا سَعِيدُ بْنُ سِنَانٍ عَنْ أَبِي الزَّاهِرِيَّةِ عَنْ أَبِي شَجَرَةَ كَثِيرِ بْنِ مُرَّةَ عَنْ ابْنِ عُمَرَأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ إِقَامَةُ حَدٍّ مِنْ حُدُودِ اللَّهِ خَيْرٌ مِنْ مَطَرِ أَرْبَعِينَ لَيْلَةً فِي بِلَادِ اللَّهِ عَزَّ وَجَلَّ","id":"Telah menceritakan kepada kami [Hisyam bin 'Ammar], telah menceritakan kepada kami [Walid bin Muslim], telah menceritakan kepada kami [Sa'id bin Sinan] dari [Abu Zahiriyyah] dari [Abu Syajarah Katsir bin Murrah] dari [Ibnu Umar], Rasulullah shallallahu 'alaihi wasallam bersabda: \"Melaksanakan salah satu dari hukum hudud lebih baik dari pada hujan empat puluh malam di negeri-negeri Allah Azza wa Jalla.\""},"2494":{"ar":"حَدَّثَنَا عَمْرُو بْنُ رَافِعٍ حَدَّثَنَا عَبْدُ اللَّهِ بْنُ الْمُبَارَكِ أَنْبَأَنَا عِيسَى بْنُ يَزِيدَ قَالَ أَظُنُّهُ عَنْ جَرِيرِ بْنِ يَزِيدَ عَنْ أَبِي زُرْعَةَ بْنِ عَمْرِو بْنِ جَرِيرٍ عَنْ أَبِي هُرَيْرَةَ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ حَدٌّ يُعْمَلُ بِهِ فِي الْأَرْضِ خَيْرٌ لِأَهْلِ الْأَرْضِ مِنْ أَنْ يُمْطَرُوا أَرْبَعِينَ صَبَاحًا","id":"Telah menceritakan kepada kami [Amru bin Rafi'], telah menceritakan kepada kami [Abdullah bin Mubarak], telah memberitakan kepada kami [Isa bin Yazid], ia berkata; aku menyangkanya dari [Jarir bin Yazid] dari [Abu Zur'ah bin Amru bin Jarir] dari [Abu Hurairah] berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Hukum hudud yang dilaksanakan diatas bumi itu lebih baik daripada mereka diberi hujan selama empat puluh hari pada waktu pagi.\""},"2495":{"ar":"حَدَّثَنَا نَصْرُ بْنُ عَلِيٍّ الْجَهْضَمِيُّ حَدَّثَنَا حَفْصُ بْنُ عُمَرَ حَدَّثَنَا الْحَكَمُ بْنُ أَبَانَ عَنْ عِكْرِمَةَ عَنْ ابْنِ عَبَّاسٍ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَنْ جَحَدَ آيَةً مِنْ الْقُرْآنِ فَقَدْ حَلَّ ضَرْبُ عُنُقِهِ وَمَنْ قَالَ لَا إِلَهَ إِلَّا اللَّهُ وَحْدَهُ لَا شَرِيكَ لَهُ وَأَنَّ مُحَمَّدًا عَبْدُهُ وَرَسُولُهُ فَلَا سَبِيلَ لِأَحَدٍ عَلَيْهِ إِلَّا أَنْ يُصِيبَ حَدًّا فَيُقَامَ عَلَيْهِ","id":"Telah menceritakan kepada kami [Nashr bin Ali Al Jahdlami], telah menceritakan kepada kami [Hafsh bin Umar], telah menceritakan kepada kami [Hakam bin Aban] dari [Ikrimah] dari [Ibnu 'Abbas], ia berkata; Rasulullah bersabda shallallahu 'alaihi wasallam: \"Barang siapa menolak satu ayat dari Al qur'an, maka telah halal memenggal lehernya, dan barang siapa berkata; tidak ada Ilah yang berhak disembah kecuali Allah satu-satunya yang tidak ada sekutu baginya dan sesungguhnya Muhammad adalah hamba-Nya dan utusan-Nya, maka tidak ada jalan bagi siapapun untuk membunuhnya, kecuali jika dia telah melanggar hukum Allah, maka ditegakkan hudud atasnya\"."},"2496":{"ar":"حَدَّثَنَا عَبْدُ اللَّهِ بْنُ سَالِمٍ الْمَفْلُوجُ حَدَّثَنَا عُبَيْدَةُ بْنُ الْأَسْوَدِ عَنْ الْقَاسِمِ بْنِ الْوَلِيدِ عَنْ أَبِي صَادِقٍ عَنْ رَبِيعَةَ بْنِ نَاجِدٍ عَنْ عُبَادَةَ بْنِ الصَّامِتِ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَقِيمُوا حُدُودَ اللَّهِ فِي الْقَرِيبِ وَالْبَعِيدِ وَلَا تَأْخُذْكُمْ فِي اللَّهِ لَوْمَةُ لَائِمٍ","id":"Telah menceritakan kepada kami [Abdullah bin Salim Al Mafluj], telah menceritakan kepada kami [Ubaidah bin Al Aswad] dari [Al Qasim bin Al Walid] dari [Abu Shadiq] dari [Rabi'ah bin Najid] dari ['Ubadah bin Shamit], ia berkata; bersabda Rasulullah shallallahu 'alaihi wasallam: \"Tegakkanlah hukum hudud Allah baik kepada orang dekat maupun orang yang jauh, dan jangan sampai cercaan orang yang mencerca mempengaruhi kalian dijalan Allah.\""},"2497":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ وَعَلِيُّ بْنُ مُحَمَّدٍ قَالَا حَدَّثَنَا وَكِيعٌ عَنْ سُفْيَانَ عَنْ عَبْدِ الْمَلِكِ بْنِ عُمَيْرٍ قَالَ سَمِعْتُ عَطِيَّةَ الْقُرَظِيَّ يَقُولُعُرِضْنَا عَلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَوْمَ قُرَيْظَةَ فَكَانَ مَنْ أَنْبَتَ قُتِلَ وَمَنْ لَمْ يُنْبِتْ خُلِّيَ سَبِيلُهُ فَكُنْتُ فِيمَنْ لَمْ يُنْبِتْ فَخُلِّيَ سَبِيلِيحَدَّثَنَا مُحَمَّدُ بْنُ الصَّبَّاحِ أَنْبَأَنَا سُفْيَانُ بْنُ عُيَيْنَةَ عَنْ عَبْدِ الْمَلِكِ بْنِ عُمَيْرٍ قَالَ سَمِعْتُ عَطِيَّةَ الْقُرَظِيَّ يَقُولُ فَهَا أَنَا ذَا بَيْنَ أَظْهُرِكُمْ","id":"Telah menceritakan kepada kami [Abu Bakar bin Abu Syaibah] dan [Ali bin Muhammad], keduanya berkata; telah menceritakan kepada kami [Waki'] dari [Sufyan] dari [Abdul Malik bin Umair] ia berkata; Aku mendengar [Athiah Al Qurazhi], ia berkata; \"Kami diperlihatkan kepada Rasulullah shallallahu 'alaihi wasallam di saat perang Bani Quraizhah. Saat itu musuh yang telah tumbuh bulu kemaluannya (telah dewasa) harus dibunuh yang belum tumbuh bulu kemaluannya dibiarkan bebas. Aku termasuk orang yang belum memiliki bulu kemaluan, maka aku dibebaskan.\" Telah menceritakan kepada kami [Muhammad bin As Shabah], telah memberitakan kepadaku [Sufyan bin Uyainah] dari [Abdul Malik bin Umair] berkata; Aku mendengar [Athiyah Al Qurazhi] berkata; \"Pada waktu itu aku berada di antara kalian.\""},"2498":{"ar":"حَدَّثَنَا عَلِيُّ بْنُ مُحَمَّدٍ حَدَّثَنَا عَبْدُ اللَّهِ بْنُ نُمَيْرٍ وَأَبُو مُعَاوِيَةَ وَأَبُو أُسَامَةَ قَالُوا حَدَّثَنَا عُبَيْدُ اللَّهِ بْنُ عُمَرَ عَنْ نَافِعٍ عَنْ ابْنِ عُمَرَ قَالَعُرِضْتُ عَلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَوْمَ أُحُدٍ وَأَنَا ابْنُ أَرْبَعَ عَشْرَةَ سَنَةً فَلَمْ يُجِزْنِي وَعُرِضْتُ عَلَيْهِ يَوْمَ الْخَنْدَقِ وَأَنَا ابْنُ خَمْسَ عَشْرَةَ سَنَةً فَأَجَازَنِيقَالَ نَافِعٌ فَحَدَّثْتُ بِهِ عُمَرَ بْنَ عَبْدِ الْعَزِيزِ فِي خِلَافَتِهِ فَقَالَ هَذَا فَصْلُ مَا بَيْنَ الصَّغِيرِ وَالْكَبِيرِ","id":"Telah menceritakan kepada kami [Ali bin Muhammad], telah menceritakan kepada kami [Abdullah bin Numair] dan [Abu Mu'awiyah] dan [Abu Usamah], mereka berkata; telah menceritakan kepada kami [Ubaidullah bin Umar] dari [Nafi'] dari [Ibnu Umar] berkata; \"Aku dihadapkan kepada Rasulullah shallallahu 'alaihi wasallam pada saat perang Uhud dan di saat itu usiaku baru empat belas tahun. Maka Rasulullah shallallahu 'alaihi wasallam belum mengizinkanku untuk ikut berperang. Kemudian aku dihadapkan kembali pada saat perang Khandaq dan saat itu usiaku sudah genap lima belas tahun, maka beliau memperkenankanku ikut berperang. Nafi berkata; Lantas aku ceritakan hal itu kepada Umar bin Abdul Aziz di masa pemerintahannya, dan ia berkata; \"Ini adalah pemisah antara anak kecil dan orang dewasa.\""},"2499":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا أَبُو مُعَاوِيَةَ عَنْ الْأَعْمَشِ عَنْ أَبِي صَالِحٍ عَنْ أَبِي هُرَيْرَةَ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَنْ سَتَرَ مُسْلِمًا سَتَرَهُ اللَّهُ فِي الدُّنْيَا وَالْآخِرَةِ","id":"Telah menceritakan kepada kami [Abu Bakar bin Abu Syaibah], telah menceritakan kepada kami [Abu Mu'awiyah] dari [Al 'A'masy] dari [Abu Shalih] dari [Abu Hurairah] berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Barang Siapa menutupi aib seorang muslim, maka Allah akan menutupi aib orang tersebut di dunia dan akhirat.\""},"2500":{"ar":"حَدَّثَنَا عَبْدُ اللَّهِ بْنُ الْجَرَّاحِ حَدَّثَنَا وَكِيعٌ عَنْ إِبْرَاهِيمَ بْنِ الْفَضْلِ عَنْ سَعِيدِ بْنِ أَبِي سَعِيدٍ عَنْ أَبِي هُرَيْرَةَ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ ادْفَعُوا الْحُدُودَ مَا وَجَدْتُمْ لَهُ مَدْفَعًا","id":"Telah menceritakan kepada kami [Abdullah bin Al Jarrah], telah menceritakan kepada kami [Waki'] dari [Ibrahim bin Al Fadlal] dari [Sa'id bin Abu Sa'id] dari [Abu Hurairah] berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Semarakkanlah hudud, selagi kalian mendapatkan kesempatan.\""}};
